        #region LanguageCodeBasedMessge
        public string GetLanguageBasedApiMessge(Guid userID, string keyName)
        {
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    string? languageCode = _userRepository.GetUserProfileByUserID(userID).LanguageCode;
                    return _genericRepository.GetUniqueKey(keyName, languageCode);
                }
            }
            catch (Exception)
            {
                return string.Empty;
            }
        }
        public string GetLanguageCodeBasedApiMessge(string LanguageCode, string keyName)
        {
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    return _genericRepository.GetUniqueKey(keyName, LanguageCode);
                }
            }
            catch (Exception)
            {
                return string.Empty;
            }
        }
