        #region ConvertSignImage       
        public string ConvertSignImage(PrivateFontCollection pfc, string text, string font, string fontsize, string fontColor, string height, string width, out int intHeight, out int intWidth, string envelopeCodeStamp = "", int electronicSignIndicationId = 1, string dateFormat = "", string userTimezone = "", string dateFormatID = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "ConvertSignImage", "Process started for Convert Sign Image", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            var objBmpImage = new Bitmap(1, 1);
            intWidth = 0;
            intHeight = 0;
            dynamic objFont;
            fontsize = fontsize.Replace("px", string.Empty);
            // Create the Font object for the image text drawing.
            if (font == "Kristi" || font == "Brush")
                objFont = new Font(pfc.Families[0], 50, FontStyle.Italic, System.Drawing.GraphicsUnit.Pixel);
            else
                objFont = new Font(pfc.Families[0], 50, System.Drawing.GraphicsUnit.Pixel);
            // Create a graphics object to measure the text's width and height.
            Graphics objGraphics = Graphics.FromImage(objBmpImage);
            // This is where the bitmap size is determined.
            intWidth = (int)objGraphics.MeasureString(text, objFont).Width;
            intHeight = (int)objGraphics.MeasureString(text, objFont).Height;
            // Create the bmpImage again with the correct size for the text and font.
            objBmpImage = new Bitmap(objBmpImage, intWidth, intHeight);
            // Add the colors to the new bitmap.
            objGraphics = Graphics.FromImage(objBmpImage);
            // Set Background color
            objGraphics.Clear(Color.Transparent);
            objGraphics.SmoothingMode = SmoothingMode.AntiAlias;
            objGraphics.TextRenderingHint = TextRenderingHint.AntiAlias;
            if (string.IsNullOrEmpty(fontColor))
                objGraphics.DrawString(text, objFont, new SolidBrush(Color.Black), 0, 0);
            else if (fontColor.ToLower() == "#ED1414".ToLower())
                objGraphics.DrawString(text, objFont, new SolidBrush(Color.Red), 0, 0);
            else if (fontColor.ToLower() == "#2247E0".ToLower())
                objGraphics.DrawString(text, objFont, new SolidBrush(Color.Blue), 0, 0);
            else
                objGraphics.DrawString(text, objFont, new SolidBrush(Color.Black), 0, 0);
            objGraphics.Flush();
            string imageSrc = string.Empty;

            if (electronicSignIndicationId > 1)
            {
                var stampImage = GenerateStamp(envelopeCodeStamp, objBmpImage, false, electronicSignIndicationId, dateFormat, userTimezone, dateFormatID);
                intWidth = stampImage.Width;
                intHeight = stampImage.Height;
                imageSrc = _eSignHelper.ImageToBase64(stampImage);
            }
            else
                imageSrc = _eSignHelper.ImageToBase64(objBmpImage);

            imageSrc = "data:image/png;base64," + imageSrc;
            return imageSrc;
        }
        public System.Drawing.Image GenerateStamp(string stampCode, System.Drawing.Image signatureImage = null, bool isHandDrawn = false, int electronicSignIndicationId = 1, string dateFormat = "", string userTimezone = "", string dateFormatID = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GenerateStamp", "Process started for Generate Stamp", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            int width = signatureImage.Width;
            int height = signatureImage.Height;

            if (!string.IsNullOrEmpty(dateFormat) && dateFormat.Contains("mmm"))
                dateFormat = dateFormat.Replace("mmm", "MMM");
            else if (!string.IsNullOrEmpty(dateFormat))
                dateFormat = dateFormat.Replace("mm", "MM");

            //stampCode = electronicSignIndicationId == 3 ? (!string.IsNullOrEmpty(dateFormat)? DateTime.Now.ToString(dateFormat + " hh:mm:tt") : DateTime.Now.ToString("dd/MM/yyyy hh:mm:tt")) : stampCode;
            if (electronicSignIndicationId == 3)
            {
                stampCode = !string.IsNullOrEmpty(dateFormatID) ? _eSignHelper.GetLocalTime(DateTime.Now, userTimezone, new Guid(dateFormatID)) : _eSignHelper.GetLocalTime(DateTime.Now, userTimezone);
            }
            var penColor = Color.FromArgb(255, 0, 0);
            var stampTextColor = Color.FromName(Color.Black.Name);
            var stampFont = "Arial";
            var stampFontSize = 16;
            var stampTextHeightPadding = 4;
            var stampLeftPadding = 4;
            var stampIndentWidth = 16;
            var stampTextSpacingFromIndent = 4;
            var applicationNameStamp = Convert.ToString(_appConfiguration["electronicStamp"]);
            var authText = electronicSignIndicationId == 2 ? Convert.ToString(_appConfiguration["electronicStampauthText"]) : "";
            var messageIdStampLength = 20;
            var stampDpi = 96;
            var stampXDpi = isHandDrawn ? 120 : 96;
            var imageDrawnYAxis = 10;

            //Get Signature stamp font and stamp properties
            var font = new Font(stampFont, stampFontSize, FontStyle.Bold);
            var stampTextHeight = stampTextHeightPadding + font.Height;

            //dummy bitmap to get graphics object
            Bitmap bitmap = new Bitmap(1, 1);
            //dummy bitmap to get graphics object
            Graphics objGraphics = Graphics.FromImage(bitmap);

            // This is where the bitmap size is determined.
            var calculatedHeight = (int)objGraphics.MeasureString(electronicSignIndicationId == 3 ? applicationNameStamp : authText + stampCode, font).Height;
            if (!isHandDrawn)
            {
                width = (int)objGraphics.MeasureString(electronicSignIndicationId == 3 ? applicationNameStamp : authText + stampCode, font).Width;
                if (width < signatureImage.Width)
                    width = signatureImage.Width;
                height = height + calculatedHeight;
            }
            else
            {
                height = height + calculatedHeight * 2;
                imageDrawnYAxis = 30;
            }

            bitmap = new Bitmap(width, height, System.Drawing.Imaging.PixelFormat.Format32bppArgb);
            bitmap.SetResolution(stampXDpi, stampDpi);

            using (Graphics g = Graphics.FromImage(bitmap))
            {
                var graphicSize = g.MeasureString(applicationNameStamp, font);

                g.InterpolationMode = InterpolationMode.HighQualityBicubic;
                g.SmoothingMode = SmoothingMode.HighQuality;
                g.CompositingQuality = CompositingQuality.HighQuality;
                g.PixelOffsetMode = PixelOffsetMode.HighQuality;
                g.TextRenderingHint = TextRenderingHint.AntiAliasGridFit;

                using (Pen pen = new Pen(penColor))
                using (Brush brush = new SolidBrush(stampTextColor))
                {
                    g.Clear(Color.Transparent);

                    //draw top line
                    g.DrawLine(pen, stampLeftPadding, 0 + font.Height / 2, stampIndentWidth, 0 + font.Height / 2);

                    //draw vertical line
                    g.DrawLine(pen, stampLeftPadding, 0 + font.Height / 2, stampLeftPadding, height - stampTextHeight / 2);

                    //draw bottom line
                    g.DrawLine(pen, stampLeftPadding, height - stampTextHeight / 2, stampIndentWidth, height - stampTextHeight / 2);

                    //draw top text
                    g.DrawString(applicationNameStamp, font, brush, stampIndentWidth + stampTextSpacingFromIndent, 0);

                    //draw bottom text
                    //g.DrawString(authText + stampCode.Substring(0, messageIdStampLength) + "...", font, brush, stampIndentWidth + stampTextSpacingFromIndent, height-font.Height);
                    g.DrawString(authText + (stampCode.Length > messageIdStampLength ? stampCode.Substring(0, messageIdStampLength) + "..." : stampCode), font, brush, stampIndentWidth + stampTextSpacingFromIndent, height - font.Height);

                    g.Flush();
                }
            }

            bitmap.MakeTransparent(Color.Transparent);

            //Generate Signature with Stamp
            var imageWithStamp = new Bitmap(width, height, System.Drawing.Imaging.PixelFormat.Format32bppArgb);
            using (var graphicWithStamp = Graphics.FromImage(imageWithStamp))
            {
                graphicWithStamp.Clear(Color.Transparent);
                graphicWithStamp.CompositingMode = CompositingMode.SourceOver; // this is the default, but just to be clear

                graphicWithStamp.DrawImage(bitmap, 0, 0);
                graphicWithStamp.DrawImage(signatureImage, 10, imageDrawnYAxis);

                graphicWithStamp.Save();
            }

            imageWithStamp = ResizeImage(imageWithStamp, width, signatureImage.Height);  //Resize Image as per the original height after generating stamp

            objGraphics.Flush();

            loggerModelNew.Message = "Process completed for Generate Stamp";
            rsignlog.RSignLogInfo(loggerModelNew);
            return imageWithStamp;
        }
        public static Bitmap ResizeImage(System.Drawing.Image imgPhoto, int newWidth, int newHeight)
        {
            LoggerModelNew loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "ResizeImage", "Process started for Resize Image", "", "", "", "", "API");
            RSignLogger rsignlog = new RSignLogger();
            rsignlog.RSignLogInfo(loggerModelNew);

            int sourceWidth = imgPhoto.Width;
            int sourceHeight = imgPhoto.Height;

            //Consider vertical pics
            if (sourceWidth < sourceHeight)
            {
                int buff = newWidth;

                newWidth = newHeight;
                newHeight = buff;
            }

            int sourceX = 0, sourceY = 0, destX = 0, destY = 0;
            float nPercent = 0, nPercentW = 0, nPercentH = 0;

            nPercentW = ((float)newWidth / (float)sourceWidth);
            nPercentH = ((float)newHeight / (float)sourceHeight);
            if (nPercentH < nPercentW)
            {
                nPercent = nPercentH;
                destX = System.Convert.ToInt16((newWidth - (sourceWidth * nPercent)) / 2);
            }
            else
            {
                nPercent = nPercentW;
                destY = System.Convert.ToInt16((newHeight - (sourceHeight * nPercent)) / 2);
            }

            int destWidth = (int)(sourceWidth * nPercent);
            int destHeight = (int)(sourceHeight * nPercent);


            Bitmap bmPhoto = new Bitmap(newWidth, newHeight, System.Drawing.Imaging.PixelFormat.Format32bppArgb);

            bmPhoto.SetResolution(imgPhoto.HorizontalResolution, imgPhoto.VerticalResolution);

            Graphics grPhoto = Graphics.FromImage(bmPhoto);
            grPhoto.Clear(Color.Transparent);
            grPhoto.InterpolationMode = System.Drawing.Drawing2D.InterpolationMode.HighQualityBicubic;
            destX = 0;
            grPhoto.DrawImage(imgPhoto, new Rectangle(destX, destY, destWidth, destHeight), new Rectangle(sourceX, sourceY, sourceWidth, sourceHeight), GraphicsUnit.Pixel);
            grPhoto.Dispose();
            imgPhoto.Dispose();
            loggerModelNew.Message = "Process completed for Resize Image";
            rsignlog.RSignLogInfo(loggerModelNew);
            return bmPhoto;
        }
        public string ConvertSignImageWithStamp(string base64string, out int intHeight, out int intWidth, string envelopeCodeStamp = "", int electronicSignIndicationId = 1, string dateFormat = "", string timeZoneSetting = "", string dateFormatID = "E3DAD8D9-E16F-40F5-B112-BBA204538136", string tempSignatureTypeID = "00000000-0000-0000-0000-000000000000") //default dateformat: US MM/dd/YY
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "ConvertSignImageWithStamp", "Process started for Convert Sign Image With Stamp", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            base64string = System.Text.RegularExpressions.Regex.Replace(base64string, @"^data:image\/[a-zA-Z]+;base64,", string.Empty);
            if (new Guid(tempSignatureTypeID) == Constants.SignatureType.UploadSignature)
            {
                Bitmap signatureImage;
                var bytes = Convert.FromBase64String(base64string);
                MemoryStream newStream = new MemoryStream();
                using (var ms = new MemoryStream(bytes))
                {
                    signatureImage = new Bitmap(ms);
                }
                var stampImage = GenerateSignatureStamp(envelopeCodeStamp, signatureImage, true, electronicSignIndicationId, dateFormat, timeZoneSetting, dateFormatID);
                intWidth = stampImage.Width;
                intHeight = stampImage.Height;
                string imageSrc = _eSignHelper.ImageToBase64(stampImage);
                imageSrc = "data:image/png;base64," + imageSrc;
                loggerModelNew.Message = "Process completed for Convert Sign Image With Stamp";
                rsignlog.RSignLogInfo(loggerModelNew);
                return imageSrc;
            }
            else
            {
                Bitmap signatureImage;
                var bytes = Convert.FromBase64String(base64string);
                MemoryStream newStream = new MemoryStream();
                using (var ms = new MemoryStream(bytes))
                {
                    signatureImage = new Bitmap(ms);
                }

                var stampImage = GenerateStamp(envelopeCodeStamp, signatureImage, false, electronicSignIndicationId, dateFormat, timeZoneSetting, dateFormatID);
                intWidth = stampImage.Width;
                intHeight = stampImage.Height;
                string imageSrc = _eSignHelper.ImageToBase64(stampImage);
                imageSrc = "data:image/png;base64," + imageSrc;
                loggerModelNew.Message = "Process completed for Convert Sign Image With Stamp";
                rsignlog.RSignLogInfo(loggerModelNew);
                return imageSrc;
            }

        }
        public System.Drawing.Image GenerateSignatureStamp(string stampCode, System.Drawing.Image signatureImage = null, bool isHandDrawn = false, int electronicSignIndicationId = 1, string dateFormat = "", string userTimezone = "", string dateFormatID = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GenerateSignatureStamp", "Process started for Generate Signature Stamp", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            int width = 528;
            int height = 113;

            if (!string.IsNullOrEmpty(dateFormat))
                dateFormat = dateFormat.Replace("mm", "MM");

            //stampCode = electronicSignIndicationId == 3 ? (!string.IsNullOrEmpty(dateFormat)? DateTime.Now.ToString(dateFormat + " hh:mm:tt") : DateTime.Now.ToString("dd/MM/yyyy hh:mm:tt")) : stampCode;
            if (electronicSignIndicationId == 3)
            {
                stampCode = !string.IsNullOrEmpty(dateFormatID) ? _eSignHelper.GetLocalTime(DateTime.Now, userTimezone, new Guid(dateFormatID)) : _eSignHelper.GetLocalTime(DateTime.Now, userTimezone);
            }
            var penColor = Color.FromArgb(255, 0, 0);
            var stampTextColor = Color.FromName(Color.Black.Name);
            var stampFont = "Arial";
            var stampFontSize = 16;
            var stampTextHeightPadding = 4;
            var stampLeftPadding = 4;
            var stampIndentWidth = 16;
            var stampTextSpacingFromIndent = 4;
            var applicationNameStamp = Convert.ToString(_appConfiguration["electronicStamp"]);
            var authText = electronicSignIndicationId == 2 ? Convert.ToString(_appConfiguration["electronicStampauthText"]) : "";
            var messageIdStampLength = 20;
            var stampDpi = 96;
            var stampXDpi = isHandDrawn ? 120 : 96;
            var imageDrawnYAxis = 10;

            //Get Signature stamp font and stamp properties
            var font = new Font(stampFont, stampFontSize, FontStyle.Bold);
            var stampTextHeight = stampTextHeightPadding + font.Height;

            //dummy bitmap to get graphics object
            Bitmap bitmap = new Bitmap(width, height);
            //dummy bitmap to get graphics object
            Graphics objGraphics = Graphics.FromImage(bitmap);

            // This is where the bitmap size is determined.
            var calculatedHeight = (int)objGraphics.MeasureString(electronicSignIndicationId == 3 ? applicationNameStamp : authText + stampCode, font).Height;
            if (!isHandDrawn)
            {
                width = (int)objGraphics.MeasureString(electronicSignIndicationId == 3 ? applicationNameStamp : authText + stampCode, font).Width;
                if (width < signatureImage.Width)
                    width = signatureImage.Width;
                height = height + calculatedHeight;
            }
            else
            {
                height = height + calculatedHeight * 2;
                imageDrawnYAxis = 30;
            }

            bitmap = new Bitmap(width, height, System.Drawing.Imaging.PixelFormat.Format32bppArgb);
            bitmap.SetResolution(stampXDpi, stampDpi);
            if (electronicSignIndicationId > 1)
            {
                using (Graphics g = Graphics.FromImage(bitmap))
                {
                    var graphicSize = g.MeasureString(applicationNameStamp, font);

                    g.InterpolationMode = InterpolationMode.HighQualityBicubic;
                    g.SmoothingMode = SmoothingMode.HighQuality;
                    g.CompositingQuality = CompositingQuality.HighQuality;
                    g.PixelOffsetMode = PixelOffsetMode.HighQuality;
                    g.TextRenderingHint = TextRenderingHint.AntiAliasGridFit;

                    using (Pen pen = new Pen(penColor))
                    using (Brush brush = new SolidBrush(stampTextColor))
                    {
                        g.Clear(Color.Transparent);

                        //draw top line
                        g.DrawLine(pen, stampLeftPadding, 0 + font.Height / 2, stampIndentWidth, 0 + font.Height / 2);

                        //draw vertical line
                        g.DrawLine(pen, stampLeftPadding, 0 + font.Height / 2, stampLeftPadding, height - stampTextHeight / 2);

                        //draw bottom line
                        g.DrawLine(pen, stampLeftPadding, height - stampTextHeight / 2, stampIndentWidth, height - stampTextHeight / 2);

                        //draw top text
                        g.DrawString(applicationNameStamp, font, brush, stampIndentWidth + stampTextSpacingFromIndent, 0);

                        //draw bottom text
                        //g.DrawString(authText + stampCode.Substring(0, messageIdStampLength) + "...", font, brush, stampIndentWidth + stampTextSpacingFromIndent, height-font.Height);
                        g.DrawString(authText + (stampCode.Length > messageIdStampLength ? stampCode.Substring(0, messageIdStampLength) + "..." : stampCode), font, brush, stampIndentWidth + stampTextSpacingFromIndent, height - font.Height);

                        g.Flush();
                    }
                }
            }
            bitmap.MakeTransparent(Color.Transparent);

            //Generate Signature with Stamp
            var imageWithStamp = new Bitmap(width, height, System.Drawing.Imaging.PixelFormat.Format32bppArgb);
            using (var graphicWithStamp = Graphics.FromImage(imageWithStamp))
            {
                graphicWithStamp.Clear(Color.Transparent);
                graphicWithStamp.CompositingMode = CompositingMode.SourceOver; // this is the default, but just to be clear

                graphicWithStamp.DrawImage(bitmap, 0, 0);
                graphicWithStamp.DrawImage(signatureImage, 10, imageDrawnYAxis);

                graphicWithStamp.Save();
            }

            imageWithStamp = ResizeImage(imageWithStamp, width, 113);  //Resize Image as per the original height after generating stamp

            objGraphics.Flush();
            loggerModelNew.Message = "Process completed for Generate Signature Stam";
            rsignlog.RSignLogInfo(loggerModelNew);
            return imageWithStamp;
        }
