        #region EmailBannerSettings       
        public string EmailBannerSettings(string mailTemlate, AdminGeneralAndSystemSettings allSettingsDetails, string MailTemplateType)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "EmailBannerSettings", "Processing Email Banner Settings", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            if (allSettingsDetails != null && allSettingsDetails.ShowCompanyLogo == true && !string.IsNullOrEmpty(allSettingsDetails.CompanyLogoImage))
            {
                string companyLogoURL = Convert.ToString(_appConfiguration["CompanyLogoDirectory"]) + allSettingsDetails.CompanyLogoImage;
                if (File.Exists(companyLogoURL))
                {
                    using (System.Drawing.Image img = System.Drawing.Image.FromFile(companyLogoURL))
                    {
                        int imgWidth = img.Width;
                        int imgHeight = img.Height;
                        int maxWidth = 200;
                        int maxHeight = 50;
                        string LogoDims = string.Empty;

                        if (img.Width <= maxWidth && img.Height <= maxHeight)
                        {
                            LogoDims = string.Format("height={0} width={1}", imgHeight, imgWidth);
                        }
                        else if (img.Width > maxWidth && img.Height <= maxHeight)
                        {
                            LogoDims = string.Format("height={0} width={1}", imgHeight, maxWidth);
                        }
                        else if (img.Width <= maxWidth && img.Height > maxHeight)
                        {
                            LogoDims = string.Format("height={1} width={0}", imgWidth, maxHeight);
                        }
                        else { LogoDims = string.Format("height={0} width={1}", maxHeight, maxWidth); }

                        mailTemlate = mailTemlate.Replace("#CompanyLogoDims", LogoDims);
                    }

                    string ext = Path.GetExtension(allSettingsDetails.CompanyLogoImage).ToLower().Replace(".", string.Empty);
                    mailTemlate = mailTemlate.Replace("#CompanyLogo", (string.Format("data:image/{0};base64,{1}", ext, Convert.ToBase64String(File.ReadAllBytes(companyLogoURL)))));
                }
                else
                {
                    mailTemlate = new Regex("<td id=\"tdBannerRight\".+?</td>", RegexOptions.Singleline).Replace(mailTemlate.ToString(), "");
                }
            }
            else
            {
                mailTemlate = new Regex("<td id=\"tdBannerRight\".+?</td>", RegexOptions.Singleline).Replace(mailTemlate.ToString(), "");
            }

            if (allSettingsDetails != null && allSettingsDetails.ShowRSignLogo)
            {
                string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RSign-Email.png");
                mailTemlate = mailTemlate.Replace("#ImageURL", imageLogoURl);
            }
            else
            {
                mailTemlate = new Regex("<td id=\"tdBannerLeft\".+?</td>", RegexOptions.Singleline).Replace(mailTemlate.ToString(), "");
            }

            mailTemlate = mailTemlate.Replace("#BgColor", (allSettingsDetails == null) ? Constants.EmailBannerColors.BackgroundColor : string.IsNullOrEmpty(allSettingsDetails.EmailBannerBackgroundColor) ? Constants.EmailBannerColors.BackgroundColor : allSettingsDetails.EmailBannerBackgroundColor);
            mailTemlate = mailTemlate.Replace("#FontColor", (allSettingsDetails == null) ? Constants.EmailBannerColors.FontColor : (string.IsNullOrEmpty(allSettingsDetails.EmailBannerFontColor)) ? Constants.EmailBannerColors.FontColor : allSettingsDetails.EmailBannerFontColor);
            return mailTemlate;
        }
