        #region GetSigningURL
        public bool IsGenerateNewSigningUrl(string emailId)
        {
            LoggerModelNew loggerModelNew = new LoggerModelNew(emailId, "EnvelopeHelperMain", "IsGenerateNewSigningUrl", "Process started for checking to provide new signer's ui or not ", "", "", "", "", "API");
            RSignLogger rsignlog = new RSignLogger();
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                if (!string.IsNullOrEmpty(emailId))
                {
                    SqlConnection connection = new SqlConnection(Convert.ToString(_configuration.Value.ConnectionStrings.RSignContext));
                    DataSet dataset = new DataSet();
                    SqlDataAdapter adapter = new SqlDataAdapter();
                    adapter.SelectCommand = new SqlCommand("Usp_GetSignersUIUserDeatils", connection);
                    adapter.SelectCommand.CommandType = CommandType.StoredProcedure;
                    adapter.SelectCommand.Parameters.AddWithValue("@UserEmail", emailId);
                    adapter.Fill(dataset);
                    List<SignersUIModel> lstSignersUIModel = new List<SignersUIModel>();
                    if (dataset != null && dataset.Tables.Count > 0)
                    {
                        lstSignersUIModel = JsonConvert.DeserializeObject<List<SignersUIModel>>(JsonConvert.SerializeObject(dataset.Tables[0]));
                        if (lstSignersUIModel != null && lstSignersUIModel.Count > 0)
                        {
                            return true;
                        }
                        else
                        {
                            return false;
                        }
                    }
                    else
                    {
                        return false;
                    }
                }
                else
                {
                    return false;
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.ToString();
                rsignlog.RSignLogError(loggerModelNew, ex);
                return false;
            }
        }
        public string getSigningURL(string senderEmailAddress, string templateKey, string envelopeID, string recID, string recEmail, string copyEmail = "", bool IsSignerIdentity = false)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "getSigningURL", "Process started for getting Signing URL", envelopeID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            // encrypt querystring
            copyEmail = string.IsNullOrEmpty(copyEmail) ? string.Empty : "&SignerType=Copy&CopyMailId=" + copyEmail;
            string strURLWithData = "";

            if (Convert.ToBoolean(IsSignerIdentity))
            {
                if (IsGenerateNewSigningUrl(senderEmailAddress))
                {
                    strURLWithData = Convert.ToString(_appConfiguration["NewSigningURL"]) + "authenticate-signer?";
                }
                else
                {
                    strURLWithData = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/AuthenticateSigner?";
                }
            }
            else
            {
                if (IsGenerateNewSigningUrl(senderEmailAddress))
                {
                    strURLWithData = Convert.ToString(_appConfiguration["NewSigningURL"]) + "/signer-landing?";
                }
                else
                {
                    strURLWithData = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/Index?";
                }
            }

            if (!string.IsNullOrEmpty(templateKey))
                return strURLWithData = strURLWithData + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&RecipientId={1}&TemplateKey={2}&EmailId={3}{4}", envelopeID, recID, templateKey, HttpUtility.UrlEncode(recEmail), HttpUtility.UrlEncode(copyEmail))));
            else
                return strURLWithData = strURLWithData + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&RecipientId={1}&EmailId={2}{3}", envelopeID, recID, HttpUtility.UrlEncode(recEmail), HttpUtility.UrlEncode(copyEmail))));
        }
        #endregion GetSigningURL

        #region EmailQueueFunction   
        public void EmailQueueFunction(EmailQueueProcessor.EmailQueueData emailQueueData, Boolean ForcefullyEmailqueueentry = false, EmailQueueProcessor.EmailQueueAttachmentData emailQueueAttachmentData = null)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "EmailQueueFunction", "Processing Email Queue Function", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            int emailRunningProcessCount = 1;
            Recipients senderDetails = new Recipients();
            int EmailQueueID = 0;
            try
            {
                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    Boolean IsAttachment = false;
                    var EmailQueueList = _emailQueueProcessor.GetEmailQueueData(emailQueueData.envelope.ID, emailQueueData.EmailType);
                    senderDetails = emailQueueData.envelope.Recipients.FirstOrDefault(r => r.RecipientTypeID == Constants.RecipientType.Sender);
                    emailQueueData.IsAttachment = IsAttachment;
                    emailQueueData.SenderName = senderDetails.Name;
                    emailQueueData.SenderEmailAddress = senderDetails.EmailAddress;
                    //SendEmailFromService
                    if (EmailQueueList.Count == 0 || ForcefullyEmailqueueentry == true || Convert.ToBoolean(emailQueueData.envelope.IsEdited) == true)
                    {
                        //Create or update data in Emailqueue
                        EmailQueueID = _emailQueueProcessor.CreateUpdateEmailQueue(emailQueueData);
                    }
                    else
                    {
                        EmailQueueID = EmailQueueList[0].ID;
                    }

                    if (emailQueueData.emailSendInfo != null && !string.IsNullOrEmpty(emailQueueData.emailSendInfo.RecipientEmail))
                    {
                        emailRunningProcessCount = 2;
                        EmailQueueProcessor.EmailQueueRecipientsData emailQueueRecipientsData = new EmailQueueProcessor.EmailQueueRecipientsData();
                        emailQueueRecipientsData.emailQueueData = emailQueueData;
                        emailQueueRecipientsData.EmailQueueID = EmailQueueID;
                        emailQueueRecipientsData.RecipientName = emailQueueData.emailSendInfo.RecipientName;
                        emailQueueRecipientsData.RecipientEmail = emailQueueData.emailSendInfo.RecipientEmail;
                        emailQueueRecipientsData.RecipientMobile = emailQueueData.emailSendInfo.RecipientMobile;
                        //New entry in EmailQueueRecipients per emailqueue and recipient.
                        Boolean SuccessEmailQueueRecipients = _emailQueueProcessor.CreateUpdateEmailQueueRecipients(emailQueueRecipientsData);
                        if (!string.IsNullOrEmpty(emailQueueRecipientsData.RecipientEmail) && !SuccessEmailQueueRecipients)
                        {
                            SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
                        }
                        else if (!string.IsNullOrEmpty(emailQueueRecipientsData.RecipientMobile) && !SuccessEmailQueueRecipients)
                        {
                            SendMobileSMS(emailQueueData.envelope, emailQueueData.MailMessageBody, emailQueueRecipientsData.RecipientMobile);
                        }

                    }
                    else if (emailQueueData.Signer == null)
                    {
                        emailRunningProcessCount = 2;
                        EmailQueueProcessor.EmailQueueRecipientsData emailQueueRecipientsData = new EmailQueueProcessor.EmailQueueRecipientsData();
                        emailQueueRecipientsData.emailQueueData = emailQueueData;
                        emailQueueRecipientsData.EmailQueueID = EmailQueueID;
                        emailQueueRecipientsData.RecipientName = emailQueueData.SanboxSigner == null ? emailQueueData.SenderName : emailQueueData.SanboxSigner.RecipientName;
                        emailQueueRecipientsData.RecipientEmail = emailQueueData.SanboxSigner == null ? emailQueueData.SenderEmailAddress : emailQueueData.SanboxSigner.RecipientEmail;
                        emailQueueRecipientsData.RecipientMobile = emailQueueData.SanboxSigner.RecipientMobile;

                        //New entry in EmailQueueRecipients per emailqueue and recipient.
                        Boolean SuccessEmailQueueRecipients = _emailQueueProcessor.CreateUpdateEmailQueueRecipients(emailQueueRecipientsData);
                        if (string.IsNullOrEmpty(emailQueueRecipientsData.RecipientMobile) && !SuccessEmailQueueRecipients)
                        {
                            SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
                        }
                        else if (!string.IsNullOrEmpty(emailQueueRecipientsData.RecipientMobile) && !SuccessEmailQueueRecipients)
                        {
                            SendMobileSMS(emailQueueData.envelope, emailQueueData.MailMessageBody, emailQueueRecipientsData.RecipientMobile);
                        }
                    }

                    if (emailQueueAttachmentData != null && EmailQueueID != 0)
                    {
                        emailRunningProcessCount = 3;
                        Boolean SuccessEmailQueueRecipients = _emailQueueProcessor.CreateEmailQueueAttachment(emailQueueAttachmentData, EmailQueueID);
                        if (!SuccessEmailQueueRecipients)
                        {
                            SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EmailQueueFunction method for the EmailQueueID:" + EmailQueueID;
                rsignlog.RSignLogError(loggerModelNew, ex);
                SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
            }
        }
        public void EmailQueueTemplateFunction(EmailQueueProcessor.EmailQueueData emailQueueData, Boolean ForcefullyEmailqueueentry = false, EmailQueueProcessor.EmailQueueAttachmentData emailQueueAttachmentData = null)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "EmailQueueTemplateFunction", "Processing Email Template Queue Function", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            int emailRunningProcessCount = 1;
            Recipients senderDetails = new Recipients();
            int EmailQueueID = 0;
            try
            {
                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    bool IsAttachment = false;
                    var EmailQueueList = _emailQueueProcessor.GetEmailQueueData(emailQueueData.template.ID, emailQueueData.EmailType);
                    //senderDetails = emailQueueData.envelope.Recipients.FirstOrDefault(r => r.RecipientTypeID == Constants.RecipientType.Sender);
                    emailQueueData.IsAttachment = IsAttachment;
                    emailQueueData.SenderName = emailQueueData.Signer.Name;
                    emailQueueData.SenderEmailAddress = emailQueueData.Signer.EmailAddress;
                    //SendEmailFromService
                    if (EmailQueueList.Count == 0 || ForcefullyEmailqueueentry == true)
                    {
                        //Create or update data in Emailqueue
                        EmailQueueID = _emailQueueProcessor.CreateUpdateTemplateEmailQueue(emailQueueData);
                    }
                    else
                    {
                        EmailQueueID = EmailQueueList[0].ID;
                    }

                    if (emailQueueData.emailSendInfo != null && !string.IsNullOrEmpty(emailQueueData.emailSendInfo.RecipientEmail))
                    {
                        emailRunningProcessCount = 2;
                        EmailQueueProcessor.EmailQueueRecipientsData emailQueueRecipientsData = new EmailQueueProcessor.EmailQueueRecipientsData();
                        emailQueueRecipientsData.emailQueueData = emailQueueData;
                        emailQueueRecipientsData.EmailQueueID = EmailQueueID;
                        emailQueueRecipientsData.RecipientName = emailQueueData.emailSendInfo.RecipientName;
                        if (!string.IsNullOrEmpty(emailQueueData.emailSendInfo.RecipientEmail) && !string.IsNullOrEmpty(emailQueueData.emailSendInfo.RecipientMobile))
                        {
                            emailQueueRecipientsData.RecipientEmail = emailQueueData.emailSendInfo.RecipientEmail;
                            emailQueueRecipientsData.RecipientMobile = emailQueueData.emailSendInfo.RecipientMobile;
                        }
                        else if (!string.IsNullOrEmpty(emailQueueData.emailSendInfo.RecipientEmail))
                        {
                            emailQueueRecipientsData.RecipientEmail = emailQueueData.emailSendInfo.RecipientEmail;
                        }
                        else if (!string.IsNullOrEmpty(emailQueueData.emailSendInfo.RecipientMobile))
                        {
                            emailQueueRecipientsData.RecipientEmail = "";
                            emailQueueRecipientsData.RecipientMobile = emailQueueData.emailSendInfo.RecipientMobile;
                        }
                        //New entry in EmailQueueRecipients per emailqueue and recipient.
                        Boolean SuccessEmailQueueRecipients = _emailQueueProcessor.CreateUpdateEmailQueueTemplateRecipients(emailQueueRecipientsData);
                        if (!SuccessEmailQueueRecipients)
                        {
                            SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
                        }

                    }
                    else if (emailQueueData.Signer == null)
                    {
                        emailRunningProcessCount = 2;
                        EmailQueueProcessor.EmailQueueRecipientsData emailQueueRecipientsData = new EmailQueueProcessor.EmailQueueRecipientsData();
                        emailQueueRecipientsData.emailQueueData = emailQueueData;
                        emailQueueRecipientsData.EmailQueueID = EmailQueueID;
                        emailQueueRecipientsData.RecipientName = emailQueueData.SanboxSigner == null ? emailQueueData.SenderName : emailQueueData.SanboxSigner.RecipientName;
                        emailQueueRecipientsData.RecipientEmail = emailQueueData.SanboxSigner == null ? emailQueueData.SenderEmailAddress : emailQueueData.SanboxSigner.RecipientEmail;
                        //New entry in EmailQueueRecipients per emailqueue and recipient.
                        Boolean SuccessEmailQueueRecipients = _emailQueueProcessor.CreateUpdateEmailQueueTemplateRecipients(emailQueueRecipientsData);
                        if (!SuccessEmailQueueRecipients)
                        {
                            SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
                        }
                    }
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EmailQueueTemplateFunction method for the EmailQueueID:" + EmailQueueID;
                rsignlog.RSignLogError(loggerModelNew, ex);
                SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
            }
        }
        #endregion EmailQueueFunction

        #region Get Document Controls  
        private List<DocumentControls> GetDocumentControls(Envelope envelopeObject, Guid recipientId)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GetDocumentControls", "Initiate the process for getting document controls", envelopeObject.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            var documentContentsData = (from doc in envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).SelectMany(d => d.DocumentContents)
                                        where doc.RecipientID == recipientId && doc.IsControlDeleted == false
                                        select doc).ToList();
            using (var dbContext = new RSignDbContext(_configuration))
            {
                foreach (var item in envelopeObject.Recipients)
                {
                    item.SignerStatus = dbContext.SignerStatus.Where(r => r.RecipientID == item.ID).ToList();
                }
            }

            var signedContentsData = (from recp in envelopeObject.Recipients
                                      join doc in envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).SelectMany(d => d.DocumentContents) on recp.ID equals doc.RecipientID
                                      where (recp.SignerStatus.OrderByDescending(s => s.CreatedDateTime).Select(s => s.StatusID).FirstOrDefault() == Constants.StatusCode.Signer.Signed) && doc.IsControlDeleted == false && doc.ControlValue != null
                                      select doc).ToList();
            if (signedContentsData.Any())
                documentContentsData.AddRange(signedContentsData);

            var labelControls = envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).SelectMany(dc => dc.DocumentContents).Where(dc => dc.RecipientID == null && dc.IsControlDeleted == false).ToList();
            if (labelControls.Any())
                documentContentsData.AddRange(labelControls);

            //Get dependency controls
            using (var dbContext = new RSignDbContext(_configuration))
            {
                var conditionalList = dbContext.ConditionalControlMapping.Where(e => e.EnvelopeId == envelopeObject.ID && e.ParentId != null && e.RuleId != null)
                              .Select(e => e.DocumentControlId).ToList();

                //Filter the dependency controls whose ControlValue is null or empty
                conditionalList = (from c in conditionalList
                                   join doc in envelopeObject.Documents.SelectMany(d => d.DocumentContents) on c equals doc.ID

                                   where string.IsNullOrEmpty(doc.ControlValue)
                                   select c).ToList();

                //Get Final controls which are not in above filtered conditionalList
                documentContentsData = (from doc in documentContentsData
                                        where !conditionalList.Contains(doc.ID)
                                        select doc).ToList();

                var fonts = _lookupRepository.GetLookup(Lookup.Fonts).ToList();

                var controls = documentContentsData.Select(control => new DocumentControls
                {
                    DocumentName = control.Documents.DocumentName,
                    ControlHhtmlId = control.ControlHtmlID,
                    XLeftposition = control.XCoordinate.GetValueOrDefault(),
                    YTopPosition = control.YCoordinate.GetValueOrDefault(),
                    ZBottompostion = control.ZCoordinate.GetValueOrDefault(),
                    PageNo = control.PageNo.GetValueOrDefault(),
                    DocumentPageNo = control.DocumentPageNo.GetValueOrDefault(),
                    Label = control.Label,
                    Required = control.Required,
                    ControlValue = (control.ControlID == Constants.Control.DropDown) ?
                    !string.IsNullOrEmpty(control.ControlValue) ? control.SelectControlOptions.Where(d => d.ID == Guid.Parse(control.ControlValue)).Select(d => d.OptionText).FirstOrDefault() : control.ControlValue : control.ControlValue,
                    ImageBytes =
                        (control.ControlID == Constants.Control.Checkbox || control.ControlID == Constants.Control.Radio || control.ControlID == Constants.Control.Signature || control.ControlID == Constants.Control.NewInitials)
                            ? _apiHelper.GetControlImage(control) : null,
                    ControlName = GetControlName(control.ControlID),
                    ControlType = GetControlType(control.ControlType),
                    Height = control.Height.GetValueOrDefault(),
                    Width = control.Width.GetValueOrDefault(),
                    UserControlStyle = control.ControlStyle == null ? null : new UserControlStyle
                    {
                        FontColor = control.ControlStyle.FontColor,
                        FontName = fonts.Where(f => f.Key == control.ControlStyle.FontID.ToString()).Select(f => f.Value).FirstOrDefault(),
                        FontSize = control.ControlStyle.FontSize,
                        IsBold = control.ControlStyle.IsBold,
                        IsItalic = control.ControlStyle.IsItalic,
                        IsUnderline = control.ControlStyle.IsUnderline,
                    },
                    UserSelectControl = control.SelectControlOptions == null ? null : control.SelectControlOptions.Select(options => new UserSelectControl
                    {
                        OptionText = options.OptionText,
                        Order = options.Order
                    }).ToList()
                }).ToList();


                loggerModelNew.Message = "Process completed and successfully retrieved " + controls.Count.ToString() + " document controls for Signer Certificate";
                rsignlog.RSignLogInfo(loggerModelNew);
                return controls;
            }
        }
        private string GetControlName(Guid controlGuid)
        {
            try
            {
                var controls = _lookupRepository.GetLookup(Lookup.Controls);
                var firstOrDefault = controls.FirstOrDefault(cn => Guid.Parse(cn.Key) == controlGuid);
                return (firstOrDefault != null) ? firstOrDefault.Value : string.Empty;
            }
            catch (Exception ex)
            {
                throw;
            }
        }
        public string GetControlType(Guid? controlGuid)
        {
            if (controlGuid == null || controlGuid == Guid.Empty)
                return "Text";
            var controls = _lookupRepository.GetLookup(Lookup.TextType);
            return controls.First(cn => Guid.Parse(cn.Key) == controlGuid).Value;
        }
        public EnvelopeInfo GetDocumentControls(Envelope envelope, EnvelopeInfo controlsInfo, Guid recipientId, Guid envelopeId, string recipientEmailId = "", string envelopeCode = "", List<ConditionalControlMapping> conditionalControlMappings = null, bool checkConditionProp = true)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GetDocumentControls", "Intializing process for Get Document Controls", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            if (controlsInfo.SubEnvelopeId != null && controlsInfo.SubEnvelopeId.Value != Guid.Empty)
                envelope.SubEnvelopeId = controlsInfo.SubEnvelopeId;
            var tempdata = RetriveControlData("1", envelopeId, recipientId, envelope, recipientEmailId, envelopeCode, conditionalControlMappings, checkConditionProp);
            if (tempdata != null)
            {
                var result = (List<ControlsData>)tempdata;
                controlsInfo.ControlsData = new List<ControlsData>();
                controlsInfo.ControlsData = result;
                loggerModelNew.Message = "SuccessFully retrieved " + controlsInfo.ControlsData.Count.ToString() + " controls for recipient";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            return controlsInfo;
        }
        public List<ControlsData> RetriveControlData(string id, Guid envelopeID, Guid currentRecipientID, Envelope envelope, string recipientEmailId = "", string envelopeCode = "", List<ConditionalControlMapping> conditionalControlMappingdata = null, bool checkConditionProp = true)
        {
            List<ControlsData> contentData = new List<ControlsData>();
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    bool isControlIDEmpty = true, isControlStyleNull = true, isMaxlengthCharcters = true;

                    List<string> recipientEmails = envelope.Recipients.Select(s => s.EmailAddress).ToList();
                    List<UserProfile> recipientUserProfilesList = _userRepository.GetUserProfileByEmailIDs(recipientEmails);
                    List<NonRpostUser> nonRpostUsers = _userRepository.GetNonRpostUserList(recipientEmails);

                    var documentContent = GetDocumentContent(envelope, envelopeID, currentRecipientID, recipientEmailId, recipientUserProfilesList, false, nonRpostUsers, false);
                    IEnumerable<LookupItem> controls = null;
                    IEnumerable<LookupItem> controlFonts = null;
                    IEnumerable<LookupItem> controlsMaxCharacters = null;
                    if (documentContent != null && documentContent.Any(d => d.ControlID != Guid.Empty))
                    {
                        isControlIDEmpty = false;
                    }
                    if (documentContent != null && documentContent.Any(d => d.ControlStyle != null))
                    {
                        isControlStyleNull = false;
                    }
                    if (documentContent != null && documentContent.Any(d => d.MaxLength != null))
                    {
                        isMaxlengthCharcters = false;
                    }
                    if (!isControlIDEmpty)
                    {
                        controls = _lookupRepository.GetLookup(Lookup.Controls);
                    }
                    if (!isControlStyleNull)
                    {
                        controlFonts = _lookupRepository.GetLookup(Lookup.Fonts);
                    }
                    if (!isMaxlengthCharcters)
                    {
                        controlsMaxCharacters = _lookupRepository.GetLookup(Lookup.MaxCharacters);
                    }
                    List<ConditionalControlMapping> conditionalControlMappings = new List<ConditionalControlMapping>();
                    if (checkConditionProp)
                    {
                        if (documentContent != null)
                        {
                            conditionalControlMappings = dbContext.ConditionalControlMapping.Where(c => c.EnvelopeId == envelopeID).ToList();
                        }
                    }
                    else
                    {
                        conditionalControlMappings = conditionalControlMappingdata;
                    }

                    contentData = documentContent
                        .Select(
                            dc => new ControlsData
                            {
                                Id = dc.ID,
                                PageNo = envelope.SubEnvelopeId != null && envelope.SubEnvelopeId.Value != Guid.Empty ? dc.TemplatePageNo : dc.PageNo,
                                TabIndex = dc.TabIndex == null ? dc.PageNo : dc.TabIndex,
                                DocPage = envelope.SubEnvelopeId != null && envelope.SubEnvelopeId.Value != Guid.Empty ? dc.TemplateDocumentPageNo : (dc.DocumentPageNo != dc.PageNo ? dc.PageNo : dc.DocumentPageNo),
                                Required = dc.Required,
                                Height = dc.Height,
                                Width = dc.Width,
                                XCoordinate = dc.XCoordinate,
                                YCoordinate = dc.YCoordinate,
                                ZCoordinate = dc.ZCoordinate,
                                Label = dc.Label,
                                Left = dc.Left,
                                Top = dc.Top,
                                DocumentId = dc.DocumentID,
                                RecipientId = dc.RecipientID,
                                ControlHtmlData = dc.ControlHtmlData,
                                ControlHtmlID = dc.ControlID == Guid.Empty ? "FooterSignature" : dc.ControlHtmlID,
                                ControlName = dc.ControlID == Guid.Empty ? "FooterSignature" : GetControlNameById(dc.ControlID, controls),
                                ControlValue = GetControlValue(dc, envelope.Recipients, recipientUserProfilesList),
                                signerName = dc.RecipientName,
                                SenderControlValue = dc.SenderControlValue,
                                IsCurrentRecipient = dc.IsCurrentRecipient,
                                IsSigned = dc.IsSigned,
                                IsReadOnly = dc.IsReadOnly,
                                SignatureScr = dc.SignatureByte == null ? null : (dc.SignatureByte.Length > 0 ? ("data:image/png;base64," + Convert.ToBase64String(dc.SignatureByte)) : null),
                                FontColor = dc.ControlStyle == null ? "" : dc.ControlStyle.FontColor,
                                FontName = dc.ControlStyle == null ? "" : controlFonts.Where(f => f.Key == dc.ControlStyle.FontID.ToString()).Select(f => f.Value).FirstOrDefault(),
                                FontSize = dc.ControlStyle == null ? 14 : dc.ControlStyle.FontSize,
                                FontBold = dc.ControlStyle == null ? "" : dc.ControlStyle.IsBold == false ? "normal" : "bold",
                                FontItalic = dc.ControlStyle == null ? "" : dc.ControlStyle.IsItalic == false ? "normal" : "italic",
                                FontUnderline = dc.ControlStyle == null ? "" : dc.ControlStyle.IsUnderline == false ? "none" : "underline",
                                AdditionalValidationName = dc.ControlStyle == null ? "" : dc.ControlStyle.AdditionalValidationName,
                                AdditionalValidationOption = dc.ControlStyle == null ? "" : dc.ControlStyle.AdditionalValidationOption,
                                SignatureText = dc.SignatureString,
                                SignatureFont = dc.SignatureFont,
                                SignatureType = dc.SignatureType,
                                GroupName = dc.GroupName,
                                ControlOptions = dc.ControlOptions == null ? (dc.SelectControlOptions == null ? null : dc.SelectControlOptions.OrderBy(y => y.Order).Select(x => new SelectControlOptions { Order = x.Order, OptionText = x.OptionText, ID = x.ID }).ToList())
                                                : dc.ControlOptions.OrderBy(y => y.Order).Select(x => new SelectControlOptions { Order = x.Order, OptionText = x.OptionText, ID = x.ID }).ToList(),
                                MaxLength = dc.MaxLength == null ? "50" : controlsMaxCharacters.Where(f => f.Key == dc.MaxLength.ToString()).Select(f => f.Value).FirstOrDefault(),//dc.MaxLength.ToString(),
                                ControlType = dc.ControlType.ToString().ToUpper(),
                                ConditionDetails = _conditionalControlRepository.GetAllConditionalControl(Constants.String.RSignStage.SignEnvelope, envelopeID, dc.ID, null, conditionalControlMappings, false),
                                IsSignatureFromDocumentContent = (dc.SignatureControlValue != null) ? true : false,
                                IsDefaultRequired = dc.IsDefaultRequired == null ? false : dc.IsDefaultRequired,
                                CustomToolTip = dc.CustomToolTip,
                                FontTypeMeasurement = dc.FontTypeMeasurement == null ? "px" : dc.FontTypeMeasurement,
                                IsFixedWidth = dc.IsFixedWidth == null ? true : Convert.ToBoolean(dc.IsFixedWidth) ? true : false
                            }).OrderBy(x => x.PageNo).ThenBy(x => x.TabIndex).ThenByDescending(x => x.GroupName).ToList();
                }

                return contentData;
            }
            catch (Exception ex)
            {
                loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "RetriveControlData", ex.Message, "", "", "", "", "API");
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }
        }
        private string GetControlValue(DocumentContents dc, ICollection<Recipients> recipients = null, List<UserProfile> userProfilesList = null)
        {
            string controlValue = null;
            bool isPrefill = false;
            Recipients recipientDetail;
            UserProfile userProfile = new UserProfile();

            if (dc.RecipientID != null)
            {
                if (recipients == null)
                {
                    recipientDetail = _recipientRepository.GetEntity(dc.RecipientID.Value);
                }
                else
                {
                    recipientDetail = recipients.Where(r => r.ID == dc.RecipientID.Value).FirstOrDefault();
                }

                if (recipientDetail != null && recipientDetail.RecipientTypeID == Constants.RecipientType.Prefill)
                {
                    isPrefill = true;
                    if (userProfilesList == null || userProfilesList.Count() == 0)
                    {
                        userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);
                    }
                    else
                    {
                        userProfile = userProfilesList.Where(u => u.EmailID.ToLower() == recipientDetail.EmailAddress.ToLower()).FirstOrDefault();
                    }
                }
            }

            if (dc.ControlID == Constants.Control.Name)
            {
                if (dc.IsCurrentRecipient)
                {
                    controlValue = string.IsNullOrEmpty(dc.ControlValue) ? (string.IsNullOrEmpty(dc.RecipientName) ? "" : dc.RecipientName) : dc.ControlValue;
                }
                else
                {
                    controlValue = string.IsNullOrEmpty(dc.ControlValue) ? "" : dc.ControlValue;
                }
                //controlValue = (dc.ControlValue == null && dc.IsCurrentRecipient) ? dc.RecipientName: dc.ControlValue != null ? dc.ControlValue : "";
            }
            else if (dc.ControlID == Constants.Control.Checkbox)
            {
                controlValue = dc.ControlValue != null ? (dc.ControlValue.ToLower() == "true" ? "true" : "false") :
                    dc.SenderControlValue != null ? (dc.SenderControlValue.ToLower() == "true" ? "true" : "false") : null;
                //controlValue = dc.SenderControlValue == "true" ? dc.SenderControlValue : dc.ControlValue != null? dc.ControlValue: null;
            }
            else if (dc.ControlID == Constants.Control.DropDown)
            {
                //if (dc.ControlValue != null)
                if (!string.IsNullOrEmpty(dc.ControlValue) && dc.ControlOptions != null)
                {
                    controlValue = dc.ControlOptions.Where(d => d.ID == Guid.Parse(dc.ControlValue)).Select(d => d.OptionText).FirstOrDefault();
                }
                else
                {
                    controlValue = dc.ControlValue;
                }
            }
            else if (isPrefill && string.IsNullOrEmpty(dc.ControlValue) && dc.ControlID == Constants.Control.Title && userProfile != null && !string.IsNullOrEmpty(userProfile.Title))
            {
                controlValue = userProfile.Title;
            }
            else if (isPrefill && string.IsNullOrEmpty(dc.ControlValue) && dc.ControlID == Constants.Control.Company && userProfile != null && !string.IsNullOrEmpty(userProfile.Company))
            {
                controlValue = userProfile.Company;
            }
            else if (isPrefill && string.IsNullOrEmpty(dc.ControlValue) && dc.ControlID == Constants.Control.Email && userProfile != null && !string.IsNullOrEmpty(userProfile.EmailID))
            {
                controlValue = userProfile.EmailID;
            }
            else if (isPrefill && string.IsNullOrEmpty(dc.ControlValue) && dc.ControlID == Constants.Control.NewInitials && userProfile != null && !string.IsNullOrEmpty(userProfile.Initials))
            {
                controlValue = userProfile.Initials;
            }
            else
            {
                controlValue = dc.ControlValue;
            }
            return controlValue;
        }
        public string GetControlNameById(Guid controlGuid, IEnumerable<LookupItem> controls = null)
        {
            if (controls == null || controls.Count() == 0)
            {
                controls = _lookupRepository.GetLookup(Lookup.Controls);
            }
            //var controls = _lookupRepository.GetLookup(Lookup.Controls);
            return controls.First(cn => Guid.Parse(cn.Key) == controlGuid).Value;
        }
        public List<DocumentContents> GetDocumentContent(Envelope envelope, Guid envelopeID, Guid currentRecipientID, string recipientEmailId = "", List<UserProfile> recipientUserProfilesList = null, bool checkRecipientUserProfile = true, List<NonRpostUser> nonRegisterProfilesList = null, bool checkNonUserProfile = true)
        {
            string envelopeCode = string.Empty;
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    bool IsUnitTestApp = false; // Convert.ToBoolean(SessionHelper.Get(SessionKey.IsUnitTestApp));
                                                // var sessionEnvelope = (Envelope)SessionHelper.Get(SessionKey.Envelope);
                                                //var envelope = envelopeRepository.GetEntity(envelopeID);
                    var tempRecipients = envelope.Recipients;
                    envelopeCode = envelope != null ? envelope.EDisplayCode.ToString() : "";
                    var recipientId = currentRecipientID;
                    var delegatedControls = _documentContentsRepository.GetDelegatedControls(currentRecipientID);
                    var delegatedControlRecipientId = (delegatedControls == null ? Guid.Empty : (delegatedControls.ParentRecipientID == null ? delegatedControls.OriginalRecipientID : delegatedControls.ParentRecipientID));
                    var documentContentList = new List<DocumentContents>();
                    var RecipientOrder = envelope.Recipients.FirstOrDefault(a => a.ID == recipientId).Order;
                    var RecipientSameOrder = envelope.Recipients.Where(a => a.Order == RecipientOrder && a.ID != recipientId).Select(a => a.ID).ToList();
                    string RecipientEmailId = tempRecipients.FirstOrDefault(a => a.ID == recipientId).EmailAddress;
                    List<Guid> SameRecipientIds = tempRecipients.Where(a => a.EmailAddress == RecipientEmailId && a.ID != recipientId && a.IsSameRecipient == true).Select(a => a.ID).ToList();

                    var documentList = envelope.SubEnvelopeId != null && envelope.SubEnvelopeId.Value != Guid.Empty ? envelope.Documents.Where(d => d.EnvelopeTemplateGroupID == envelope.SubEnvelopeId && d.ActionType == Constants.ActionTypes.Sign) : envelope.Documents;
                    foreach (var document in documentList)
                    {
                        // foreach (var documentcontent in document.DocumentContents.OrderBy(dc => dc.PageNo).Where(d => d.IsControlDeleted == false))
                        var documentContentLst = new List<DocumentContents>();
                        documentContentLst = document.DocumentContents.OrderBy(dc => dc.PageNo).Where(d => d.IsControlDeleted == false).ToList();

                        foreach (var documentcontent in documentContentLst)
                        {
                            if ((documentcontent.RecipientID == recipientId || (SameRecipientIds != null && SameRecipientIds.Count > 0 && documentcontent.RecipientID != null && documentcontent.RecipientID != Guid.Empty && SameRecipientIds.Contains(documentcontent.RecipientID.Value)) || (documentcontent.RecipientID == delegatedControlRecipientId && documentcontent.ControlID != Constants.Control.Signature) || !string.IsNullOrEmpty(documentcontent.ControlValue) || documentcontent.RecipientID == null))
                            {
                                var firstOrDefault = envelope.Recipients.FirstOrDefault(x => x.ID == recipientId);
                                if (firstOrDefault != null)
                                    documentcontent.RecipientName = firstOrDefault.Name;

                                documentcontent.IsCurrentRecipient = (documentcontent.RecipientID == recipientId || (documentcontent.RecipientID == delegatedControlRecipientId && documentcontent.ControlID != Constants.Control.Signature) || documentcontent.RecipientID == null);
                                var tRec = tempRecipients.FirstOrDefault(r => r.ID == documentcontent.RecipientID);
                                if (tRec != null)
                                {
                                    var tStat = dbContext.SignerStatus.OrderByDescending(o => o.CreatedDateTime).Where(s => s.RecipientID == tRec.ID).FirstOrDefault();
                                    // var tStat = tRec.SignerStatus.OrderByDescending(o => o.CreatedDateTime).FirstOrDefault();
                                    if (tStat != null)
                                    {
                                        documentcontent.IsSigned = tStat.StatusID == Constants.StatusCode.Signer.Signed;
                                    }
                                    else if (tRec.IsSameRecipient == true && !string.IsNullOrEmpty(documentcontent.ControlValue))
                                    {
                                        documentcontent.IsSigned = true;
                                    }
                                }
                                //documentcontent.IsSigned = 
                                if (documentcontent.RecipientID != null)
                                {
                                    Recipients recipientDetail;
                                    UserProfile userProfile = new UserProfile();
                                    if (IsUnitTestApp) // changes for unit test code
                                    {
                                        recipientDetail = envelope.Recipients.FirstOrDefault(a => a.ID == recipientId);
                                        userProfile = (UserProfile)SessionHelper.Get(SessionKey.User);
                                    }
                                    else
                                    {
                                        // recipientDetail = _recipientRepository.GetEntity(Guid.Parse(documentcontent.RecipientID.Value.ToString()));
                                        // userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);

                                        recipientDetail = envelope.Recipients.FirstOrDefault(a => a.ID == Guid.Parse(documentcontent.RecipientID.Value.ToString()));
                                        if (checkRecipientUserProfile)
                                        {
                                            userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);
                                        }
                                        else if (recipientUserProfilesList != null && recipientDetail != null)
                                        {
                                            userProfile = recipientUserProfilesList.Where(r => r.EmailID.ToLower() == recipientDetail.EmailAddress.ToLower()).FirstOrDefault();
                                        }

                                    }
                                    // for signature
                                    if (documentcontent.ControlID == Constants.Control.Signature && (documentcontent.SignatureByte == null ||
                                        (documentcontent.SignatureByte != null && documentcontent.SignatureByte.Length == 0)))
                                    {
                                        if (documentcontent.SignatureControlValue != null && documentcontent.SignatureControlValue.Length > 0)
                                        {
                                            documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                        }
                                        else if (userProfile != null && userProfile.ID != Guid.Empty)
                                        {
                                            if (userProfile.IsAutoPopulateSignaturewhileSinging)
                                            {
                                                if (userProfile.SignatureImage != null)
                                                    documentcontent.SignatureByte = userProfile.SignatureImage;
                                                else
                                                    documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                                documentcontent.SignatureType = userProfile.SignatureTypeID;
                                                if (userProfile.SignatureTypeID == Constants.SignatureType.Auto)
                                                {
                                                    documentcontent.SignatureString = userProfile.SignatureText;
                                                    documentcontent.SignatureFont = userProfile.FontClass;
                                                }
                                            }
                                        }
                                        else
                                        {
                                            // NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);

                                            if (!documentcontent.IsCurrentRecipient)
                                            {
                                                NonRpostUser nonRpostuser = null;
                                                if (checkNonUserProfile)
                                                {
                                                    nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                                }
                                                else if (nonRegisterProfilesList != null && recipientDetail != null)
                                                {
                                                    nonRpostuser = nonRegisterProfilesList.Where(n => n.EmailAddress.ToLower() == recipientDetail.EmailAddress.ToLower()).FirstOrDefault();
                                                }

                                                if (nonRpostuser != null)
                                                {
                                                    documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                                    documentcontent.SignatureType = nonRpostuser.SignatureTypeID;
                                                    if (nonRpostuser.SignatureTypeID == Constants.SignatureType.Auto)
                                                    {
                                                        documentcontent.SignatureString = nonRpostuser.SignatureText;
                                                        documentcontent.SignatureFont = nonRpostuser.FontClass;
                                                    }
                                                }
                                                else
                                                {
                                                    documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                                }
                                            }

                                        }
                                    }
                                    // for company
                                    else if (documentcontent.ControlID == Constants.Control.Company && documentcontent.ControlValue == null)
                                    {
                                        if (userProfile != null)
                                        {
                                            documentcontent.ControlValue = userProfile.Company;
                                        }
                                        else
                                        {
                                            // NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            NonRpostUser nonRpostuser = null;
                                            if (checkNonUserProfile)
                                            {
                                                nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            }
                                            else if (nonRegisterProfilesList != null && recipientDetail != null)
                                            {
                                                nonRpostuser = nonRegisterProfilesList.Where(n => n.EmailAddress.ToLower() == recipientDetail.EmailAddress.ToLower()).FirstOrDefault();
                                            }
                                            if (nonRpostuser != null)
                                            {
                                                documentcontent.ControlValue = nonRpostuser.Company;
                                            }

                                        }
                                    }
                                    // for title
                                    else if (documentcontent.ControlID == Constants.Control.Title && documentcontent.ControlValue == null)
                                    {
                                        if (userProfile != null)
                                        {
                                            documentcontent.ControlValue = userProfile.Title;
                                        }
                                        else
                                        {
                                            // NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            NonRpostUser nonRpostuser = null;
                                            if (checkNonUserProfile)
                                            {
                                                nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            }
                                            else if (nonRegisterProfilesList != null && recipientDetail != null)
                                            {
                                                nonRpostuser = nonRegisterProfilesList.Where(n => n.EmailAddress.ToLower() == recipientDetail.EmailAddress.ToLower()).FirstOrDefault();
                                            }
                                            if (nonRpostuser != null)
                                            {
                                                documentcontent.ControlValue = nonRpostuser.Title;
                                            }

                                        }
                                    }
                                    // for Initials                                    
                                    else if (documentcontent.ControlID == Constants.Control.NewInitials && (documentcontent.SignatureByte == null || documentcontent.SignatureByte.Length == 0))
                                    {
                                        if (documentcontent.SignatureControlValue != null && documentcontent.SignatureControlValue.Length > 0)
                                        {
                                            documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                        }
                                        else if (userProfile != null)
                                        {
                                            if (!string.IsNullOrEmpty(userProfile.Initials))
                                                documentcontent.SignatureByte = GetInitialByteValue(userProfile.Initials, documentcontent.Height, documentcontent.Width);
                                            else
                                                documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                        }
                                    }

                                    documentcontent.ControlStyle = documentcontent.ControlStyle;
                                    if (documentcontent.ControlID == Constants.Control.DropDown)
                                        documentcontent.ControlOptions = documentcontent.SelectControlOptions.ToList();
                                    documentContentList.Add(documentcontent);
                                }
                                else
                                {
                                    if ((documentcontent.ControlID == Constants.Control.NewInitials || documentcontent.ControlID == Constants.Control.Signature)
                                        && documentcontent.SignatureControlValue != null && documentcontent.SignatureControlValue.Length > 0)
                                        documentcontent.SignatureByte = documentcontent.SignatureControlValue;
                                    documentcontent.ControlStyle = documentcontent.ControlStyle;
                                    documentContentList.Add(documentcontent);
                                }
                            }

                        }
                    }
                    // for footer signature control and if no signature control assign to recipient
                    // Recipients recipientDetailObject = _recipientRepository.GetEntity(recipientId);
                    Recipients recipientDetailObject = envelope.Recipients.FirstOrDefault(a => a.ID == recipientId);
                    var documentContentObject = new DocumentContents
                    {
                        ControlName = "FooterSignature",
                        IsCurrentRecipient = true
                    };
                    UserProfile userprofile = new UserProfile();
                    if (IsUnitTestApp)   // changes for unit test code
                    {
                        userprofile = (UserProfile)SessionHelper.Get(SessionKey.User);
                    }
                    else
                    {
                        // userprofile = _userRepository.GetUserProfileByEmailID(recipientDetailObject.EmailAddress);
                        if (checkRecipientUserProfile)
                        {
                            userprofile = _userRepository.GetUserProfileByEmailID(recipientDetailObject.EmailAddress);
                        }
                        else if (recipientUserProfilesList != null)
                        {
                            userprofile = recipientUserProfilesList.Where(r => r.EmailID == recipientDetailObject.EmailAddress).FirstOrDefault();
                        }
                    }
                    if (userprofile != null && userprofile.ID != Guid.Empty)
                    {
                        if (userprofile.IsAutoPopulateSignaturewhileSinging)
                        {
                            documentContentObject.SignatureByte = userprofile.SignatureImage;
                            documentContentObject.SignatureType = userprofile.SignatureTypeID;
                            if (userprofile.SignatureTypeID == Constants.SignatureType.Auto)
                            {
                                documentContentObject.SignatureString = userprofile.SignatureText;
                                documentContentObject.SignatureFont = userprofile.FontClass;
                            }
                        }
                    }
                    else
                    {
                        // NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetailObject.EmailAddress);
                        NonRpostUser nonRpostuser = null;
                        if (checkNonUserProfile)
                        {
                            nonRpostuser = _userRepository.GetNonRpostUser(recipientDetailObject.EmailAddress);
                        }
                        else if (nonRegisterProfilesList != null)
                        {
                            nonRpostuser = nonRegisterProfilesList.Where(n => n.EmailAddress == recipientDetailObject.EmailAddress).FirstOrDefault();
                        }
                        if (nonRpostuser != null)
                        {
                            documentContentObject.SignatureByte = nonRpostuser.Signature;
                            documentContentObject.SignatureType = nonRpostuser.SignatureTypeID;
                            if (nonRpostuser.SignatureTypeID == Constants.SignatureType.Auto)
                            {
                                documentContentObject.SignatureString = nonRpostuser.SignatureText;
                                documentContentObject.SignatureFont = nonRpostuser.FontClass;
                            }
                        }

                    }
                    documentContentObject.ControlStyle = null;
                    documentContentList.Add(documentContentObject);
                    return documentContentList;
                }
            }
            catch (Exception ex)
            {
                throw;
            }
        }
        public byte[] GetInitialByteValue(string controlValue, int? height, int? width)
        {
            var FontFolderPath = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["FontFolderPath"]));
            int intHeight = 0;
            int intWidth = 0;
            var pfc = new System.Drawing.Text.PrivateFontCollection();
            pfc.AddFontFile(Path.Combine(FontFolderPath, Constants.String.SignatureFontStyle.HomemadeApple) + ".ttf");
            string imageSource = ConvertSignImage(pfc, controlValue, Constants.String.SignatureFontStyle.HomemadeApple, "13px".ToString(), ("#000000"), height.ToString(), width.ToString(), out intHeight, out intWidth);
            imageSource = imageSource.Replace("data:image/png;base64,", string.Empty);
            byte[] signByte = Convert.FromBase64String(imageSource);
            return signByte;
        }
        public EnvelopeInfo GetStaticDocumentControls(EnvelopeInfo controlsInfo, Guid templateID)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GetStaticDocumentControls", "Process started for Get Static Document Controls", templateID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            var tempdata = RetriveStaticControlData("1", templateID);
            if (tempdata != null)
            {
                var result = (List<ControlsData>)tempdata;
                controlsInfo.ControlsData = new List<ControlsData>();
                controlsInfo.ControlsData = result;
                loggerModelNew.Message = "Successfully retrieve " + controlsInfo.ControlsData.Count.ToString() + " controls for recipient";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            loggerModelNew.Message = "Process completed for Get Static Document Controls";
            rsignlog.RSignLogInfo(loggerModelNew);
            return controlsInfo;
        }
        public List<ControlsData> RetriveStaticControlData(string id, Guid templateID)
        {
            List<ControlsData> contentData = new List<ControlsData>();
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "RetriveStaticControlData", "Process started for Retrive Static Control Data", templateID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                var documentContent = GetStaticDocumentContent(templateID);
                var fonts = _lookupRepository.GetLookup(Lookup.Fonts).ToList();
                var maxCharacters = _lookupRepository.GetLookup(Lookup.MaxCharacters).ToList();
                ControlsData controlsData;
                foreach (var dc in documentContent)
                {
                    controlsData = new ControlsData
                    {
                        Id = dc.ID,
                        PageNo = dc.PageNo,
                        TabIndex = dc.TabIndex == null ? dc.PageNo : dc.TabIndex,
                        DocPage = dc.DocumentPageNo,
                        Required = dc.Required,
                        Height = dc.Height,
                        Width = dc.Width,
                        XCoordinate = dc.XCoordinate,
                        YCoordinate = dc.YCoordinate,
                        ZCoordinate = dc.ZCoordinate,
                        Label = dc.Label,
                        Left = 0.0,// dc.LeftIndex,
                        Top = 0.0,// dc.TopIndex,
                        DocumentId = dc.DocumentID,
                        ControlHtmlData = dc.ControlHtmlData,
                        ControlHtmlID = dc.ControlID == Guid.Empty ? "FooterSignature" : dc.ControlHtmlID,
                        ControlName = dc.ControlID == Guid.Empty ? "FooterSignature" : GetControlNameById(dc.ControlID),
                        ControlValue = GetControlValue(dc),
                        signerName = dc.RecName,
                        SenderControlValue = dc.SenderControlValue,
                        //IsCurrentRecipient = dc.IsCurrentRecipient,
                        //SignatureScr = dc.SignatureByte == null ? null : "data:image/png;base64," + Convert.ToBase64String(dc.SignatureByte),
                        FontColor = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.FontColor,
                        FontName = dc.TemplateControlStyle == null ? "" : fonts.Where(f => f.Key == dc.TemplateControlStyle.FontID.ToString()).Select(f => f.Value).FirstOrDefault(),
                        FontSize = dc.TemplateControlStyle == null ? 14 : dc.TemplateControlStyle.FontSize,
                        FontBold = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.IsBold == false ? "normal" : "bold",
                        FontItalic = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.IsItalic == false ? "normal" : "italic",
                        FontUnderline = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.IsUnderline == false ? "none" : "underline",
                        AdditionalValidationName = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.AdditionalValidationName,
                        AdditionalValidationOption = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.AdditionalValidationOption,
                        //SignatureText = dc.SignatureString,
                        //SignatureFont = dc.SignatureFont,
                        //SignatureType = dc.SignatureType,
                        GroupName = dc.GroupName,
                        ControlOptions = dc.TemplateSelectControlOptions == null ? null : dc.TemplateSelectControlOptions.OrderBy(y => y.Order).Select(x => new SelectControlOptions { Order = x.Order, OptionText = x.OptionText, ID = x.ID }).ToList(),
                        MaxLength = dc.MaxLength == null ? "50" : maxCharacters.Where(f => f.Key == dc.MaxLength.ToString()).Select(f => f.Value).FirstOrDefault(),//dc.MaxLength.ToString(),
                        ControlType = dc.ControlType.ToString().ToUpper(),
                        IsDefaultRequired = dc.IsDefaultRequired == null ? false : dc.IsDefaultRequired,
                        CustomToolTip = dc.CustomToolTip,
                        FontTypeMeasurement = dc.FontTypeMeasurement == null ? "px" : dc.FontTypeMeasurement,
                        IsFixedWidth = dc.IsFixedWidth == null ? true : Convert.ToBoolean(dc.IsFixedWidth) ? true : false,
                        ConditionDetails = _conditionalControlRepository.GetAllConditionalControl(Constants.String.RSignStage.SignEnvelope, templateID, dc.ID, null)
                    };
                    contentData.Add(controlsData);
                }
                contentData = contentData.OrderBy(x => x.PageNo).ThenBy(x => x.TabIndex).ThenByDescending(x => x.GroupName).ToList();
                return contentData;

            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }
        }
        public List<TemplateDocumentContents> GetStaticDocumentContent(Guid templateID)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GetStaticDocumentContent", "Process started for Get Static Document Content", templateID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                bool IsUnitTestApp = Convert.ToBoolean(SessionHelper.Get(SessionKey.IsUnitTestApp));
                var envelope = _genericRepository.GetTemplateEntity(templateID);
                var documentContentList = new List<TemplateDocumentContents>();
                foreach (var document in envelope.TemplateDocuments)
                {
                    var documentContentLst = new List<TemplateDocumentContents>();
                    documentContentLst = document.TemplateDocumentContents.OrderBy(dc => dc.PageNo).Where(d => d.IsControlDeleted == false).ToList();

                    foreach (var documentcontent in documentContentLst)
                    {
                        documentcontent.TemplateControlStyle = documentcontent.TemplateControlStyle;
                        documentcontent.TemplateSelectControlOptions = documentcontent.TemplateSelectControlOptions;
                        documentContentList.Add(documentcontent);
                    }
                }
                loggerModelNew.Message = "Process completed for Get Static Document Content";
                rsignlog.RSignLogInfo(loggerModelNew);
                return documentContentList;

            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }
        }
        public string GetControlValue(TemplateDocumentContents dc)
        {
            string controlValue = null;
            if (dc.ControlID == Constants.Control.Name)
            {
                controlValue = string.IsNullOrEmpty(dc.ControlValue) ? "" : dc.ControlValue;
            }
            else if (dc.ControlID == Constants.Control.Checkbox)
            {
                controlValue = dc.ControlValue != null ? (dc.ControlValue.ToLower() == "true" ? "true" : "false") :
                    dc.SenderControlValue != null ? (dc.SenderControlValue.ToLower() == "true" ? "true" : "false") : null;
            }
            else if (dc.ControlID == Constants.Control.DropDown)
            {
                if (!string.IsNullOrEmpty(dc.ControlValue))
                {
                    controlValue = dc.TemplateSelectControlOptions.Where(d => d.ID == Guid.Parse(dc.ControlValue)).Select(d => d.OptionText).FirstOrDefault();
                }
                else
                {
                    controlValue = dc.ControlValue;
                }
            }
            else
            {
                controlValue = dc.ControlValue;
            }
            return controlValue;
        }
