                        Height = dc.Height,
                        Width = dc.Width,
                        XCoordinate = dc.XCoordinate,
                        YCoordinate = dc.YCoordinate,
                        ZCoordinate = dc.ZCoordinate,
                        Label = dc.Label,
                        Left = 0.0,// dc.LeftIndex,
                        Top = 0.0,// dc.TopIndex,
                        DocumentId = dc.DocumentID,
                        RecipientId = dc.RecipientID,
                        ControlHtmlData = dc.ControlHtmlData,
                        ControlHtmlID = dc.ControlID == Guid.Empty ? "FooterSignature" : dc.ControlHtmlID,
                        ControlName = dc.ControlID == Guid.Empty ? "FooterSignature" : GetControlNameById(dc.ControlID),
                        ControlValue = GetControlValue(dc),
                        signerName = dc.RecName,
                        SenderControlValue = dc.SenderControlValue,
                        IsCurrentRecipient = dc.IsCurrentRecipient,
                        //SignatureScr = dc.SignatureByte == null ? null : "data:image/png;base64," + Convert.ToBase64String(dc.SignatureByte),
                        FontColor = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.FontColor,
                        FontName = dc.TemplateControlStyle == null ? "" : fonts.Where(f => f.Key == dc.TemplateControlStyle.FontID.ToString()).Select(f => f.Value).FirstOrDefault(),
                        FontSize = dc.TemplateControlStyle == null ? 14 : dc.TemplateControlStyle.FontSize,
                        FontBold = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.IsBold == false ? "normal" : "bold",
                        FontItalic = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.IsItalic == false ? "normal" : "italic",
                        FontUnderline = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.IsUnderline == false ? "none" : "underline",
                        AdditionalValidationName = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.AdditionalValidationName,
                        AdditionalValidationOption = dc.TemplateControlStyle == null ? "" : dc.TemplateControlStyle.AdditionalValidationOption,
                        //SignatureText = dc.SignatureString,
                        //SignatureFont = dc.SignatureFont,
                        //SignatureType = dc.SignatureType,
                        GroupName = dc.GroupName,
                        ControlOptions = dc.TemplateSelectControlOptions == null ? null : dc.TemplateSelectControlOptions.OrderBy(y => y.Order).Select(x => new SelectControlOptions { Order = x.Order, OptionText = x.OptionText, ID = x.ID }).ToList(),
                        MaxLength = dc.MaxLength == null ? "50" : maxCharacters.Where(f => f.Key == dc.MaxLength.ToString()).Select(f => f.Value).FirstOrDefault(),//dc.MaxLength.ToString(),
                        ControlType = dc.ControlType.ToString().ToUpper(),
                        IsDefaultRequired = dc.IsDefaultRequired == null ? false : dc.IsDefaultRequired,
                        CustomToolTip = dc.CustomToolTip,
                        FontTypeMeasurement = dc.FontTypeMeasurement == null ? "px" : dc.FontTypeMeasurement,
                        IsFixedWidth = dc.IsFixedWidth == null ? true : Convert.ToBoolean(dc.IsFixedWidth) ? true : false,
                        ConditionDetails = _conditionalControlRepository.GetAllConditionalControl(Constants.String.RSignStage.SignEnvelope, templateID, dc.ID, null)
                    };
                    contentData.Add(controlsData);
                }
                contentData = contentData.OrderBy(x => x.PageNo).ThenBy(x => x.TabIndex).ThenByDescending(x => x.GroupName).ToList();
                return contentData;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }
        }
