        public bool InviteSenderConfirmationEmailForStaticTemplate(Guid EnvelopeID, UserProfile senderDetails, string recepientID, bool isTosign, List<DocumentContents> documentContentDetail, bool isResent = false, List<SendConfirmationDataModel> sendConfirmationData = null, string recipientDeliveryMode = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "InviteSenderConfirmationEmailForStaticTemplate", "Process started for Send Confirmation Email For Static Template", EnvelopeID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                var envelopeObject = _genericRepository.GetEntity(EnvelopeID);
                List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();
                string EmailSentType = string.Empty; int RetryCount = 0;

                string EmailDisclaimer = string.Empty;
                int SignReqReplyToAddressValue = 1;
                var msgId = Guid.NewGuid();
                var settingDetailEmailDesclaimer = _settingsRepository.GetEntityForByKeyConfig(senderDetails.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                if (settingDetailEmailDesclaimer != null)
                {
                    EmailDisclaimer = Convert.ToString(settingDetailEmailDesclaimer.OptionValue);
                }
                var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(senderDetails.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
                if (settingsDetails != null)
                    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

                int electronicStampRequired = GetElectronicSignIndicationValueForUser(senderDetails.UserID);
                //We require Signature controls for current recipient.
                if (!isResent)
                {
                    Recipients recipientDetail = _recipientRepository.GetEntity(new Guid(recepientID));
                    var documentContents = new List<DocumentContents>();
                    foreach (Documents document in envelopeObject.Documents)
                        documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == new Guid(recepientID) && d.ControlID == Constants.Control.Signature));
                    if (documentContents.Count == 0)
                        SaveSignature(documentContentDetail, documentContents, new Guid(recepientID), recipientDetail, string.Empty, electronicStampRequired);
                }
                //End save signature control


                foreach (var recipData in envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.EnvelopeID == EnvelopeID && r.SignNowOrInviteEmail == 1 && r.ID == new Guid(recepientID)).ToList())
                {
                    var strURL = !(webApiCall) ? Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SubmitEnvByConfirmationLink?"
                         : Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SubmitEnvByConfirmationLink?";
                    // encrypt querystring
                    var strURLWithData = strURL + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&RecipientId={1}&status={2}", EnvelopeID, recipData.ID, isTosign ? "S" : "D")));

                    string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                    imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
                    cultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();

                    string signingShortURL = string.Empty;
                    if (Convert.ToBoolean(envelopeObject.EnableMessageToMobile))
                    {
                        string md5ShortUriPasscode = _modelHelper.CalculateMD5HashForShortURL(strURLWithData).ToLower();
                        signingShortURL = Convert.ToString(_appConfiguration["SigningURL"]) + "Msg/Rs/" + md5ShortUriPasscode;
                        SaveShortUrlForSMS(envelopeObject, strURLWithData, signingShortURL, md5ShortUriPasscode, false);
                    }

                    string[] recipientEmail = new string[] { recipData.EmailAddress };
                    string[] recipientName = new string[] { recipData.Name };
                    string CultureInfo = string.IsNullOrEmpty(recipData.CultureInfo) ? envelopeObject.CultureInfo : recipData.CultureInfo;
                    var mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.SendStaticTemplateConfirm, CultureInfo, EmailDisclaimer);

                    //* Added by RLabs-RSign DEV Team
                    allSettingsDetails = GetAllSettingsDetails(senderDetails.UserID, senderDetails.EmailID);

                    if (allSettingsDetails.ShowRSignLogo != true)
                    {
                        imageLogoURl = string.Empty;
                    }
                    // bool isEmailSend = false; bool isMobileSend = false;
                    var sendConfirmationEmailMobileData = "";
                    var sendConfirmationMobile = "";
                    var sendConfirmationDialCode = "";
                    var sendConfirmationRecpEmail = "";
                    if (Convert.ToBoolean(envelopeObject.EnableMessageToMobile))
                    {
                        if (sendConfirmationData != null && sendConfirmationData.Count > 0)
                        {
                            var sendConfirmationObj = sendConfirmationData[0];
                            if (sendConfirmationObj.IsEmailChecked && sendConfirmationObj.IsMobileChecked)
                            {
                                //isEmailSend = true;
                                //isMobileSend = true;
                                sendConfirmationEmailMobileData = sendConfirmationObj.Email + ", " + sendConfirmationObj.DialCode + sendConfirmationObj.MobileNumber;
                                sendConfirmationMobile = sendConfirmationObj.MobileNumber;
                                sendConfirmationDialCode = sendConfirmationObj.DialCode;
                            }
                            else if (sendConfirmationObj.IsEmailChecked)
                            {
                                //isEmailSend = true;
                                sendConfirmationEmailMobileData = sendConfirmationObj.Email;
                            }
                            else if (sendConfirmationObj.IsMobileChecked)
                            {
                                //isMobileSend = true;
                                sendConfirmationEmailMobileData = sendConfirmationObj.DialCode + sendConfirmationObj.MobileNumber;
                                sendConfirmationMobile = sendConfirmationObj.MobileNumber;
                                sendConfirmationDialCode = sendConfirmationObj.DialCode;
                            }
                            sendConfirmationRecpEmail = sendConfirmationObj.Email;
                        }
                        else
                        {
                            sendConfirmationEmailMobileData = recipientEmail[0];
                            sendConfirmationRecpEmail = recipientEmail[0];
                            // isEmailSend = true;
                        }
                    }
                    else
                    {
                        sendConfirmationEmailMobileData = recipientEmail[0];
                        sendConfirmationRecpEmail = recipientEmail[0];
                        // isEmailSend = true;
                    }

                    bool isEmailSend = false; //isPwdEmailSend = false;
                    bool isMobileSend = false;  //isPwdMobileSend = false;
                    int? DeliveryMode = 1;
                    if (!string.IsNullOrEmpty(recipientDeliveryMode))
                    {
                        DeliveryMode = Convert.ToInt32(recipientDeliveryMode);
                    }
                    Recipients recSigner = new Recipients() { DeliveryMode = DeliveryMode, EmailAddress = sendConfirmationRecpEmail, Mobile = sendConfirmationMobile };
                    GetEmailDeiliveryModeOptions(recSigner, ref isEmailSend, ref isMobileSend);
                    // GetMobileDeiliveryModeOptions(recSigner, ref isPwdEmailSend, ref isPwdMobileSend); //no password emails

                    if (isEmailSend)
                    {
                        mailTemplate = mailTemplate.Replace("#SenderName", senderDetails.FirstName + " " + senderDetails.LastName);
                        mailTemplate = mailTemplate.Replace("#SenderEmailId", senderDetails.EmailID);
                        if (string.IsNullOrEmpty(sendConfirmationEmailMobileData)) sendConfirmationEmailMobileData = recipientEmail[0];

                        //if (isMobileSend)
                        mailTemplate = mailTemplate.Replace("#SignerEmailId", sendConfirmationEmailMobileData);
                        //else
                        //    mailTemplate = mailTemplate.Replace("#SignerEmailId", recipientEmail[0]);
                        mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", envelopeObject.EDisplayCode.ToString());
                        mailTemplate = mailTemplate.Replace("#EmailBodyText", envelopeObject.Message);
                        mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(envelopeObject.EDisplayCode));
                        mailTemplate = mailTemplate.Replace("#URL", strURLWithData);
                        //mailTemplate = mailTemplate.Replace("#ImageURL", imageLogoURl);
                        mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.SendStaticTemplateConfirm);

                        mailTemplate = _genericRepository.AppendFooterText(mailTemplate, recipientEmail[0].ToString(), Constants.String.MailTemplateName.SendStaticTemplateConfirm, CultureInfo, "FinalContractFooter");

                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            //Recipients recipientsigner = envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.ID == new Guid(recepientID)).FirstOrDefault();
                            EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                            EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                            emailQueueData.envelope = envelopeObject;
                            emailQueueData.MailMessageBody = mailTemplate;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            emailQueueData.EmailType = Constants.EmailTypes.SC;
                            emailQueueData.EmailSubject = GetEmailSubject(CultureInfo, envelopeObject.Subject, Constants.EmailSubject.EmailVerification);

                            emailSendData.RecipientName = string.Join(",", recipientName);
                            emailSendData.RecipientEmail = string.Join(",", recipientEmail);
                            emailQueueData.emailSendInfo = emailSendData;
                            EmailQueueFunction(emailQueueData);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            emailLogs = Chilkat.SendMailUsingChilKet(recipientEmail, recipientName, null, null, null, null, senderDetails.EmailID, senderDetails.FirstName + " " + senderDetails.LastName, GetEmailSubjectPrefix(CultureInfo, envelopeObject.Subject, Constants.EmailSubject.EmailVerification), mailTemplate, null, null, envelopeObject.EDisplayCode, Constants.String.EmailOperation.InitialOfferStatic, SignReqReplyToAddressValue, msgId);
                            _genericRepository.SaveEmailLogsRecord(emailLogs, out EmailSentType, out RetryCount);
                            //Save email destination record
                            _genericRepository.SaveDestinationRecord(new Destination() { MessageId = msgId, EnvelopeCode = envelopeObject.EDisplayCode, RecipientEmail = recipientEmail[0], IsSent = true, IsProcessed = false, EmailSentType = EmailSentType, RetryCount = RetryCount });
                        }
                    }

                    if (isMobileSend)
                    {
                        mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.SendStaticTemplateConfirm, CultureInfo, EmailDisclaimer, 3, "mobile");
                        mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", envelopeObject.EDisplayCode.ToString());
                        mailTemplate = mailTemplate.Replace("#SigningShortURL", signingShortURL);

                        Recipients recp = new Recipients();
                        recp.Mobile = sendConfirmationMobile;
                        recp.DialCode = sendConfirmationDialCode;
                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            string emailSubject = GetEmailSubject(CultureInfo, envelopeObject.Subject, Constants.EmailSubject.EmailVerification);
                            SendSMSThroughEmailService(envelopeObject, mailTemplate, SignReqReplyToAddressValue, Constants.EmailTypes.SC, recp, emailSubject);
                        }
                        else
                        {
                            string signerMobileNumber = sendConfirmationDialCode + sendConfirmationMobile;
                            SendMobileSMS(envelopeObject, mailTemplate, signerMobileNumber);
                        }
                    }

                    loggerModelNew.Message = "Process completed for Send Confirmation Email For Static Template";
                    rsignlog.RSignLogInfo(loggerModelNew);
                }
                return true;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.ToString();
                rsignlog.RSignLogError(loggerModelNew, ex);
                return false;
            }
        }
        private void InviteRecipientMail(Envelope sessionEnvelope, Guid recipientId, string senderEmailAddress, string senderName, int SignReqReplyToAddressValue = 1)
        {
            loggerModelNew = new LoggerModelNew(senderEmailAddress, "EnvelopeHelperMain", "InviteRecipientMail", "Process started for sending Recipient Mail", sessionEnvelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            using (var dbContext = new RSignDbContext(_configuration))
            {
                Guid msgId = Guid.NewGuid();
                bool IsPrefillCase = false, IsSenderReceiveConfirmationEmail = false;
                double fileSizes = 0;

                var userprofile = _userRepository.GetUserProfile(sessionEnvelope.UserID);
                int isContractToGenerateFromImages = Constants.FinalContractOptions.Aspose;
                string EmailSentType = string.Empty; int RetryCount = 0;
                List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();

                string EmailDisclaimer = string.Empty;
                var settingDetailEmailDesclaimer = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                if (settingDetailEmailDesclaimer != null)
                {
                    EmailDisclaimer = Convert.ToString(settingDetailEmailDesclaimer.OptionValue);
                }
                int intDtFormat = 0;
                var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(sessionEnvelope.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
                if (settingsDateTimeFormt != null)
                {
                    intDtFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);
                }

                int DisclaimerLocationId = Constants.DisclaimerLocation.BottomOfEmail;
                var settingsDetailsDisclaimerLocation = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.DisclaimerLocation);
                if (settingsDetailsDisclaimerLocation != null)
                {
                    DisclaimerLocationId = Convert.ToInt32(settingsDetailsDisclaimerLocation.OptionValue);
                }

                Recipients recipientObject = _recipientRepository.GetEntity(recipientId);
                cultureInfo = sessionEnvelope.CultureInfo;
                //if (
                //    !IsCurrentLevelComplete(sessionEnvelope.Recipients.ToList(), recipientId,
                //                            Convert.ToInt16(recipientObject.Order))) return;
                var orderCollection = sessionEnvelope.Recipients.Where(r => r.Order != null && r.IsSameRecipient != true).OrderBy(o => o.Order).Select(r => r.Order).ToList();
                //int nextOrder = 0;
                //if (!orderCollection.Any(o => o != null && o.Value > recipientObject.Order)) return;
                //foreach (int order in orderCollection.Cast<int>().Where(order => order > recipientObject.Order))
                //{
                //    nextOrder = order;
                //    break;
                //}
                List<Recipients> recipientList = _recipientRepository.GetAll(sessionEnvelope.ID).Where(r => r.Order == 1 && r.IsSameRecipient != true && r.ID != recipientId && r.SignNowOrInviteEmail != 1).ToList();
                int i = 5;
                foreach (var signerStatus in recipientList.OrderBy(r => r.CreatedDateTime).Select(signer => new SignerStatus
                {
                    ID = Guid.NewGuid(),
                    RecipientID = signer.ID,
                    CreatedDateTime = DateTime.Now.AddSeconds(2).AddMilliseconds(i),
                    StatusID = Constants.StatusCode.Signer.Pending
                }))
                {
                    i = i + 5;
                    if (!IsUnitTestApp)
                    {
                        if (Convert.ToBoolean(sessionEnvelope.IsStatic) && recipientList.Count > 0)
                        {
                            if (_recipientRepository.GetAllSignerStatus(signerStatus.RecipientID).Where(s => s.StatusID == Constants.StatusCode.Signer.Pending).Count() == 0)
                                _recipientRepository.Save(signerStatus);
                        }
                        else
                            _recipientRepository.Save(signerStatus);

                    }
                }
                if (!IsUnitTestApp)
                    dbContext.SaveChanges();
                var imageLogoURl = _appConfiguration["domain"].ToString() + "Content/img/RMail-100.png";
                var authKey = string.Empty;

                //Written two different loop as the saving changes to db and sending email should not be merged.                
                var recipientPrefill = sessionEnvelope.Recipients.FirstOrDefault(x => (x.ID == recipientId)).RecipientTypeID;
                if (recipientPrefill == Constants.RecipientType.Prefill)
                {
                    IsPrefillCase = true;
                    var ccList = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.CC).ToList();
                    recipientList.AddRange(ccList);
                }

                string strURLForcc = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPreviewPDF?");
                string strURLWithDataForcc = string.Empty;
                if (!webApiCall)
                    strURLWithDataForcc = strURLForcc + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", sessionEnvelope.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                else
                    strURLWithDataForcc = strURLForcc + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", sessionEnvelope.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));

                var finalDocName = (sessionEnvelope.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) ? "Contracts" : sessionEnvelope.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).First().DocumentName;
                if (sessionEnvelope.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() == 1)
                    finalDocName = finalDocName.Substring(0, finalDocName.LastIndexOf('.'));

                bool isMultiTemplate = sessionEnvelope.Recipients.Where(s => s.TemplateID != null && s.RecipientTypeID == Constants.RecipientType.Signer).Select(s => s.TemplateID).Distinct().Count() > 1;
                var multiSubject = string.Empty;
                var multiEmailList = recipientList.Where(s => s.TemplateID != null && s.RecipientTypeID == Constants.RecipientType.Signer).GroupBy(s => s.EmailAddress).Where(grp => grp.Count() > 1).Select(grp => grp.Key).ToList();
                Dictionary<string, int> emailDispatch = new Dictionary<string, int>();
                foreach (string email in multiEmailList)
                    emailDispatch.Add(email, 1);

                //* Added by RLabs-RSign DEV Team
                allSettingsDetails = GetAllSettingsDetails(sessionEnvelope.UserID, senderEmailAddress);

                if (allSettingsDetails.ShowRSignLogo != true)
                {
                    imageLogoURl = string.Empty;
                }
                //*//
                foreach (var signer in recipientList)
                {
                    bool isEmailSend = false, isPwdEmailSend = false;
                    bool isMobileSend = false, isPwdMobileSend = false;
                    var isPasswordMailToSigner = sessionEnvelope.IsPasswordMailToSigner;

                    if (Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile))
                    {
                        isPasswordMailToSigner = true;
                        Recipients recSigner = new Recipients() { DeliveryMode = signer.DeliveryMode, EmailAddress = signer.EmailAddress, Mobile = signer.Mobile };
                        GetEmailDeiliveryModeOptions(recSigner, ref isEmailSend, ref isMobileSend);
                        GetMobileDeiliveryModeOptions(recSigner, ref isPwdEmailSend, ref isPwdMobileSend);

                        //if ((signer.SignNowOrInviteEmail == 2 || signer.SignNowOrInviteEmail == 3) && !string.IsNullOrEmpty(signer.EmailAddress))
                        //{
                        //    isEmailSend = true;
                        //}

                        //if ((signer.SignNowOrInviteEmail == 3 || signer.SignNowOrInviteEmail == 4) && !string.IsNullOrEmpty(signer.Mobile))
                        //{
                        //    isMobileSend = true;
                        //}
                        //if (signer.DeliveryMode == null) { isEmailSend = true; }
                    }
                    else
                    {
                        isPwdEmailSend = true;
                        isEmailSend = true;
                    }

                    msgId = Guid.NewGuid();
                    if (sessionEnvelope.PasswordReqdtoSign == true && signer.RecipientTypeID != Constants.RecipientType.CC)
                    {
                        string password = ModelHelper.Decrypt(sessionEnvelope.PasswordtoSign, sessionEnvelope.PasswordKey, (int)sessionEnvelope.PasswordKeySize);
                        string mailTemplatepassword = string.Empty;
                        string mobileTemplatepassword = string.Empty;
                        mailTemplatepassword = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordSign, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, EmailDisclaimer);
                        string firstName = signer.Name.Split(' ').FirstOrDefault();

                        //bool isEmailSend = false; bool isMobileSend = false;
                        //if (Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile))
                        //{
                        //    if ((signer.SignNowOrInviteEmail == 2 || signer.SignNowOrInviteEmail == 3) && !string.IsNullOrEmpty(signer.EmailAddress))
                        //    {
                        //        isEmailSend = true;
                        //    }

                        //    if ((signer.SignNowOrInviteEmail == 3 || signer.SignNowOrInviteEmail == 4) && !string.IsNullOrEmpty(signer.Mobile))
                        //    {
                        //        isMobileSend = true;
                        //    }
                        //    if (signer.DeliveryMode == null) { isEmailSend = true; }
                        //}
                        //else
                        //{
                        //    isEmailSend = true;
                        //}

                        if (isPwdEmailSend && isPasswordMailToSigner)
                        {
                            mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", senderName);
                            mailTemplatepassword = mailTemplatepassword.Replace("#SenderEmailId", senderEmailAddress);
                            mailTemplatepassword = mailTemplatepassword.Replace("#RecipientName", firstName);
                            mailTemplatepassword = mailTemplatepassword.Replace("#SignerName", signer.Name);

                            string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signer.DeliveryMode, signer.EmailAddress, signer.DialCode, signer.Mobile);
                            mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", emailMobileNumberDetails);


                            //if (isMobileSend)
                            //{
                            //    if (signer.DeliveryMode == 2)
                            //        mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", signer.EmailAddress + ", " + signer.DialCode + signer.Mobile);
                            //    else
                            //        mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", signer.DialCode + signer.Mobile);
                            //}
                            //else
                            //    mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", signer.EmailAddress);

                            mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));
                            mailTemplatepassword = mailTemplatepassword.Replace("#PasswordToOpenDoc", System.Web.HttpUtility.HtmlEncode(password));
                            //mailTemplatepassword = mailTemplatepassword.Replace("#ImageURL", imageLogoURl);
                            mailTemplatepassword = mailTemplatepassword.Replace("#clientLogo", string.Empty);
                            mailTemplatepassword = EmailBannerSettings(mailTemplatepassword, allSettingsDetails, Constants.String.MailTemplateName.PasswordSign);

                            mailTemplatepassword = _genericRepository.AppendFooterText(mailTemplatepassword, signer.EmailAddress, Constants.String.MailTemplateName.PasswordSign, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, "FinalContractFooter");

                            if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                            {
                                //To Add data in Emailqueue and EmailqueueRecipients for submit (Electronic Signature Password Notification) *
                                EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                                EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                                emailQueueData.envelope = sessionEnvelope;
                                emailQueueData.MailMessageBody = mailTemplatepassword;
                                emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                                //emailQueueData.Signer = signer; 
                                emailQueueData.EmailType = Constants.EmailTypes.ESPN;
                                emailQueueData.EmailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.PasswordToSign);
                                emailSendData.RecipientName = signer.Name;
                                emailSendData.RecipientEmail = signer.EmailAddress;
                                emailQueueData.emailSendInfo = emailSendData;
                                EmailQueueFunction(emailQueueData, true);
                            }
                            else
                            {
                                var Chilkat = new ChilkatHelper(_appConfiguration);
                                Chilkat.SendMailUsingChilKet(new string[] { signer.EmailAddress }, new string[] { signer.Name }, null, null, null, null,
                                         senderEmailAddress, senderName, GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.PasswordToSign), mailTemplatepassword, null, null, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.PasswordToSign, SignReqReplyToAddressValue);
                            }
                        }

                        if (isPwdMobileSend)
                        {
                            mobileTemplatepassword = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordSign, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, EmailDisclaimer, 3, "mobile");
                            mobileTemplatepassword = mobileTemplatepassword.Replace("#SenderName", senderName);
                            mobileTemplatepassword = mobileTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(password));
                            mobileTemplatepassword = mobileTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));

                            if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                            {
                                string emailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.PasswordToSign);
                                SendSMSThroughEmailService(sessionEnvelope, mobileTemplatepassword, SignReqReplyToAddressValue, Constants.EmailTypes.ESPN, signer, emailSubject);
