                    //  string strURL = Path.Combine(Convert.ToString(_appConfiguration["SigningURL"]), "SignDocument/Index?");
                    if (Convert.ToBoolean(sessionEnvelope.IsSignerIdentitiy) && signer.RecipientTypeID != Constants.RecipientType.CC)
                    {
                        if (IsGenerateNewSigningUrl(senderEmailAddress))
                            strURL = Convert.ToString(_appConfiguration["NewSigningURL"]) + "authenticate-signer?";
                        else
