                        // strURL = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/AuthenticateSigner?";
                    }
                    string strURLWithData = string.Empty;

                    var templateKey = (from q in dbContext.Envelope
                                       where q.ID == sessionEnvelope.ID
                                       select q.TemplateKey).First();
                    if (templateKey != null)
                    {
                        if (!webApiCall)
                            strURLWithData = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}&TemplateKey={2}&EmailId={3}", sessionEnvelope.ID.ToString(), signer.ID.ToString(), Convert.ToString(templateKey), HttpUtility.UrlEncode(signer.EmailAddress.ToString())), Convert.ToString(_appConfiguration["AppKey"])));
                        else
                            strURLWithData = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}&TemplateKey={2}&EmailId={3}", sessionEnvelope.ID.ToString(), signer.ID.ToString(), Convert.ToString(templateKey), HttpUtility.UrlEncode(signer.EmailAddress.ToString())), Convert.ToString(_appConfiguration["AppKey"])));
                    }
                    else
                    {
                        if (!webApiCall)
                            strURLWithData = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}&EmailId={2}", sessionEnvelope.ID.ToString(), signer.ID.ToString(), HttpUtility.UrlEncode(signer.EmailAddress.ToString())), Convert.ToString(_appConfiguration["AppKey"])));
                        else
                            strURLWithData = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}&EmailId={2}", sessionEnvelope.ID.ToString(), signer.ID.ToString(), HttpUtility.UrlEncode(signer.EmailAddress.ToString())), Convert.ToString(_appConfiguration["AppKey"])));
                    }

                    string signingShortURL = string.Empty;
                    if (Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile))
                    {
                        string md5ShortUriPasscode = _modelHelper.CalculateMD5HashForShortURL(strURLWithData).ToLower();
                        signingShortURL = Convert.ToString(_appConfiguration["SigningURL"]) + "Msg/Rs/" + md5ShortUriPasscode;
                        SaveShortUrlForSMS(sessionEnvelope, strURLWithData, signingShortURL, md5ShortUriPasscode, false);
                    }

                    var mailTemlate = string.Empty;
                    var mobilelTemlate = string.Empty;
                    if (signer.RecipientTypeID == Constants.RecipientType.CC)
                    {
                        var htmlCodeCC = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#CCName (<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#CCEmailId'>#CCEmailId</a>)</font>";
                        List<Recipients> ccRecipients = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.CC).ToList();
                        List<Recipients> signerRecipients = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer).ToList();
                        StringBuilder sbCC = new StringBuilder();
                        mailTemlate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.CCRecipient, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId);
                        //Append All "TO LIST"
                        mailTemlate = AppendAllSignerRecipient(signerRecipients, mailTemlate, sessionEnvelope.EnableMessageToMobile);
                        //foreach (var ccRecipient in ccRecipients)
                        //{
                        //    var tempHtmlCode = htmlCodeCC.Replace("'", "\"");
                        //    tempHtmlCode = tempHtmlCode.Replace("#CCName", ccRecipient.Name);
                        //    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccRecipient.EmailAddress);
                        //    sbCC.Append(tempHtmlCode + ",");
                        //}                       

                        var ccString = AppendCCUserEmailsList(ccRecipients, Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile));
                        sbCC.Append(ccString);
                        string FirstName = signer.Name.Split(' ').FirstOrDefault();
                        mailTemlate = mailTemlate.Replace("#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
                        mailTemlate = mailTemlate.Replace("#CCFirstName", FirstName);
                        mailTemlate = mailTemlate.Replace("#SenderName", senderName);
                        mailTemlate = mailTemlate.Replace("#SenderEmailId", senderEmailAddress);
                        mailTemlate = mailTemlate.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));
                        //mailTemlate = mailTemlate.Replace("#ImageURL", imageLogoURl);
                        mailTemlate = mailTemlate.Replace("#EmailBodyText", sessionEnvelope.Message);
