                                 senderEmailAddress, senderName, GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SignatureRequest) + multiSubject, mailTemlate, null, null, Convert.ToString(sessionEnvelope.EDisplayCode), Constants.String.EmailOperation.SignRecipient, SignReqReplyToAddressValue, msgId);

                                _genericRepository.SaveEmailLogsRecord(emailLogs, out EmailSentType, out RetryCount);
                                //Save email destination record
                                _genericRepository.SaveDestinationRecord(new Destination() { MessageId = msgId, EnvelopeCode = sessionEnvelope.EDisplayCode, RecipientEmail = signer.EmailAddress, IsSent = true, IsProcessed = false, EmailSentType = EmailSentType, RetryCount = RetryCount });
                                //LogMsg("Document sent to next recipient for signing");
                            }
                        }

                        if (isMobileSend)
                        {
                            if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                            {
                                string emailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SignatureRequest) + multiSubject;
                                SendSMSThroughEmailService(sessionEnvelope, mobilelTemlate, SignReqReplyToAddressValue, Constants.EmailTypes.SR, signer, emailSubject);
                            }
                            else
                            {
                                string signerMobileNumber = signer.DialCode + signer.Mobile;
                                SendMobileSMS(sessionEnvelope, mobilelTemlate, signerMobileNumber);
                            }
                        }

                        //START RAPP - Update Invite by email recipient signature request RAPP notification
                        var signerStatusId = dbContext.SignerStatus.Where(r => r.RecipientID == signer.ID).FirstOrDefault().ID.ToString();
                        _genericRepository.UpdateEnvelopeCommonWebhookTransaction(sessionEnvelope, Constants.WebhookEventNames.SignerStatus, senderEmailAddress, signer.ID.ToString(), signerStatusId, "", "signingrequest");
                        //End RAPP - Update Invite by email recipient signature request RAPP notification
                    }
                    multiSubject = string.Empty;
                }

                //Sender Confirmation Email
                if (IsPrefillCase == true)
                {
                    var settingsDetailForConfirmation = _settingsRepository.GetEntityForByKeyConfig(sessionEnvelope.UserID, Constants.SettingsKeyConfig.ReceiveSendingEmailConfirmation);
                    if (settingsDetailForConfirmation != null)
                        IsSenderReceiveConfirmationEmail = !string.IsNullOrEmpty(settingsDetailForConfirmation.OptionValue) ? Convert.ToBoolean(settingsDetailForConfirmation.OptionValue) : false;

                    if (IsSenderReceiveConfirmationEmail == true)
                    {
                        var fromEmailAddress = Convert.ToString(_appConfiguration["FromEmailAddress"].ToString());

                        sessionEnvelope.IsFinalCertificateReq = false;
                        string completionDate = string.Empty;
                        settingsDetailForConfirmation = _settingsRepository.GetEntityForByKeyConfig(sessionEnvelope.UserID, Constants.SettingsKeyConfig.TimeZone);
                        if (settingsDetailForConfirmation == null || string.IsNullOrEmpty(settingsDetailForConfirmation.OptionValue))
                            completionDate = String.Format("{0:MM/dd/yyyy HH:mm tt}", sessionEnvelope.ModifiedDateTime) + " " + _eSignHelper.GetTimeZoneAbbreviation(TimeZone.CurrentTimeZone.StandardName);
                        else
                            completionDate = _eSignHelper.GetLocalTime(sessionEnvelope.ModifiedDateTime, Convert.ToString(settingsDetailForConfirmation.OptionValue), sessionEnvelope.DateFormatID);

                        string mailTemlateSender = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.SendingConfirmation, sessionEnvelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId);
                        mailTemlateSender = SenderConfirmationEmail(sessionEnvelope, mailTemlateSender, completionDate, imageLogoURl, strURLWithDataForcc);
                        mailTemlateSender = EmailBannerSettings(mailTemlateSender, allSettingsDetails, Constants.String.MailTemplateName.SendingConfirmation);

                        var userSettings = new FinalContractSettings
                        {
                            WatermarkAuthText = string.Empty,
                            WatermarkBackgroundText = string.Empty,
                            FinalContractOptions = isContractToGenerateFromImages,
                            UserTimeZone = string.Empty,
                            IsControlDisplayInTag = false
                        };
                        string[] senderArray = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).Select(r => r.EmailAddress).ToArray();
                        string[] senderDisplayName = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).Select(r => r.Name).ToArray();

                        var attachments = new List<byte[]>();
                        var dirPath = _modelHelper.GetEnvelopeDirectoryNew(sessionEnvelope.ID, string.Empty);
                        string previewDocDirectory = dirPath + sessionEnvelope.ID + "\\Final\\PreviewDoc.pdf";
                        if (!File.Exists(previewDocDirectory))
                        {
                            string finalPdfFilePath = string.Empty;
                            try
                            {
                                finalPdfFilePath = _apiHelper.finalMergePDFApi(sessionEnvelope, userSettings, dirPath, string.Empty, false);
                            }
                            catch (Exception ex)
                            {
                                DeleteContractFileInCaseOfError(sessionEnvelope.ID, dirPath);
                                userSettings.FinalContractOptions = Convert.ToInt32(userSettings.FinalContractOptions) != Constants.FinalContractOptions.iText ? Constants.FinalContractOptions.iText : Constants.FinalContractOptions.Aspose;
                                finalPdfFilePath = _apiHelper.finalMergePDFApi(sessionEnvelope, userSettings, dirPath, string.Empty, false);
                            }
                            byte[] finalMergedArray = System.IO.File.ReadAllBytes(finalPdfFilePath);
                            if (finalMergedArray != null)
                                attachments.Add(finalMergedArray);

                            System.IO.File.WriteAllBytes(previewDocDirectory, finalMergedArray);
                            fileSizes = attachments.Sum(arr => arr.Length);
                            fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);
                        }
                        else
                        {
                            byte[] finalMergedArray = System.IO.File.ReadAllBytes(previewDocDirectory);
                            if (finalMergedArray != null)
                                attachments.Add(finalMergedArray);
                            fileSizes = attachments.Sum(arr => arr.Length);
                            fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);
                        }

                        var isPasswordMailToSigner = sessionEnvelope.IsPasswordMailToSigner;
                        if (Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile))
                        {
                            isPasswordMailToSigner = true;
                        }

                        if (sessionEnvelope.PasswordReqdtoOpen == true && isPasswordMailToSigner)
                        {
                            string mailTemlateSenderPwd = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PwOpenForConfirmationEmail, sessionEnvelope.CultureInfo, EmailDisclaimer);
                            mailTemlateSenderPwd = EmailBannerSettings(mailTemlateSenderPwd, allSettingsDetails, Constants.String.MailTemplateName.PwOpenForConfirmationEmail);

                            mailTemlateSenderPwd = SenderConfirmationPwd(sessionEnvelope, mailTemlateSenderPwd, imageLogoURl, senderName, senderEmailAddress);

                            mailTemlateSenderPwd = _genericRepository.AppendFooterText(mailTemlateSenderPwd, Convert.ToString(senderArray[0]), Constants.String.MailTemplateName.PwOpenForConfirmationEmail, sessionEnvelope.CultureInfo, "FinalContractFooter");

                            if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                            {
                                //To Add data in Emailqueue and EmailqueueRecipients for  Sending Confirmation Password Notification
                                EmailQueueProcessor.EmailQueueData emailQueueDatasender = new EmailQueueProcessor.EmailQueueData();
                                EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                                emailQueueDatasender.envelope = sessionEnvelope;
                                emailQueueDatasender.MailMessageBody = mailTemlateSenderPwd;
                                emailQueueDatasender.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                                //emailQueueDatasender.Signer = recipientObject; 
                                emailQueueDatasender.EmailType = Constants.EmailTypes.SCPN;
                                emailQueueDatasender.EmailSubject = GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingPasswordConfirmation);
                                emailSendData.RecipientName = null;
                                emailSendData.RecipientEmail = string.Join(",", senderArray);
                                emailQueueDatasender.emailSendInfo = emailSendData;
                                EmailQueueFunction(emailQueueDatasender, true);
                            }
                            else
                            {
                                var Chilkat = new ChilkatHelper(_appConfiguration);
                                Chilkat.SendMailUsingChilKet(senderArray, null,
                                                  null, null,
                                                  null, null,
                                                  //TODO : change singerdetails to senderdetails at all places
                                                  fromEmailAddress, senderName, GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingPasswordConfirmation), mailTemlateSenderPwd,
                                                  null, null, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.PasswordToOpen, SignReqReplyToAddressValue);
                            }
                        }

                        mailTemlateSender = mailTemlateSender.Replace("#DocSizeMsg", "");

                        mailTemlateSender = _genericRepository.AppendFooterText(mailTemlateSender, Convert.ToString(senderArray[0]), Constants.String.MailTemplateName.SendingConfirmation, sessionEnvelope.CultureInfo, "FinalContractFooter");

                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            //To Add data in Emailqueue and EmailqueueRecipients for SendingConfirmation 
                            EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                            EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                            emailQueueData.envelope = sessionEnvelope;
                            emailQueueData.MailMessageBody = mailTemlateSender;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            //emailQueueData.Signer = recipientObject; 
                            emailQueueData.EmailType = Constants.EmailTypes.SC;
                            emailQueueData.EmailSubject = GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingConfirmation);
                            emailSendData.RecipientName = string.Join(",", senderDisplayName);
                            emailSendData.RecipientEmail = string.Join(",", senderArray);
                            emailQueueData.emailSendInfo = emailSendData;
                            EmailQueueFunction(emailQueueData);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            Chilkat.SendMailUsingChilKet(senderArray, senderDisplayName,
                                    null, null,
                                    null, null,
                                    fromEmailAddress, senderName,
                                    GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingConfirmation), mailTemlateSender,
                                     null, new List<string> { AppendDateTime(intDtFormat, finalDocName) + ".pdf" }, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.SendingConfirmation, SignReqReplyToAddressValue);
                        }
                    }
                }
            }
            loggerModelNew.Message = "Process completed for sending Recipient Mail";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        public bool SignStaticDocument(List<DocumentContents> documentContentDetail, Envelope apiEnvelope, Guid apiRecipientId, string strUserSettings, string envelopeDirectoryPath, out string errorIfFound)
        {
            errorIfFound = string.Empty;
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SignStaticDocument", "Process started for Sign Static Document", apiEnvelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            string currentMethod = "SignStaticDocument";
            string EmailSentType = string.Empty; int RetryCount = 0;
            using (var dbContext = new RSignDbContext(_configuration))
            {
                Guid msgId = Guid.NewGuid();
                int isContractToGenerateFromImages = Constants.FinalContractOptions.Aspose;
                Guid intAttachedsignedPDF = Constants.AttachSignedPDF.SenderSigner;
                var sessionEnvelope = new Envelope();
                sessionEnvelope = apiEnvelope;
                var userProfile = _userRepository.GetUserProfile(apiEnvelope.UserID);
                cultureInfo = sessionEnvelope.CultureInfo;
                var envelopeContentData = dbContext.EnvelopeContent.Where(t => t.EnvelopeID == sessionEnvelope.ID).First();
                var dirPath = envelopeDirectoryPath;// ModelHelper.GetEnvelopeDirectoryNew(sessionEnvelope.ID, string.Empty);
                int SignReqReplyToAddressValue = 1;
                List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();
                /*Update recipients for Out of Office Setting if any*/
                int updatedOutOfOffice = _recipientRepository.UpdateRecipientsforOutOfOffice(sessionEnvelope.ID);

                // original recipient id
                Guid recipientId = apiRecipientId;
                //LogMsg("Recipient Id : " + recipientId);
                Recipients recipientDetail = _recipientRepository.GetEntity(recipientId);
                Guid signerStatusId = _recipientRepository.GetSignerStatusId(recipientId);

                int electronicStampRequired = GetElectronicSignIndicationValueForUser(apiEnvelope.UserID);

                //We require Signature controls for current recipient.
                Envelope envelopeObject = _genericRepository.GetEntity(sessionEnvelope.ID);
                envelopeObject.ElectronicSignIndicationOptionID = electronicStampRequired;
                var documentContents = new List<DocumentContents>();
                foreach (Documents document in sessionEnvelope.Documents)
                    documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == recipientId && d.ControlID == Constants.Control.Signature));
                //if (documentContents.Count == 0)
                SaveSignature(documentContentDetail, documentContents, recipientId, recipientDetail, string.Empty, electronicStampRequired);
                //End save signature control

                loggerModelNew.Email = recipientDetail.EmailAddress;
                loggerModelNew.Message = "Recipient is in process of signing";
                rsignlog.RSignLogInfo(loggerModelNew);
                //Envelope envelopeObject = apiEnvelope;//envelopeRepository.GetEntity(sessionEnvelope.ID);
                Boolean isEnvelopeComplete = false;
                // Fetching the envelope object to check if other signer already signed the document or not while signer revieving the document. [To avoid concurrency problem]
                if (IsEnvelopeComplete(envelopeObject.Recipients.ToList(), recipientId))
                {
                    var envelopeStatus = new EnvelopeStatus();
                    Guid envelopeStatusId = Constants.StatusCode.Envelope.Completed;
                    envelopeStatus.CreatedDateTime = DateTime.Now;
                    envelopeStatus.EnvelopeID = sessionEnvelope.ID;
                    envelopeStatus.ID = Guid.NewGuid();
                    envelopeStatus.StatusID = envelopeStatusId;
                    dbContext.EnvelopeStatus.Add(envelopeStatus);
                    dbContext.SaveChanges();

                    _genericRepository.UpdateEnvelopeStatus(sessionEnvelope.ID, envelopeStatusId);
                    isEnvelopeComplete = true;
                    //--- Update envelopeContent table
                    envelopeContentData = dbContext.EnvelopeContent.Where(t => t.EnvelopeID == sessionEnvelope.ID).First();
                    XDocument doc = XDocument.Parse(envelopeContentData.ContentXML);
                    if (doc != null)
                    {
                        var envelopeStatusElement = doc.Element("Envelope").Elements("EnvelopeStatus").FirstOrDefault();
                        if (envelopeStatusElement != null)
                            envelopeStatusElement.Value = "Completed";
                        envelopeContentData.ContentXML = doc.ToString();
                        SaveEnvelopeContentData(envelopeContentData);
                    }
                    //----
                    //LogMsg("Envelope Completed : true");
                    loggerModelNew.Message = "Envelope is Completed";
                    rsignlog.RSignLogInfo(loggerModelNew);
                }
                else
                    //LogMsg("Envelope Completed : false");

                    // save changes to db
                    if (!IsUnitTestApp)
                    dbContext.SaveChanges();

                var senderDetails = _recipientRepository.GetSenderDetails(sessionEnvelope.ID);
                if (isEnvelopeComplete && Convert.ToBoolean(_appConfiguration["IsSignedDocumentService"]))
                {
                    Guid newSignerStatusId = _recipientRepository.GetSignerPrimaryStatusId(recipientId);

                    _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.SignerStatus, senderDetails.EmailAddress, recipientId.ToString(), newSignerStatusId.ToString(), "", "webhook");

                    if (IsEnvelopeComplete(envelopeObject.Recipients.ToList(), recipientId) && !envelopeObject.IsTemplateShared)
                    {
                        _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.EnvelopeStatus, senderDetails.EmailAddress);

                        _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.EnvelopeCompleted, senderDetails.EmailAddress);
                    }
                    var envelopeContractStatus = new EnvelopeContractStatus
                    {
                        Id = sessionEnvelope.ID,
                        Status = 1,
                        ServerName = System.Environment.MachineName,
                        CreatedDateTime = DateTime.Now
                    };
                    dbContext.EnvelopeContractStatus.Add(envelopeContractStatus);
                    dbContext.SaveChanges();
                }
                else
                {
                    var signerDetails = _recipientRepository.GetEntity(recipientId);
                    int intDtFormat = 0;
                    var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(apiEnvelope.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
                    if (settingsDateTimeFormt != null)
                    {
                        intDtFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);
                    }

                    var replyTosettingsDetails = _settingsRepository.GetEntityForByKeyConfig(apiEnvelope.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
                    if (replyTosettingsDetails != null)
                        SignReqReplyToAddressValue = Convert.ToInt32(replyTosettingsDetails.OptionValue);

                    //Modify last entry of this recipient as completed.
                    Guid envelopeID = apiEnvelope.ID;
                    Guid recipientID = apiRecipientId;
                    bool modifyStatus = false;
                    if (webApiCall)
                        modifyStatus = _recipientRepository.ModifyLastRecipientEntry(recipientID, Constants.StatusCode.Signer.Signed, apiEnvelope.IpAddress);
                    else
                        modifyStatus = _recipientRepository.SaveRecipientDetail(recipientID, Constants.StatusCode.Signer.Signed, apiEnvelope.IpAddress);
                    if (!IsUnitTestApp)
                        dbContext.SaveChanges();

                    // email send to sender
                    if (signerDetails.RecipientTypeID != Constants.RecipientType.Prefill && !isEnvelopeComplete)
                    {
                        AcceptMail(envelopeObject, signerDetails.EmailAddress, signerDetails.Name, senderDetails.Name, senderDetails.EmailAddress, senderDetails.ID, SignReqReplyToAddressValue, senderDetails, signerDetails);
                    }

                    //LogMsg("Document submitted mail for recipient with EmailID : " + recipientDetail.EmailAddress + " send to sender");
                    var senderName = _userRepository.GetUserNameByEmailid(senderDetails.EmailAddress);
                    RecipientMail(envelopeObject, recipientId, senderDetails.EmailAddress, senderName, SignReqReplyToAddressValue);
                    if (isEnvelopeComplete == true)
                    {
                        var dictionary = new Dictionary<EnvelopeNodes, string>
                            {
                                {EnvelopeNodes.IsEnvelopeCompleted, "true"}
                            };
                        _eSignHelper.UpdateEnvelopeXML(sessionEnvelope.ID, dictionary, dirPath);
                        envelopeObject = _genericRepository.GetEntity(sessionEnvelope.ID);
                        //var company = companyRepository.GetCompanyProfileByEnvelopeID(envelopeObject.ID);
                        //int isContractToGenerateFromImages = (company != null) ? Convert.ToInt32(company.FinalContractOptionID) : Constants.FinalContractOptions.Aspose;
                        var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.FinalContractOptionSetting);
                        if (settingsDetails != null)
                            isContractToGenerateFromImages = string.IsNullOrEmpty(settingsDetails.OptionValue) ? Constants.FinalContractOptions.Aspose : Convert.ToInt32(settingsDetails.OptionValue);

                        string EmailDisclaimer = string.Empty;
                        var settingsDetailsEmailDisclaimer = _settingsRepository.GetEntityForByKeyConfig(userProfile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                        if (settingsDetailsEmailDisclaimer != null)
                        {
                            EmailDisclaimer = settingsDetailsEmailDisclaimer.OptionValue.ToString();
                        }
                        var documentPaperSizeSettings = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.DocumentPaperSize);
                        if (documentPaperSizeSettings != null && documentPaperSizeSettings.OptionValue != null && documentPaperSizeSettings.OptionValue.Length > 0)
                            envelopeObject.DocumentPaperSizeID = Convert.ToInt32(documentPaperSizeSettings.OptionValue);

                        var signStampSettingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.StampOnSignerCopySetting);
                        string watermarkAuthText = string.Empty, watermarkBackgroundText = string.Empty;
                        if (signStampSettingsDetails != null)
                        {
                            if (Convert.ToBoolean(signStampSettingsDetails.OptionValue))
                            {
                                settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.StampOnSignerCopyAuthrozieText);
                                watermarkAuthText = settingsDetails != null ? Convert.ToString(settingsDetails.OptionValue) : string.Empty;
                                settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.StampOnSignerCopyWatermarkText);
                                watermarkBackgroundText = settingsDetails != null ? Convert.ToString(settingsDetails.OptionValue) : string.Empty;
                            }
                        }

                        var userSettings = new FinalContractSettings
                        {
                            WatermarkAuthText = watermarkAuthText,
                            WatermarkBackgroundText = watermarkBackgroundText,
                            FinalContractOptions = isContractToGenerateFromImages,
                            UserTimeZone = strUserSettings,
                            IsControlDisplayInTag = false
                        };
                        string finalPdfFilePath = string.Empty; string finalCertificateName = string.Empty;
                        try
                        {
                            finalPdfFilePath = _apiHelper.finalMergePDFApi(envelopeObject, userSettings, dirPath, "", true);
                        }
                        catch (Exception ex)
                        {
                            DeleteContractFileInCaseOfError(envelopeObject.ID, dirPath);
                            if (ex.Message.ToString().ToLower() == "invalid font name")
                                userSettings.FinalContractOptions = Constants.FinalContractOptions.FromImages;
                            else
                                userSettings.FinalContractOptions = Convert.ToInt32(userSettings.FinalContractOptions) != Constants.FinalContractOptions.iText ? Constants.FinalContractOptions.iText : Constants.FinalContractOptions.Aspose;
                            try
                            {
                                finalPdfFilePath = _apiHelper.finalMergePDFApi(envelopeObject, userSettings, dirPath, string.Empty, true);
                            }
                            catch (Exception e)
                            {
                                DeleteContractFileInCaseOfError(envelopeObject.ID, dirPath);

                                string convertedDocDirectory = Path.Combine(dirPath, envelopeObject.ID.ToString(), "Converted");
                                foreach (var file in Directory.GetFiles(convertedDocDirectory))
                                {
                                    if (Path.GetExtension(file) == ".pdf")
                                        _asposeHelper.TransformPDFFromDocxAndCopyToDestination(Path.Combine(convertedDocDirectory, file), convertedDocDirectory, Path.Combine(convertedDocDirectory, Path.GetFileNameWithoutExtension(file) + ".pdf"));
                                }
                                userSettings.FinalContractOptions = Constants.FinalContractOptions.Aspose;
                                finalPdfFilePath = _apiHelper.finalMergePDFApi(envelopeObject, userSettings, dirPath, string.Empty, true);
                            }
                        }
                        //LogMsg("Final document created at path : " + finalPdfFilePath);
                        loggerModelNew.Message = "Final document created at path : " + finalPdfFilePath;
                        rsignlog.RSignLogInfo(loggerModelNew);

                        //asposeHelper = new AsposeHelper();
                        iText7Helper iTextHelper = new iText7Helper(_appConfiguration);
                        string tempEnvelopeDir = Path.Combine(dirPath, Convert.ToString(envelopeID));
                        string SignerDocDir = dirPath + envelopeObject.ID + "\\SignerAttachments";
                        string finalTransperancyPath = string.Empty;
                        string finalSignerAttachFilePath = string.Empty;
                        byte[] xmlattachment = null;
                        string xmlfilepath = string.Empty;
                        string xmlfileName = "Envelope.xml";
                        if (envelopeObject.IsTransparencyDocReq)
                            finalTransperancyPath = _apiHelper.GetTransperancyDocument(tempEnvelopeDir, envelopeObject);
                        if (Directory.Exists(SignerDocDir))
                        {
                            var file = Directory.GetFiles(SignerDocDir, "*", SearchOption.AllDirectories).FirstOrDefault();
                            if (file != null)
                            {
                                string signerattchzip = Path.Combine(SignerDocDir, "SignerDoc.zip");
                                if (file.Contains("SignerDoc.zip"))
                                {
                                    System.IO.File.Delete(signerattchzip);
                                }
                            }
                            if (envelopeObject.IsSignerAttachFileReq > 0 && file != null)
                                finalSignerAttachFilePath = _apiHelper.GetRecipientDocumentZip(SignerDocDir);
                        }
                        if (envelopeObject.IsAttachXML == true)
                        {
                            EnvelopeContent envelopeContent = CreateXml(envelopeObject);
                            xmlfilepath = _eSignHelper.CreateXmlFileToSend(envelopeObject, envelopeContent);
                            xmlattachment = File.ReadAllBytes(xmlfilepath);
                        }

                        string passwordToTransp = null;

                        if (envelopeObject.PasswordReqdtoOpen && envelopeObject.IsTransparencyDocReq)
                        {
                            passwordToTransp = ModelHelper.Decrypt(envelopeObject.PasswordtoOpen, envelopeObject.PasswordKey, (int)envelopeObject.PasswordKeySize);
                            _asposeHelper.EncryptPdfFile(finalTransperancyPath, passwordToTransp, passwordToTransp, finalTransperancyPath);
                        }
                        if (envelopeObject.IsTransparencyDocReq && !string.IsNullOrEmpty(finalTransperancyPath)
                            && System.IO.File.Exists(finalTransperancyPath)
                            && _asposeHelper.IsFileEligibleForDigitallySign(finalTransperancyPath, (!envelopeObject.PasswordReqdtoOpen ? string.Empty : passwordToTransp)))
                        {
                            //Add Digital Signature On Transparency Document
                            var dirTransp = System.IO.Path.GetDirectoryName(finalTransperancyPath);
                            var tempTranspPath = (dirTransp + "\\" + System.IO.Path.GetFileNameWithoutExtension(finalTransperancyPath) + "_T.pdf");
                            System.IO.File.Move(finalTransperancyPath, tempTranspPath);
                            iTextHelper.AddDigitalSignatureToTheDocument(tempTranspPath,
                                    (!envelopeObject.PasswordReqdtoOpen ? string.Empty : passwordToTransp),
                                    finalTransperancyPath);
                            if (File.Exists(tempTranspPath))
                                File.Delete(tempTranspPath);
                        }

                        //string certificatePath = Path.Combine(Convert.ToString(_appConfiguration["ContentFolderPath"]), "certificate", Convert.ToString(_appConfiguration["CertificateName"]));
                        string certificatePath = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), "certificate");
                        certificatePath = Path.Combine(certificatePath, Convert.ToString(_appConfiguration["CertificateName"]));
                        byte[] finalMergedArray = System.IO.File.ReadAllBytes(finalPdfFilePath);
                        string documentFolderPath = Path.Combine(dirPath, Convert.ToString(envelopeObject.ID), "EnvOutput.pdf");
                        string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                        imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
                        string documentHash = _eSignHelper.GetHashSha256(documentFolderPath);
                        envelopeObject.DocumentHash = documentHash;
                        if (envelopeObject.PasswordReqdtoOpen)
                            envelopeObject.PasswordtoOpen = ModelHelper.Decrypt(envelopeObject.PasswordtoOpen, envelopeObject.PasswordKey, (int)envelopeObject.PasswordKeySize);
                        if (envelopeObject.PasswordReqdtoSign)
                            envelopeObject.PasswordtoSign = ModelHelper.Decrypt(envelopeObject.PasswordtoSign, envelopeObject.PasswordKey, (int)envelopeObject.PasswordKeySize);
                        envelopeObject.IsDisclaimerAccepted = !string.IsNullOrEmpty(envelopeObject.DisclaimerText);
                        _genericRepository.Save(envelopeObject);

                        var attachementSizeCalc = new List<byte[]>();
                        var attachements = new List<byte[]>();
                        var attachementsWithTransperancy = new List<byte[]>();
                        var docNamesWithTransperancy = new List<string>();
                        var attachementsSigner = new List<byte[]>();
                        string fileNameFileReview = string.Empty;
                        byte[] attachementFileReview = new byte[0];
                        if (envelopeObject.IsWaterMark == true)
