        #region GetImages
        public bool PrepareEnvelopeDocumentsFromStaticTemplate(Guid templateID, Guid envelopeID, string envelopeFolderUNCPath, string templateFolderUNCPath, bool IsRuleConsumed = false)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "PrepareEnvelopeDocumentsFromStaticTemplate", "Intializing process for Prepare Envelope Documents From StaticTemplate", envelopeID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                //Each new static envelope will be created on new path
                var envelopeDirectoryPath = envelopeFolderUNCPath;// ConfigurationManager.AppSettings["TempDirectory"];
                var templateDirectoryPath = templateFolderUNCPath;

                string staticTemplateDocPath = Path.Combine(templateDirectoryPath, templateID.ToString());//eSignHelper.GetUploadedDocumentsFolderPath(templateID);
                string staticEnvelopeDocPath = Path.Combine(envelopeDirectoryPath, envelopeID.ToString());//eSignHelper.GetUploadedDocumentsFolderPath(envelopeID);
                foreach (string dirPath in Directory.GetDirectories(staticTemplateDocPath, "*",
                    SearchOption.AllDirectories))
                    Directory.CreateDirectory(dirPath.Replace(staticTemplateDocPath, staticEnvelopeDocPath));

                if (!Directory.Exists(staticEnvelopeDocPath))
                    Directory.CreateDirectory(staticEnvelopeDocPath);

                //Copy all the files & Replaces any files with the same name
                foreach (string newPath in Directory.GetFiles(staticTemplateDocPath, "*.*",
                    SearchOption.AllDirectories))
                    File.Copy(newPath, newPath.Replace(staticTemplateDocPath, staticEnvelopeDocPath), true);

                // Deleting the as we are copying the all files to New Envelope after consuming rule
                if (IsRuleConsumed)
                {
                    System.IO.DirectoryInfo diEnvelope = new DirectoryInfo(staticTemplateDocPath);
                    foreach (FileInfo file in diEnvelope.GetFiles())
                    {
                        file.Delete();
                    }
                    foreach (DirectoryInfo dir in diEnvelope.GetDirectories())
                    {
                        dir.Delete(true);
                    }
                }

                loggerModelNew.Message = "Process completed for Prepare Envelope Documents From StaticTemplate";
                rsignlog.RSignLogInfo(loggerModelNew);
                return true;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.ToString();
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw ex;
            }
        }
        public List<DocumentContents> GetDocumentContents(List<DocumentContentDetails> documentContentDetails)
        {
            List<DocumentContents> documentContents = new List<DocumentContents>();
            if (documentContentDetails != null)
            {
                foreach (var tempContent in documentContentDetails)
                {
                    DocumentContents documentContent = new DocumentContents();
                    documentContent.ID = tempContent.ID;
                    documentContent.ControlID = tempContent.ControlID;
                    documentContent.DocumentID = tempContent.DocumentID;
                    documentContent.RecipientID = tempContent.RecipientID;
                    documentContent.ControlHtmlID = tempContent.ControlHtmlID;
                    documentContent.Required = tempContent.Required;
                    documentContent.DocumentPageNo = tempContent.DocumentPageNo;
                    documentContent.PageNo = tempContent.PageNo;
                    documentContent.XCoordinate = tempContent.XCoordinate;
                    documentContent.YCoordinate = tempContent.YCoordinate;
                    documentContent.ZCoordinate = tempContent.ZCoordinate;
                    documentContent.ControlValue = tempContent.ControlValue;
                    documentContent.Label = tempContent.Label;
                    documentContent.Height = tempContent.Height;
                    documentContent.Width = tempContent.Width;
                    documentContent.GroupName = tempContent.GroupName;
                    documentContent.ControlHtmlData = tempContent.ControlHtmlData;
                    documentContent.ControHtmlData = tempContent.ControlHtmlData;
                    documentContent.RecName = tempContent.RecipientName;
                    documentContent.IsControlDeleted = false;
                    documentContent.LeftIndex = tempContent.LeftIndex;
                    documentContent.TopIndex = tempContent.TopIndex;
                    documentContent.SenderControlValue = tempContent.SenderControlValue;
                    documentContent.ControlName = (tempContent.ID == Guid.Empty
                        && !string.IsNullOrEmpty(tempContent.ControlValue)
                        && (tempContent.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || tempContent.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || tempContent.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())) ? Constants.String.SignatureControlName : null;
                    documentContent.LeftIndex = tempContent.LeftIndex;
                    documentContent.TopIndex = tempContent.TopIndex;
                    documentContent.IsDefaultRequired = tempContent.IsDefaultRequired;
                    documentContent.CustomToolTip = tempContent.CustomToolTip;
                    documentContent.FontTypeMeasurement = tempContent.FontTypeMeasurement;
                    documentContent.IsFixedWidth = tempContent.IsFixedWidth == null ? true : Convert.ToBoolean(tempContent.IsFixedWidth) ? true : false;
                    if (!string.IsNullOrEmpty(tempContent.MaxLength))
                        documentContent.MaxLength = new Guid(tempContent.MaxLength);
                    if (!string.IsNullOrEmpty(tempContent.TextType))
                        documentContent.ControlType = new Guid(tempContent.TextType);
                    if (tempContent.ControlStyle != null)
                    {
                        ControlStyle controlStyle = new ControlStyle();
                        controlStyle.DocumentContentId = documentContent.ID;
                        controlStyle.FontID = tempContent.ControlStyle.FontID;
                        controlStyle.FontSize = tempContent.ControlStyle.FontSize;
                        controlStyle.FontColor = tempContent.ControlStyle.FontColor;
                        controlStyle.IsBold = tempContent.ControlStyle.IsBold;
                        controlStyle.IsItalic = tempContent.ControlStyle.IsItalic;
                        controlStyle.IsUnderline = tempContent.ControlStyle.IsUnderline;
                        documentContent.ControlStyle = controlStyle;
                    }
                    if (tempContent.SelectControlOptions != null)
                    {
                        documentContent.ControlOptions = new List<SelectControlOptions>();
                        foreach (var tempOption in tempContent.SelectControlOptions)
                        {
                            documentContent.ControlOptions.Add(new SelectControlOptions
                            {
                                ID = tempOption.ID,
                                DocumentContentID = documentContent.ID,
                                OptionText = tempOption.OptionText,
                                Order = (byte)tempOption.Order
                            });
                        }
                    }
                    documentContents.Add(documentContent);
                }
            }
            return documentContents;
        }
        public EnvelopeInfo GetEnvelopeImageInfoByRecipientGroup(Envelope envelope, Guid recipientId, Guid envelopeTemplateGroupId, string envelopeDirectoryUNCPath)
        {
            string envelopeCode = envelope != null && !string.IsNullOrEmpty(envelope.EDisplayCode) ? envelope.ID.ToString() : envelope.EDisplayCode;
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GetEnvelopeImageInfoByRecipientGroup", "Process started for Get Envelope Image Information By Recipient Group", envelope.EDisplayCode, "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                EnvelopeInfo controlsInfo = new EnvelopeInfo();
                var sessionEnvelope = envelope;

                // Put Document images information in session variable
                string imagesPath = _eSignHelper.GetImagesFolderPath(sessionEnvelope.ID, envelopeDirectoryUNCPath);
                DirectoryInfo dirInfo = new DirectoryInfo(imagesPath);
                if (dirInfo.GetFiles().Count() <= 0)
                    return null;
                Dictionary<Guid, string> envelopeDocumentsByOrder = new Dictionary<Guid, string>();
                foreach (var doc in envelope.Documents.Where(d => d.EnvelopeTemplateGroupID == envelopeTemplateGroupId).OrderBy(o => o.Order).ThenBy(o => o.DocumentName))
                    envelopeDocumentsByOrder.Add(doc.ID, doc.DocumentName);
                //List<string> documentImageList;
                List<EnvelopeImageInformation> documentImageData = new List<EnvelopeImageInformation>();
                foreach (var doc in envelopeDocumentsByOrder)
                {
                    dirInfo = new DirectoryInfo(imagesPath);
                    var files = dirInfo.GetFiles(Path.GetFileNameWithoutExtension(doc.Value) + "_*.png")
                        .Where(item => Path.GetFileNameWithoutExtension(doc.Value) + "_" + Regex.Match(Path.GetFileNameWithoutExtension(item.ToString()), @"\d+$").Value == Path.GetFileNameWithoutExtension(item.ToString()))
                        .OrderBy(o => o.Name).Select(s => s.Name).ToList();
                    if (files.Count == 0)
                    {
                        files = dirInfo.GetFiles(Path.GetFileNameWithoutExtension(doc.Value) + "_*.jpg")
                            .Where(item => Path.GetFileNameWithoutExtension(doc.Value) + "_" + Regex.Match(Path.GetFileNameWithoutExtension(item.ToString()), @"\d+$").Value == Path.GetFileNameWithoutExtension(item.ToString()))
                            .OrderBy(o => o.Name).Select(s => s.Name).ToList();
                    }
                    documentImageData.AddRange(
                        files.Select(file =>
                        new EnvelopeImageInformation
                        {
                            Id = int.Parse(file.Substring(file.LastIndexOf('_') + 1, file.LastIndexOf('.') - 1 - file.LastIndexOf('_'))), //// Image real id
                            Document = GetDocumentInfo(file.Substring(0, file.LastIndexOf('_')), envelopeDocumentsByOrder),
                            Dimension = GetDimensions(Path.Combine(imagesPath, file)), //changes done for unit test
                            ImagePath = Path.Combine(imagesPath, file).Replace(@"\", "/"),
                        }).OrderBy(order => order.Id).ToList());
                }
                var docName = documentImageData[0].Document.Name;
                int docPageNo = 1;
                int pageNo = 1;
                foreach (var docInfo in documentImageData)
                {
                    if (docInfo.Document.Name == docName)
                    {
                        docInfo.DocPageNo = docPageNo;
                        docInfo.PageNo = pageNo++;
                        docPageNo++;
                    }
                    else
                    {
                        docName = docInfo.Document.Name;
                        docPageNo = 1;
                        docInfo.DocPageNo = docPageNo;
                        docInfo.PageNo = pageNo++;
                        docPageNo++;
                    }
                }
                IEnumerable<Recipients> recipients = sessionEnvelope.Recipients.Where(x => x.EnvelopeTemplateGroupID == envelopeTemplateGroupId && (x.RecipientTypeID == Constants.RecipientType.Signer) || (x.RecipientTypeID == Constants.RecipientType.Prefill)).ToList(); // V2 Team Prefill Change
                Dictionary<Guid, string> resultRecipients = recipients.ToDictionary(x => x.ID, x => x.Name.ToString());

                var fonts = _lookupRepository.GetLookup(Lookup.Fonts).OrderBy(fn => fn.Value);
                Dictionary<string, string> resultFonts = fonts.ToDictionary(x => x.Key, x => x.Value);

                IEnumerable<int> fontSizes = _eSignHelper.GetFontSize().Select(x => x).ToList();
                var controlType = _lookupRepository.GetLookupMasterLanguage(Lookup.MasterLanguageKeyDetails, envelope.CultureInfo, Lookup.TextType.ToString());
                var maxChar = _lookupRepository.GetLookup(Lookup.MaxCharacters);
                Dictionary<string, string> maxCharacter = maxChar.ToDictionary(x => x.Key, x => x.Value);
                Dictionary<string, string> textType = controlType.ToDictionary(x => x.Key.ToString(), x => x.Value.ToString());
                ConditionalControlRules conditionalControlRules = new ConditionalControlRules();
                conditionalControlRules.TextRules = DropdownFiller(_lookupRepository.GetLookup(Lookup.TextConditions, envelope.CultureInfo));
                conditionalControlRules.InitialRules = DropdownFiller(_lookupRepository.GetLookup(Lookup.InitialConditions, envelope.CultureInfo));
                conditionalControlRules.CheckBoxRules = DropdownFiller(_lookupRepository.GetLookup(Lookup.CheckboxConditions, envelope.CultureInfo));
                controlsInfo = new EnvelopeInfo
                {
                    RecipientTypeId = Constants.RecipientType.Signer,
                    SignersList = resultRecipients,
                    FontsList = resultFonts,
                    FontSizes = fontSizes,
                    EnvelopeImageCollection = documentImageData,
                    MaxCharacters = maxCharacter,
                    TextTypes = textType,
                    GlobalEnvelopeID = envelope.ID,
                    ConditionalControlRules = conditionalControlRules
                };
                loggerModelNew.Message = "Get Envelope Image Information End with Success";
                rsignlog.RSignLogInfo(loggerModelNew);
                return controlsInfo;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error Occured: " + ex;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }
        }
