        public DocumentInfo GetDocumentInfo(string name, Dictionary<Guid, string> dicDocuments)
        {
            try
            {
                var docData = dicDocuments.FirstOrDefault(drc => Path.GetFileNameWithoutExtension(drc.Value) == name);
                return new DocumentInfo { Id = docData.Key, Name = docData.Value };
            }
            catch (Exception ex)
            {
                throw;
            }
        }
        public Dimension GetDimensions(string filepath)
        {
            using (var selectedImg = System.Drawing.Image.FromFile(filepath))
            {
                var dimension = new Dimension { Height = selectedImg.Height, Width = selectedImg.Width };
                return dimension;
            }
        }
        public List<string> GetSignerDocFromDirectory(Guid EnvelopeID, Guid RecipientID, string envelopeDirectoryUNCPath)
        {
            try
            {
                List<string> lstFiles = new List<string>();
                var dirPath = envelopeDirectoryUNCPath + EnvelopeID;
                var uploadedDirectory = dirPath + "\\SignerAttachments\\" + RecipientID;
                if (Directory.Exists(uploadedDirectory))
                {
                    lstFiles = Directory.EnumerateFiles(uploadedDirectory, "*", SearchOption.AllDirectories).Select(Path.GetFileName).OrderBy(x => x).ToList();
                }
                if (RecipientID != Guid.Empty)
                {
                    Guid tempRecipientID = Guid.Empty;
                    uploadedDirectory = dirPath + "\\SignerAttachments\\" + tempRecipientID;
                    if (Directory.Exists(uploadedDirectory))
                    {
                        lstFiles.AddRange(Directory.EnumerateFiles(uploadedDirectory, "*", SearchOption.AllDirectories).Select(Path.GetFileName).OrderBy(x => x).ToList());
                    }
                }
                return lstFiles;
            }
            catch (Exception e)
            {
                //Elmah.ErrorSignal.FromCurrentContext().Raise(e);
                return new List<string>();
            }
        }
