        #region BotClicks
        public int IsBotClick(string ipAddress, string userAgent)
        {
            #region Identify is Bot Click
            int botClickVal = 1;
            var rpostRestService = new RpostRestService(_appConfiguration);
            BotClickDataModal botClickDataModal = new BotClickDataModal() { IPAddress = ipAddress, UserAgent = userAgent, Domain = "", Network = "" };
            HttpResponseMessage response = rpostRestService.ValidateBotClick(botClickDataModal);
            if (!_eSignHelper.IsFailureStatusCode(response.StatusCode))
            {
                botClickVal = 2;
            }
            else if (response.StatusCode == HttpStatusCode.OK)
            {
                var botClickResult = JsonConvert.DeserializeObject<ValidateBotClickResponseMessage>(response.Content.ReadAsStringAsync().Result);
                if (botClickResult != null && botClickResult.ResultContent != null && botClickResult.ResultContent.IsBotClick)
                {
                    botClickVal = 3;
                }
            }
            #endregion Identify is Bot Click
            return botClickVal;
        }
        #endregion BotClicks

