        public void SaveShortUrlForSMS(Envelope sessionEnvelope, string strURLWithData, string signingShortURL, string shortUriCode, bool isEnvelopeCompleted)
        {
            LoggerModelNew loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SaveShortUrlForSMS", "process started for Save Short Url For SMS", "", "", "", "", "API");
            RSignLogger rSignLogger = new RSignLogger();
            rSignLogger.RSignLogInfo(loggerModelNew);
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    SigningShortURL signingShortObj = new SigningShortURL();
                    signingShortObj.EnvelopeID = sessionEnvelope.ID;
                    signingShortObj.EDisplayCode = sessionEnvelope.EDisplayCode;
                    signingShortObj.SigningURI = strURLWithData;
                    signingShortObj.ShortURI = signingShortURL;
                    signingShortObj.ShortURICode = shortUriCode;
                    signingShortObj.IsEnvelopeCompleted = isEnvelopeCompleted;
                    signingShortObj.CreatedDate = DateTime.UtcNow;
                    dbContext.SigningShortURL.Add(signingShortObj);
                    dbContext.SaveChanges();
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Saving short url is failed and message is " + ex.ToString();
                rSignLogger.RSignLogWarn(loggerModelNew);
                throw ex;
            }
        }
        public bool SendMobileSMS(Envelope sessionEnvelope, string mobileTemplatepassword, string signerMobileNumber, Template template = null)
        {
            LoggerModelNew loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SendMobileSMS", "Sending sms to recipient mobile: " + signerMobileNumber, "", "", "", "", "SendMobileSMS");
            RSignLogger rSignLogger = new RSignLogger();
            rSignLogger.RSignLogInfo(loggerModelNew);

            try
            {
                List<SendMobileSMSModel> lstPasswordModal = new List<SendMobileSMSModel>();
                SendMobileSMSModel sendMobileSMSModel = new SendMobileSMSModel();
                sendMobileSMSModel.message = mobileTemplatepassword;
                sendMobileSMSModel.referenceId = sessionEnvelope != null ? Convert.ToString(sessionEnvelope.EDisplayCode) : Convert.ToString(template.ID);
                sendMobileSMSModel.to = signerMobileNumber;
                lstPasswordModal.Add(sendMobileSMSModel);
                bool smsStatus = SendMobileSMSThroughSMSService(lstPasswordModal);
                if (smsStatus)
                {
                    loggerModelNew.Message = "Sending sms to " + signerMobileNumber + " is success.";
                    rSignLogger.RSignLogInfo(loggerModelNew);
                    return true;
                }
                else
                {
                    loggerModelNew.Message = "Sending sms to " + signerMobileNumber + " is failed.";
                    rSignLogger.RSignLogWarn(loggerModelNew);
                    return false;
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "There is a exception with sending sms and error message is:" + ex.ToString();
                rSignLogger.RSignLogWarn(loggerModelNew);
                return false;
            }
        }
        public void SendSMSThroughEmailService(Envelope sessionEnvelope, string mobileTemplatepassword, int signReqReplyToAddressValue, string emailTypeVal, Recipients signer, string emailSubject)
        {
            //To Add data in Emailqueue and EmailqueueRecipients for submit (Electronic Signature Password Notification) *
            EmailQueueData emailQueueData = new EmailQueueData();
            EmailSendInfo emailSendData = new EmailSendInfo();
            emailQueueData.envelope = sessionEnvelope;
            emailQueueData.MailMessageBody = mobileTemplatepassword;
            emailQueueData.SignReqReplyToAddressValue = signReqReplyToAddressValue;
            emailQueueData.EmailType = emailTypeVal;
            emailQueueData.EmailSubject = emailSubject;
            emailSendData.RecipientName = signer.Name;
            emailSendData.RecipientEmail = "";
            emailSendData.RecipientMobile = signer.DialCode + signer.Mobile;
            emailQueueData.emailSendInfo = emailSendData;
            EmailQueueFunction(emailQueueData, true);
        }
        public void SendTemplateSMSTThroughEmailService(Template template, string mobileTemplatepassword, int signReqReplyToAddressValue, string emailTypeVal, string signerMobile, string emailSubject, UserProfile userprofile)
        {
            EmailQueueData emailQueueData = new EmailQueueData();
            EmailSendInfo emailSendData = new EmailSendInfo();
            Recipients Senderrecipients = new Recipients();
            Senderrecipients.Name = userprofile.FirstName;
            Senderrecipients.EmailAddress = userprofile.EmailID;
            emailQueueData.template = template;
            emailQueueData.MailMessageBody = mobileTemplatepassword;
            emailQueueData.SignReqReplyToAddressValue = signReqReplyToAddressValue;
            emailQueueData.EmailType = Constants.EmailTypes.ESPN;
            emailQueueData.EmailSubject = emailSubject;
            emailSendData.RecipientName = "";
            emailSendData.RecipientEmail = "";
            emailSendData.RecipientMobile = signerMobile;
            emailQueueData.emailSendInfo = emailSendData;
            emailQueueData.Signer = Senderrecipients;
            EmailQueueTemplateFunction(emailQueueData);
        }
        public bool SendMobileSMSThroughSMSService(List<SendMobileSMSModel> sendMobileSMSModelData)
        {
            LoggerModelNew loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SendMobileSMSThroughSMSService", "Sending sms to recipient mobile: " + sendMobileSMSModelData[0].to, "", "", "", "", "SendMobileSMSThroughSMSService");
            RSignLogger rSignLogger = new RSignLogger();
            rSignLogger.RSignLogInfo(loggerModelNew);
            bool isSuccess = true;
            try
            {
                MobileSMSService mobileSMSService = new MobileSMSService(_appConfiguration);
                HttpResponseMessage validateResponse = mobileSMSService.AuthticateMobileService();
                if (!_eSignHelper.IsFailureStatusCode(validateResponse.StatusCode))
                {
                    isSuccess = false;
                    loggerModelNew.Message = "There is a problem with AuthticateMobileService and status is false and message is: " + validateResponse.ReasonPhrase;
                    rSignLogger.RSignLogWarn(loggerModelNew);
                }
                else if (validateResponse.StatusCode == HttpStatusCode.OK)
                {
                    loggerModelNew.Message = "AuthticateMobileService is success.";
                    rSignLogger.RSignLogInfo(loggerModelNew);

                    var validTokenModel = JsonConvert.DeserializeObject<AccessTokenModel>(validateResponse.Content.ReadAsStringAsync().Result);
                    if (validTokenModel != null && validTokenModel.accessToken != null && validTokenModel.accessToken.statusCode == HttpStatusCode.OK && validTokenModel.accessToken.token != null)
                    {
                        HttpResponseMessage response = mobileSMSService.SendMobileSMS(sendMobileSMSModelData, validTokenModel.accessToken.token);
                        if (response.StatusCode == HttpStatusCode.OK)
                        {
                            isSuccess = true;
                            loggerModelNew.Message = "SMS Success: Sending sms is success for " + sendMobileSMSModelData[0].to + "and reference id is:" + sendMobileSMSModelData[0].referenceId;
                            rSignLogger.RSignLogWarn(loggerModelNew);
                        }
                        else
                        {
                            isSuccess = false;
                            loggerModelNew.Message = "SMS Failed: Sending sms is failed for " + sendMobileSMSModelData[0].to + " and reference id is:" + sendMobileSMSModelData[0].referenceId + " and message is: " + response.ReasonPhrase;
                            rSignLogger.RSignLogWarn(loggerModelNew);
                        }
                    }
                    else
                    {
                        isSuccess = false;
                        loggerModelNew.Message = "Getting validTokenModel is failed for " + sendMobileSMSModelData[0].to + " and reference id is:" + sendMobileSMSModelData[0].referenceId;
                        rSignLogger.RSignLogWarn(loggerModelNew);
                    }
                }
            }
            catch (Exception ex)
            {
                isSuccess = false;
                loggerModelNew.Message = "Getting exception in SendMobileSMSThroughSMSService method while sending sms to " + sendMobileSMSModelData[0].to + " and error message is:" + ex.ToString();
                rSignLogger.RSignLogWarn(loggerModelNew);
            }
            return isSuccess;
        }
        public bool SendMobileSMSThroughEmailServiceSMSService(List<SendMobileSMSModel> sendMobileSMSModelData)
        {
            return SendMobileSMSThroughSMSService(sendMobileSMSModelData);
        }
