        public string CreateVerificationCodeMailTemplate(Envelope envelope, string imageLogoURl, string fromEmailId, string userName, Recipients signer, string firstName, string mailTemplate, string signerEmail = "", string SigneruserName = "", string VerificationCode = "")
        {
            mailTemplate = mailTemplate.Replace("#SenderName", userName);
            mailTemplate = mailTemplate.Replace("#SenderEmailId", fromEmailId);
            mailTemplate = mailTemplate.Replace("#RecipientName", firstName);
            mailTemplate = mailTemplate.Replace("#SignerName", string.IsNullOrEmpty(SigneruserName) ? signer.Name : SigneruserName);

            string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signer.DeliveryMode, signer.EmailAddress, signer.DialCode, signer.Mobile);
            mailTemplate = mailTemplate.Replace("#SignerEmailId", emailMobileNumberDetails);

            //bool isMobileSend = false;
            //if ((signer.DeliveryMode == 2 || signer.DeliveryMode == 3) && !string.IsNullOrEmpty(signer.Mobile))
            //{
            //    isMobileSend = true;
            //}
            //if (isMobileSend)
            //{
            //    if (signer.DeliveryMode == 2)
            //        mailTemplate = mailTemplate.Replace("#SignerEmailId", signer.EmailAddress + ", " + signer.DialCode + signer.Mobile);
            //    else
            //        mailTemplate = mailTemplate.Replace("#SignerEmailId", signer.DialCode + signer.Mobile);
            //}
            //else
            //    mailTemplate = mailTemplate.Replace("#SignerEmailId", string.IsNullOrEmpty(signerEmail) ? signer.EmailAddress : signerEmail);

            mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", !string.IsNullOrEmpty(Convert.ToString(envelope.EDisplayCode)) ? Convert.ToString(envelope.EDisplayCode) : "");
            mailTemplate = mailTemplate.Replace("#VerificationCode", VerificationCode);
            mailTemplate = mailTemplate.Replace("#clientLogo", string.Empty);
            return mailTemplate;
        }
        public List<DialingCountryCodes> LoadDialingCountryCodes()
        {
            using (var dbContext = new RSignDbContext(_configuration))
            {
                List<DialingCountryCodes> updatedLstDailingCountryOptions = new List<DialingCountryCodes>();
                var lstDailingCountryOptions = dbContext.DialingCountryCodes.Where(r => r.IsActive == true).OrderBy(c => c.CountryName).ToList();
                if (lstDailingCountryOptions != null && lstDailingCountryOptions.Count > 0)
                {
                    var item = lstDailingCountryOptions.Where(c => c.CountryName == "Select").FirstOrDefault();
                    lstDailingCountryOptions = lstDailingCountryOptions.Where(c => c.CountryName != "Select").OrderBy(c => c.CountryName).ToList();
                    if (item != null)
                        updatedLstDailingCountryOptions.Add(item);
                    updatedLstDailingCountryOptions.AddRange(lstDailingCountryOptions);
                }
                return updatedLstDailingCountryOptions;
            }
        }
