        #region Finish Later Reminder Email
        public bool SendFinishLaterReminderEmail(Envelope envelope, string urlForFinishLater, Recipients recipint, Recipients sender)
        {
            LoggerModelNew loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SendFinishLaterReminderEmail", "Process started for Send Finish Later Reminder Email ", "", "", "", "", "API");
            RSignLogger rsignlog = new RSignLogger();
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                string recpEmailMobileAddress = "";
                string EmailDisclaimer = string.Empty;
                int DisclaimerLocationId = Constants.DisclaimerLocation.BottomOfEmail;
                var envelopeSettingObject = new EnvelopeSettingsDetail();
                int SignReqReplyToAddressValue = 1;
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    var userprofile = _userRepository.GetUserProfile(envelope.UserID); ;
                    var imageLogoURl = _appConfiguration["domain"].ToString() + "Content/img/RMail-100.png";
                    AdminGeneralAndSystemSettings allSettingsDetails = GetAllSettingsDetails(envelope.UserID, userEmail);
                    if (allSettingsDetails.ShowRSignLogo != true)
                        imageLogoURl = "";

                    var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                    if (settingsDetails != null)
                        EmailDisclaimer = Convert.ToString(settingsDetails.OptionValue);
                    settingsDetails = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.DisclaimerLocation);
                    if (settingsDetails != null)
                        DisclaimerLocationId = Convert.ToInt32(settingsDetails.OptionValue);
                    envelopeSettingObject = dbContext.EnvelopeSettingsDetail.Where(e => e.EnvelopeId == envelope.ID).FirstOrDefault();
                    if (envelopeSettingObject != null)
                        SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

                    //if (!string.IsNullOrEmpty(recipint.EmailAddress) && !string.IsNullOrEmpty(recipint.Mobile) && recipint.DeliveryMode == 2)
                    //    recpEmailMobileAddress = recipint.EmailAddress + ", " + recipint.DialCode + recipint.Mobile;
                    //else if (!string.IsNullOrEmpty(recipint.EmailAddress) && recipint.DeliveryMode == 1)
                    //    recpEmailMobileAddress = recipint.EmailAddress;
                    //else if (!string.IsNullOrEmpty(recipint.Mobile) && recipint.DeliveryMode == 3)
                    //    recpEmailMobileAddress = recipint.DialCode + recipint.Mobile;
                    //else if (!string.IsNullOrEmpty(recipint.EmailAddress))
                    //    recpEmailMobileAddress = recipint.EmailAddress;

                    recpEmailMobileAddress = _asposeHelper.AppendSignerEmailMobileDetails(recipint.DeliveryMode, recipint.EmailAddress, recipint.DialCode, recipint.Mobile);

                    //if (Convert.ToBoolean(envelope.EnableMessageToMobile))
                    //{
                    //    if ((recipint.DeliveryMode == 1 || recipint.DeliveryMode == 2) && !string.IsNullOrEmpty(recipint.EmailAddress)) isEmailSend = true;
                    //    if ((recipint.DeliveryMode == 2 || recipint.DeliveryMode == 3) && !string.IsNullOrEmpty(recipint.DialCode) && !string.IsNullOrEmpty(recipint.Mobile)) isMobileSend = true;
                    //    if (recipint.DeliveryMode == null) isEmailSend = true;
                    //}
                    //else isEmailSend = true;

                    bool isEmailSend = false, isPwdEmailSend = false;
                    bool isMobileSend = false, isPwdMobileSend = false;
                    var isPasswordMailToSigner = envelope.IsPasswordMailToSigner;

                    if (Convert.ToBoolean(envelope.EnableMessageToMobile))
                    {
                        GetEmailDeiliveryModeOptions(recipint, ref isEmailSend, ref isMobileSend);
                        GetMobileDeiliveryModeOptions(recipint, ref isPwdEmailSend, ref isPwdMobileSend);
                    }
                    else
                    {
                        isPwdEmailSend = true;
                        isEmailSend = true;
                    }

                    string strURLWithData = "";
                    bool applyNewSigningUrl = IsGenerateNewSigningUrl(sender.EmailAddress);
                    if (applyNewSigningUrl)
                        strURLWithData = Convert.ToString(_appConfiguration["NewSigningURL"]) + "/signer-landing?";
                    else
                        strURLWithData = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/Index?";

                    if (Convert.ToBoolean(envelope.IsSignerIdentitiy) && recipint.RecipientTypeID != Constants.RecipientType.CC)
                    {
                        if (applyNewSigningUrl)
                            strURLWithData = Convert.ToString(_appConfiguration["NewSigningURL"]) + "/authenticate-signer?";
                        else
                            strURLWithData = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/AuthenticateSigner?";
                    }
                    Guid? templateKey = envelope.TemplateKey;
                    if (templateKey != null)
                        strURLWithData = strURLWithData + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&RecipientId={1}&TemplateKey={2}&EmailId={3}&SignerType={4}&CopyMailId={5}", envelope.ID, recipint.ID, templateKey, HttpUtility.UrlEncode(recipint.EmailAddress), "false", string.Empty)));
                    else
                        strURLWithData = strURLWithData + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&RecipientId={1}&EmailId={2}&SignerType={3}&CopyMailId={4}", envelope.ID, recipint.ID, HttpUtility.UrlEncode(recipint.EmailAddress), "false", string.Empty)));

                    var strURLForSecurityCode = "";
                    if (applyNewSigningUrl)
                        strURLForSecurityCode = Convert.ToString(_appConfiguration["NewSigningURL"]) + "/security-code";
                    else
                        strURLForSecurityCode = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SignDocuments";

                    bool isMultiTemplate = envelope.Recipients.Where(s => s.TemplateID != null && s.RecipientTypeID == Constants.RecipientType.Signer).Select(s => s.TemplateID).Distinct().Count() > 1;
                    if (isEmailSend)
                    {
                        loggerModelNew.Message = "Send finish later email reminder to:" + recpEmailMobileAddress;
                        rsignlog.RSignLogInfo(loggerModelNew);

                        string mailTemplate = string.Empty;
                        mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.FinishLaterReminderTemplate, !string.IsNullOrEmpty(recipint.CultureInfo) ? recipint.CultureInfo : envelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId);
                        mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.FinishLaterReminderTemplate);
                        mailTemplate = _genericRepository.AppendFooterText(mailTemplate, recipint.EmailAddress, Constants.String.MailTemplateName.FinishLaterReminderTemplate, !string.IsNullOrEmpty(recipint.CultureInfo) ? recipint.CultureInfo : envelope.CultureInfo, "FinalContractFooter");

                        string signerFirstName = recipint.Name.Split(' ').FirstOrDefault();
                        mailTemplate = mailTemplate.Replace("#SignerFirstName", signerFirstName);
                        mailTemplate = mailTemplate.Replace("#SenderName", sender.Name);
                        mailTemplate = mailTemplate.Replace("#SenderEmailId", sender.EmailAddress);
                        mailTemplate = mailTemplate.Replace("#SignerName", recipint.Name);
                        mailTemplate = mailTemplate.Replace("#SignerEmailId", recpEmailMobileAddress);
                        mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode)); // Envelope Code
                        mailTemplate = mailTemplate.Replace("#EnvelopeSecurityCode", Convert.ToString(recipint.RecipientCode)); // Envelope Code
                        mailTemplate = mailTemplate.Replace("#GenerateCodeURL", strURLForSecurityCode);
                        mailTemplate = mailTemplate.Replace("#URL", strURLWithData);
                        mailTemplate = mailTemplate.Replace("#EmailBodyText", envelope.Message);
                        mailTemplate = mailTemplate.Replace("#ImageURL", imageLogoURl);

                        if (recipint.TemplateID != null && isMultiTemplate)
                        {
                            mailTemplate = mailTemplate.Replace("#DocumentLabel", "Document:");
                            mailTemplate = mailTemplate.Replace("#DocumentName", string.Join(", ", _genericRepository.GetTemplatDocumentNames(recipint.TemplateID.Value).ToArray()));
                        }
                        else
                        {
                            mailTemplate = mailTemplate.Replace("#DocumentLabel", string.Empty);
                            mailTemplate = mailTemplate.Replace("#DocumentName", string.Empty);
                        }

                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            EmailQueueData emailQueueData = new EmailQueueData();
                            emailQueueData.envelope = envelope;
                            emailQueueData.MailMessageBody = mailTemplate;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            emailQueueData.EmailType = Constants.EmailTypes.ESR;
                            emailQueueData.EmailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipint.CultureInfo) ? recipint.CultureInfo : envelope.CultureInfo, envelope.Subject, Constants.EmailSubject.SignatureReminder);
                            EmailSendInfo emailSendData = new EmailSendInfo();
                            emailSendData.RecipientName = recipint.Name;
                            emailSendData.RecipientEmail = recipint.EmailAddress;
                            emailQueueData.emailSendInfo = emailSendData;
                            EmailQueueFunction(emailQueueData);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            Guid msgId = Guid.NewGuid();
                            List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();
                            emailLogs = Chilkat.SendMailUsingChilKet(new string[] { recipint.EmailAddress }, new string[] { recipint.Name }, null, null, null, null, userEmail, "",
                                 GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipint.CultureInfo) ? recipint.CultureInfo : envelope.CultureInfo,
                                 envelope.Subject, Constants.EmailSubject.SignatureReminder), mailTemplate, null, null, envelope.EDisplayCode, Constants.String.EmailOperation.Send, SignReqReplyToAddressValue, msgId);
                        }
                    }

                    if (isMobileSend)
                    {
                        loggerModelNew.Message = "Send finish later message reminder to:" + recpEmailMobileAddress;
                        rsignlog.RSignLogInfo(loggerModelNew);

                        string mobilelTemlate = string.Empty;
                        mobilelTemlate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.FinishLaterReminderTemplate, !string.IsNullOrEmpty(recipint.CultureInfo) ? recipint.CultureInfo : envelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId, "mobile");
                        string md5ShortUriPasscode = _modelHelper.CalculateMD5HashForShortURL(strURLWithData).ToLower();
                        string signingShortURL = Convert.ToString(_appConfiguration["SigningURL"]) + "Msg/Rs/" + md5ShortUriPasscode;
                        SaveShortUrlForSMS(envelope, strURLWithData, signingShortURL, md5ShortUriPasscode, false);

                        mobilelTemlate = mobilelTemlate.Replace("#SenderName", sender.Name);
                        mobilelTemlate = mobilelTemlate.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode));
                        mobilelTemlate = mobilelTemlate.Replace("#SigningShortURL", signingShortURL);
                        if (!string.IsNullOrEmpty(recipint.DialCode) && !string.IsNullOrEmpty(recipint.Mobile))
                        {
                            if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                            {
                                string emailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipint.CultureInfo) ? recipint.CultureInfo : envelope.CultureInfo, envelope.Subject, Constants.EmailSubject.SignatureReminder);
                                SendSMSThroughEmailService(envelope, mobilelTemlate, SignReqReplyToAddressValue, Constants.EmailTypes.ESR, recipint, emailSubject);
                            }
                            else
                            {
                                string signerMobileNumber = recipint.DialCode + recipint.Mobile;
                                SendMobileSMS(envelope, mobilelTemlate, signerMobileNumber);
                            }
                        }
                    }

                    loggerModelNew.Message = "Process completed for Send Finish Later Reminder to:" + recpEmailMobileAddress;
                    rsignlog.RSignLogWarn(loggerModelNew);
                    return true;
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                return false;
            }
        }
