            List<string> RecipCCEmailList = new List<string>();
            List<Recipients> lstCCRecipients = envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.CC).ToList();
            foreach (var ccDetails in lstCCRecipients)
            {
                string ccEmailMobileDetail = "";
                //if (!string.IsNullOrEmpty(ccDetails.EmailAddress) && !string.IsNullOrEmpty(ccDetails.Mobile) && ccDetails.DeliveryMode == 2)
                //{
                //    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.EmailAddress + ", " + ccDetails.DialCode + ccDetails.Mobile + ")";
                //}
                //else if (!string.IsNullOrEmpty(ccDetails.EmailAddress) && ccDetails.DeliveryMode == 1)
                //{
                //    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.EmailAddress + ")";
                //}
                //else if (!string.IsNullOrEmpty(ccDetails.Mobile) && ccDetails.DeliveryMode == 3)
                //{
                //    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.DialCode + ccDetails.Mobile + ")";
                //}
                //else
                //{
                //    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.EmailAddress + ")";
                //}

