                {
                    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.EmailAddress + ")";
                }
                else if (!string.IsNullOrEmpty(ccDetails.EmailAddress) && !string.IsNullOrEmpty(ccDetails.Mobile) && (ccDetails.DeliveryMode == Constants.DeliveryModes.EmailSlashMobile
                    || ccDetails.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile || ccDetails.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile
                    || ccDetails.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmail || ccDetails.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile
                    || ccDetails.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone || ccDetails.DeliveryMode == Constants.DeliveryModes.MobileSlashEmail
                    || ccDetails.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile))
                {
                    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.EmailAddress + ", " + ccDetails.DialCode + ccDetails.Mobile + ")";
                }
                else if (!string.IsNullOrEmpty(ccDetails.Mobile) && (ccDetails.DeliveryMode == Constants.DeliveryModes.MobileSlashMobile
                   || ccDetails.DeliveryMode == Constants.DeliveryModes.MobileSlashNone))
                {
                    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.DialCode + ccDetails.Mobile + ")";
                }
                else if (!string.IsNullOrEmpty(ccDetails.EmailAddress))
                {
                    ccEmailMobileDetail = ccDetails.Name + " (" + ccDetails.EmailAddress + ")";
                }
                else if (!string.IsNullOrEmpty(ccDetails.Mobile))
