            List<string> senderEmailwithNames = new List<string>();

            senderEmailList.AddRange(senderRecipients.EmailAddress.Split(','));
            foreach (var signer in envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).ToArray())
            {
                if (!string.IsNullOrEmpty(signer.CopyEmailAddress))
                {
                    senderEmailList.AddRange(signer.CopyEmailAddress.Split(','));
                }
            }

            foreach (var signer in envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer).ToArray())
            {
                if (!string.IsNullOrEmpty(signer.CopyEmailAddress))
                {
                    signersEmailList.AddRange(signer.CopyEmailAddress.Split(','));
                }
            }

            foreach (var senderEmail in senderEmailList)
            {
                UserProfile userprofile = _userRepository.GetUserProfileByEmailID(senderEmail);
                senderEmailwithNames.Add(userprofile != null ? userprofile.FirstName + " " + userprofile.LastName + " (" + senderEmail + ")" : " (" + senderEmail + ")");
            }
            foreach (var signerEmail in signersEmailList)
            {
                UserProfile userprofile = _userRepository.GetUserProfileByEmailID(signerEmail);
                signersEmailwithNames.Add(userprofile != null ? userprofile.FirstName + " " + userprofile.LastName + " (" + signerEmail + ")" : " (" + signerEmail + ")");
            }
            RecipEmailList.AddRange(signersEmailwithNames);


            string[] toArray = RecipEmailList.ToArray();
            toList = string.Join(", ", toArray);

            string[] ccArray = RecipCCEmailList.ToArray();
            ccList = string.Join(", ", ccArray);

            string[] senderArray = senderEmailList.ToArray();
            string[] senderNameArray = senderEmailwithNames.ToArray();
            fromList = String.Join(", ", senderArray);
            fromNamesList = String.Join(", ", senderEmailwithNames);
            if (senderRecipients != null)
            {
                //mailTemlateSender = mailTemlateSender.Replace("#SenderName", fromNamesList);
                mailTemlateSender = mailTemlateSender.Replace("#SenderList", fromNamesList);
                mailTemlateSender = mailTemlateSender.Replace("#ToList", toList);
                mailTemlateSender = mailTemlateSender.Replace("#CCList", ccList);
                mailTemlateSender = mailTemlateSender.Replace("#DateSent", completionDate);
                mailTemlateSender = mailTemlateSender.Replace("#DateSent", completionDate);
                mailTemlateSender = mailTemlateSender.Replace("#EnvelopeDisplayCode", "ENV" + Convert.ToString(envelope.EDisplayCode));
                mailTemlateSender = mailTemlateSender.Replace("#EmailBodyText", envelope.Message);
                //mailTemlateSender = mailTemlateSender.Replace("#ImageURL", imageLogoURl);
                mailTemlateSender = mailTemlateSender.Replace("#clientLogo", string.Empty);
                mailTemlateSender = mailTemlateSender.Replace("#URL", strURLWithDataForcc);
            }
            return mailTemlateSender;
        }
        private string SenderConfirmationPwd(Envelope sessionEnvelope, string mailTemplatepassword, string imageLogoURl, string senderName, string senderEmail)
        {
            string passwordOpen = ModelHelper.Decrypt(sessionEnvelope.PasswordtoOpen, sessionEnvelope.PasswordKey, (int)sessionEnvelope.PasswordKeySize);
            mailTemplatepassword = mailTemplatepassword.Replace("#RecipientName", senderName);
            mailTemplatepassword = mailTemplatepassword.Replace("#ToName", senderName);
            mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", senderEmail);
            mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));
            mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(passwordOpen));
            //mailTemplatepassword = mailTemplatepassword.Replace("#ImageURL", imageLogoURl);
            mailTemplatepassword = mailTemplatepassword.Replace("#clientLogo", string.Empty);
            return mailTemplatepassword;
        }
        public bool GenerateRSignDocuments(Guid envelopeID, bool IsService = false, List<Guid> recipientList = null)
        {
            try
            {
                Envelope envelopeObject;
                string[] copyEmail = new string[] { };
                string[] rerouteEmail = new string[] { };
                string dirPath = _modelHelper.GetEnvelopeDirectoryNew(envelopeID, string.Empty);
                tempEnvelopeDir = Path.Combine(dirPath, Convert.ToString(envelopeID));
                var mailTemplateSettings = new SandboxMailTemplateSettings();
                mailTemplateSettings.ContractToGenerateOption = Constants.FinalContractOptions.Aspose;
                mailTemplateSettings.AttachedPdfOption = Constants.AttachSignedPDF.SenderSigner;
                string watermarkAuthText = string.Empty;
                string watermarkBackgroundText = string.Empty;

                envelopeObject = _genericRepository.GetEntity(envelopeID);
                var userprofile = _userRepository.GetUserProfile(envelopeObject.UserID);

                loggerModelNew = new LoggerModelNew(userprofile.EmailID, "SignDocumentService", IsService ? "GenerateRSignContract Using Service" : "GenerateRSignContract Using WebApp", "Process started for Generate RSign Contract initiated with setting details", envelopeObject.ID.ToString(), "", "", "", "API");
                rsignlog.RSignLogInfo(loggerModelNew);
                string EmailDisclaimer = string.Empty;
                try
                {
                    List<SettingsDetailsAdditionalValues> settingsDetailsAdditionals = GetSettingDetailByUserId(envelopeObject.UserID);
                    if (settingsDetailsAdditionals != null && settingsDetailsAdditionals.Count() > 0)
                    {
                        var settingsTimeZoneValue = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.TimeZone, settingsDetailsAdditionals);

                        if (settingsTimeZoneValue != null)
                            mailTemplateSettings.TimeZone = Convert.ToString(settingsTimeZoneValue.OptionValue);

