                            mailTemplateSettings.DateFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);

                        var settingsDetails = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.FinalContractOptionSetting, settingsDetailsAdditionals);
                        if (settingsDetails != null)
                            mailTemplateSettings.ContractToGenerateOption = string.IsNullOrEmpty(settingsDetails.OptionValue) ? Constants.FinalContractOptions.Aspose : Convert.ToInt32(settingsDetails.OptionValue);

                        //var settingsDetailsEmailDisclaimer = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.EmailDisclaimer, settingsDetailsAdditionals);
                        //if (settingsDetailsEmailDisclaimer != null)
                        //    mailTemplateSettings.EmailDisclaimer = settingsDetailsEmailDisclaimer.OptionValue.ToString();

                        var attachSignPdfSettingsOptions = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.AttachSignedPDFOptionSetting, settingsDetailsAdditionals);
                        if (attachSignPdfSettingsOptions != null)
                            mailTemplateSettings.AttachedPdfOption = string.IsNullOrEmpty(attachSignPdfSettingsOptions.OptionValue) ? Constants.AttachSignedPDF.SenderSigner : new Guid(attachSignPdfSettingsOptions.OptionValue);
                        if (!Convert.ToBoolean(envelopeObject.IsFinalDocLinkReq))
                            mailTemplateSettings.AttachedPdfOption = Constants.AttachSignedPDF.SenderSigner;

                        var copyEmailAddress = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.EsignMailCopyAddress, settingsDetailsAdditionals);

                        if (copyEmailAddress != null && copyEmailAddress.OptionValue != null && copyEmailAddress.OptionValue.Length > 0)
                            copyEmail = copyEmailAddress.OptionValue.Split(new string[] { "," }, StringSplitOptions.None).Distinct().ToArray();

                        var rerouteEmailAddress = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.EsignMailRerouteAddress, settingsDetailsAdditionals);

                        if (rerouteEmailAddress != null && rerouteEmailAddress.OptionValue != null && rerouteEmailAddress.OptionValue.Length > 0)
                            rerouteEmail = rerouteEmailAddress.OptionValue.Split(new string[] { "," }, StringSplitOptions.None).Distinct().ToArray();

                        var documentPaperSizeSettings = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.DocumentPaperSize, settingsDetailsAdditionals);
                        if (documentPaperSizeSettings != null && documentPaperSizeSettings.OptionValue != null && documentPaperSizeSettings.OptionValue.Length > 0)
                            envelopeObject.DocumentPaperSizeID = Convert.ToInt32(documentPaperSizeSettings.OptionValue);

                        var signStampSettingsDetails = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.StampOnSignerCopySetting, settingsDetailsAdditionals);
                        if (signStampSettingsDetails != null)
                        {
                            if (Convert.ToBoolean(signStampSettingsDetails.OptionValue))
                            {
                                settingsDetails = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.StampOnSignerCopyAuthrozieText, settingsDetailsAdditionals);
                                watermarkAuthText = settingsDetails != null ? Convert.ToString(settingsDetails.OptionValue) : string.Empty;
                                settingsDetails = GetSettingsDetailsByKeyConfig(Constants.SettingsKeyConfig.StampOnSignerCopyWatermarkText, settingsDetailsAdditionals);
                                watermarkBackgroundText = settingsDetails != null ? Convert.ToString(settingsDetails.OptionValue) : string.Empty;
                            }
                        }
                    }
                    else
                    {
                        var settingsTimeZone = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.TimeZone);
                        if (settingsTimeZone != null)
                            mailTemplateSettings.TimeZone = Convert.ToString(settingsTimeZone.OptionValue);

                        var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
                        if (settingsDateTimeFormt != null)
                            mailTemplateSettings.DateFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);

                        var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.FinalContractOptionSetting);
                        if (settingsDetails != null)
                            mailTemplateSettings.ContractToGenerateOption = string.IsNullOrEmpty(settingsDetails.OptionValue) ? Constants.FinalContractOptions.Aspose : Convert.ToInt32(settingsDetails.OptionValue);

                        //var settingsDetailsEmailDisclaimer = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                        //if (settingsDetailsEmailDisclaimer != null)
                        //    mailTemplateSettings.EmailDisclaimer = settingsDetailsEmailDisclaimer.OptionValue.ToString();

                        var attachSignPdfSettingsOptions = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.AttachSignedPDFOptionSetting);
                        if (attachSignPdfSettingsOptions != null)
                            mailTemplateSettings.AttachedPdfOption = string.IsNullOrEmpty(attachSignPdfSettingsOptions.OptionValue) ? Constants.AttachSignedPDF.SenderSigner : new Guid(attachSignPdfSettingsOptions.OptionValue);
                        if (!Convert.ToBoolean(envelopeObject.IsFinalDocLinkReq))
                            mailTemplateSettings.AttachedPdfOption = Constants.AttachSignedPDF.SenderSigner;

                        var copyEmailAddress = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.EsignMailCopyAddress);

                        if (copyEmailAddress != null && copyEmailAddress.OptionValue != null && copyEmailAddress.OptionValue.Length > 0)
                            copyEmail = copyEmailAddress.OptionValue.Split(new string[] { "," }, StringSplitOptions.None).Distinct().ToArray();

                        var rerouteEmailAddress = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.EsignMailRerouteAddress);

                        if (rerouteEmailAddress != null && rerouteEmailAddress.OptionValue != null && rerouteEmailAddress.OptionValue.Length > 0)
                            rerouteEmail = rerouteEmailAddress.OptionValue.Split(new string[] { "," }, StringSplitOptions.None).Distinct().ToArray();

                        var documentPaperSizeSettings = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.DocumentPaperSize);
                        if (documentPaperSizeSettings != null && documentPaperSizeSettings.OptionValue != null && documentPaperSizeSettings.OptionValue.Length > 0)
                            envelopeObject.DocumentPaperSizeID = Convert.ToInt32(documentPaperSizeSettings.OptionValue);

                        //////Get user Settings - Optimized Code
                        ////APISettings apiSettings = settingsRepository.GetEntityByParam(userProfile.UserID, userProfile.EmailID, Constants.String.SettingsType.User);
                        ////var userSettings = envelopeHelperMain.TransformSettingsDictionaryToEntity(apiSettings);

                        var signStampSettingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.StampOnSignerCopySetting);
                        if (signStampSettingsDetails != null)
                        {
                            if (Convert.ToBoolean(signStampSettingsDetails.OptionValue))
                            {
                                settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.StampOnSignerCopyAuthrozieText);
                                watermarkAuthText = settingsDetails != null ? Convert.ToString(settingsDetails.OptionValue) : string.Empty;
                                settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.StampOnSignerCopyWatermarkText);
                                watermarkBackgroundText = settingsDetails != null ? Convert.ToString(settingsDetails.OptionValue) : string.Empty;
                            }
                        }
                    }

                    var settingsDetailsEmailDisclaimer = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                    if (settingsDetailsEmailDisclaimer != null)
                        mailTemplateSettings.EmailDisclaimer = settingsDetailsEmailDisclaimer.OptionValue.ToString();

                    // Appending Multiplefilenamecustomize value 21-11-2023 Start

                    var settingMultiplefileNameCustomize = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EnableMultipleAttachmentsCustomizable);
                    if (settingMultiplefileNameCustomize != null)
                        envelopeObject.EnableMultipleNameCustomize = Convert.ToBoolean(settingMultiplefileNameCustomize.OptionValue);

                    if (envelopeObject.EnableMultipleNameCustomize)
                    {
                        var settingRenameFileTo = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.RenameFileToMode);
                        if (settingRenameFileTo != null)
                            envelopeObject.RenameFileTo = Convert.ToInt32(settingRenameFileTo.OptionValue);

                        var settingAddPrefixToFileNameMode = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.AddPrefixToFileNameMode);
                        if (settingAddPrefixToFileNameMode != null)
                            envelopeObject.AddPrefixToFileNameMode = Convert.ToInt32(settingAddPrefixToFileNameMode.OptionValue);

                        var settingDateTimeStampForMultipleDocSettingsForPrefix = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.DateTimeStampForMultipleDocSettingsForPrefix);
                        if (settingDateTimeStampForMultipleDocSettingsForPrefix != null)
                            envelopeObject.DateTimeStampForMultipleDocSettingsForPrefix = Convert.ToInt32(settingDateTimeStampForMultipleDocSettingsForPrefix.OptionValue);

                        var settingPrefixCustomName = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.PrefixCustomName);
                        if (settingPrefixCustomName != null)
                            envelopeObject.PrefixCustomName = Convert.ToString(settingPrefixCustomName.OptionValue);

                        var settingAddSuffixFileToMode = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.AddSuffixFileToMode);
                        if (settingAddSuffixFileToMode != null)
                            envelopeObject.AddSuffixFileToMode = Convert.ToInt32(settingAddSuffixFileToMode.OptionValue);

                        var settingDateTimeStampForMultipleDocSettingsForSufix = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.DateTimeStampForMultipleDocSettingsForSufix);
                        if (settingDateTimeStampForMultipleDocSettingsForSufix != null)
                            envelopeObject.DateTimeStampForMultipleDocSettingsForSufix = Convert.ToInt32(settingDateTimeStampForMultipleDocSettingsForSufix.OptionValue);

                        var settingSufixCustomName = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.SuffixCustomName);
                        if (settingSufixCustomName != null)
                            envelopeObject.SuffixCustomName = Convert.ToString(settingSufixCustomName.OptionValue);
                    }

                    // Appending Multiplefilenamecustomize value 21-11-2023 End


                    loggerModelNew.Message = "Get required settings key completed  And Generate RSign Contract processes started";
                    rsignlog.RSignLogInfo(loggerModelNew);
                    var userSettings = new FinalContractSettings
                    {
                        WatermarkAuthText = watermarkAuthText,
                        WatermarkBackgroundText = watermarkBackgroundText,
                        FinalContractOptions = mailTemplateSettings.ContractToGenerateOption,
                        UserTimeZone = mailTemplateSettings.TimeZone,
                        IsControlDisplayInTag = false
                    };

                    finalPdfFilePath = GetFinalSignDocument(envelopeObject, userSettings, dirPath);

                    loggerModelNew.Message = "Generate RSign Contract processes Completed and transparency and other file process started if transparency equal to " + Convert.ToString(envelopeObject.IsTransparencyDocReq);
                    rsignlog.RSignLogInfo(loggerModelNew);

                    if (envelopeObject.IsTransparencyDocReq)
                        finalTransperancyPath = GetTransparencyDocument(envelopeObject, tempEnvelopeDir);

                    if (envelopeObject.IsSignerAttachFileReq > 0)
                        GetSignerAttachDocument(envelopeObject.ID);

                    if (Convert.ToBoolean(envelopeObject.IsAttachXML))
                        GetXmlDocument(envelopeObject);
                }
                catch (Exception ex)
                {
                    using (var dbContext = new RSignDbContext(_configuration))
                    {
                        var recipientID = (from r in dbContext.Recipients
                                           join s in dbContext.SignerStatus on r.ID equals s.RecipientID
                                           where (s.StatusID == Constants.StatusCode.Signer.Signed && r.EnvelopeID == envelopeID)
                                           orderby s.CreatedDateTime descending
                                           select r.ID).FirstOrDefault();

                        _recipientRepository.ModifyLastRecipientSignedEntry(recipientID, Constants.StatusCode.Signer.Viewed, envelopeObject.IpAddress, dbContext);
                        var envStatus = dbContext.EnvelopeStatus.Where(d => d.EnvelopeID == envelopeID && d.StatusID == Constants.StatusCode.Envelope.Completed).OrderByDescending(o => o.CreatedDateTime).FirstOrDefault();
                        if (envStatus != null)
                            dbContext.EnvelopeStatus.Remove(envStatus);
                    }
                    _genericRepository.UpdateEnvelopeStatus(envelopeID, Constants.StatusCode.Envelope.Waiting_For_Signature);

                    DeleteContractFileInCaseOfError(envelopeObject.ID, dirPath);
                    loggerModelNew.Message = "Error while generating final singed document " + ex.Message.ToString();
                    rsignlog.RSignLogError(loggerModelNew, ex);
                    UpdateEnvelopeContractStatus(envelopeID, 2, ex.Message.ToString() + " : Stack Trace" + ex.StackTrace.ToString());
                    return false;
                }

                bool IsDocumentSenttoService = GetFinalSignDocumentInCaseZeroKB(finalPdfFilePath, envelopeID, IsService);

                if (!IsDocumentSenttoService)
                {
                    loggerModelNew.Message = "Transparency and other file process Completed and Mail Send process started";
                    rsignlog.RSignLogInfo(loggerModelNew);

                    //* Added by RLabs-RSign DEV Team
                    AdminGeneralAndSystemSettings allSettingsDetails;
                    var senderDetails = envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).FirstOrDefault();
                    allSettingsDetails = GetAllSettingsDetails(envelopeObject.UserID, senderDetails.EmailAddress);

                    string[] CultureInfoList = envelopeObject.Recipients.Select(r => !string.IsNullOrEmpty(r.CultureInfo) ? r.CultureInfo : envelopeObject.CultureInfo).Distinct().ToArray();

                    var mailTemplateList = _genericRepository.GetMailTemplateCode().Where(c => CultureInfoList.Contains(c.CultureInfo)).ToList();
                    mailTemplateSettings.MailTemplateList = mailTemplateList;

                    SendPwdMailToRecipients(envelopeObject, mailTemplateSettings.EmailDisclaimer, rerouteEmail, copyEmail, mailTemplateSettings.AttachedPdfOption, recipientList);
                    SendRSignDocumentMailToRecipients(envelopeObject, mailTemplateSettings, rerouteEmail, copyEmail, CultureInfoList, dirPath, recipientList, false);

                    loggerModelNew.Message = "Password and Signed Document Email successfully dispatched to respective recipients";
                    rsignlog.RSignLogInfo(loggerModelNew);
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in generating signed documents service. " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                UpdateEnvelopeContractStatus(envelopeID, 3, "Error while sending signed document email; Error Message : " + ex.Message.ToString() + " : Stack Trace : " + ex.StackTrace.ToString());
                return false;
                //throw ex;
            }
            return true;
        }
        private string GetFinalSignDocument(Envelope envelopeObject, FinalContractSettings userSettings, string envelopeDirectoryUNCPath)
        {
            loggerModelNew = new LoggerModelNew("", "Envelope Helper main", "GetFinalSignDocument", "Process started for generating final singed document", envelopeObject.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                finalPdfFilePath = _apiHelper.finalMergePDFApi(envelopeObject, userSettings, envelopeDirectoryUNCPath, string.Empty, true);
            }
            catch (Exception ex)
            {
                DeleteContractFileInCaseOfError(envelopeObject.ID, envelopeDirectoryUNCPath);
                if (ex.Message.ToString().ToLower() == "invalid font name")
                    userSettings.FinalContractOptions = Constants.FinalContractOptions.FromImages;
                else
                    userSettings.FinalContractOptions = Convert.ToInt32(userSettings.FinalContractOptions) != Constants.FinalContractOptions.iText ? Constants.FinalContractOptions.iText : Constants.FinalContractOptions.Aspose;
                try
                {
                    finalPdfFilePath = _apiHelper.finalMergePDFApi(envelopeObject, userSettings, envelopeDirectoryUNCPath, string.Empty, true);
                }
                catch (Exception e)
                {
                    DeleteContractFileInCaseOfError(envelopeObject.ID, envelopeDirectoryUNCPath);

                    var dirPath = envelopeDirectoryUNCPath;
                    string convertedDocDirectory = Path.Combine(dirPath, envelopeObject.ID.ToString(), "Converted");
                    foreach (var file in Directory.GetFiles(convertedDocDirectory))
                    {
                        if (Path.GetExtension(file) == ".pdf")
                            _asposeHelper.TransformPDFFromDocxAndCopyToDestination(Path.Combine(convertedDocDirectory, file), convertedDocDirectory, Path.Combine(convertedDocDirectory, Path.GetFileNameWithoutExtension(file) + ".pdf"));
                    }

                    userSettings.FinalContractOptions = Constants.FinalContractOptions.Aspose;
                    finalPdfFilePath = _apiHelper.finalMergePDFApi(envelopeObject, userSettings, envelopeDirectoryUNCPath, string.Empty, true);
                }
            }
            return finalPdfFilePath;
        }
