        {
            try
            {
                finalTransperancyPath = _apiHelper.GetTransperancyDocument(tempEnvelopeDir, envelopeObject);
            }
            catch (Exception ex)
            {
            }
            return finalTransperancyPath;
        }
        private string GetSignerAttachDocument(Guid EnvelopeId)
        {
            string SignerDocDir = Path.Combine(tempEnvelopeDir, "SignerAttachments");
            if (Directory.Exists(SignerDocDir))
            {
                var file = Directory.GetFiles(SignerDocDir, "*", SearchOption.AllDirectories).FirstOrDefault();
                if (file != null)
                {
                    string signerattchzip = Path.Combine(SignerDocDir, "SignerDoc.zip");
                    if (file.Contains("SignerDoc.zip"))
                    {
                        System.IO.File.Delete(signerattchzip);
                    }
                }
                if (file != null)
                    finalSignerAttachFilePath = _apiHelper.GetRecipientDocumentZip(SignerDocDir);
            }
            return finalSignerAttachFilePath;
        }
        private string GetXmlDocument(Envelope envelopeObject)
        {
            EnvelopeContent envelopeContent = CreateXml(envelopeObject);
            xmlFilePath = _eSignHelper.CreateXmlFileToSend(envelopeObject, envelopeContent);
            return xmlFilePath;
        }
        public bool GetFinalSignDocumentInCaseZeroKB(string finalPdfFilePath, Guid envelopeID, bool IsService = false)
        {
            bool IsDocumentSenttoService = false;
            try
            {
                if (System.IO.File.Exists(finalPdfFilePath))
                {
                    byte[] finalMergedArray = System.IO.File.ReadAllBytes(finalPdfFilePath);
                    double filesizeKB = finalMergedArray.Length / 1024d;
                    if (filesizeKB < 1)
                    {
                        UpdateEnvelopeContractStatus(envelopeID, 2, (filesizeKB + " KB file generated " + (IsService ? "using Service" : "using Web App")));
                        IsDocumentSenttoService = true;
                    }
                }
                return IsDocumentSenttoService;
            }
            catch (Exception ex)
            {
                return IsDocumentSenttoService;
            }
        }
        private bool SendPwdMailToRecipients(Envelope envelopeObject, string EmailDisclaimer, string[] rerouteEmail, string[] copyEmail, Guid attachedPdfOption, List<Guid> recipientIds = null)
        {
            string mailTemplatepassword;
            string[] allRecepients = new string[] { };
            var senderDetails = envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).FirstOrDefault();
            int SignReqReplyToAddressValue = 1;
            List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();
            string EmailSentType = string.Empty; int RetryCount = 0;

            var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
            //if (settingsDetails != null)
            //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(envelopeObject.ID); //dbContext.EnvelopeSettingsDetail.Where(e => e.EnvelopeId == envelopeObject.ID).FirstOrDefault();
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            var isPasswordMailToSigner = envelopeObject.IsPasswordMailToSigner;
            if (envelopeObject.PasswordReqdtoOpen == true)
            {
                string passwordOpen = ModelHelper.Decrypt(envelopeObject.PasswordtoOpen, envelopeObject.PasswordKey, (int)envelopeObject.PasswordKeySize);
                var recipientList = GetRecipientList(envelopeObject, rerouteEmail, copyEmail);
                AdminGeneralAndSystemSettings allSettingsDetails;
                allSettingsDetails = GetAllSettingsDetails(envelopeObject.UserID, senderDetails.EmailAddress);

                foreach (var rec in recipientList.Where(r => (r.RecipientTypeID == Constants.RecipientType.CC && (r.CCSignerType == null || r.CCSignerType == Constants.CCRecipientType.Empty || r.CCSignerType == Constants.CCRecipientType.UnsignedandSigned || r.CCSignerType == Constants.CCRecipientType.Signed || r.CCSignerType == Constants.CCRecipientType.NotificationsAndSigned)) ||
               (r.RecipientTypeID == Constants.RecipientType.Signer && r.RecipientEmail != senderDetails.EmailAddress) || r.RecipientTypeID == Constants.RecipientType.Sender))
                {
                    string recCultureInfo = !string.IsNullOrEmpty(rec.CultureInfo) ? rec.CultureInfo : envelopeObject.CultureInfo;
                    var mailTemplateList = _genericRepository.GetMailTemplateCode().Where(c => c.CultureInfo == recCultureInfo).ToList();

                    bool isEmailSend = false, isPwdEmailSend = false;
                    bool isMobileSend = false, isPwdMobileSend = false;
                    if (Convert.ToBoolean(envelopeObject.EnableMessageToMobile))
                    {
                        isPasswordMailToSigner = true;
                        Recipients recSigner = new Recipients() { DeliveryMode = rec.DeliveryMode, EmailAddress = rec.RecipientEmail, Mobile = rec.RecipientMobile };
                        GetEmailDeiliveryModeOptions(recSigner, ref isEmailSend, ref isMobileSend);
                        GetMobileDeiliveryModeOptions(recSigner, ref isPwdEmailSend, ref isPwdMobileSend);
                    }
                    else
                    {
                        isPwdEmailSend = true;
                        isEmailSend = true;
                    }

                    if (isPwdEmailSend && Convert.ToBoolean(isPasswordMailToSigner))
                    {
                        var mailTemplatePWD = mailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.PasswordOpen).Select(t => t.Template).SingleOrDefault();
                        mailTemplatePWD = EmailBannerSettings(mailTemplatePWD, allSettingsDetails, Constants.String.MailTemplateName.PasswordOpen);

                        mailTemplatePWD += "</br>" + Convert.ToString(EmailDisclaimer);
                        string signerName = rec.RecipientName == "Hi" ? rec.RecipientEmail : rec.RecipientName;
                        mailTemplatepassword = mailTemplatePWD;
                        mailTemplatepassword = mailTemplatepassword.Replace("#RecipientName", rec.RecipientName);
                        mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeStatus", "Signed".ToLower());
                        mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", senderDetails.Name);
                        mailTemplatepassword = mailTemplatepassword.Replace("#SenderEmailId", senderDetails.EmailAddress);
                        mailTemplatepassword = mailTemplatepassword.Replace("#ToName", signerName);

                        Recipients recPwdSigner = new Recipients() { DeliveryMode = rec.DeliveryMode, EmailAddress = rec.RecipientEmail, DialCode = rec.DialCode, Mobile = rec.RecipientMobile };
                        mailTemplatepassword = AppendSignerDeliveryModeDetails(recPwdSigner, mailTemplatepassword, "#ToEmailEmailId");

                        mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(envelopeObject.EDisplayCode));
                        mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(passwordOpen));
                        //mailTemplatepassword = mailTemplatepassword.Replace("#ImageURL", imageLogoURl);
                        mailTemplatepassword = mailTemplatepassword.Replace("#clientLogo", string.Empty);

                        mailTemplatepassword = _genericRepository.AppendFooterText(mailTemplatepassword, rec.RecipientEmail, Constants.String.MailTemplateName.PasswordOpen, recCultureInfo, "FinalContractFooter");

                        if (((rec.RecipientTypeID == Constants.RecipientType.Signer || rec.RecipientTypeID == Constants.RecipientType.CC)
                            && (attachedPdfOption != Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                            && attachedPdfOption != Constants.AttachSignedPDF.SenderOnlyandNoemailtoRecipient)) || rec.RecipientTypeID == Constants.RecipientType.Sender)
                        {
                            if (recipientIds == null || (recipientIds != null && recipientIds.Any(s => rec.RecipientID == s)))
                            {
                                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                                {
                                    // To Add data in Emailqueue and EmailqueueRecipients for PasswordOpen.
                                    EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                                    EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                                    emailQueueData.envelope = envelopeObject;
                                    emailQueueData.MailMessageBody = mailTemplatepassword;
                                    emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                                    //emailQueueData.Signer = senderDetails; 
                                    emailQueueData.EmailType = Constants.EmailTypes.ESPO;
                                    emailQueueData.EmailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(rec.CultureInfo) ? rec.CultureInfo : envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.PasswordToOpen);
                                    emailSendData.RecipientName = signerName;
                                    emailSendData.RecipientEmail = rec.RecipientEmail;
                                    emailQueueData.emailSendInfo = emailSendData;
                                    EmailQueueFunction(emailQueueData);
                                }
                                else
                                {
                                    var Chilkat = new ChilkatHelper(_appConfiguration);
                                    emailLogs = Chilkat.SendMailUsingChilKet(new string[] { rec.RecipientEmail }, new string[] { signerName },
                                                null, null,
                                                 null, null,
                                                 senderDetails.EmailAddress, senderDetails.Name,
                                                GetEmailSubjectPrefix(!string.IsNullOrEmpty(rec.CultureInfo) ? rec.CultureInfo : envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.PasswordToOpen), mailTemplatepassword,
                                                 null, null, Convert.ToString(envelopeObject.EDisplayCode), Constants.String.EmailOperation.PasswordToOpen, SignReqReplyToAddressValue);
                                    _genericRepository.SaveEmailLogsRecord(emailLogs, out EmailSentType, out RetryCount);
                                    //Save email destination record
                                    _genericRepository.SaveDestinationRecord(new Destination() { EnvelopeCode = envelopeObject.EDisplayCode, RecipientEmail = rec.RecipientEmail, IsSent = true, IsProcessed = false, EmailSentType = EmailSentType, RetryCount = RetryCount });
                                }
                            }
                        }
                    }

                    if (isPwdMobileSend)
                    {
                        var mailTemplatePWD = mailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.PasswordOpen).Select(t => t.MobileTemplate).SingleOrDefault();
                        string signerName = rec.RecipientName == "Hi" ? rec.RecipientEmail : rec.RecipientName;
                        mailTemplatepassword = mailTemplatePWD;
                        mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", senderDetails.Name);
                        mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(envelopeObject.EDisplayCode));
                        mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(passwordOpen));
                        if (((rec.RecipientTypeID == Constants.RecipientType.Signer || rec.RecipientTypeID == Constants.RecipientType.CC)
                           && (attachedPdfOption != Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                           && attachedPdfOption != Constants.AttachSignedPDF.SenderOnlyandNoemailtoRecipient)) || rec.RecipientTypeID == Constants.RecipientType.Sender)
                        {
                            if (recipientIds == null || (recipientIds != null && recipientIds.Any(s => rec.RecipientID == s)))
                            {
                                if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                                {
                                    Recipients recp = new Recipients();
                                    recp.Name = rec.RecipientName;
                                    recp.Mobile = rec.RecipientMobile;
                                    recp.DialCode = rec.DialCode;

                                    string emailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(rec.CultureInfo) ? rec.CultureInfo : envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.PasswordToOpen);
                                    SendSMSThroughEmailService(envelopeObject, mailTemplatepassword, SignReqReplyToAddressValue, Constants.EmailTypes.ESPO, recp, emailSubject);
                                }
                                else
                                {
                                    string signerMobileNumber = rec.DialCode + rec.RecipientMobile;
                                    SendMobileSMS(envelopeObject, mailTemplatepassword, signerMobileNumber);
                                }
                            }
                        }
                    }
                }
            }
            return true;
        }
        private bool SendRSignDocumentMailToRecipients(Envelope envelopeObject, SandboxMailTemplateSettings mailTemplateSettings, string[] rerouteEmail, string[] copyEmail, string[] CultureInfoList, string envelopeDirectoryPath, List<Guid> recipientIDs = null, bool isSendWithoutAttachment = false)
        {
            string authKey = string.Empty, trSenderUrl = string.Empty, mailTemplateSender = string.Empty, completionDate = string.Empty, cultureInfo = string.Empty;
            //mailTemplate = string.Empty, mailTemplateCCNotification = string.Empty
            var msgId = Guid.NewGuid();
            var senderDetails = envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).FirstOrDefault();
            cultureInfo = envelopeObject.CultureInfo;
            int SignReqReplyToAddressValue = 1;
            string EmailSentType = string.Empty; int RetryCount = 0;
            List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();

            var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
            //if (settingsDetails != null)
            //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(envelopeObject.ID);
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            var isPasswordMailToSigner = envelopeObject.IsPasswordMailToSigner;
            //* Added by RLabs-RSign DEV Team        
            AdminGeneralAndSystemSettings allSettingsDetails = GetAllSettingsDetails(envelopeObject.UserID, senderDetails.EmailAddress);

            // link and Url to downlad Signed Document
            string strURLWithData = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
            string strRetrievalLink = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/ViewDocument?");
            string strURLWithDataTransperancy = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetTransperancy?");
            string strURLEnvXml = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetEnvelopeXml?");
            string strURLSignerAttachment = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetSignerAttachment?");
            strURLWithData += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelopeObject.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
            strRetrievalLink += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelopeObject.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
            strURLWithDataTransperancy += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelopeObject.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
            strURLEnvXml += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelopeObject.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
            strURLSignerAttachment += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelopeObject.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));

            string strFileReviewURLWithData = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetDownloadFileReview?");
            strFileReviewURLWithData += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelopeObject.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
            // Attachment process
            var arrayDocuments = GetAttachmentByteArray(envelopeObject, envelopeDirectoryPath, mailTemplateSettings.DateFormat);
            var attachments = arrayDocuments.ElementAt(0).Key;
            var attachmentName = arrayDocuments.ElementAt(0).Value;
            double fileSizes = attachments.Sum(arr => arr.Length);
            fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);

            if (!string.IsNullOrEmpty(mailTemplateSettings.TimeZone))
                completionDate = _eSignHelper.GetLocalTime(envelopeObject.ModifiedDateTime, mailTemplateSettings.TimeZone, envelopeObject.DateFormatID);
            else
                completionDate = String.Format("{0:MM/dd/yyyy HH:mm tt}", envelopeObject.ModifiedDateTime) + " " + _eSignHelper.GetTimeZoneAbbreviation(TimeZone.CurrentTimeZone.StandardName);

            // Mail template Process
            var mailTemplateLabelSettings = new MailTemplateLabelSettings();
            mailTemplateLabelSettings.EnvelopeId = envelopeObject.ID;
            mailTemplateLabelSettings.AttachedPdfOption = mailTemplateSettings.AttachedPdfOption;
            mailTemplateLabelSettings.UrlGetPdf = strURLWithData;
            mailTemplateLabelSettings.RetrievalLink = strRetrievalLink;
            var htmlCodeSigner = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#ToName(<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#ToEmailId'>#ToEmailId</a>)</font>";  // changes
            var htmlCodeCC = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#CCName (<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#CCEmailId'>#CCEmailId</a>)</font>";
            var htmlCodePrefill = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#ToName (<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#ToEmailId'>#ToEmailId</a>) (Prefill)</font>";
            StringBuilder sbSigner = new StringBuilder();
            StringBuilder sbCC = new StringBuilder();
            StringBuilder sbPrefill = new StringBuilder();

            //Header
            mailTemplateSender = mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.FinalContractHeader && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();
            //Final Contract
            if (Convert.ToBoolean(envelopeObject.IsFinalDocLinkReq) || fileSizes > 20)
                mailTemplateSender += mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.FinalContractLink && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();
            //Transperancy
            if (Convert.ToBoolean(envelopeObject.IsTransparencyDocReq))
                mailTemplateSender += mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.TransparencyLink && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();
            //Envelope Xml
            if (envelopeObject.IsAttachXML == true)
                mailTemplateSender += mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.EnvelopeXMLLink && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();
            //Signer Attachne
            if (envelopeObject.IsSignerAttachFileReq > 0 && !string.IsNullOrEmpty(finalSignerAttachFilePath))
                mailTemplateSender += mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.SignerAttachmentLink && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();

            if (envelopeObject.IsEnableFileReview == true && envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).Count() > 0)
            {
                mailTemplateSender += mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.EnvelopeFileReviewLink && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();
            }
            //mailTemplateSender += mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.FinalContractFooter && t.CultureInfo == cultureInfo).Select(t => t.Template).SingleOrDefault();

            var recipientList = GetRecipientList(envelopeObject, rerouteEmail, copyEmail);
            int isCopyAddress = 0;
            UserProfile usersInfo = new UserProfile();
            List<string> signersEmailList = new List<string>();
            string SigneruserName = string.Empty;

            foreach (var signerRecipient in envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.IsSameRecipient != true))
            {
                isCopyAddress = 0;
                signersEmailList.Clear();
                signersEmailList.Add(signerRecipient.EmailAddress);
                if (!string.IsNullOrEmpty(signerRecipient.CopyEmailAddress))
                {
                    signersEmailList.AddRange(signerRecipient.CopyEmailAddress.Split(','));
                }
                foreach (string signerEmail in signersEmailList)
                {
                    if (isCopyAddress > 0)
                    {
                        usersInfo = !string.IsNullOrEmpty(signerEmail) ? _userRepository.GetUserProfileByEmailID(signerEmail) : null;
                        SigneruserName = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : signerEmail.Split('@')[0];
                    }
                    var tempHtmlCode = htmlCodeSigner.Replace("'", "\"");
                    tempHtmlCode = tempHtmlCode.Replace("#ToName", isCopyAddress == 0 ? signerRecipient.Name.Replace(Constants.String.Notations.Prefill, "") : SigneruserName);
                    if (Convert.ToBoolean(envelopeObject.EnableMessageToMobile))
                    {
                        //if (!string.IsNullOrEmpty(signerEmail) && !string.IsNullOrEmpty(signerRecipient.Mobile))
                        //{
                        //    string signerMobileNumber = signerRecipient.EmailAddress + ", " + signerRecipient.DialCode + signerRecipient.Mobile;
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerMobileNumber);
                        //}
                        //else if (!string.IsNullOrEmpty(signerEmail))
                        //{
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerEmail);
                        //}
                        //else if (!string.IsNullOrEmpty(signerRecipient.Mobile))
                        //{
                        //    string signerMobileNumber = signerRecipient.DialCode + signerRecipient.Mobile;
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerMobileNumber);
                        //}

                        string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signerRecipient.DeliveryMode, signerRecipient.EmailAddress, signerRecipient.DialCode, signerRecipient.Mobile);
                        tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", emailMobileNumberDetails);

                    }
                    else
                    {
                        tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerEmail);
                    }
                    sbSigner.Append(tempHtmlCode + ", ");
                    isCopyAddress++;
                }
            }
            foreach (var ccRecipient in envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.CC))
            {
                var tempHtmlCode = htmlCodeCC.Replace("'", "\"");
                tempHtmlCode = tempHtmlCode.Replace("#CCName", ccRecipient.Name);
                if (Convert.ToBoolean(envelopeObject.EnableMessageToMobile))
                {
                    //if (!string.IsNullOrEmpty(ccRecipient.EmailAddress) && !string.IsNullOrEmpty(ccRecipient.Mobile))
                    //{
                    //    string signerMobileNumber = ccRecipient.EmailAddress + ", " + ccRecipient.DialCode + ccRecipient.Mobile;
                    //    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", signerMobileNumber);
                    //}
                    //else if (!string.IsNullOrEmpty(ccRecipient.EmailAddress))
                    //{
                    //    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccRecipient.EmailAddress);
                    //}
                    //else if (!string.IsNullOrEmpty(ccRecipient.Mobile))
                    //{
                    //    string signerMobileNumber = ccRecipient.DialCode + ccRecipient.Mobile;
                    //    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", signerMobileNumber);
                    //}

                    string ccEmailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(ccRecipient.DeliveryMode, ccRecipient.EmailAddress, ccRecipient.DialCode, ccRecipient.Mobile);
                    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccEmailMobileNumberDetails);

                }
                else
                {
                    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccRecipient.EmailAddress);
                }
                sbCC.Append(tempHtmlCode + ", ");
            }

            string SigningCertificateType = ((Convert.ToBoolean(envelopeObject.IsFinalDocLinkReq) || fileSizes > 20) ? Constants.String.MailTemplateName.SigningCertificate : Constants.String.MailTemplateName.SigningCertificateN);

            Dictionary<string, string> mailTemplate = _genericRepository.GetNewMailTemplateList(SigningCertificateType, CultureInfoList, mailTemplateSettings.EmailDisclaimer);

            //Dictionary<string, string> tempDisclaimer = new Dictionary<string, string>();
            //foreach (KeyValuePair<string, string> temp in mailTemplate)
            //{
            //    tempDisclaimer[temp.Key] = temp.Value + "</br>" + Convert.ToString(mailTemplateSettings.EmailDisclaimer);
            //}
            //mailTemplate = tempDisclaimer;

            mailTemplate = EmailBannerSettingsNew(mailTemplate, allSettingsDetails, SigningCertificateType);

            if (envelopeObject.IsEnableFileReview == true && envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).Count() > 0)
            {
                Dictionary<string, string> tempFileReview = new Dictionary<string, string>();
                foreach (KeyValuePair<string, string> temp in mailTemplate)
                {
                    tempFileReview[temp.Key] = temp.Value.Replace("id=\"tblfileReview\">", ">" + mailTemplateSettings.MailTemplateList.Where(t => t.Name == Constants.String.MailTemplateName.EnvelopeFileReviewLink && t.CultureInfo == temp.Key).Select(t => t.Template).SingleOrDefault());
                }
                mailTemplate = tempFileReview;
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#EnvelopeFileReviewURL", strFileReviewURLWithData);
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#FileReviewTransparencyURL", strFileReviewURLWithData);
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#LabelFileReviewContent", "Click the link below to download the files reviewed.");
            }

            Dictionary<string, string> mailTemplateForRecepientLogInNew = _genericRepository.GetNewMailTemplateList(Constants.String.MailTemplateName.SigningCertificateRecepLogIn, CultureInfoList, mailTemplateSettings.EmailDisclaimer);

            Dictionary<string, string> RecepientLogIntempDisclaimer = new Dictionary<string, string>();
            foreach (KeyValuePair<string, string> temp in mailTemplateForRecepientLogInNew)
            {
                RecepientLogIntempDisclaimer[temp.Key] = temp.Value + "</br>" + Convert.ToString(mailTemplateSettings.EmailDisclaimer);
            }
            mailTemplateForRecepientLogInNew = RecepientLogIntempDisclaimer;

            mailTemplateForRecepientLogInNew = EmailBannerSettingsNew(mailTemplateForRecepientLogInNew, allSettingsDetails, Constants.String.MailTemplateName.SigningCertificateRecepLogIn);

            var prefillDeatilsCount = recipientList.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).ToList().Count();
            if (sbSigner.Length > 0)
            {
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#ToList", sbSigner.ToString().Substring(0, sbSigner.ToString().LastIndexOf(",")));
                mailTemplateSender = mailTemplateSender.Replace("#ToList", sbSigner.ToString().Substring(0, sbSigner.ToString().LastIndexOf(",")));
                mailTemplateForRecepientLogInNew = ReplaceMailTemplateValue(mailTemplateForRecepientLogInNew, "#ToList", sbSigner.ToString().Substring(0, sbSigner.ToString().LastIndexOf(",")));
            }
            else if (sbSigner.Length == 0 && prefillDeatilsCount > 0) //If only prefill exists in envelope
            {
                var senderDeatils = recipientList.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).FirstOrDefault();
                var tempHtmlCode = htmlCodePrefill.Replace("'", "\"");
                tempHtmlCode = tempHtmlCode.Replace("#ToName", senderDeatils.RecipientName);
                tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", senderDeatils.RecipientEmail);
                sbPrefill.Append(tempHtmlCode + ", ");

                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#ToList", sbPrefill.ToString().Substring(0, sbPrefill.ToString().LastIndexOf(",")));
                mailTemplateSender = mailTemplateSender.Replace("#ToList", sbPrefill.ToString().Substring(0, sbPrefill.ToString().LastIndexOf(",")));
                mailTemplateForRecepientLogInNew = ReplaceMailTemplateValue(mailTemplateForRecepientLogInNew, "#ToList", sbPrefill.ToString().Substring(0, sbPrefill.ToString().LastIndexOf(",")));
            }
            else
            {
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#ToList", "-");
                mailTemplateSender = mailTemplateSender.Replace("#ToList", "-");
                mailTemplateForRecepientLogInNew = ReplaceMailTemplateValue(mailTemplateForRecepientLogInNew, "#ToList", "-");
            }
            if (sbCC.Length > 0)
            {
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
                mailTemplateSender = mailTemplateSender.Replace("#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
                mailTemplateForRecepientLogInNew = ReplaceMailTemplateValue(mailTemplateForRecepientLogInNew, "#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
            }
            else
            {
                mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#CCList", "-");
                mailTemplateSender = mailTemplateSender.Replace("#CCList", "-");
                mailTemplateForRecepientLogInNew = ReplaceMailTemplateValue(mailTemplateForRecepientLogInNew, "#CCList", "-");
            }
            //Sender Email Process

            mailTemplateSender = mailTemplateSender.Replace("#EnvelopeDisplayCode", Convert.ToString(envelopeObject.EDisplayCode));
            //mailTemplateSender = mailTemplateSender.Replace("#ImageURL", imageLogoURl);
            mailTemplateSender = mailTemplateSender.Replace("#CompletionDate", completionDate);
            mailTemplateSender = mailTemplateSender.Replace("#clientLogo", string.Empty);
            mailTemplateSender = mailTemplateSender.Replace("#TransparencyURL", strURLWithDataTransperancy);
            mailTemplateSender = mailTemplateSender.Replace("#SignerAttachedURL", strURLSignerAttachment);
            mailTemplateSender = mailTemplateSender.Replace("#EnvelopeXMLURL", strURLEnvXml);
            mailTemplateSender = mailTemplateSender.Replace("#EnvelopeFileReviewURL", strFileReviewURLWithData);
            mailTemplateSender = mailTemplateSender.Replace("#FileReviewTransparencyURL", strFileReviewURLWithData);
            mailTemplateSender = mailTemplateSender.Replace("#LabelFileReviewContent", "Click the link below to download the files reviewed.");
            mailTemplateSender = EmailBannerSettings(mailTemplateSender, allSettingsDetails, Constants.String.MailTemplateName.FinalContractHeader);
            List<string> senderCopyEmailList = new List<string>();
            string signerName = string.Empty, senderName = string.Empty, senderEmailAddress = string.Empty;

            EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
            EmailQueueProcessor.EmailQueueAttachmentData emailQueueAttachmentData = new EmailQueueProcessor.EmailQueueAttachmentData();
            foreach (var rec in recipientList.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender))
            {
                mailTemplateLabelSettings.RecipientTypeId = Constants.RecipientType.Sender;
                signerName = rec.RecipientName == "Hi" ? rec.RecipientEmail : rec.RecipientName;
                string tempMailTemplateRecipients = mailTemplateSender;
                tempMailTemplateRecipients = tempMailTemplateRecipients.Replace("#SenderName", signerName);
                tempMailTemplateRecipients = tempMailTemplateRecipients.Replace("#SenderEmailId", rec.RecipientEmail);
                tempMailTemplateRecipients = tempMailTemplateRecipients + "</br>" + Convert.ToString(mailTemplateSettings.EmailDisclaimer);
                tempMailTemplateRecipients = tempMailTemplateRecipients.Replace("#RecipientName", signerName);
                tempMailTemplateRecipients = MailTemplateReplaceLabelContent(tempMailTemplateRecipients, fileSizes, envelopeObject.CultureInfo, mailTemplateLabelSettings);

                tempMailTemplateRecipients = _genericRepository.AppendFooterText(tempMailTemplateRecipients, rec.RecipientEmail, Constants.String.MailTemplateName.FinalContractFooter, cultureInfo, "FinalContractFooter", "append");

                if (recipientIDs == null || (recipientIDs != null && recipientIDs.Any(s => rec.RecipientID == s)))
                {
                    if (fileSizes > 20 || mailTemplateSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                                || mailTemplateSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                                || mailTemplateSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn || isSendWithoutAttachment == true)
                    {
                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            emailQueueData.envelope = envelopeObject;
                            emailQueueData.MailMessageBody = tempMailTemplateRecipients;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            emailQueueData.SanboxSigner = rec;
                            emailQueueData.EmailType = Constants.EmailTypes.DS;
                            emailQueueData.EmailSubject = GetEmailSubjectPrefix(envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.DocumentSigned);
                            EmailQueueFunction(emailQueueData);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            emailLogs = Chilkat.SendMailUsingChilKet(new string[] { rec.RecipientEmail }, new string[] { signerName }, null, null, null, null, senderDetails.EmailAddress, senderDetails.Name, GetEmailSubjectPrefix(envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.DocumentSigned), tempMailTemplateRecipients, null, null, Convert.ToString(envelopeObject.EDisplayCode), Constants.String.EmailOperation.SignDocument, SignReqReplyToAddressValue);
                        }
                    }
                    else
                    {
                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            emailQueueData.envelope = envelopeObject;
                            emailQueueData.MailMessageBody = tempMailTemplateRecipients;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            emailQueueData.SanboxSigner = rec;
                            emailQueueData.EmailType = Constants.EmailTypes.DS;
                            emailQueueData.EmailSubject = GetEmailSubjectPrefix(envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.DocumentSigned);
                            // EnvelopeHelperMain.EmailQueueFunction(emailQueueData);
                            emailQueueAttachmentData = new EmailQueueProcessor.EmailQueueAttachmentData();
                            emailQueueAttachmentData.AttachmentData = attachments;
                            emailQueueAttachmentData.AttachmentNamesInfo = attachmentName;
                            EmailQueueFunction(emailQueueData, false, emailQueueAttachmentData);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
