                            else if (mailTemplateSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderSigner)
                            {
                                if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                                {
                                    string emailType = "";
                                    if (rec.RecipientTypeID == Constants.RecipientType.CC)
                                    {
                                        emailType = Constants.EmailTypes.ESCC;
                                    }
                                    else
                                    {
                                        emailType = Constants.EmailTypes.FD;
                                    }
                                    Recipients recp = new Recipients();
                                    recp.Name = rec.RecipientName;
                                    recp.Mobile = rec.RecipientMobile;
                                    recp.DialCode = rec.DialCode;
                                    string emailSubject = GetEmailSubjectPrefix(recipientCulture, envelopeObject.Subject, rec.RecipientTypeID == Constants.RecipientType.CC ? Constants.EmailSubject.FinalDocumentCC : Constants.EmailSubject.FinalDocument);
                                    SendSMSThroughEmailService(envelopeObject, recipientMailTemplate, SignReqReplyToAddressValue, emailType, recp, emailSubject);
                                }
                                else
                                {
                                    string signerMobileNumber = rec.DialCode + rec.RecipientMobile;
                                    SendMobileSMS(envelopeObject, recipientMailTemplate, signerMobileNumber);
                                }
                            }
                            else if (mailTemplateSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn ||
                            mailTemplateSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                            {
                                if (recipientIDs == null || (recipientIDs != null && recipientIDs.Any(s => rec.RecipientID == s)))
                                {
                                    if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                                    {
                                        string emailType = "";
                                        if (rec.RecipientTypeID == Constants.RecipientType.CC)
                                        {
                                            emailType = Constants.EmailTypes.ESCC;
                                        }
                                        else
                                        {
                                            emailType = Constants.EmailTypes.FD;
                                        }
                                        Recipients recp = new Recipients();
                                        recp.Name = rec.RecipientName;
                                        recp.Mobile = rec.RecipientMobile;
                                        recp.DialCode = rec.DialCode;
                                        string emailSubject = GetEmailSubjectPrefix(recipientCulture, envelopeObject.Subject, rec.RecipientTypeID == Constants.RecipientType.CC ? Constants.EmailSubject.FinalDocumentCC : Constants.EmailSubject.FinalDocument);
                                        SendSMSThroughEmailService(envelopeObject, recipientMailTemplateLogin, SignReqReplyToAddressValue, emailType, recp, emailSubject);
                                    }
                                    else
                                    {
                                        string signerMobileNumber = rec.DialCode + rec.RecipientMobile;
                                        SendMobileSMS(envelopeObject, recipientMailTemplateLogin, signerMobileNumber);
                                    }
                                }
                            }
                        }
                    }
                    else if (rec.RecipientTypeID == Constants.RecipientType.CC && (rec.CCSignerType == Constants.CCRecipientType.NotificationsOnly))
                    {
                        Dictionary<string, string> mailTemplateCCNotification = _genericRepository.GetNewMailTemplateList(Constants.String.MailTemplateName.FinalDocumentCC, CultureInfoList, mailTemplateSettings.EmailDisclaimer, 3, "mobile");

                        mailTemplate = new Dictionary<string, string>();
                        string recipientCulture = !string.IsNullOrEmpty(rec.CultureInfo) ? rec.CultureInfo : envelopeObject.CultureInfo;
                        mailTemplate = mailTemplateCCNotification;
                        mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#SenderName", senderDetails.Name);
                        mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#EnvelopeDisplayCode", Convert.ToString(envelopeObject.EDisplayCode));

                        if (sbSigner.Length > 0)
                        {
                            mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#ToList", sbSigner.ToString().Substring(0, sbSigner.ToString().LastIndexOf(",")));
                        }
                        else if (sbSigner.Length == 0 && prefillDeatilsCount > 0) //If only prefill exists in envelope
                        {
                            var senderDeatils = recipientList.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).FirstOrDefault();
                            var tempHtmlCode = htmlCodePrefill.Replace("'", "\"");
                            tempHtmlCode = tempHtmlCode.Replace("#ToName", senderDeatils.RecipientName);
                            tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", senderDeatils.RecipientEmail);
                            sbPrefill.Append(tempHtmlCode + ", ");

                            mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#ToList", sbPrefill.ToString().Substring(0, sbPrefill.ToString().LastIndexOf(",")));
                        }
                        else
                        {
                            mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#ToList", "-");
                        }
                        if (sbCC.Length > 0)
                        {
                            mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
                        }
                        else
                        {
                            mailTemplate = ReplaceMailTemplateValue(mailTemplate, "#CCList", "-");
                        }

                        msgId = Guid.NewGuid();
                        signerName = rec.RecipientName == "Hi" ? rec.RecipientEmail : rec.RecipientName;
                        Dictionary<string, string> message = mailTemplate;
                        string recipientMailTemplateCCNotifyOnly = mailTemplate.ContainsKey(recipientCulture) ? mailTemplate[recipientCulture] : mailTemplate.First().Value;
                        if (recipientIDs == null || (recipientIDs != null && recipientIDs.Any(s => rec.RecipientID == s)))
                        {
                            if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                            {
                                string emailType = Constants.EmailTypes.ESNCC;
                                Recipients recp = new Recipients();
                                recp.Name = rec.RecipientName;
                                recp.Mobile = rec.RecipientMobile;
                                recp.DialCode = rec.DialCode;
                                string emailSubject = GetEmailSubjectPrefix(recipientCulture, envelopeObject.Subject, Constants.EmailSubject.FinalDocumentCC);
                                SendSMSThroughEmailService(envelopeObject, recipientMailTemplateCCNotifyOnly, SignReqReplyToAddressValue, emailType, recp, emailSubject);
                            }
                            else
                            {
                                string signerMobileNumber = rec.DialCode + rec.RecipientMobile;
                                SendMobileSMS(envelopeObject, recipientMailTemplateCCNotifyOnly, signerMobileNumber);
                            }
                        }
                    }
                }
            }
            return true;
        }
        public void RejectToMail(string comment, string subject, string finalPdfFilePath, Envelope envelope, Recipients signerDetails, Recipients senderDetails, string contextVal, string envelopeDirectoryPath)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "RejectToMail", "Process started for Reject To Mail", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                string mailTemplate = string.Empty, mailTemplateRaw = string.Empty, mailTemplateCC = string.Empty, mailTemplatePwd = string.Empty, passwordOpen = string.Empty;
                List<string> docNames = new List<string>();
                bool IsAattachmentSent = true;
                var userProfile = _userRepository.GetUserProfile(envelope.UserID);
                Guid recipientTypeId = Constants.RecipientType.Sender;
                string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");

                //* Added by RLabs-RSign DEV Team
                var allSettingsDetails = GetAllSettingsDetails(envelope.UserID, senderDetails.EmailAddress);
                if (allSettingsDetails.ShowRSignLogo != true)
                {
                    imageLogoURl = "";
                }
                //*//
                string EmailDisclaimer = string.Empty;
                var settingDetailEmailDesclaimer = _settingsRepository.GetEntityForByKeyConfig(userProfile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                if (settingDetailEmailDesclaimer != null)
                {
                    EmailDisclaimer = Convert.ToString(settingDetailEmailDesclaimer.OptionValue);
                }
                int intDtFormat = 0;
                var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
                if (settingsDateTimeFormt != null)
                {
                    intDtFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);
                }
                var cultureInfo = envelope.CultureInfo;
                var currentCultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
                Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(cultureInfo);
                Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;
                string[] copyemail = new string[] { };
                UserProfile CopyusersInfo = !string.IsNullOrEmpty(senderDetails.EmailAddress) ? _userRepository.GetUserProfileByEmailID(senderDetails.EmailAddress) : null;
                if (CopyusersInfo != null)
                {
                    var copyEmailAddress = _settingsRepository.GetEntityForByKeyConfig(_userRepository.GetUserProfileByEmailID(senderDetails.EmailAddress).UserID, Constants.SettingsKeyConfig.EsignMailCopyAddress);

                    if (copyEmailAddress != null && copyEmailAddress.OptionValue != null && copyEmailAddress.OptionValue.Length > 0)
                    {
                        copyemail = copyEmailAddress.OptionValue.Split(new string[] { "," }, StringSplitOptions.None).Distinct().ToArray();
                    }
                }
                /*Update recipients for Out of Office Setting if any*/
                int updatedOutOfOffice = _recipientRepository.UpdateRecipientsforOutOfOffice(envelope.ID);
                var signerDetailsList = _recipientRepository.GetAll(envelope.ID).Where(r => (r.RecipientTypeID == Constants.RecipientType.Signer && r.Order <= signerDetails.Order) || r.RecipientTypeID == Constants.RecipientType.CC).ToList();

                var isPasswordMailToSigner = Convert.ToBoolean(envelope.IsPasswordMailToSigner);
                if (Convert.ToBoolean(envelope.EnableMessageToMobile))
                {
                    isPasswordMailToSigner = true;
                }
                if (envelope.PasswordReqdtoOpen == true && isPasswordMailToSigner)
                {
                    passwordOpen = ModelHelper.Decrypt(envelope.PasswordtoOpen, envelope.PasswordKey, (int)envelope.PasswordKeySize);
                    mailTemplatePwd = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordOpen, string.IsNullOrEmpty(cultureInfo) ? envelope.CultureInfo : cultureInfo, EmailDisclaimer);
                    mailTemplatePwd = EmailBannerSettings(mailTemplatePwd, allSettingsDetails, Constants.String.MailTemplateName.PasswordOpen);
                }
                // Created final docment with final contract
                var finalDocName = (envelope.Documents.Count() > 1) ? "Contracts" : envelope.Documents.First().DocumentName;
                finalDocName = Path.GetFileNameWithoutExtension(finalDocName);
                finalDocName = (envelope.Documents.Count() > 1 && envelope.IsSeparateMultipleDocumentsAfterSigningRequired == true) ? finalDocName + ".zip" : finalDocName + ".pdf";
                var attachments = new List<byte[]>();
                if (envelope.IsWaterMark == true)
                {
                    string finalPdfFilePathSigner = Path.GetDirectoryName(finalPdfFilePath);
                    if (envelope.Documents.Count() > 1 && envelope.IsSeparateMultipleDocumentsAfterSigningRequired == true)
                        finalPdfFilePathSigner = Path.Combine(finalPdfFilePathSigner, "ContractsSigner.zip");
                    else
                        finalPdfFilePathSigner = Path.Combine(finalPdfFilePathSigner, "OutputSigner.Pdf");
                    if (System.IO.File.Exists(finalPdfFilePathSigner))
                        finalPdfFilePath = finalPdfFilePathSigner;
                }
                byte[] finalMergedArray = System.IO.File.ReadAllBytes(finalPdfFilePath);
                if (finalMergedArray != null)
                    attachments.Add(finalMergedArray);
                docNames.Add(AppendDateTime(intDtFormat, finalDocName, envelope.ModifiedDateTime.ToString()));
                string finalCertificateName = string.Empty;
                if (envelope.IsFinalCertificateReq == null || (envelope.IsFinalCertificateReq != null && !envelope.IsFinalCertificateReq.Value))
                {
                    string tempEnvelopeDir = Path.Combine(envelopeDirectoryPath, envelope.ID.ToString());
                    var certificatepath = Path.Combine(tempEnvelopeDir, "ENV" + (envelope.EDisplayCode).ToString(System.Globalization.CultureInfo.InvariantCulture) + "_SigningCertificate.pdf");
                    finalCertificateName = "Certificate-" + envelope.EDisplayCode;
                    attachments.Add(System.IO.File.ReadAllBytes(certificatepath));
                    docNames.Add(AppendDateTime(intDtFormat, finalCertificateName, envelope.ModifiedDateTime.ToString()) + ".pdf");
                }
                mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.RejectSender, cultureInfo, EmailDisclaimer);
                mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.RejectSender);

                mailTemplateCC = mailTemplate;
                string strURL = string.Empty, strRetrievalLink = string.Empty; Guid intAttachedsignedPDF = Constants.AttachSignedPDF.SenderSigner;
                strURL = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
                //strURL += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelope.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));

                strURL += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2}&CultureInfo={3}", envelope.ID.ToString(), "", Convert.ToBoolean(envelope.EnableMessageToMobile) ? "1" : "0", cultureInfo), Convert.ToString(_appConfiguration["AppKey"])));

                strRetrievalLink = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/ViewDocument?");
                strRetrievalLink += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelope.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));

                string mailTemplateForRecepientLogIn = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.RejectSenderLogIn, cultureInfo, EmailDisclaimer);
                mailTemplateForRecepientLogIn = EmailBannerSettings(mailTemplateForRecepientLogIn, allSettingsDetails, Constants.String.MailTemplateName.RejectSenderLogIn);

                string mailTemplateForRecepientLogInCC = mailTemplateForRecepientLogIn;

                var attachSignPdfSettingsOptions = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.AttachSignedPDFOptionSetting);
                if (attachSignPdfSettingsOptions != null)
                    intAttachedsignedPDF = string.IsNullOrEmpty(attachSignPdfSettingsOptions.OptionValue) ? Constants.AttachSignedPDF.SenderSigner : new Guid(attachSignPdfSettingsOptions.OptionValue);
                if (!Convert.ToBoolean(envelope.IsFinalDocLinkReq))
                    intAttachedsignedPDF = Constants.AttachSignedPDF.SenderSigner;

                List<string> recipientSuccessEmailNotificationList = new List<string>();
                recipientSuccessEmailNotificationList.Add(senderDetails.EmailAddress);//As we are sending a different mail notification to sender, adding senders email address directly.

                List<string> signersEmailList = new List<string>();
                int isCopyAddress = 0;
                UserProfile usersInfo = new UserProfile();
                string SigneruserName = string.Empty;

                if (signerDetailsList != null && signerDetailsList.Count == 0)
                {
                    signerDetailsList = _recipientRepository.GetAll(envelope.ID).Where(r => (r.RecipientTypeID == Constants.RecipientType.Signer) || r.RecipientTypeID == Constants.RecipientType.CC).ToList();
                }

                foreach (Recipients recipient in signerDetailsList)
                {
                    signersEmailList.Clear();
                    isCopyAddress = 0;
                    signersEmailList.Add(recipient.EmailAddress);
                    if (!string.IsNullOrEmpty(recipient.CopyEmailAddress))
                    {
                        signersEmailList.AddRange(recipient.CopyEmailAddress.Split(','));
                    }
                    foreach (string signerEmail in signersEmailList)
                    {
                        if (isCopyAddress > 0)
                        {
                            usersInfo = _userRepository.GetSignerUserProfileByEmail(signerEmail);
                            SigneruserName = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : string.Empty;
                        }
                        mailTemplateRaw = mailTemplate;
                        if (recipient.RecipientTypeID == Constants.RecipientType.Sender)
                        {
                            IsAattachmentSent = (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient ||
                              intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn) ? false : true;
                            if (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink ||
                                 intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient ||
                                 intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                                mailTemplateRaw = mailTemplateRaw.Replace("#URL", strRetrievalLink);
                            else
                                mailTemplateRaw = mailTemplateRaw.Replace("#URL", strURL);
                        }
                        else
                        {
                            IsAattachmentSent = (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly ||
                                        intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn ||
                                        intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn
                                        || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                                        ) ? false : true;
                            if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderSigner)
                            {
                                if (envelope.IsWaterMark == true)
                                {
                                    strURL = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
                                    //strURL += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}", envelope.ID.ToString(), recipient.RecipientTypeID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                                    strURL += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2}&CultureInfo={3}", envelope.ID.ToString(), signerDetails.RecipientTypeID.ToString(), Convert.ToBoolean(envelope.EnableMessageToMobile) ? "1" : "0", envelope.CultureInfo), Convert.ToString(_appConfiguration["AppKey"])));
                                }
                                mailTemplateRaw = mailTemplateRaw.Replace("#URL", strURL);
                            }
                            else if (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly)
                            {
                                if (envelope.IsWaterMark == true)
                                {
                                    strRetrievalLink = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/ViewDocument?");
                                    strRetrievalLink += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&currentStatus={1}&RecipientTypeId={2}", envelope.ID.ToString(), "0", recipient.RecipientTypeID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                                }
                                mailTemplateRaw = mailTemplateRaw.Replace("#URL", strRetrievalLink);
                            }
                            else if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                                mailTemplateForRecepientLogIn = mailTemplateForRecepientLogIn.Replace("#URL", Path.Combine(Convert.ToString(_appConfiguration["SigningURL"])));
                        }

                        if (recipientSuccessEmailNotificationList.Contains(signerEmail, StringComparer.OrdinalIgnoreCase))
                            continue;
                        recipientSuccessEmailNotificationList.Add(signerEmail);

                        bool isEmailSend = false, isPwdEmailSend = false;
                        bool isMobileSend = false, isPwdMobileSend = false;

                        if (envelope != null && Convert.ToBoolean(envelope.EnableMessageToMobile))
                        {
                            isPasswordMailToSigner = true;
                            GetEmailDeiliveryModeOptions(signerDetails, ref isEmailSend, ref isMobileSend);
                            GetMobileDeiliveryModeOptions(signerDetails, ref isPwdEmailSend, ref isPwdMobileSend);
                        }
                        else
                        {
                            isPwdEmailSend = true;
                            isEmailSend = true;
                        }

                        if (envelope.PasswordReqdtoOpen == true && isPasswordMailToSigner)
                        {
                            mailTemplatePwd = _genericRepository.AppendFooterText(mailTemplatePwd, signerEmail, Constants.String.MailTemplateName.PasswordOpen, !string.IsNullOrEmpty(recipient.CultureInfo) ? recipient.CultureInfo : cultureInfo, "FinalContractFooter");

                            if (((recipient.RecipientTypeID == Constants.RecipientType.Signer || recipient.RecipientTypeID == Constants.RecipientType.CC)
                                && (intAttachedsignedPDF != Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                                && intAttachedsignedPDF != Constants.AttachSignedPDF.SenderOnlyandNoemailtoRecipient)) || recipient.RecipientTypeID == Constants.RecipientType.Sender)
                                sendPasswordEmail(signerEmail, isCopyAddress == 0 ? recipient.Name : SigneruserName, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipient.CultureInfo) ? recipient.CultureInfo : cultureInfo, envelope.Subject, Constants.EmailSubject.PasswordToOpen),
                                    passwordOpen, mailTemplatePwd, recipient, senderDetails, envelope.UserID, envelope, "Password", isPwdEmailSend, isPwdMobileSend);
                        }
                        if (recipient.RecipientTypeID == Constants.RecipientType.Sender)
                        {
                            mailTemplateRaw = _genericRepository.AppendFooterText(mailTemplateRaw, signerEmail, Constants.String.MailTemplateName.RejectSender, cultureInfo, "FinalContractFooter");

                            sendEmailTemplate(signerEmail, isCopyAddress == 0 ? recipient.Name : SigneruserName, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipient.CultureInfo) ? recipient.CultureInfo : cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplateRaw, recipient, senderDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), "", envelope, "RejectMailToSinger", true, false);
                        }
                        else
                        {
                            if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderSigner || intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly)
                            {
                                mailTemplateRaw = _genericRepository.AppendFooterText(mailTemplateRaw, signerEmail, Constants.String.MailTemplateName.RejectSender, cultureInfo, "FinalContractFooter");

                                sendEmailTemplate(signerEmail, isCopyAddress == 0 ? recipient.Name : SigneruserName, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipient.CultureInfo) ? recipient.CultureInfo : cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplateRaw, recipient, senderDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), signerEmail, envelope, "RejectMailToSinger", isEmailSend, isMobileSend);
                            }
                            else if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                            {
                                mailTemplateForRecepientLogIn = _genericRepository.AppendFooterText(mailTemplateForRecepientLogIn, signerEmail, Constants.String.MailTemplateName.RejectSenderLogIn, cultureInfo, "FinalContractFooter");

                                sendEmailTemplate(signerEmail, isCopyAddress == 0 ? recipient.Name : SigneruserName, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(!string.IsNullOrEmpty(recipient.CultureInfo) ? recipient.CultureInfo : cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplateForRecepientLogIn, recipient, senderDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), signerEmail, envelope, "RejectMailToSinger", isEmailSend, isMobileSend);
                            }
                        }
                        isCopyAddress++;
                    }
                }

                if (copyemail.Length > 0)
                {
                    foreach (var rec in copyemail)
                    {
                        if (recipientSuccessEmailNotificationList.Contains(rec, StringComparer.OrdinalIgnoreCase))
                            continue;
                        recipientSuccessEmailNotificationList.Add(rec);
                        if (envelope.PasswordReqdtoOpen && envelope.IsPasswordMailToSigner)
                        {
                            if (intAttachedsignedPDF != Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                                && intAttachedsignedPDF != Constants.AttachSignedPDF.SenderOnlyandNoemailtoRecipient)
                            {
                                mailTemplatePwd = _genericRepository.AppendFooterText(mailTemplatePwd, rec, Constants.String.MailTemplateName.PasswordOpen, cultureInfo, "FinalContractFooter");

                                sendPasswordEmailToAddress(rec, rec, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, envelope.Subject, Constants.EmailSubject.PasswordToOpen), passwordOpen, mailTemplatePwd, rec, senderDetails, envelope.UserID, envelope);
                            }
                        }
                        if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderSigner || intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly)
                        {
                            mailTemplateCC = _genericRepository.AppendFooterText(mailTemplateCC, rec, Constants.String.MailTemplateName.RejectSender, cultureInfo, "FinalContractFooter");

                            sendEmailTemplateToAddress(rec, rec, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplateCC, rec, senderDetails, envelope.UserID, envelope.ID.ToString(), envelope);
                        }
                        else if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        {
                            mailTemplateForRecepientLogInCC = _genericRepository.AppendFooterText(mailTemplateForRecepientLogInCC, rec, Constants.String.MailTemplateName.RejectSenderLogIn, cultureInfo, "FinalContractFooter");

                            sendEmailTemplateToAddress(rec, rec, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplateForRecepientLogInCC, rec, senderDetails, envelope.UserID, envelope.ID.ToString(), envelope);
                        }
                    }
                }

                _recipientRepository.ModifyLastRecipientEntry(signerDetails.ID, Constants.StatusCode.Signer.Rejected, envelope.IpAddress);

                loggerModelNew.Message = "Process completed for Reject To Mail";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - RejectToMail method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
        }
        public void RejectMailToSender(string comment, string subject, string finalPdfFilePath, Envelope envelope, Recipients signerDetails, Recipients senderDetails, string contextVal, string envelopeDirectoryPath)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "RejectMailToSender", "Process started for Reject Mail To Sender", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                string mailTemplate = string.Empty;
                var userprofile = _userRepository.GetUserProfile(envelope.UserID);
                byte[] xmlAttachment = null;
                List<string> docNames = new List<string>();
                UserProfile usersInfo = new UserProfile();
                var cultureInfo = envelope.CultureInfo;
                var currentCultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
                Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(cultureInfo);
                Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;
                string EmailDisclaimer = string.Empty;
                Guid intAttachedsignedPDF = Constants.AttachSignedPDF.SenderSigner;
                string senderOrgName = string.Empty, senderOrgEmail = string.Empty;
                //* Added by RLabs-RSign DEV Team
                var allSettingsDetails = GetAllSettingsDetails(envelope.UserID, senderDetails.EmailAddress);

                Recipients senderCopyDetails = new Recipients();
                senderCopyDetails = senderDetails;
                senderOrgName = senderDetails.Name;
                senderOrgEmail = senderDetails.EmailAddress;
                int isSenderCopyAddress = 0;
                var settingDetailEmailDesclaimer = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                if (settingDetailEmailDesclaimer != null)
                {
                    EmailDisclaimer = Convert.ToString(settingDetailEmailDesclaimer.OptionValue);
                }
                int intDtFormat = 0;
                var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
                if (settingsDateTimeFormt != null)
                {
                    intDtFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);
                }
                string[] rerouteEmail = new string[] { };
                UserProfile CopyusersInfo = !string.IsNullOrEmpty(senderDetails.EmailAddress) ? _userRepository.GetUserProfileByEmailID(senderDetails.EmailAddress) : null;
                if (CopyusersInfo != null)
                {
                    var rerouteEmailAddress = _settingsRepository.GetEntityForByKeyConfig(_userRepository.GetUserProfileByEmailID(senderDetails.EmailAddress).UserID, Constants.SettingsKeyConfig.EsignMailRerouteAddress);

                    if (rerouteEmailAddress != null && rerouteEmailAddress.OptionValue != null && rerouteEmailAddress.OptionValue.Length > 0)
                    {
                        rerouteEmail = rerouteEmailAddress.OptionValue.Split(new string[] { "," }, StringSplitOptions.None).Distinct().ToArray();
                    }
                }
                List<string> senderEmailList = new List<string>();
                //List<string> senderEmailNamesList = new List<string>();
                senderEmailList = new List<string>(new string[] { senderDetails.EmailAddress });
                //senderEmailNamesList = new List<string>(new string[] { senderDetails.Name });

                if (envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender && !string.IsNullOrEmpty(r.CopyEmailAddress)).Count() > 0)
                {
                    if (!string.IsNullOrEmpty(senderDetails.CopyEmailAddress))
                    {
                        senderEmailList.AddRange(senderDetails.CopyEmailAddress.Split(','));
                    }
                }

                var attachSignPdfSettingsOptions = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.AttachSignedPDFOptionSetting);
                if (attachSignPdfSettingsOptions != null)
                    intAttachedsignedPDF = string.IsNullOrEmpty(attachSignPdfSettingsOptions.OptionValue) ? Constants.AttachSignedPDF.SenderSigner : new Guid(attachSignPdfSettingsOptions.OptionValue);
                if (!Convert.ToBoolean(envelope.IsFinalDocLinkReq))
                    intAttachedsignedPDF = Constants.AttachSignedPDF.SenderSigner;

                //bool isEmailSend = false;
                //bool isMobileSend = false;

                //if (envelope != null && Convert.ToBoolean(envelope.EnableMessageToMobile))
                //{
                //    if ((signerDetails.DeliveryMode == 1 || signerDetails.DeliveryMode == 2) && !string.IsNullOrEmpty(signerDetails.EmailAddress))
                //    {
                //        isEmailSend = true;
                //    }

                //    if ((signerDetails.DeliveryMode == 2 || signerDetails.DeliveryMode == 3) && !string.IsNullOrEmpty(signerDetails.Mobile))
                //    {
                //        isMobileSend = true;
                //    }
                //    if (signerDetails.DeliveryMode == null) { isEmailSend = true; }
                //}
                //else
                //{
                //    isEmailSend = true;
                //}

                var isPasswordMailToSigner = Convert.ToBoolean(envelope.IsPasswordMailToSigner);
                if (Convert.ToBoolean(envelope.EnableMessageToMobile))
                {
                    isPasswordMailToSigner = true;
                }

                if (envelope.PasswordReqdtoOpen == true && isPasswordMailToSigner)
                {
                    string passwordOpen = ModelHelper.Decrypt(envelope.PasswordtoOpen, envelope.PasswordKey, (int)envelope.PasswordKeySize);
                    mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordOpen, string.IsNullOrEmpty(cultureInfo) ? envelope.CultureInfo : cultureInfo, EmailDisclaimer);
                    mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.PasswordOpen);
                    if (rerouteEmail.Length > 0)
                    {
                        foreach (var rec in rerouteEmail)
                        {
                            mailTemplate = _genericRepository.AppendFooterText(mailTemplate, rec, Constants.String.MailTemplateName.PasswordOpen, string.IsNullOrEmpty(cultureInfo) ? envelope.CultureInfo : cultureInfo, "FinalContractFooter");

                            sendPasswordEmail(rec, rec, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, envelope.Subject, Constants.EmailSubject.PasswordToOpen), passwordOpen, mailTemplate, senderDetails, senderDetails, envelope.UserID, envelope, "Password", true, false);
                        }
                    }

                    if (((senderDetails.RecipientTypeID == Constants.RecipientType.Signer || senderDetails.RecipientTypeID == Constants.RecipientType.CC)
                        && (intAttachedsignedPDF != Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                        && intAttachedsignedPDF != Constants.AttachSignedPDF.SenderOnlyandNoemailtoRecipient)) || senderDetails.RecipientTypeID == Constants.RecipientType.Sender)
                    {
                        foreach (string senderEmail in senderEmailList)
                        {
                            if (isSenderCopyAddress > 0)
                            {
                                senderCopyDetails.EmailAddress = senderEmail;
                                usersInfo = !string.IsNullOrEmpty(senderEmail) ? _userRepository.GetUserProfileByEmailID(senderEmail) : null;
                                senderCopyDetails.Name = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : senderEmail.Split('@')[0];
                            }
                            isSenderCopyAddress++;

                            mailTemplate = _genericRepository.AppendFooterText(mailTemplate, senderEmail, Constants.String.MailTemplateName.PasswordOpen, string.IsNullOrEmpty(cultureInfo) ? envelope.CultureInfo : cultureInfo, "FinalContractFooter");

                            sendPasswordEmail(string.Empty, string.Empty, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, envelope.Subject, Constants.EmailSubject.PasswordToOpen), passwordOpen, mailTemplate, senderCopyDetails, senderCopyDetails, envelope.UserID, envelope, "Password", true, false);
                        }
                    }
                }
                senderDetails.EmailAddress = senderOrgEmail;
                senderDetails.Name = senderOrgName;
                // Created final docment with final contract
                var finalDocName = (envelope.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) ? "Contracts" : envelope.Documents.First().DocumentName;
                finalDocName = Path.GetFileNameWithoutExtension(finalDocName);
                finalDocName = (envelope.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1 && envelope.IsSeparateMultipleDocumentsAfterSigningRequired == true) ? finalDocName + ".zip" : finalDocName + ".pdf";

                var attachments = new List<byte[]>();
                byte[] finalMergedArray = System.IO.File.ReadAllBytes(finalPdfFilePath);
                if (finalMergedArray != null)
                    attachments.Add(finalMergedArray);
                docNames.Add(AppendDateTime(intDtFormat, finalDocName, envelope.ModifiedDateTime.ToString()));
                if (envelope.IsAttachXML == true)
                {
                    EnvelopeContent envelopeContent = CreateXml(envelope);
                    xmlAttachment = System.IO.File.ReadAllBytes(_eSignHelper.CreateXmlFileToSend(envelope, envelopeContent));
                    if (xmlAttachment != null)
                    {
                        attachments.Add(xmlAttachment);
                        docNames.Add(AppendDateTime(intDtFormat, "Envelope.xml", envelope.ModifiedDateTime.ToString()));
                    }
                }
                string finalCertificateName = string.Empty;
                if (envelope.IsFinalCertificateReq == null || (envelope.IsFinalCertificateReq != null && !envelope.IsFinalCertificateReq.Value))
                {
                    string tempEnvelopeDir = Path.Combine(envelopeDirectoryPath, envelope.ID.ToString());
                    var certificatepath = Path.Combine(tempEnvelopeDir, "ENV" + (envelope.EDisplayCode).ToString(System.Globalization.CultureInfo.InvariantCulture) + "_SigningCertificate.pdf");
                    finalCertificateName = "Certificate-" + envelope.EDisplayCode;
                    attachments.Add(System.IO.File.ReadAllBytes(certificatepath));
                    docNames.Add(AppendDateTime(intDtFormat, finalCertificateName, envelope.ModifiedDateTime.ToString()) + ".pdf");
                }
                mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.RejectSender, cultureInfo, EmailDisclaimer);
                mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.RejectSender);

                string strURL = string.Empty, strRetrievalLink = string.Empty;
                strURL = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
                //strURL += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelope.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                strURL += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2},&CultureInfo={3}", envelope.ID.ToString(), "", Convert.ToBoolean(envelope.EnableMessageToMobile) ? "1" : "0", envelope.CultureInfo), Convert.ToString(_appConfiguration["AppKey"])));
                strRetrievalLink = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/ViewDocument?");
                strRetrievalLink += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", envelope.ID.ToString()), Convert.ToString(_appConfiguration["AppKey"])));

                string mailTemplateForRecepientLogIn = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.RejectSenderLogIn, cultureInfo, EmailDisclaimer);
                mailTemplateForRecepientLogIn = EmailBannerSettings(mailTemplateForRecepientLogIn, allSettingsDetails, Constants.String.MailTemplateName.RejectSenderLogIn);

                string mailTemplateForRecepientLogInCC = mailTemplateForRecepientLogIn;

                bool IsAattachmentSent = true;
                if (senderDetails.RecipientTypeID == Constants.RecipientType.Sender)
                {
                    IsAattachmentSent = (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient ||
                             intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn) ? false : true;
                    if (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient ||
                             intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        mailTemplate = mailTemplate.Replace("#URL", strRetrievalLink);
                    else
                        mailTemplate = mailTemplate.Replace("#URL", strURL);
                }
                else
                {
                    IsAattachmentSent = (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly ||
                             intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn) ? false : true;
                    if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderSigner)
                        mailTemplate = mailTemplate.Replace("#URL", strURL);
                    else if (intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly)
                        mailTemplate = mailTemplate.Replace("#URL", strRetrievalLink);
                    else if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        mailTemplateForRecepientLogIn = mailTemplateForRecepientLogIn.Replace("#URL", Path.Combine(Convert.ToString(_appConfiguration["SigningURL"])));
                }

                string RecipientfirstName = string.Empty, mailTemplateSender = string.Empty, senderName = string.Empty;
                //UserProfile usersInfo = new UserProfile();
                //foreach (string senderEmail in senderEmailList)
                //{
                //}
                if (rerouteEmail.Length > 0)
                {
                    foreach (var rec in rerouteEmail)
                    {
                        mailTemplate = _genericRepository.AppendFooterText(mailTemplate, rec, Constants.String.MailTemplateName.RejectSender, cultureInfo, "FinalContractFooter");

                        sendEmailTemplate(rec, string.Empty, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplate, senderDetails, senderDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), rec, envelope, "RejectMailToSender", true, false);
                    }
                }
                isSenderCopyAddress = 0;
                senderCopyDetails = senderDetails;
                foreach (string senderEmail in senderEmailList)
                {
                    if (isSenderCopyAddress > 0)
                    {
                        senderCopyDetails.EmailAddress = senderEmail;
                        usersInfo = !string.IsNullOrEmpty(senderEmail) ? _userRepository.GetUserProfileByEmailID(senderEmail) : null;
                        senderCopyDetails.Name = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : senderEmail.Split('@')[0];
                    }
                    isSenderCopyAddress++;
                    if (senderDetails.RecipientTypeID == Constants.RecipientType.Sender)
                    {
                        mailTemplate = _genericRepository.AppendFooterText(mailTemplate, senderEmail, Constants.String.MailTemplateName.RejectSender, cultureInfo, "FinalContractFooter");

                        sendEmailTemplate(string.Empty, string.Empty, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplate, signerDetails, senderCopyDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), "", envelope, "RejectMailToSender", true, false);
                    }
                    else
                    {
                        if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderSigner || intAttachedsignedPDF == Constants.AttachSignedPDF.RetrievalLink || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnly)
                        {
                            mailTemplate = _genericRepository.AppendFooterText(mailTemplate, senderEmail, Constants.String.MailTemplateName.RejectSender, cultureInfo, "FinalContractFooter");

                            sendEmailTemplate(string.Empty, string.Empty, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplate, signerDetails, senderCopyDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), "", envelope, "RejectMailToSender", true, false);
                        }
                        else if (intAttachedsignedPDF == Constants.AttachSignedPDF.SenderOnlyandRecipientSignIn || intAttachedsignedPDF == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        {
                            mailTemplateForRecepientLogIn = _genericRepository.AppendFooterText(mailTemplateForRecepientLogIn, senderEmail, Constants.String.MailTemplateName.RejectSenderLogIn, cultureInfo, "FinalContractFooter");

                            sendEmailTemplate(string.Empty, string.Empty, envelope.EDisplayCode.ToString(), GetEmailSubjectPrefix(cultureInfo, subject, Constants.EmailSubject.SignatureRequest), comment, attachments, docNames, mailTemplateForRecepientLogIn, signerDetails, senderCopyDetails, IsAattachmentSent, envelope.UserID, envelope.ID.ToString(), "", envelope, "RejectMailToSender", true, false);
                        }
                    }
                }
                loggerModelNew.Message = "Process completed for Reject Mail To Sender";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - RejectMailToSender method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
        }
        private void sendPasswordEmail(string rEmail, string rName, string EDisplayCode, string subject, string passwordOpen, string mailTemplatepassword, Recipients signerDetails, Recipients senderDetails, Guid UserId, Envelope envelope, string from = "", bool isEmailSend = false, bool isMobileSend = false)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "sendEmailTemplateToAddress", "Process started for Send Password Email", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
            imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
            int SignReqReplyToAddressValue = 1;

            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(envelope.ID);
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            if (isEmailSend)
            {
                mailTemplatepassword = mailTemplatepassword.Replace("#RecipientName", senderDetails.Name.Split(' ').FirstOrDefault());
                mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeStatus", "Rejected".ToLower());
                mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", senderDetails.Name);
                mailTemplatepassword = mailTemplatepassword.Replace("#SenderEmailId", senderDetails.EmailAddress);
                mailTemplatepassword = mailTemplatepassword.Replace("#ToName", signerDetails.Name);

                //if (!string.IsNullOrEmpty(signerDetails.Mobile) && !string.IsNullOrEmpty(signerDetails.EmailAddress) && signerDetails.DeliveryMode == 2)
                //    mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", signerDetails.EmailAddress + ", " + signerDetails.DialCode + signerDetails.Mobile);
                //else if (!string.IsNullOrEmpty(signerDetails.EmailAddress) && signerDetails.DeliveryMode == 1)
                //    mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", signerDetails.EmailAddress);
                //else if (!string.IsNullOrEmpty(signerDetails.Mobile) && signerDetails.DeliveryMode == 3)
                //    mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", signerDetails.DialCode + signerDetails.Mobile);
                //else if (!string.IsNullOrEmpty(signerDetails.EmailAddress))
                //    mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", signerDetails.EmailAddress);

                string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signerDetails.DeliveryMode, signerDetails.EmailAddress, signerDetails.DialCode, signerDetails.Mobile);
                mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", emailMobileNumberDetails);


                mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", EDisplayCode);
                mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(passwordOpen));
                //mailTemplatepassword = mailTemplatepassword.Replace("#ImageURL", imageLogoURl);
                mailTemplatepassword = mailTemplatepassword.Replace("#clientLogo", string.Empty);
                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    //To Add data in Emailqueue and EmailqueueRecipients for  Electronic Signature Password Open 
                    EmailQueueData emailQueueData = new EmailQueueData();
                    EmailSendInfo emailSendData = new EmailSendInfo();
                    emailQueueData.envelope = envelope;
                    emailQueueData.MailMessageBody = mailTemplatepassword;
                    emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                    emailQueueData.EmailType = Constants.EmailTypes.ESPO;
                    emailQueueData.EmailSubject = subject;
                    emailSendData.RecipientName = string.IsNullOrEmpty(rName) ? senderDetails.Name : rName;
                    emailSendData.RecipientEmail = string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail;
                    emailQueueData.emailSendInfo = emailSendData;

                    if (from == "RejectMailToSender")
                    {
                        emailQueueData.EmailType = Constants.EmailTypes.DESR;
                        EmailQueueFunction(emailQueueData);
                    }
                    else if (from == "Password")
                    {
                        EmailQueueFunction(emailQueueData);
                    }
                    else
                    {
                        EmailQueueFunction(emailQueueData, true);
                    }
                }
                else
                {
                    var Chilkat = new ChilkatHelper(_appConfiguration);
                    Chilkat.SendMailUsingChilKet(new string[] { string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail }, new string[] { string.IsNullOrEmpty(rName) ? senderDetails.Name : rName },
                       null, null,
                        null, null,
                        senderDetails.EmailAddress, senderDetails.Name,
                       subject, mailTemplatepassword,
                        null, null, EDisplayCode, Constants.String.EmailOperation.PasswordToOpen, SignReqReplyToAddressValue);
                }
            }

            if (isMobileSend)
            {
                cultureInfo = string.IsNullOrEmpty(signerDetails.CultureInfo) ? "en-us" : signerDetails.CultureInfo;
                mailTemplatepassword = string.Empty;
                mailTemplatepassword = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordOpen, cultureInfo, "", 3, "mobile");

                mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", senderDetails.Name);
                mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", EDisplayCode);
                mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(passwordOpen));

                if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    string emailSubject = GetEmailSubjectPrefix(cultureInfo, envelope.Subject, Constants.EmailSubject.PasswordToOpen);
                    SendSMSThroughEmailService(envelope, mailTemplatepassword, SignReqReplyToAddressValue, Constants.EmailTypes.ESPN, signerDetails, emailSubject);
                }
                else
                {
                    string signerMobileNumber = signerDetails.DialCode + signerDetails.Mobile;
                    SendMobileSMS(envelope, mailTemplatepassword, signerMobileNumber);
                }
            }

            loggerModelNew.Message = "Process completed for Send Password Email";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        private void sendEmailTemplate(string rEmail, string rName, string EDisplayCode, string subject, string comment, List<byte[]> attachments, List<string> docNames, string mailTemplateToSenderOrRecipient, Recipients signerDetails, Recipients senderDetails, Boolean IsAtachmentsent, Guid userId, string EnvelopeId = "", string emailName = "", Envelope envelope = null, string from = "", bool isEmailSend = false, bool isMobileSend = false)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "sendEmailTemplate", "Process started for send email template", EnvelopeId, "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
            imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
            int SignReqReplyToAddressValue = 1;

            var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(userId, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
            //if (settingsDetails != null)
            //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(new Guid(EnvelopeId));  //dbContext.EnvelopeSettingsDetail.Where(e => e.EnvelopeId == new Guid(EnvelopeId)).FirstOrDefault();
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            if (isEmailSend)
            {
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#RecipientName", string.IsNullOrEmpty(rName) ? senderDetails.Name : rName.Split(' ').FirstOrDefault());
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#SenderName", senderDetails.Name);
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#SenderEmailId", senderDetails.EmailAddress);
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToName", string.IsNullOrEmpty(rName) ? signerDetails.Name : rName.Split(' ').FirstOrDefault());

                //if (!string.IsNullOrEmpty(signerDetails.Mobile) && !string.IsNullOrEmpty(signerDetails.EmailAddress))
                //    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToEmailId", signerDetails.EmailAddress + ", " + signerDetails.DialCode + signerDetails.Mobile);
                //else if (!string.IsNullOrEmpty(signerDetails.EmailAddress))
                //    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToEmailId", signerDetails.EmailAddress);
                //else if (!string.IsNullOrEmpty(signerDetails.Mobile))
                //    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToEmailId", signerDetails.DialCode + signerDetails.Mobile);

                string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signerDetails.DeliveryMode, signerDetails.EmailAddress, signerDetails.DialCode, signerDetails.Mobile);
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToEmailId", emailMobileNumberDetails);

                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#EnvelopeDisplayCode", EDisplayCode);
                //mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ImageURL", imageLogoURl);
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ReasonToDecline", comment);
                mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#clientLogo", string.Empty);
                //string strURL = Path.Combine(Convert.ToString(System.Configuration._appConfiguration["domain"]), "SignDocument/GetPDF?");
                //strURL = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", EnvelopeId.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                //mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#URL", strURL);
                double fileSizes = attachments.Sum(arr => arr.Length);
                fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);

                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    if (fileSizes > 20 || IsAtachmentsent == false)
                    {
                        mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", Convert.ToString(_appConfiguration["DocumentSizeMsg"]));
                    }
                    else
                    {
                        mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", "");
                    }

                    //To Add data in Emailqueue and EmailqueueRecipients for Reject 
                    EmailQueueData emailQueueData = new EmailQueueData();
                    EmailSendInfo emailSendData = new EmailSendInfo();
                    emailQueueData.envelope = envelope;
                    emailQueueData.MailMessageBody = mailTemplateToSenderOrRecipient;
                    emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                    if (!string.IsNullOrEmpty(rName))
                    {
                        emailQueueData.EmailType = Constants.EmailTypes.DSR;
                    }
                    else
                    {
                        emailQueueData.EmailType = Constants.EmailTypes.DESR;
                    }
                    emailQueueData.EmailSubject = subject;

                    if (from == "RejectMailToSender")
                    {
                        emailSendData.RecipientName = senderDetails.Name;
                        emailSendData.RecipientEmail = senderDetails.EmailAddress;
                        emailQueueData.emailSendInfo = emailSendData;
                    }
                    else
                    {
                        emailSendData.RecipientName = signerDetails.Name;
                        emailSendData.RecipientEmail = signerDetails.EmailAddress;
                        emailQueueData.emailSendInfo = emailSendData;
                    }
                    if (fileSizes > 20 || IsAtachmentsent == false)
                    {
                        EmailQueueFunction(emailQueueData);
                    }
                    else
                    {
                        EmailQueueAttachmentData emailQueueAttachmentData = new EmailQueueAttachmentData();
                        emailQueueAttachmentData.AttachmentData = attachments;
                        emailQueueAttachmentData.AttachmentNamesInfo = docNames;
                        EmailQueueFunction(emailQueueData, false, emailQueueAttachmentData);
                    }
                }
                else
                {
                    var Chilkat = new ChilkatHelper(_appConfiguration);
                    if (fileSizes > 20 || IsAtachmentsent == false)
                    {
                        if (fileSizes > 20)
                        {
                            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", Convert.ToString(_appConfiguration["DocumentSizeMsg"]));
                        }
                        else if (IsAtachmentsent == false)
                        {
                            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", "");
                        }

                        Chilkat.SendMailUsingChilKet(new string[] { string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail }, new string[] { string.IsNullOrEmpty(emailName) ? (string.IsNullOrEmpty(rName) ? senderDetails.Name : rName) : emailName },
                                            null, null,
                                            null, null,
                                            senderDetails.EmailAddress.ToString(), senderDetails.Name, subject, mailTemplateToSenderOrRecipient, null, null, EDisplayCode, Constants.String.EmailOperation.Reject, SignReqReplyToAddressValue);
                    }
                    else
                    {
                        mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", "");
                        Chilkat.SendMailUsingChilKet(new string[] { string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail }, new string[] { string.IsNullOrEmpty(emailName) ? (string.IsNullOrEmpty(rName) ? senderDetails.Name : rName) : emailName },
                                            null, null,
                                            null, null,
                                            senderDetails.EmailAddress.ToString(), senderDetails.Name, subject, mailTemplateToSenderOrRecipient, attachments, docNames, EDisplayCode, Constants.String.EmailOperation.Reject, SignReqReplyToAddressValue);
                    }
                }

            }

            if (isMobileSend)
            {
                string mailTemplate = "";
                string cultureInfo = string.IsNullOrEmpty(signerDetails.CultureInfo) ? "en-us" : signerDetails.CultureInfo.ToLower();
                mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.RejectRecipient, cultureInfo, "", 3, "mobile");
                mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", EDisplayCode);

                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    // EnvelopeHelperMain envelopeHelperMain = new EnvelopeHelperMain();
                    string emailSubject = GetEmailSubjectPrefix(cultureInfo, envelope.Subject, Constants.EmailSubject.SignatureRequest);
                    SendSMSThroughEmailService(envelope, mailTemplate, SignReqReplyToAddressValue, Constants.EmailTypes.DESR, signerDetails, emailSubject);
                }
                else
                {
                    string signerMobileNumber = signerDetails.DialCode + signerDetails.Mobile;
                    SendMobileSMS(envelope, mailTemplate, signerMobileNumber);
                }
            }

            loggerModelNew.Message = "Process completed for send email template";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        public void sendPasswordEmailToAddress(string rEmail, string rName, string EDisplayCode, string subject, string passwordOpen, string mailTemplatepassword, string Email, Recipients senderDetails, Guid UserId, Envelope envelope = null)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "sendEmailTemplateToAddress", "Process started for Send Password Email To Address", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
            imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
            int SignReqReplyToAddressValue = 1;

            // var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(UserId, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
            //if (settingsDetails != null)
            //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(envelope.ID);
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            mailTemplatepassword = mailTemplatepassword.Replace("#RecipientName", senderDetails.Name.Split(' ').FirstOrDefault());
            mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeStatus", "Rejected".ToLower());
            mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", senderDetails.Name);
            mailTemplatepassword = mailTemplatepassword.Replace("#SenderEmailId", senderDetails.EmailAddress);
            mailTemplatepassword = mailTemplatepassword.Replace("#ToName", "Hi");
            mailTemplatepassword = mailTemplatepassword.Replace("#ToEmailEmailId", Email);
            mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", EDisplayCode);
            mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(passwordOpen));
            mailTemplatepassword = mailTemplatepassword.Replace("#ImageURL", imageLogoURl);
            mailTemplatepassword = mailTemplatepassword.Replace("#clientLogo", string.Empty);
            if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
            {
                //To Add data in Emailqueue and EmailqueueRecipients for Electronic Signature Password Notification 
                EmailQueueData emailQueueDataPassword = new EmailQueueData();
                EmailSendInfo emailSendData = new EmailSendInfo();
                // EmailQueueProcessor.EmailQueueData emailQueueDataPassword = new EmailQueueProcessor.EmailQueueData();
                emailQueueDataPassword.envelope = envelope;
                emailQueueDataPassword.MailMessageBody = mailTemplatepassword;
                emailQueueDataPassword.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                //emailQueueDataPassword.Signer = senderDetails;
                emailQueueDataPassword.EmailType = Constants.EmailTypes.ESPN;
                emailQueueDataPassword.EmailSubject = GetEmailSubjectPrefix(envelope.CultureInfo, envelope.Subject, Constants.EmailSubject.PasswordToOpen);
                emailSendData.RecipientName = string.IsNullOrEmpty(rName) ? senderDetails.Name : rName;
                emailSendData.RecipientEmail = string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail;
                emailQueueDataPassword.emailSendInfo = emailSendData;
                EmailQueueFunction(emailQueueDataPassword);
            }
            else
            {
                var Chilkat = new ChilkatHelper(_appConfiguration);
                Chilkat.SendMailUsingChilKet(new string[] { string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail }, new string[] { string.IsNullOrEmpty(rName) ? senderDetails.Name : rName },
                   null, null,
                    null, null,
                    senderDetails.EmailAddress, senderDetails.Name,
                   subject, mailTemplatepassword,
                    null, null, EDisplayCode, Constants.String.EmailOperation.PasswordToOpen, SignReqReplyToAddressValue);
            }
            loggerModelNew.Message = "Process completed for Send Password Email To Address";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        private void sendEmailTemplateToAddress(string rEmail, string rName, string EDisplayCode, string subject, string comment, List<byte[]> attachments, List<string> docNames, string mailTemplateToSenderOrRecipient, string Email, Recipients senderDetails, Guid UserId, string EnvelopeId = "", Envelope envelope = null)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "sendEmailTemplateToAddress", "Process started for Send Email Template To Address", EnvelopeId, "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
            imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
            int SignReqReplyToAddressValue = 1;

            // var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(UserId, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
            //if (settingsDetails != null)
            //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(new Guid(EnvelopeId)); //dbContext.EnvelopeSettingsDetail.Where(e => e.EnvelopeId == new Guid(EnvelopeId)).FirstOrDefault();
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#RecipientName", string.IsNullOrEmpty(rName) ? senderDetails.Name : rName.Split(' ').FirstOrDefault());
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#SenderName", senderDetails.Name);
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#SenderEmailId", senderDetails.EmailAddress);
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToName", "Hi");
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ToEmailId", Email);
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#EnvelopeDisplayCode", EDisplayCode);
            //mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ImageURL", imageLogoURl);
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#ReasonToDecline", comment);
            mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#clientLogo", string.Empty);
            //string strURL = Path.Combine(Convert.ToString(_appConfiguration["domain"]), "SignDocument/GetPDF?");
            //strURL = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}", EnvelopeId.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
            //mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#URL", strURL);
            double fileSizes = attachments.Sum(arr => arr.Length);
            fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);
            if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
            {
                if (fileSizes > 20)
                {
                    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", Convert.ToString(_appConfiguration["DocumentSizeMsg"]));
                }
                else
                {
                    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", "");
                }

                // To Add data in Emailqueue and EmailqueueRecipients for Final Document.
                EmailQueueData emailQueueData = new EmailQueueData();
                EmailSendInfo emailSendData = new EmailSendInfo();
                emailQueueData.envelope = envelope;
                emailQueueData.MailMessageBody = mailTemplateToSenderOrRecipient;
                emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;

                emailQueueData.EmailType = Constants.EmailTypes.DESR;
                emailQueueData.EmailSubject = GetEmailSubjectPrefix(envelope.CultureInfo, envelope.Subject, Constants.EmailSubject.FinalDocument);
                emailSendData.RecipientName = string.IsNullOrEmpty(rName) ? senderDetails.Name : rName;
                emailSendData.RecipientEmail = string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail;
                emailQueueData.emailSendInfo = emailSendData;
                if (fileSizes > 20)
                {
                    EmailQueueFunction(emailQueueData);
                }
                else
                {
                    EmailQueueAttachmentData emailQueueAttachmentData = new EmailQueueAttachmentData();
                    emailQueueAttachmentData.AttachmentData = attachments;
                    emailQueueAttachmentData.AttachmentNamesInfo = docNames;
                    EmailQueueFunction(emailQueueData, true, emailQueueAttachmentData);
                }
            }
            else
            {
                var Chilkat = new ChilkatHelper(_appConfiguration);
                if (fileSizes > 20)
                {
                    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", Convert.ToString(_appConfiguration["DocumentSizeMsg"]));
                    Chilkat.SendMailUsingChilKet(new string[] { string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail }, new string[] { string.IsNullOrEmpty(rName) ? senderDetails.Name : rName },
                                        null, null,
                                        null, null,
                                        senderDetails.EmailAddress.ToString(), senderDetails.Name, subject, mailTemplateToSenderOrRecipient, null, null, EDisplayCode, Constants.String.EmailOperation.Reject, SignReqReplyToAddressValue);
                }
                else
                {
                    mailTemplateToSenderOrRecipient = mailTemplateToSenderOrRecipient.Replace("#DocSizeMsg", "");
                    Chilkat.SendMailUsingChilKet(new string[] { string.IsNullOrEmpty(rEmail) ? senderDetails.EmailAddress : rEmail }, new string[] { string.IsNullOrEmpty(rName) ? senderDetails.Name : rName },
                                        null, null,
                                        null, null,
                                        senderDetails.EmailAddress.ToString(), senderDetails.Name, subject, mailTemplateToSenderOrRecipient, attachments, docNames, EDisplayCode, Constants.String.EmailOperation.Reject, SignReqReplyToAddressValue);
                }

            }
            loggerModelNew.Message = "Process completed for Send Email Template To Address";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        public EnvelopeContent GetEnvelopeContent(Guid envelopeId)
        {
            using (var dbContext = new RSignDbContext(_configuration))
            {
                return dbContext.EnvelopeContent.Where(t => t.EnvelopeID == envelopeId).First();
            }
        }
        public bool AllowSendConfirmationEmailForStaticTemplate(Envelope envelopeObject, Guid EnvelopeID, UserProfile senderDetails, string recepientID, bool isTosign, List<DocumentContents> documentContentDetail, string certificateSignature = "", bool isResent = false)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SendConfirmationEmailForStaticTemplate", "Process started for Send Confirmation Email For Static Template", EnvelopeID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();
                string EmailSentType = string.Empty; int RetryCount = 0;
                var envelopeContentData = GetEnvelopeContent(envelopeObject.ID);

                XDocument doc = XDocument.Parse(envelopeContentData.ContentXML);
                var documentContents = new List<DocumentContents>();
                string EmailDisclaimer = string.Empty;
                int SignReqReplyToAddressValue = 1;
                var msgId = Guid.NewGuid();
                var settingDetailEmailDesclaimer = _settingsRepository.GetEntityForByKeyConfig(senderDetails.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
                if (settingDetailEmailDesclaimer != null)
                {
                    EmailDisclaimer = Convert.ToString(settingDetailEmailDesclaimer.OptionValue);
                }
                var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(senderDetails.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
                if (settingsDetails != null)
                    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

                //int electronicStampRequired = GetElectronicSignIndicationValueForUser(senderDetails.UserID);
                var documentList = envelopeObject.SubEnvelopeId != null && envelopeObject.SubEnvelopeId.Value != Guid.Empty ? envelopeObject.Documents.Where(d => d.EnvelopeTemplateGroupID == envelopeObject.SubEnvelopeId) : envelopeObject.Documents;
                //We require Signature controls for current recipient.
                int electronicStampRequired = envelopeObject.ElectronicSignIndicationOptionID != null ? envelopeObject.ElectronicSignIndicationOptionID.Value : 1;
                string userTimezone = string.Empty;
                var settingUserTimezone = _settingsRepository.GetEntityForByKeyConfig(envelopeObject.UserID, Constants.SettingsKeyConfig.TimeZone);
                if (settingUserTimezone != null)
                {
                    userTimezone = settingUserTimezone.OptionValue.ToString();
                }
                string dateTimeStampControlValue = string.Empty;
                if (envelopeObject.DateFormatID != null)
                {
                    dateTimeStampControlValue = GetDateTimeStampControlValue(envelopeObject.DateFormatID, string.IsNullOrEmpty(userTimezone) ? "UTC" : userTimezone);
                }
                if (!isResent)
                {
                    Recipients recipientDetail = _recipientRepository.GetEntity(new Guid(recepientID));

                    bool CanEdit = Convert.ToBoolean(envelopeObject.Recipients.FirstOrDefault(a => a.ID == new Guid(recepientID)).CanEdit);
                    if (Convert.ToBoolean(envelopeObject.IsStatic) && !Convert.ToBoolean(envelopeObject.IsInvitedBySigner)) // Single Signing Process
                    {
                        foreach (Documents document in documentList)
                            documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == new Guid(recepientID) || d.RecipientID == null));
                        SaveControlForSingleSigning(documentContentDetail, envelopeObject.ID, recipientDetail, doc, documentContents, envelopeObject.IpAddress, dateTimeStampControlValue);
                    }
                    else if (Convert.ToBoolean(envelopeObject.IsStatic) && CanEdit)
                    {
                        //var delegatedControls = documentContentsRepository.GetDelegatedControls(recipientId);
                        //var delegatedControlRecipientId = delegatedControls == null ? Guid.Empty : delegatedControls.OriginalRecipientID;

                        foreach (Documents document in documentList)
                            documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID != Guid.Empty));

                        if (documentContents.Count == 0)     // save only signature control value if no other control assign to signer
                            SaveSignature(documentContentDetail, documentContents, new Guid(recepientID), recipientDetail, string.Empty, electronicStampRequired);
                        else
                            CanEditSaveControl(documentContentDetail, envelopeObject, new Guid(recepientID), recipientDetail, doc, documentContents, true, certificateSignature, electronicStampRequired, dateTimeStampControlValue);
                    }
                    else
                    {
                        var delegatedControls = _documentContentsRepository.GetDelegatedControls(new Guid(recepientID));
                        var delegatedControlRecipientId = delegatedControls == null ? Guid.Empty : delegatedControls.OriginalRecipientID;
                        foreach (Documents document in documentList)
                            documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == new Guid(recepientID) || d.RecipientID == null || d.RecipientID == delegatedControlRecipientId));

                        if (documentContents.Count == 0)     // save only signature control value if no other control assign to signer
                            SaveSignature(documentContentDetail, documentContents, new Guid(recepientID), recipientDetail, string.Empty, electronicStampRequired);
                        else
                            SaveControl(documentContentDetail, new Guid(recepientID), recipientDetail, doc, documentContents, true, certificateSignature, electronicStampRequired, dateTimeStampControlValue);
                    }
                }
                //End save signature control
                _recipientRepository.SaveRecipientDetailForEmailConfirm(new Guid(recepientID), Constants.StatusCode.Signer.AwaitingConfirmation, envelopeObject.IpAddress);

                var strURL = !(webApiCall) ? Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SubmitEnvByConfirmationLink?"
                           : Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SubmitEnvByConfirmationLink?";
                // encrypt querystring
                var strURLWithData = strURL + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&RecipientId={1}&status={2}", EnvelopeID, recepientID, isTosign ? "S" : "D")));
                string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
                cultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
                string[] recipientEmail = envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.ID == new Guid(recepientID))
                                                             .OrderBy(r => r.Order)
                                                             .Select(r => r.EmailAddress).ToArray();
                string[] recipientName = envelopeObject.Recipients
                                              .Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.ID == new Guid(recepientID))
                                              .OrderBy(r => r.Order)
                                              .Select(r => r.Name).ToArray();
                var mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.SendStaticTemplateConfirm, envelopeObject.CultureInfo, EmailDisclaimer);

                //* Added by RLabs-RSign DEV Team
                var allSettingsDetails = GetAllSettingsDetails(senderDetails.UserID, senderDetails.EmailID);
                if (allSettingsDetails.ShowRSignLogo != true)
                {
                    imageLogoURl = string.Empty;
                }
                //*//
                mailTemplate = mailTemplate.Replace("#SenderName", senderDetails.FirstName + " " + senderDetails.LastName);
                mailTemplate = mailTemplate.Replace("#SenderEmailId", senderDetails.EmailID);
                mailTemplate = mailTemplate.Replace("#SignerEmailId", recipientEmail[0]);
                mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", envelopeObject.EDisplayCode.ToString());
                mailTemplate = mailTemplate.Replace("#EmailBodyText", envelopeObject.Message);
                mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(envelopeObject.EDisplayCode));
                mailTemplate = mailTemplate.Replace("#URL", strURLWithData);
                //mailTemplate = mailTemplate.Replace("#ImageURL", imageLogoURl);
                mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.SendStaticTemplateConfirm);

                mailTemplate = _genericRepository.AppendFooterText(mailTemplate, recipientEmail[0].ToString(), Constants.String.MailTemplateName.SendStaticTemplateConfirm, envelopeObject.CultureInfo, "FinalContractFooter");

                if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                {
                    //Recipients recipientsigner = envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.ID == new Guid(recepientID)).FirstOrDefault();
                    EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                    EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                    emailQueueData.envelope = envelopeObject;
                    emailQueueData.MailMessageBody = mailTemplate;
                    emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                    emailQueueData.EmailType = Constants.EmailTypes.SC;
                    emailQueueData.EmailSubject = GetEmailSubject(envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.EmailVerification);
                    emailSendData.RecipientName = string.Join(",", recipientName);
                    emailSendData.RecipientEmail = string.Join(",", recipientEmail);
                    emailQueueData.emailSendInfo = emailSendData;
                    EmailQueueFunction(emailQueueData);
                }
                else
                {
                    var Chilkat = new ChilkatHelper(_appConfiguration);
                    emailLogs = Chilkat.SendMailUsingChilKet(recipientEmail, recipientName, null, null, null, null, senderDetails.EmailID, senderDetails.FirstName + " " + senderDetails.LastName, GetEmailSubjectPrefix(envelopeObject.CultureInfo, envelopeObject.Subject, Constants.EmailSubject.EmailVerification), mailTemplate, null, null, envelopeObject.EDisplayCode, Constants.String.EmailOperation.InitialOfferStatic, SignReqReplyToAddressValue, msgId);
                    _genericRepository.SaveEmailLogsRecord(emailLogs, out EmailSentType, out RetryCount);
                    //Save email destination record
                    _genericRepository.SaveDestinationRecord(new Destination() { MessageId = msgId, EnvelopeCode = envelopeObject.EDisplayCode, RecipientEmail = recipientEmail[0], IsSent = true, IsProcessed = false, EmailSentType = EmailSentType, RetryCount = RetryCount });
                }
                loggerModelNew.Message = "Process completed for Send Confirmation Email For Static Template";
                rsignlog.RSignLogInfo(loggerModelNew);
                return true;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.ToString();
                rsignlog.RSignLogError(loggerModelNew, ex);
                return false;
            }
        }
        private void SaveControlForSingleSigning(List<DocumentContents> documentContentDetail, Guid envelopeId, Recipients recipientDetail, XDocument doc, List<DocumentContents> documentContents, string ipAddress, string timeStampControlValue = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SaveControlForSingleSigning", "Intializing process for Save Control For Single Signing", envelopeId.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            foreach (var documentContent in documentContents.Where(r => r.IsControlDeleted == false))
            {
                if (documentContentDetail != null)
                {
                    var documentContentWithValue = documentContentDetail.FirstOrDefault(d => d.ID == documentContent.ID);
                    if (documentContentWithValue != null)
                    {
                        documentContentWithValue.OriginalControlValue = string.IsNullOrEmpty(documentContent.OriginalControlValue) ? documentContent.ControlValue : documentContent.OriginalControlValue;
                        documentContentWithValue.LastModifiedBy = recipientDetail.EmailAddress;
                        if (documentContentWithValue.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || documentContentWithValue.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || documentContentWithValue.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())
                        {
                            if (documentContentWithValue.ControlValue != null && !documentContentWithValue.ControlValue.StartsWith("/Content/NewTheme/img/signature"))
                            {
                                string signValue = documentContentWithValue.ControlValue;
                                signValue = signValue.Replace("data:image/png;base64,", string.Empty);
                                byte[] signByte = Convert.FromBase64String(signValue);
                                documentContentWithValue.SignatureControlValue = signByte;
                                documentContentWithValue.ControlValue = "Signed";
                                documentContent.SignatureControlValue = signByte;
                                documentContent.ControlValue = "Signed";
                                documentContent.ControlHtmlID = documentContentWithValue.ControlHtmlID;
                            }
                        }
                        if (doc != null)
                        {
                            var controlElement = doc.Element("Envelope").Elements("Documents")
                                                .Elements("Documents").FirstOrDefault(m => m.Attribute("ID").Value == documentContent.DocumentID.ToString())
                                     .Elements("Controls").Elements("Control").Where(s => s.Attribute("ID").Value == documentContentWithValue.ID.ToString());
                            if (documentContentWithValue.ControlValue != null)
                            {
                                if (documentContentWithValue.ControlName == "DateTimeStamp" && !string.IsNullOrEmpty(timeStampControlValue))
                                {
                                    documentContentWithValue.ControlValue = timeStampControlValue;
                                }
                                if (controlElement.FirstOrDefault() != null && controlElement.FirstOrDefault().Attribute("text") != null)
                                    controlElement.FirstOrDefault().Attribute("text").Value = (documentContent.ControlID == Constants.Control.DropDown) ? !string.IsNullOrEmpty(documentContentWithValue.ControlValue) ? documentContent.SelectControlOptions.Where(d => d.ID == Guid.Parse(documentContentWithValue.ControlValue)).Select(d => d.OptionText).FirstOrDefault() : documentContentWithValue.ControlValue : documentContentWithValue.ControlValue;// documentContentWithValue.ControlValue;
                            }
                        }
                        _documentContentsRepository.Save(documentContentWithValue);
                    }
                    else
                    {
                        //if it is dependent control then only set ControlValue = null;
                        //Dependent controls we found based on "data-parent-id"  from documentContents -- These are coming from DB
                        var dataControlHtmlData = (documentContent.ControlHtmlData);
                        int topIndex = dataControlHtmlData.IndexOf("data-parent-id");
                        if (topIndex > 0 && documentContent.IsReadOnly != true)
                        {
                            documentContent.ControlValue = null;
                            if (!IsUnitTestApp)
                                _documentContentsRepository.Save(documentContent);
                        }
                        //else if (topIndex > 0 && documentContent.IsReadOnly == true && string.IsNullOrEmpty(documentContent.ControlValue))
                        //{
                        //    documentContent.RecipientName = recipientDetail.Name;
                        //    documentContent.ControlValue = GetControlValueFromDocumentContent(documentContent);
                        //    documentContent.RecipientName = "";
                        //    documentContentsRepository.Save(documentContent);
                        //    unitOfWork.SaveChanges();
                        //}
                    }
                }
            }
            var recipients = _recipientRepository.GetActiveRecipientData(envelopeId);
            bool isDefaultSignature = false;
            foreach (var rec in recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer))
            {
                var signatureContents = documentContents.Where(d => d.IsControlDeleted == false && d.ControlID == Constants.Control.Signature && d.SignatureControlValue != null).ToList();
                if (signatureContents.Count <= 0 && !isDefaultSignature)
                {
                    if (documentContentDetail != null && documentContentDetail.Any(dc => dc.ControlName == Constants.String.SignatureControlName && dc.ID == Guid.Empty && !string.IsNullOrEmpty(dc.ControlValue)
                     && (dc.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || dc.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || dc.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())))
                    {
                        var documentContentWithValue = documentContentDetail.FirstOrDefault(dc => dc.ControlName == Constants.String.SignatureControlName && dc.ID == Guid.Empty);
                        string signValue = documentContentWithValue.ControlValue;
                        signValue = signValue.Replace("data:image/png;base64,", string.Empty);
                        if (IsBase64(signValue))
                        {
                            byte[] signByte = Convert.FromBase64String(signValue);
                            // signature stored in new table 
                            var signerSignature = new SignerSignature
                            {
                                ID = Guid.NewGuid(),
                                RecipientID = rec.ID,
                                Signature = signByte,
                                SignatureTypeId = Guid.Parse(documentContentWithValue.ControlHtmlID)
                            };
                            _recipientRepository.Save(signerSignature);
                            isDefaultSignature = true;
                        }
                    }
                }
                foreach (var signature in signatureContents)
                {
                    Guid guidOutput = Constants.SignatureType.Auto;
                    if (!string.IsNullOrEmpty(signature.SenderControlValue) && rec.ID == Guid.Parse(signature.SenderControlValue) && signature.SignatureControlValue.Length > 0)
                    {
                        var signerSignature = new SignerSignature
                        {
                            ID = Guid.NewGuid(),
                            RecipientID = rec.ID,
                            Signature = signature.SignatureControlValue,
                            SignatureTypeId = Guid.TryParse(signature.ControlHtmlID, out guidOutput) ? guidOutput : Constants.SignatureType.Auto
                        };
                        using (var dbContext = new RSignDbContext(_configuration))
                        {
                            dbContext.SignerSignature.Add(signerSignature);
                            dbContext.SaveChanges();
                        }
                    }
                    else if (signature.SignatureControlValue != null && rec.ID != null && signature.SignatureControlValue.Length > 0)
                    {
                        var signerSignature = new SignerSignature
                        {
                            ID = Guid.NewGuid(),
                            RecipientID = rec.ID,
                            Signature = signature.SignatureControlValue,
                            SignatureTypeId = Guid.TryParse(signature.ControlHtmlID, out guidOutput) ? guidOutput : Constants.SignatureType.Auto
                        };
                        using (var dbContext = new RSignDbContext(_configuration))
                        {
                            dbContext.SignerSignature.Add(signerSignature);
                            dbContext.SaveChanges();
                        }
                    }
                }
                if (rec.ID != recipientDetail.ID)
                {
                    _recipientRepository.AddSignerStatus(rec.ID, Constants.StatusCode.Signer.Signed, ipAddress);
                    _recipientRepository.AddOrModifyLastRecipientEntry(rec.ID, Constants.StatusCode.Signer.Signed, ipAddress);
                }
            }

            loggerModelNew.Message = "Process completed for Save Control For Single Signing";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        private void CanEditSaveControl(List<DocumentContents> documentContentDetail, Envelope envelopeobj, Guid recipientId, Recipients recipientDetail, XDocument doc, List<DocumentContents> documentContents, bool isSignProcess, string certificateSignature = "", int electronicStampRequired = 1, string timeStampControlValue = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SaveControl", "Process is started for Save Control", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            // save signature control value              
            if (isSignProcess)
                SaveSignature(documentContentDetail, documentContents, recipientId, recipientDetail, certificateSignature, electronicStampRequired);
            foreach (var documentContent in documentContents.Where(r => r.IsControlDeleted == false))
            {
                bool canEditControlforRecipient = Convert.ToBoolean(envelopeobj.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.ID == documentContent.RecipientID).Select(r => r.CanEdit).FirstOrDefault());
                if (documentContentDetail != null)
                {
                    var documentContentWithValue = documentContentDetail.FirstOrDefault(d => d.ID == documentContent.ID);

                    if (documentContentWithValue != null)
                    {
                        documentContentWithValue.OriginalControlValue = string.IsNullOrEmpty(documentContent.OriginalControlValue) ? documentContent.ControlValue : documentContent.OriginalControlValue;
                        documentContentWithValue.LastModifiedBy = recipientDetail.EmailAddress;
                    }
                    if (documentContentWithValue != null)
                    {
                        if (documentContentWithValue.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || documentContentWithValue.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || documentContentWithValue.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())
                        {
                            if (documentContentWithValue.ControlValue != null && !documentContentWithValue.ControlValue.StartsWith("/Content/NewTheme/img/signature"))
                            {
                                string signValue = documentContentWithValue.ControlValue;
                                signValue = signValue.Replace("data:image/png;base64,", string.Empty);
                                byte[] signByte = Convert.FromBase64String(signValue);
                                documentContentWithValue.SignatureControlValue = signByte;
                                documentContentWithValue.ControlValue = "Signed";
                            }
                        }
                        else
                        {
                            Guid controlId = documentContent.ControlID;
                            UserProfile userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);
                            if (controlId == Constants.Control.Company && isSignProcess)
                            {
                                if (userProfile != null)
                                {
                                    userProfile.Company = documentContentWithValue.ControlValue;
                                    _userRepository.Save(userProfile);
                                }
                                else
                                {
                                    NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                    if (nonRpostuser != null)
                                    {
                                        nonRpostuser.Company = documentContentWithValue.ControlValue;
                                        _userRepository.Save(nonRpostuser);
                                    }
                                }
                            }
                            else if (controlId == Constants.Control.Title && isSignProcess)
                            {
                                if (userProfile != null)
                                {
                                    userProfile.Title = documentContentWithValue.ControlValue;
                                    _userRepository.Save(userProfile);
                                }
                                else
                                {
                                    NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                    if (nonRpostuser != null)
                                    {
                                        nonRpostuser.Title = documentContentWithValue.ControlValue;
                                        _userRepository.Save(nonRpostuser);
                                    }
                                }
                            }
                            else if (controlId == Constants.Control.Initials && isSignProcess)
                            {
                                if (userProfile != null)
                                {
                                    userProfile.Initials = documentContentWithValue.ControlValue;
                                    if (!IsUnitTestApp)
                                        _userRepository.Save(userProfile);
                                }
                                else
                                {
                                    NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                    if (nonRpostuser != null)
                                    {
                                        nonRpostuser.Initials = documentContentWithValue.ControlValue;
                                        _userRepository.Save(nonRpostuser);
                                    }
                                }
                            }
                        }
                        if (doc != null)
                        {
                            var controlElement = doc.Element("Envelope").Elements("Documents")
                                                .Elements("Documents").FirstOrDefault(m => m.Attribute("ID").Value == documentContent.DocumentID.ToString())
                                     .Elements("Controls").Elements("Control").Where(s => s.Attribute("ID").Value == documentContentWithValue.ID.ToString());
                            if (documentContentWithValue.ControlValue != null)
                            {
                                if (documentContentWithValue.ControlName == "DateTimeStamp" && !string.IsNullOrEmpty(timeStampControlValue))
                                {
                                    documentContentWithValue.ControlValue = timeStampControlValue;
                                }
                                if (controlElement.FirstOrDefault() != null && controlElement.FirstOrDefault().Attribute("text") != null)
                                    controlElement.FirstOrDefault().Attribute("text").Value = (documentContent.ControlID == Constants.Control.DropDown) ? !string.IsNullOrEmpty(documentContentWithValue.ControlValue) ? documentContent.SelectControlOptions.Where(d => d.ID == Guid.Parse(documentContentWithValue.ControlValue)).Select(d => d.OptionText).FirstOrDefault() : documentContentWithValue.ControlValue : documentContentWithValue.ControlValue;// documentContentWithValue.ControlValue;
                            }
                        }

                        if (!IsUnitTestApp)
                            _documentContentsRepository.Save(documentContentWithValue);
                    }
                    else //if dependency control is not checked the don't show dependecy controls in final signed document
                    {
                        //if it is dependent control then only set ControlValue = null;
                        //Dependent controls we found based on "data-parent-id"  from documentContents -- These are coming from DB
                        if (canEditControlforRecipient && !(documentContent.ControlID.ToString().ToUpper() == "BBB41561-0426-4D1F-9887-15D7DFC7C5A2" || documentContent.ControlID.ToString().ToUpper() == "BBB41561-0426-4D1F-9887-15D7DFC7C5A2" || documentContent.ControlID.ToString().ToUpper() == "BBB41561-0426-4D1F-9887-15D7DFC7C5A2"))
                        {
                            string dataControlHtmlData = (documentContent.ControlHtmlData);
                            int topIndex = dataControlHtmlData.IndexOf("data-parent-id");
                            if (topIndex > 0 && documentContent.IsReadOnly != true)
                            {
                                documentContent.ControlValue = null;
                                if (!IsUnitTestApp)
                                    _documentContentsRepository.Save(documentContent);
                            }
                        }
                    }
                }
            }

            loggerModelNew.Message = "Process completed for Save Control";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        public bool SignDocument(Envelope envelopeObject, List<DocumentContents> documentContentDetail, Envelope apiEnvelope, Guid apiRecipientId, string strUserSettings, out string errorIfFound, string certificateSignature = "", string copyEmail = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SignDocument", "Process is started for Recipient to signing", apiEnvelope.EDisplayCode.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            errorIfFound = string.Empty;
            loggerModelNew = new LoggerModelNew();
            string strDateTimeFormat = string.Empty;

            int isContractToGenerateFromImages = Constants.FinalContractOptions.Aspose;
            Guid intAttachedsignedPDF = Constants.AttachSignedPDF.SenderSigner;
            var sessionEnvelope = new Envelope();
            sessionEnvelope = apiEnvelope;
            int SignReqReplyToAddressValue = 1;

            var userProfile = _userRepository.GetUserProfile(apiEnvelope.UserID);
            cultureInfo = sessionEnvelope.CultureInfo;
            var envelopeContentData = GetEnvelopeContent(sessionEnvelope.ID);
            var dirPath = _modelHelper.GetEnvelopeDirectoryNew(sessionEnvelope.ID, string.Empty);

            /*Update recipients for Out of Office Setting if any*/
            //int updatedOutOfOffice = recipientRepository.UpdateRecipientsforOutOfOffice(sessionEnvelope.ID);

            // original recipient id
            Guid recipientId = apiRecipientId;
            Recipients recipientDetail = _recipientRepository.GetEntity(recipientId);
            Guid signerStatusId = _recipientRepository.GetSignerStatusId(recipientId);

            //Once prefill user sign the document and submit then check for IsPrefillSigner. If it is true then save it as empty
            if (recipientDetail.RecipientTypeID == Constants.RecipientType.Prefill && apiEnvelope.DraftType == "Sign")
            {
                _genericRepository.UpdateEnvelopePrefillSigner(sessionEnvelope.ID, "");
            }

            envelopeObject = _genericRepository.GetEntity(sessionEnvelope.ID);
            XDocument doc = XDocument.Parse(envelopeContentData.ContentXML);
            var documentContents = new List<DocumentContents>();
            int intDtFormat = 0;
            string EmailDisclaimer = string.Empty;
            var settingsDetailsEmailDisclaimer = _settingsRepository.GetEntityForByKeyConfig(userProfile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
            if (settingsDetailsEmailDisclaimer != null)
            {
                EmailDisclaimer = settingsDetailsEmailDisclaimer.OptionValue.ToString();
            }
            var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(apiEnvelope.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
            if (settingsDateTimeFormt != null)
            {
                intDtFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);
            }
            string userTimezone = string.Empty;
            var settingUserTimezone = _settingsRepository.GetEntityForByKeyConfig(apiEnvelope.UserID, Constants.SettingsKeyConfig.TimeZone);
            if (settingUserTimezone != null)
            {
                userTimezone = settingUserTimezone.OptionValue.ToString();
            }
            string dateTimeStampControlValue = string.Empty;
            if (apiEnvelope.DateFormatID != null)
            {
                dateTimeStampControlValue = GetDateTimeStampControlValue(apiEnvelope.DateFormatID, string.IsNullOrEmpty(userTimezone) ? "UTC" : userTimezone);
            }
            var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(apiEnvelope.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
            //if (settingsDetails != null)
            //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

            //Get Envelope settings for SignatureRequestReplyAddress
            var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(apiEnvelope.ID);
            if (envelopeSettingObject != null)
                SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

            int electronicStampRequired = apiEnvelope.ElectronicSignIndicationOptionID != null ? apiEnvelope.ElectronicSignIndicationOptionID.Value : 1;
            //We require controls for current recipient.
            var documentList = sessionEnvelope.SubEnvelopeId != null && sessionEnvelope.SubEnvelopeId.Value != Guid.Empty ? sessionEnvelope.Documents.Where(d => d.EnvelopeTemplateGroupID == sessionEnvelope.SubEnvelopeId) : sessionEnvelope.Documents;

            List<Guid> SameRecipientIds = envelopeObject.Recipients.Where(a => a.EmailAddress == recipientDetail.EmailAddress && a.ID != recipientId && a.IsSameRecipient == true).Select(a => a.ID).ToList(); //&& a.IsSameRecipient != true
            bool CanEdit = Convert.ToBoolean(envelopeObject.Recipients.FirstOrDefault(a => a.ID == recipientId).CanEdit);
            if (Convert.ToBoolean(sessionEnvelope.IsStatic) && !Convert.ToBoolean(sessionEnvelope.IsInvitedBySigner)) // Single Signing Process
            {
                foreach (Documents document in documentList)
                    documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == recipientId || (SameRecipientIds.Count > 0 && d.RecipientID != null && d.RecipientID != Guid.Empty && SameRecipientIds.Contains(d.RecipientID.Value)) || d.RecipientID == null));
                SaveControlForSingleSigning(documentContentDetail, sessionEnvelope.ID, recipientDetail, doc, documentContents, apiEnvelope.IpAddress, dateTimeStampControlValue);
            }
            else if (Convert.ToBoolean(sessionEnvelope.IsStatic) && CanEdit)
            {
                //var delegatedControls = documentContentsRepository.GetDelegatedControls(recipientId);
                //var delegatedControlRecipientId = delegatedControls == null ? Guid.Empty : delegatedControls.OriginalRecipientID;
                foreach (Documents document in documentList)
                    documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID != Guid.Empty));

                if (documentContents.Count == 0)     // save only signature control value if no other control assign to signer
                    SaveSignature(documentContentDetail, documentContents, recipientId, recipientDetail, string.Empty, electronicStampRequired);
                else
                    SaveControl(documentContentDetail, recipientId, recipientDetail, doc, documentContents, true, certificateSignature, electronicStampRequired, dateTimeStampControlValue);
            }
            else
            {
                var delegatedControls = _documentContentsRepository.GetDelegatedControls(recipientId);
                var delegatedControlRecipientId = delegatedControls == null ? Guid.Empty : delegatedControls.OriginalRecipientID;
                foreach (Documents document in documentList)
                    documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == recipientId || (SameRecipientIds.Count > 0 && d.RecipientID != null && d.RecipientID != Guid.Empty && SameRecipientIds.Contains(d.RecipientID.Value)) || d.RecipientID == null || d.RecipientID == delegatedControlRecipientId));

                if (documentContents.Count == 0)     // save only signature control value if no other control assign to signer
                    SaveSignature(documentContentDetail, documentContents, recipientId, recipientDetail, string.Empty, electronicStampRequired);
                else
                    SaveControl(documentContentDetail, recipientId, recipientDetail, doc, documentContents, true, certificateSignature, electronicStampRequired, dateTimeStampControlValue);
            }

            //update IP
            if (doc != null && doc.Element("Envelope").Elements("Recipients").Any() == true)
            {
                var controlElement = doc.Element("Envelope").Elements("Recipients").Where(m => m.Attribute("ID").Value == recipientId.ToString()).FirstOrDefault();
                if (controlElement != null)
                    controlElement.Attribute("IPAddress").Value = apiEnvelope.IpAddress;
            }
            envelopeContentData.ContentXML = doc.ToString();
            SaveEnvelopeContentData(envelopeContentData);

            string ipAddress = apiEnvelope.IpAddress;
            Guid statusId = Constants.StatusCode.Signer.Signed;

            loggerModelNew.Message = "Envelope is signed by " + recipientDetail.EmailAddress;
            rsignlog.RSignLogInfo(loggerModelNew);

            // updated recipient status
            if (!IsUnitTestApp)
                _recipientRepository.AddSignerStatus(recipientId, statusId, ipAddress, copyEmail);

            bool isEnvelopeComplete = false;

            // Fetching the envelope object to check if other signer already signed the document or not while signer revieving the document. [To avoid concurrency problem]
            var senderDetails = _recipientRepository.GetSenderDetails(sessionEnvelope.ID);

            if (IsEnvelopeComplete(envelopeObject.Recipients.ToList(), recipientId) && !envelopeObject.IsTemplateShared)
            {
                UpdateEnvelopeStatus(sessionEnvelope, Constants.StatusCode.Envelope.Completed);
                //---- Update envelopeContent table.
                if (doc != null)
                {
                    var envelopeStatusElement = doc.Element("Envelope").Elements("EnvelopeStatus").FirstOrDefault();
                    if (envelopeStatusElement != null)
                        envelopeStatusElement.Value = "Completed";
                    envelopeContentData.ContentXML = doc.ToString();
                    SaveEnvelopeContentData(envelopeContentData);
                }

                isEnvelopeComplete = true;
                loggerModelNew.Message = "Envelope Completed";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            else
            {
                if (sessionEnvelope.SubEnvelopeId != null && sessionEnvelope.SubEnvelopeId.Value != Guid.Empty)
                {
                    var subEnvelope = GetEnvelopeTemplateGroupDetails(sessionEnvelope.SubEnvelopeId.Value);
                    if (subEnvelope != null)
                        subEnvelope.ModifiedDateTime = DateTime.Now;
                    envelopeObject.ModifiedDateTime = DateTime.Now;
                }
            }

            var signerDetails = _recipientRepository.GetEntity(recipientId);
            Guid newSignerStatusId = _recipientRepository.GetSignerPrimaryStatusId(recipientId);

            _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.DocumentSigned, senderDetails.EmailAddress, recipientId.ToString(), newSignerStatusId.ToString());

            _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.SignerStatus, senderDetails.EmailAddress, recipientId.ToString(), newSignerStatusId.ToString(), "", "webhook");

            if (IsEnvelopeComplete(envelopeObject.Recipients.ToList(), recipientId) && !envelopeObject.IsTemplateShared)
            {
                _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.EnvelopeStatus, senderDetails.EmailAddress);

                _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelopeObject, Constants.WebhookEventNames.EnvelopeCompleted, senderDetails.EmailAddress);
            }

            //Modify last entry of this recipient as completed.
            Guid envelopeID = apiEnvelope.ID;
            Guid recipientID = apiRecipientId;
            bool modifyStatus = false;
            modifyStatus = _recipientRepository.AddOrModifyLastRecipientEntry(recipientID, Constants.StatusCode.Signer.Signed, apiEnvelope.IpAddress);

            RecipientMail(envelopeObject, recipientId, senderDetails.EmailAddress, senderDetails.Name, SignReqReplyToAddressValue);

            // email send to sender
            if (signerDetails.RecipientTypeID != Constants.RecipientType.Prefill && !isEnvelopeComplete && envelopeObject.SendIndividualSignatureNotifications == true)
                AcceptMail(envelopeObject, signerDetails.EmailAddress, signerDetails.Name, senderDetails.Name, senderDetails.EmailAddress, senderDetails.ID, SignReqReplyToAddressValue, senderDetails, signerDetails);

            if (signerDetails.RecipientTypeID != Constants.RecipientType.Prefill && sessionEnvelope.Recipients.Where(r => (r.CCSignerType == Constants.CCRecipientType.NotificationsOnly || r.CCSignerType == Constants.CCRecipientType.NotificationsAndSigned) && r.RecipientTypeID == Constants.RecipientType.CC).Count() > 0 && !isEnvelopeComplete && envelopeObject.SendIndividualSignatureNotifications == true)
            {
                foreach (var ccRec in sessionEnvelope.Recipients.Where(r => (r.CCSignerType == Constants.CCRecipientType.NotificationsOnly || r.CCSignerType == Constants.CCRecipientType.NotificationsAndSigned) && r.RecipientTypeID == Constants.RecipientType.CC))
                {
                    CCNotificationMail(envelopeObject, signerDetails.EmailAddress, signerDetails.Name, senderDetails.Name, senderDetails.EmailAddress, ccRec.ID, SignReqReplyToAddressValue, senderDetails);
                }
            }

            if (isEnvelopeComplete == true)
            {
                if (!Convert.ToBoolean(_appConfiguration["IsSignedDocumentService"]))
                {
                    return GenerateRSignDocuments(envelopeID);
                }
                else
                {
                    var envelopeContractStatus = new EnvelopeContractStatus
                    {
                        Id = envelopeID,
                        Status = 1,
                        ServerName = System.Environment.MachineName,
                        CreatedDateTime = DateTime.Now
                    };
                    try
                    {
                        using (var dbContext = new RSignDbContext(_configuration))
                        {
                            dbContext.EnvelopeContractStatus.Add(envelopeContractStatus);
                            dbContext.SaveChanges();
                        }
                    }
                    catch (Exception exception)
                    {
                        loggerModelNew.Message = "EnvelopeContractStatus table record inserted in catch block.";
                        rsignlog.RSignLogError(loggerModelNew, exception);
                        return true;
                    }
                }
            }
            loggerModelNew.Message = "Process completed for Sign Document";
            rsignlog.RSignLogInfo(loggerModelNew);
            return true;
        }
        public bool SaveEnvelopeContentData(EnvelopeContent envelopeContent)
        {
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    var envelopeObject = dbContext.EnvelopeContent.Where(e => e.ID == envelopeContent.ID).FirstOrDefault();
                    if (envelopeObject == null)
                    {
                        dbContext.EnvelopeContent.Add(envelopeContent);
                    }
                    else
                    {
                        envelopeObject.ContentXML = envelopeContent.ContentXML;
                        dbContext.Entry(envelopeObject).State = EntityState.Modified;
                    }
                    dbContext.SaveChanges();
                }
            }
            catch (Exception ex)
            {
                throw;
            }
            return true;
        }
        private bool IsEnvelopeComplete(List<Recipients> recipients, Guid currentRecipientid)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "IsEnvelopeComplete", "Process is started for Is Envelope Complete method", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            var orderCollection = recipients.Where(r => r.Order != null).Select(r => r.Order).ToList().OrderBy(r => r.Value);
            int orderNo = 0;
            foreach (int order in orderCollection)
            {
                if (orderNo == order)   // check if the duplicate order, if so then no need to check the completion of the same order hence continue with loop
                    continue;

                if (!IsCurrentLevelComplete(recipients, currentRecipientid, order))
                    return false;
                orderNo = order;
            }
            loggerModelNew.Message = "Process completed for Is Envelope Complete method";
            rsignlog.RSignLogInfo(loggerModelNew);
            return true;
        }
        private bool IsCurrentLevelComplete(IEnumerable<Recipients> recipients, Guid currentRecipientid, int currentLevel)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "IsCurrentLevelComplete", "Process is started for Is Current Level Complete method", "", "", currentRecipientid.ToString(), "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            List<Recipients> currentLevelRecipients = (from rec in recipients
                                                       where rec.Order == currentLevel && rec.IsSameRecipient != true
                                                       select rec).ToList<Recipients>();


            using (var dbContext = new RSignDbContext(_configuration))
            {
                foreach (Recipients recipient in currentLevelRecipients)
                {
                    if (recipient.ID == currentRecipientid)
                        continue;

                    var SignerStaus = dbContext.SignerStatus.Where(r => r.RecipientID == recipient.ID).ToList();
                    recipient.SignerStatus = SignerStaus;

                    if (recipient.SignerStatus == null || recipient.SignerStatus.Count == 0)
                        return false;

                    SignerStatus signerStatus = recipient.SignerStatus.OrderByDescending(s => s.CreatedDateTime).Take(1).First();

                    if (signerStatus.StatusID == Constants.StatusCode.Signer.Pending
                        || signerStatus.StatusID == Constants.StatusCode.Signer.Rejected || signerStatus.StatusID == Constants.StatusCode.Signer.Viewed)
                        return false;
                }
            }

            return true;
        }
        private void UpdateEnvelopeStatus(Envelope sessionEnvelope, Guid envelopeStatusId)
        {
            var envelopeStatus = new EnvelopeStatus();
            envelopeStatus.CreatedDateTime = DateTime.Now;
            envelopeStatus.EnvelopeID = sessionEnvelope.ID;
            envelopeStatus.ID = Guid.NewGuid();
            envelopeStatus.StatusID = envelopeStatusId;

            using (var dbContext = new RSignDbContext(_configuration))
            {
                dbContext.EnvelopeStatus.Add(envelopeStatus);
                dbContext.SaveChanges();

                Envelope envelope = dbContext.Envelope.Where(e => e.ID == sessionEnvelope.ID).FirstOrDefault();
                envelope.StatusID = envelopeStatusId;
                envelope.ModifiedDateTime = DateTime.Now;
                dbContext.Entry(envelope).State = EntityState.Modified;
                dbContext.SaveChanges();
            }
        }
        public EnvelopeTemplateGroups GetEnvelopeTemplateGroupDetails(Guid envelopeId)
        {
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    return (from q in dbContext.EnvelopeTemplateGroups
                            where q.ID == envelopeId
                            select q).FirstOrDefault();
                }
            }
            catch (Exception ex)
            {
                return null;
            }
        }
        private void RecipientMail(Envelope sessionEnvelope, Guid recipientId, string senderEmailAddress, string senderName, int SignReqReplyToAddressValue = 1)
        {
            loggerModelNew = new LoggerModelNew(senderEmailAddress, "EnvelopeHelperMain", "RecipientMail", "Process started for sending Recipient Mail", sessionEnvelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            Guid msgId = Guid.NewGuid();
            bool IsPrefillCase = false, IsSenderReceiveConfirmationEmail = false;
            double fileSizes = 0;

            var userprofile = _userRepository.GetUserProfile(sessionEnvelope.UserID);

            int isContractToGenerateFromImages = Constants.FinalContractOptions.Aspose;
            string EmailSentType = string.Empty; int RetryCount = 0;
            List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();

            string EmailDisclaimer = string.Empty;
            var settingDetailEmailDesclaimer = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.EmailDisclaimer);
            if (settingDetailEmailDesclaimer != null)
            {
                EmailDisclaimer = Convert.ToString(settingDetailEmailDesclaimer.OptionValue);
            }

            int DisclaimerLocationId = Constants.DisclaimerLocation.BottomOfEmail;
            var settingsDetailsDisclaimerLocation = _settingsRepository.GetEntityForByKeyConfig(userprofile.CompanyID.Value, Constants.SettingsKeyConfig.DisclaimerLocation);
            if (settingsDetailsDisclaimerLocation != null)
            {
                DisclaimerLocationId = Convert.ToInt32(settingsDetailsDisclaimerLocation.OptionValue);
            }

            int intDtFormat = 0;
            var settingsDateTimeFormt = _settingsRepository.GetEntityForByKeyConfig(sessionEnvelope.UserID, Constants.SettingsKeyConfig.AddDatetoSignedDocumentNameOptionSettings);
            if (settingsDateTimeFormt != null)
            {
                intDtFormat = Convert.ToInt32(settingsDateTimeFormt.OptionValue);
            }
            Recipients recipientObject = _recipientRepository.GetEntity(recipientId);
            cultureInfo = sessionEnvelope.CultureInfo;
            if (
                !IsCurrentLevelComplete(sessionEnvelope.Recipients.ToList(), recipientId,
