                            //        tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccRecipient.EmailAddress);
                            //    sbCC.Append(tempHtmlCode + ", ");
                            //}

                            mailTemlate = mailTemlate.Replace("#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
                        }
                        else
                        {
                            mailTemlate = mailTemlate.Replace("#CCList", "-");
                        }

                        //mailTemlate = mailTemlate.Replace("#ImageURL", imageLogoURl);
                        mailTemlate = mailTemlate.Replace("#EmailBodyText", sessionEnvelope.Message);

                        mailTemlate = mailTemlate.Replace("#clientLogo", "");
                        mailTemlate = mailTemlate.Replace("#ExpireDays", ExpireDays);
                        mailTemlate = mailTemlate.Replace("#DoNotShareMail", DoNotShareMail);
                        mailTemlate = mailTemlate.Replace("#AlternateSigningOption", AlternateSigningOption);
                        mailTemlate = mailTemlate.Replace("#SignFromRSignWebSite", SignFromRSignWebSite);
                        mailTemlate = mailTemlate.Replace("#QuestionsAboutDocument", QuestionsAboutDocument);
                        mailTemlate = mailTemlate.Replace("#QuestionsAboutDocText", QuestionsAboutDocumentText);
                        mailTemlate = EmailBannerSettings(mailTemlate, allSettingsDetails, Constants.String.MailTemplateName.SendEnvelope);

                        // Email template
                        string message = mailTemlate;
                        List<Recipients> signerRecipients = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer && r.IsSameRecipient != true).ToList();
                        mailTemlate = AppendAllSignerRecipient(signerRecipients, mailTemlate, sessionEnvelope.EnableMessageToMobile);

                        mailTemlate = _genericRepository.AppendFooterText(mailTemlate, signer.EmailAddress, templatename, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, "FinalContractFooter");

                        if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            //To Add data in Emailqueue and EmailqueueRecipients for submit (Electronic Signature Notification) *
                            EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                            EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                            emailQueueData.envelope = sessionEnvelope;
                            emailQueueData.MailMessageBody = mailTemlate;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            //emailQueueData.Signer = signer; 
                            emailQueueData.EmailType = Constants.EmailTypes.SR;
                            emailQueueData.EmailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SignatureRequest) + multiSubject;

                            emailSendData.RecipientName = signer.Name;
                            emailSendData.RecipientEmail = signer.EmailAddress;
                            emailQueueData.emailSendInfo = emailSendData;
                            EmailQueueFunction(emailQueueData, true);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            emailLogs = Chilkat.SendMailUsingChilKet(new string[] { signer.EmailAddress }, new string[] { signer.Name }, null, null, null, null,
                             senderEmailAddress, senderName, GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SignatureRequest) + multiSubject, mailTemlate, null, null, Convert.ToString(sessionEnvelope.EDisplayCode), Constants.String.EmailOperation.SignRecipient, SignReqReplyToAddressValue, msgId);

                            _genericRepository.SaveEmailLogsRecord(emailLogs, out EmailSentType, out RetryCount);
                            //Save email destination record
                            _genericRepository.SaveDestinationRecord(new Destination() { MessageId = msgId, EnvelopeCode = sessionEnvelope.EDisplayCode, RecipientEmail = signer.EmailAddress, IsSent = true, IsProcessed = false, EmailSentType = EmailSentType, RetryCount = RetryCount });
                            //LogMsg("Document sent to next recipient for signing");
                        }
                    }

                    if (isMobileSend)
                    {
                        string mobilelTemlate = "";
                        if (Convert.ToBoolean(sessionEnvelope.IsSignerIdentitiy) && signer.RecipientTypeID != Constants.RecipientType.CC)
                        {
                            templatename = Constants.String.MailTemplateName.AuthenticateSigner;
                            mobilelTemlate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.AuthenticateSigner, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId, "mobile");
                        }
                        else
                        {
                            templatename = Constants.String.MailTemplateName.SendEnvelope;
                            mobilelTemlate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.SendEnvelope, !string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId, "mobile");
                        }

                        mobilelTemlate = mobilelTemlate.Replace("#SenderName", senderName);
                        mobilelTemlate = mobilelTemlate.Replace("#SigningShortURL", signingShortURL);
                        mobilelTemlate = mobilelTemlate.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));

                        if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            string emailSubject = GetEmailSubjectPrefix(!string.IsNullOrEmpty(signer.CultureInfo) ? signer.CultureInfo : sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SignatureRequest) + multiSubject;
                            SendSMSThroughEmailService(sessionEnvelope, mobilelTemlate, SignReqReplyToAddressValue, Constants.EmailTypes.SR, signer, emailSubject);
                        }
                        else
                        {
                            string signerMobileNumber = signer.DialCode + signer.Mobile;
                            SendMobileSMS(sessionEnvelope, mobilelTemlate, signerMobileNumber);
                        }
                    }

                    //START - Update Current recipient signature request notification
                    using (var dbContext = new RSignDbContext(_configuration))
                    {
                        var signerStatusId = dbContext.SignerStatus.Where(r => r.RecipientID == signer.ID).FirstOrDefault().ID.ToString();
                        _genericRepository.UpdateEnvelopeCommonWebhookTransaction(sessionEnvelope, Constants.WebhookEventNames.SignerStatus, senderEmailAddress, signer.ID.ToString(), signerStatusId, "", "signingrequest");
                    }

                    //End - Update Current recipient signature request notification
                }
                multiSubject = string.Empty;
            }

            //Sender Confirmation Email
            if (IsPrefillCase == true)
            {
                var settingsDetailForConfirmation = _settingsRepository.GetEntityForByKeyConfig(sessionEnvelope.UserID, Constants.SettingsKeyConfig.ReceiveSendingEmailConfirmation);
                if (settingsDetailForConfirmation != null)
                    IsSenderReceiveConfirmationEmail = !string.IsNullOrEmpty(settingsDetailForConfirmation.OptionValue) ? Convert.ToBoolean(settingsDetailForConfirmation.OptionValue) : false;

                if (IsSenderReceiveConfirmationEmail == true)
                {
                    var fromEmailAddress = Convert.ToString(_appConfiguration["FromEmailAddress"].ToString());

                    sessionEnvelope.IsFinalCertificateReq = false;
                    string completionDate = string.Empty;
                    settingsDetailForConfirmation = _settingsRepository.GetEntityForByKeyConfig(sessionEnvelope.UserID, Constants.SettingsKeyConfig.TimeZone);
                    if (settingsDetailForConfirmation == null || string.IsNullOrEmpty(settingsDetailForConfirmation.OptionValue))
                        completionDate = String.Format("{0:MM/dd/yyyy HH:mm tt}", sessionEnvelope.ModifiedDateTime) + " " + _eSignHelper.GetTimeZoneAbbreviation(TimeZone.CurrentTimeZone.StandardName);
                    else
                        completionDate = _eSignHelper.GetLocalTime(sessionEnvelope.ModifiedDateTime, Convert.ToString(settingsDetailForConfirmation.OptionValue), sessionEnvelope.DateFormatID);

                    string mailTemlateSender = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.SendingConfirmation, sessionEnvelope.CultureInfo, EmailDisclaimer, DisclaimerLocationId);
                    mailTemlateSender = SenderConfirmationEmail(sessionEnvelope, mailTemlateSender, completionDate, imageLogoURl, strURLWithDataForcc);
                    mailTemlateSender = EmailBannerSettings(mailTemlateSender, allSettingsDetails, Constants.String.MailTemplateName.SendingConfirmation);

                    var userSettings = new FinalContractSettings
                    {
                        WatermarkAuthText = string.Empty,
                        WatermarkBackgroundText = string.Empty,
                        FinalContractOptions = isContractToGenerateFromImages,
                        UserTimeZone = string.Empty,
                        IsControlDisplayInTag = false
                    };
                    string[] senderArray = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).Select(r => r.EmailAddress).ToArray();
                    string[] senderDisplayName = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender).Select(r => r.Name).ToArray();

                    var attachments = new List<byte[]>();
                    var dirPath = _modelHelper.GetEnvelopeDirectoryNew(sessionEnvelope.ID, string.Empty);
                    string previewDocDirectory = dirPath + sessionEnvelope.ID + "\\Final\\PreviewDoc.pdf";
                    if (!File.Exists(previewDocDirectory))
                    {
                        string finalPdfFilePath = string.Empty;
                        try
                        {
                            finalPdfFilePath = _apiHelper.finalMergePDFApi(sessionEnvelope, userSettings, dirPath, string.Empty, false);
                        }
                        catch (Exception ex)
                        {
                            DeleteContractFileInCaseOfError(sessionEnvelope.ID, dirPath);
                            userSettings.FinalContractOptions = Convert.ToInt32(userSettings.FinalContractOptions) != Constants.FinalContractOptions.iText ? Constants.FinalContractOptions.iText : Constants.FinalContractOptions.Aspose;
                            finalPdfFilePath = _apiHelper.finalMergePDFApi(sessionEnvelope, userSettings, dirPath, string.Empty, false);
                        }
                        byte[] finalMergedArray = System.IO.File.ReadAllBytes(finalPdfFilePath);
                        if (finalMergedArray != null)
                            attachments.Add(finalMergedArray);

                        System.IO.File.WriteAllBytes(previewDocDirectory, finalMergedArray);
                        fileSizes = attachments.Sum(arr => arr.Length);
                        fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);
                    }
                    else
                    {
                        byte[] finalMergedArray = System.IO.File.ReadAllBytes(previewDocDirectory);
                        if (finalMergedArray != null)
                            attachments.Add(finalMergedArray);
                        fileSizes = attachments.Sum(arr => arr.Length);
                        fileSizes = Math.Round(fileSizes / Math.Pow(1024, 2), 2);
                    }
                    if ((sessionEnvelope.PasswordReqdtoOpen == true && sessionEnvelope.PasswordReqdtoSign == true) && sessionEnvelope.IsPasswordMailToSigner)
                    {
                        string mailTemlateSenderPwd = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PwOpenForConfirmationEmail, sessionEnvelope.CultureInfo, EmailDisclaimer);
                        mailTemlateSenderPwd = EmailBannerSettings(mailTemlateSenderPwd, allSettingsDetails, Constants.String.MailTemplateName.PwOpenForConfirmationEmail);

                        mailTemlateSenderPwd = SenderConfirmationPwd(sessionEnvelope, mailTemlateSenderPwd, imageLogoURl, senderName, senderEmailAddress);

                        mailTemlateSenderPwd = _genericRepository.AppendFooterText(mailTemlateSenderPwd, senderArray[0].ToString(), Constants.String.MailTemplateName.PwOpenForConfirmationEmail, sessionEnvelope.CultureInfo, "FinalContractFooter");

                        if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            //To Add data in Emailqueue and EmailqueueRecipients for  Sending Confirmation Password Notification
                            EmailQueueProcessor.EmailQueueData emailQueueDatasender = new EmailQueueProcessor.EmailQueueData();
                            EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                            emailQueueDatasender.envelope = sessionEnvelope;
                            emailQueueDatasender.MailMessageBody = mailTemlateSenderPwd;
                            emailQueueDatasender.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            //emailQueueDatasender.Signer = recipientObject; 
                            emailQueueDatasender.EmailType = Constants.EmailTypes.SCPN;
                            emailQueueDatasender.EmailSubject = GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingPasswordConfirmation);
                            emailSendData.RecipientName = null;
                            emailSendData.RecipientEmail = string.Join(",", senderArray);
                            emailQueueDatasender.emailSendInfo = emailSendData;
                            EmailQueueFunction(emailQueueDatasender, true);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            Chilkat.SendMailUsingChilKet(senderArray, null,
                                              null, null,
                                              null, null,
                                              //TODO : change singerdetails to senderdetails at all places
                                              fromEmailAddress, senderName, GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingPasswordConfirmation), mailTemlateSenderPwd,
                                              null, null, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.PasswordToOpen, SignReqReplyToAddressValue);
                        }
                    }

                    //if (fileSizes > 20)
                    //{
                    //    mailTemlateSender = mailTemlateSender.Replace("#DocSizeMsg", Convert.ToString(_appConfiguration["DocumentSizeMsg"]));
                    //    smtpHelper.SendMail(senderArray, senderDisplayName,
                    //            null, null,
                    //            null, null,
                    //            fromEmailAddress, senderName,
                    //            sessionEnvelope.Subject, mailTemlateSender,
                    //             null, null, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.SendingConfirmation);
                    //}
                    //else
                    //{
                    //    mailTemlateSender = mailTemlateSender.Replace("#DocSizeMsg", "");
                    //    smtpHelper.SendMail(senderArray, senderDisplayName,
                    //            null, null,
                    //            null, null,
                    //            fromEmailAddress, senderName,
                    //            sessionEnvelope.Subject, mailTemlateSender,
                    //             attachments, new List<string> { AppendDateTime(intDtFormat, finalDocName) + ".pdf" }, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.SendingConfirmation);
                    //}

                    mailTemlateSender = mailTemlateSender.Replace("#DocSizeMsg", "");
                    mailTemlateSender = _genericRepository.AppendFooterText(mailTemlateSender, senderArray[0].ToString(), Constants.String.MailTemplateName.SendingConfirmation, sessionEnvelope.CultureInfo, "FinalContractFooter");
                    if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                    {
                        //To Add data in Emailqueue and EmailqueueRecipients for SendingConfirmation 
                        EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                        EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                        emailQueueData.envelope = sessionEnvelope;
                        emailQueueData.MailMessageBody = mailTemlateSender;
                        emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                        //emailQueueData.Signer = recipientObject; 
                        emailQueueData.EmailType = Constants.EmailTypes.SC;
                        emailQueueData.EmailSubject = GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingConfirmation);
                        emailSendData.RecipientName = string.Join(",", senderDisplayName);
                        emailSendData.RecipientEmail = string.Join(",", senderArray);
                        emailQueueData.emailSendInfo = emailSendData;
                        EmailQueueFunction(emailQueueData);
                    }
                    else
                    {
                        var Chilkat = new ChilkatHelper(_appConfiguration);
                        Chilkat.SendMailUsingChilKet(senderArray, senderDisplayName,
                                null, null,
                                null, null,
                                fromEmailAddress, senderName,
                                GetEmailSubjectPrefix(sessionEnvelope.CultureInfo, sessionEnvelope.Subject, Constants.EmailSubject.SendingConfirmation), mailTemlateSender,
                                 null, new List<string> { AppendDateTime(intDtFormat, finalDocName) + ".pdf" }, sessionEnvelope.EDisplayCode, Constants.String.EmailOperation.SendingConfirmation, SignReqReplyToAddressValue);
                    }
                }
            }

            loggerModelNew.Message = "Process completed for sending Recipient Mail";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        private void AcceptMail(Envelope sessionEnvelope, string signerEmailAddress, string signerName, string senderName, string senderEmailAddress, Guid senderRecipientId, int SignReqReplyToAddressValue, dynamic senderDetails, Recipients signerDetails)
        {
            loggerModelNew = new LoggerModelNew(signerEmailAddress, "EnvelopeHelperMain", "AcceptMail", "Process started for AcceptMail", sessionEnvelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            cultureInfo = sessionEnvelope.CultureInfo;
            var currentCultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
            Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(RSign.Common.Helpers.Common.GetCultureInfoValue(cultureInfo));
            Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;
            string subject = signerName + " (" + signerEmailAddress + ")" + " " + "has Signed your Document.";

            string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
            imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");

            string strURL = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/PDFCurrentStatus?");
            //var strURLWithData = strURL + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}", sessionEnvelope.ID)));
            var strURLWithData = strURL + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}&CultureInfo={1}", sessionEnvelope.ID, sessionEnvelope.CultureInfo)));
            string[] toAddressSender = sessionEnvelope.Recipients.Where(r => r.ID == senderRecipientId).Select(r => r.EmailAddress).ToArray();
            string[] toDisplayNameSender = sessionEnvelope.Recipients.Where(r => r.ID == senderRecipientId).Select(r => r.Name).ToArray();
            string mailTemplate = string.Empty;

            mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.Accept, sessionEnvelope.CultureInfo, AppendEmailDisclaimer(sessionEnvelope.UserID));
            string senderFirstName = senderName.Split(' ').FirstOrDefault();
            mailTemplate = mailTemplate.Replace("#RecipientName", senderFirstName);
            mailTemplate = mailTemplate.Replace("#Subject", sessionEnvelope.Subject);
            mailTemplate = mailTemplate.Replace("#SenderName", senderName);
            mailTemplate = mailTemplate.Replace("#SenderEmailId", senderEmailAddress);
            mailTemplate = mailTemplate.Replace("#ToName", signerName);

            if (Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile))
            {
                if (signerDetails != null)
                {
                    //if (!string.IsNullOrEmpty(signerDetails.EmailAddress) && !string.IsNullOrEmpty(signerDetails.Mobile))
                    //{
                    //    string signerMobileNumber = signerDetails.EmailAddress + ", " + signerDetails.DialCode + signerDetails.Mobile;
                    //    subject = signerName + " (" + signerMobileNumber + ")" + " " + "has Signed your Document.";
                    //    mailTemplate = mailTemplate.Replace("#ToEmailId", signerMobileNumber);
                    //}
                    //else if (!string.IsNullOrEmpty(signerDetails.EmailAddress))
                    //{
                    //    subject = signerName + " (" + signerDetails.EmailAddress + ")" + " " + "has Signed your Document.";
                    //    mailTemplate = mailTemplate.Replace("#ToEmailId", signerDetails.EmailAddress);
                    //}
                    //else if (!string.IsNullOrEmpty(signerDetails.Mobile))
                    //{
                    //    string signerMobileNumber = signerDetails.DialCode + signerDetails.Mobile;
                    //    subject = signerName + " (" + signerMobileNumber + ")" + " " + "has Signed your Document.";
                    //    mailTemplate = mailTemplate.Replace("#ToEmailId", signerMobileNumber);
                    //}
                    string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signerDetails.DeliveryMode, signerDetails.EmailAddress, signerDetails.DialCode, signerDetails.Mobile);
                    mailTemplate = mailTemplate.Replace("#ToEmailId", emailMobileNumberDetails);
                    subject = signerName + " (" + emailMobileNumberDetails + ")" + " " + "has Signed your Document.";

                }
                else
                    mailTemplate = mailTemplate.Replace("#ToEmailId", signerEmailAddress);
            }
            else
                mailTemplate = mailTemplate.Replace("#ToEmailId", signerEmailAddress);
            //mailTemplate = mailTemplate.Replace("#ImageURL", imageLogoURl);
            mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));
            mailTemplate = mailTemplate.Replace("#CurrentPDF", strURLWithData);

            //* Added by RLabs-RSign DEV Team
            var allSettingsDetails = GetAllSettingsDetails(sessionEnvelope.UserID, userEmail);

            if (allSettingsDetails.ShowRSignLogo != true)
            {
                imageLogoURl = string.Empty;
            }
            //*//
            mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.Accept);

            mailTemplate = _genericRepository.AppendFooterText(mailTemplate, senderEmailAddress, Constants.String.MailTemplateName.Accept, sessionEnvelope.CultureInfo, "FinalContractFooter");

            Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(currentCultureInfo);
            Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;

            //To Add data in Emailqueue and EmailqueueRecipients for Accept mail  
            if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
            {
                EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                emailQueueData.envelope = sessionEnvelope;
                emailQueueData.MailMessageBody = mailTemplate;
                emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                //emailQueueData.Signer = senderDetails; 
                emailQueueData.EmailType = Constants.EmailTypes.AESR;
                emailQueueData.EmailSubject = subject;
                emailSendData.RecipientName = string.Join(",", toDisplayNameSender);
                emailSendData.RecipientEmail = string.Join(",", toAddressSender);
                emailQueueData.emailSendInfo = emailSendData;
                EmailQueueFunction(emailQueueData);
            }
            else
            {
                var Chilkat = new ChilkatHelper(_appConfiguration);
                Chilkat.SendMailUsingChilKet(toAddressSender, toDisplayNameSender, null, null, null, null, senderEmailAddress, senderName, subject, mailTemplate, null, null, Convert.ToString(sessionEnvelope.EDisplayCode), Constants.String.EmailOperation.Accept, SignReqReplyToAddressValue);
            }
            loggerModelNew.Message = "Process completed for Accept Mail";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        private void CCNotificationMail(Envelope sessionEnvelope, string signerEmailAddress, string signerName, string senderName, string senderEmailAddress, Guid senderRecipientId, int SignReqReplyToAddressValue, dynamic senderDetails)
        {
            loggerModelNew = new LoggerModelNew(signerEmailAddress, "EnvelopeHelperMain", "CCNotificationMail", "Process started for CCNotification Mail", sessionEnvelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            cultureInfo = sessionEnvelope.CultureInfo;
            var currentCultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
            Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(RSign.Common.Helpers.Common.GetCultureInfoValue(cultureInfo));
            Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;
            string subject = signerName + " (" + signerEmailAddress + ")" + " " + "has Signed your Document.";
            string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
            imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");
            string strURL = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/PDFCurrentStatus?");
            var strURLWithData = strURL + HttpUtility.UrlEncode(EncryptQueryString(string.Format("EnvelopeId={0}", sessionEnvelope.ID)));
            string[] toAddressSender = sessionEnvelope.Recipients.Where(r => r.ID == senderRecipientId).Select(r => r.EmailAddress).ToArray();
            string[] toDisplayNameSender = sessionEnvelope.Recipients.Where(r => r.ID == senderRecipientId).Select(r => r.Name).ToArray();
            string mailTemplate = string.Empty;

            mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.ElectronicSignatureNCC, sessionEnvelope.CultureInfo, AppendEmailDisclaimer(sessionEnvelope.UserID));
            mailTemplate = _genericRepository.AppendFooterText(mailTemplate, toAddressSender[0].ToString(), Constants.String.MailTemplateName.ElectronicSignatureNCC, sessionEnvelope.CultureInfo, "FinalContractFooter");

            var htmlCodeCC = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#CCName (<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#CCEmailId'>#CCEmailId</a>)</font>";
            List<Recipients> ccRecipients = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.CC).ToList();
            List<Recipients> signerRecipients = sessionEnvelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer).ToList();
            StringBuilder sbCC = new StringBuilder();
            //Append All "TO LIST"
            mailTemplate = AppendAllSignerRecipient(signerRecipients, mailTemplate, sessionEnvelope.EnableMessageToMobile);
            var ccString = AppendCCUserEmailsList(ccRecipients, Convert.ToBoolean(sessionEnvelope.EnableMessageToMobile));
            sbCC.Append(ccString);
            //foreach (var ccRecipient in ccRecipients)
            //{
            //    var tempHtmlCode = htmlCodeCC.Replace("'", "\"");
            //    tempHtmlCode = tempHtmlCode.Replace("#CCName", ccRecipient.Name);
            //    tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccRecipient.EmailAddress);
            //    sbCC.Append(tempHtmlCode + ",");
            //}
            string FirstName = signerName;
            mailTemplate = mailTemplate.Replace("#CCList", sbCC.ToString().Substring(0, sbCC.ToString().LastIndexOf(",")));
            mailTemplate = mailTemplate.Replace("#CCFirstName", FirstName);
            mailTemplate = mailTemplate.Replace("#SenderName", senderName);
            mailTemplate = mailTemplate.Replace("#SenderEmailId", senderEmailAddress);
            mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(sessionEnvelope.EDisplayCode));

            mailTemplate = mailTemplate.Replace("#clientLogo", string.Empty);

            mailTemplate = mailTemplate.Replace("#SignerName", FirstName);

            var allSettingsDetails = GetAllSettingsDetails(sessionEnvelope.UserID, userEmail);

            mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.CCRecipient);
            mailTemplate = _genericRepository.AppendFooterText(mailTemplate, toAddressSender[0].ToString(), Constants.String.MailTemplateName.CCRecipient, sessionEnvelope.CultureInfo, "FinalContractFooter");

            //* Added by RLabs-RSign DEV Team  
            if (allSettingsDetails.ShowRSignLogo != true)
            {
                imageLogoURl = string.Empty;
            }

            Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(currentCultureInfo);
            Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;
            //To Add data in Emailqueue and EmailqueueRecipients for Accept mail  
            if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
            {
                EmailQueueProcessor.EmailQueueData emailQueueData = new EmailQueueProcessor.EmailQueueData();
                EmailQueueProcessor.EmailSendInfo emailSendData = new EmailQueueProcessor.EmailSendInfo();
                emailQueueData.envelope = sessionEnvelope;
                emailQueueData.MailMessageBody = mailTemplate;
                emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                //emailQueueData.Signer = senderDetails; 
                emailQueueData.EmailType = Constants.EmailTypes.ESNCC;
                emailQueueData.EmailSubject = subject;
                emailSendData.RecipientName = string.Join(",", toDisplayNameSender);
                emailSendData.RecipientEmail = string.Join(",", toAddressSender);
                emailQueueData.emailSendInfo = emailSendData;
                EmailQueueFunction(emailQueueData);
            }
            else
            {
                var Chilkat = new ChilkatHelper(_appConfiguration);
                Chilkat.SendMailUsingChilKet(toAddressSender, toDisplayNameSender, null, null, null, null, senderEmailAddress, senderName, subject, mailTemplate, null, null, Convert.ToString(sessionEnvelope.EDisplayCode), Constants.String.EmailOperation.SignRecipientCC, SignReqReplyToAddressValue);
            }
            loggerModelNew.Message = "Process completed for CCNotification Mail";
            rsignlog.RSignLogInfo(loggerModelNew);
        }
        public string AppendDateTime(int dtFormatId, string fileName)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "AppendDateTime", "Append Date Time process started", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            if (dtFormatId <= 1)
                return fileName;
            string extension = Path.GetExtension(fileName);
            fileName = Path.GetFileNameWithoutExtension(fileName);
            try
            {
                switch (Convert.ToInt32(dtFormatId))
                {
                    case 2:
                        fileName = String.Format("{0}-{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("yyyy-MM-dd-HH-mm-ss"));
                        break;
                    case 3:
                        fileName = String.Format("{0}-{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"));
                        break;
                    case 4:
                        fileName = String.Format("{0}-{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MM-yyyy-HH-mm-ss"));
                        break;
                    case 5:
                        fileName = String.Format("{0}-{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("yyyy-MM-dd-HH-mm-ss"), fileName);
                        break;
                    case 6:
                        fileName = String.Format("{0}-{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"), fileName);
                        break;
                    case 7:
                        fileName = String.Format("{0}-{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MM-yyyy-HH-mm-ss"), fileName);
                        break;
                    case 8:
                        fileName = String.Format("{0}_{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("yyyy_MM_dd_HH_mm_ss"));
                        break;
                    case 9:
                        fileName = String.Format("{0}_{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("MM_dd_yyyy_HH_mm_ss"));
                        break;
                    case 10:
                        fileName = String.Format("{0}_{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd_MM_yyyy_HH_mm_ss"));
                        break;
                    case 11:
                        fileName = String.Format("{0}_{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("yyyy_MM_dd_HH_mm_ss"), fileName);
                        break;
                    case 12:
                        fileName = String.Format("{0}_{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"), fileName);
                        break;
                    case 13:
                        fileName = String.Format("{0}_{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd_MM_yyyy_HH_mm_ss"), fileName);
                        break;
                    case 14:
                        fileName = String.Format("{0}_{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MMM-yyyy-HH-mm-ss"));
                        break;
                    case 15:
                        fileName = String.Format("{0}_{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MMM-yyyy-HH-mm-ss"), fileName);
                        break;
                    default:
                        return fileName;
                }
                //TODO: Check extension contains "." or not?
                if (!string.IsNullOrEmpty(extension))
                    return fileName + extension;
                return fileName;
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }
        public bool UpdateEnvelopeContractStatus(Guid envelopeID, int intStatus, string errMsg)
        {
            Guid envopleIds = Guid.Empty;
            using (var dbContext = new RSignDbContext(_configuration))
            {
                var envContractEntities = dbContext.EnvelopeContractStatus.Where(m => m.Id == envelopeID).FirstOrDefault();
                if (envContractEntities != null)
                {
                    envContractEntities.Status = intStatus;
                    envContractEntities.ServerName = System.Environment.MachineName;
                    envContractEntities.ModifiedDateTime = DateTime.Now;
                    envContractEntities.ErrorMessage = errMsg;
                    dbContext.SaveChanges();
                }
                else if (envContractEntities == null && intStatus == 2)
                {
                    envContractEntities = new EnvelopeContractStatus();
                    envContractEntities.Status = 1;
                    envContractEntities.ServerName = System.Environment.MachineName;
                    envContractEntities.CreatedDateTime = DateTime.Now;
                    envContractEntities.Id = envelopeID;
                    envContractEntities.ErrorMessage = errMsg;
                    dbContext.EnvelopeContractStatus.Add(envContractEntities);
                    dbContext.SaveChanges();
                }
            }
            return true;
        }
        private List<SanboxRecipients> GetRecipientList(Envelope envelopeObject, string[] rerouteEmail, string[] copyEmail)
        {
            List<SanboxRecipients> recipientList = new List<SanboxRecipients>();
            List<string> sendercopyEmailList = new List<string>();
            string senderUserName = string.Empty;
            UserProfile usersInfo = new UserProfile();
            int isCopyEmailAddress = 0;
            if (rerouteEmail.Length > 0)
            {
                foreach (var item in rerouteEmail)
                {
                    var recipient = new SanboxRecipients
                    {
                        RecipientName = "Hi",
                        RecipientEmail = item,
                        RecipientTypeID = Constants.RecipientType.Sender,
                        CCSignerType = 0
                    };
                    if (!recipientList.Any(a => a.RecipientEmail == recipient.RecipientEmail))
                        recipientList.Add(recipient);
                }
            }
            else
            {
                foreach (var item in envelopeObject.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender))
                {
                    sendercopyEmailList.Clear();
                    isCopyEmailAddress = 0;
                    sendercopyEmailList.Add(item.EmailAddress);
                    if (!string.IsNullOrEmpty(item.CopyEmailAddress))
                    {
                        sendercopyEmailList.AddRange(item.CopyEmailAddress.Split(','));
                    }

                    foreach (string senderEmail in sendercopyEmailList)
                    {
                        senderUserName = string.Empty;
                        if (isCopyEmailAddress > 0)
                        {
                            usersInfo = !string.IsNullOrEmpty(senderEmail) ? _userRepository.GetUserProfileByEmailID(senderEmail) : null;
                            senderUserName = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : senderEmail.Split('@')[0];
                        }

                        var recipient = new SanboxRecipients
                        {
                            RecipientID = item.ID,
                            RecipientName = isCopyEmailAddress == 0 ? item.Name : senderUserName,
                            RecipientEmail = isCopyEmailAddress == 0 ? item.EmailAddress : senderEmail,
                            RecipientTypeID = item.RecipientTypeID,
                            CCSignerType = 0,
                            CultureInfo = item.CultureInfo,
                            DeliveryMode = 1,
                            DialCode = "",
                            CountryCode = "",
                            RecipientMobile = "",
                        };
                        if (!recipientList.Any(a => a.RecipientEmail == recipient.RecipientEmail && a.RecipientTypeID == recipient.RecipientTypeID))
                            recipientList.Add(recipient);

                        isCopyEmailAddress++;
                    }
                }
            }

            List<RecipientDetails> recipientDetails = new List<RecipientDetails>();
            recipientDetails = GetActiveRecipientList(envelopeObject.ID);
            List<string> signersEmailList = new List<string>();
            string SigneruserName = string.Empty;
            int isCopyAddress = 0;

            foreach (var item in recipientDetails.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer || r.RecipientTypeID == Constants.RecipientType.CC))
            {
                signersEmailList.Clear();
                isCopyAddress = 0;
                signersEmailList.Add(item.EmailID);
                if (!string.IsNullOrEmpty(item.CopyEmailID))
                {
                    signersEmailList.AddRange(item.CopyEmailID.Split(','));
                }

                foreach (string signerEmail in signersEmailList)
                {
                    SigneruserName = string.Empty;
                    if (isCopyAddress > 0)
                    {
                        usersInfo = !string.IsNullOrEmpty(signerEmail) ? _userRepository.GetUserProfileByEmailID(signerEmail) : null;
                        SigneruserName = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : signerEmail.Split('@')[0];
                    }

                    var recipient = new SanboxRecipients
                    {
                        RecipientID = item.ID,
                        RecipientName = isCopyAddress == 0 ? item.RecipientName : SigneruserName,
                        RecipientEmail = signerEmail,
                        RecipientTypeID = item.RecipientTypeID,
                        CCSignerType = item.RecipientTypeID == Constants.RecipientType.CC ? item.CCSignerType : 0,
                        CultureInfo = item.CultureInfo,
                        DeliveryMode = item.DeliveryMode,
                        DialCode = item.DialCode,
                        CountryCode = item.CountryCode,
                        RecipientMobile = item.Mobile,
                    };
                    if (!recipientList.Any(a => a.RecipientEmail == recipient.RecipientEmail && a.RecipientTypeID == recipient.RecipientTypeID))
                        recipientList.Add(recipient);

                    isCopyAddress++;
                }

            }

            if (copyEmail.Length > 0)
            {
                foreach (var item in copyEmail)
                {
                    var recipient = new SanboxRecipients
                    {
                        RecipientName = "Hi",
                        RecipientEmail = item,
                        RecipientTypeID = Constants.RecipientType.CC,
                        CCSignerType = 0
                    };
                    if (!recipientList.Any(a => a.RecipientEmail == recipient.RecipientEmail))
                        recipientList.Add(recipient);
                }
            }
            return recipientList;
        }
        public List<RecipientDetails> GetActiveRecipientList(Guid envelopeId)
