                    return recipients;
                }
            }
            catch (Exception ex)
            {
                return null;
            }
        }
        public void DelegateToMail(string delegatedPersonName, string delegatedPersonEmail, Envelope envelope, Recipients recipientDetails, Guid delegatedRecipientId, string envelopeSenderEmail,
           string envelopeSenderName, string ipAddress, string contextVal, string authKey, string recipientCode, Recipients delegatedRecipientDetails)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "DelegateToMail", "Process started for Delegated To Mail", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");

                int SignReqReplyToAddressValue = 1; var msgId = Guid.NewGuid();
                string EmailSentType = string.Empty; int RetryCount = 0;
                List<ChilkatHelper.EmailLogs> emailLogs = new List<ChilkatHelper.EmailLogs>();

                var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
                var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(envelope.ID);
                if (envelopeSettingObject != null)
                    SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

                var cultureInfo = !string.IsNullOrEmpty(recipientDetails.CultureInfo) ? recipientDetails.CultureInfo : envelope.CultureInfo;

                string subject = GetLanguageBasedApiMessge(envelope.UserID, "Subject_DocumentDelegated");
                int ExpiresInValue = 1;
                string ExpireDays = string.Empty, DoNotShareMail = string.Empty, AlternateSigningOption = string.Empty,
                    SignFromRSignWebSite = string.Empty, QuestionsAboutDocument = string.Empty, QuestionsAboutDocumentText = string.Empty;
                ExpiresInValue = GetExpiryDays(ExpiresInValue, Convert.ToString(envelope.ExpiryTypeID), envelope.CreatedDateTime == envelope.ModifiedDateTime ? envelope.CreatedDateTime : envelope.ModifiedDateTime, envelope.Subject.Contains(":"));
                ExpireDays = _genericRepository.GetUniqueKey("InviteExpiresIn", cultureInfo) + " " + ExpiresInValue + " " + _genericRepository.GetUniqueKey((ExpiresInValue > 1 ? "Days" : "Day"), cultureInfo);
                DoNotShareMail = _genericRepository.GetUniqueKey("DoNotShareMail", cultureInfo);
                AlternateSigningOption = _genericRepository.GetUniqueKey("AlternateSigningOption", cultureInfo);
                SignFromRSignWebSite = _genericRepository.GetUniqueKey("SignFromRSignWebSite", cultureInfo);
                QuestionsAboutDocument = _genericRepository.GetUniqueKey("QuestionsAboutDocument", cultureInfo);
                QuestionsAboutDocumentText = _genericRepository.GetUniqueKey("QuestionsAboutDocumentText", cultureInfo);
                //* Added by RLabs-RSign DEV Team
                AdminGeneralAndSystemSettings allSettingsDetails = GetAllSettingsDetails(envelope.UserID, envelopeSenderEmail);
                if (allSettingsDetails.ShowRSignLogo != true)
                {
                    imageLogoURl = "";
                }

                string EmailDesclaimer = AppendEmailDisclaimer(envelope.UserID);
                int DisclaimerLocationId = GetDisclaimerLocation(envelope.UserID, Guid.Empty);

                var isPasswordMailToSigner = envelope.IsPasswordMailToSigner;
                bool isEmailSend = false, isPwdEmailSend = false;
                bool isMobileSend = false, isPwdMobileSend = false;
                if (Convert.ToBoolean(envelope.EnableMessageToMobile))
                {
                    isPasswordMailToSigner = true;
                    Recipients recSigner = new Recipients() { DeliveryMode = delegatedRecipientDetails.DeliveryMode, EmailAddress = delegatedRecipientDetails.EmailAddress, Mobile = delegatedRecipientDetails.Mobile };
                    GetEmailDeiliveryModeOptions(recSigner, ref isEmailSend, ref isMobileSend);
                    GetMobileDeiliveryModeOptions(recSigner, ref isPwdEmailSend, ref isPwdMobileSend);
                }
                else
                {
                    isPwdEmailSend = true;
                    isEmailSend = true;
                }

                //cultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
                //send password to recipient to sign the document 
                if (envelope.PasswordReqdtoSign == true && recipientDetails.RecipientTypeID != Constants.RecipientType.CC && isPasswordMailToSigner)
                {
                    string password = ModelHelper.Decrypt(envelope.PasswordtoSign, envelope.PasswordKey, (int)envelope.PasswordKeySize);
                    string mailTemplatepassword = string.Empty;
                    string firstName = delegatedPersonName.Split(' ').FirstOrDefault();

                    if (isPwdEmailSend)
                    {
                        mailTemplatepassword = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordSign, cultureInfo, EmailDesclaimer);
                        mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", envelopeSenderName);
                        mailTemplatepassword = mailTemplatepassword.Replace("#SenderEmailId", envelopeSenderEmail);
                        mailTemplatepassword = mailTemplatepassword.Replace("#RecipientName", firstName);
                        mailTemplatepassword = mailTemplatepassword.Replace("#SignerName", delegatedPersonName);
                        //if (isMobileSend)
                        //    mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", (delegatedPersonEmail + ", " + delegatedRecipientDetails.DialCode + delegatedRecipientDetails.Mobile));
                        //else
                        //    mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", delegatedPersonEmail);


                        string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(delegatedRecipientDetails.DeliveryMode, delegatedRecipientDetails.EmailAddress, delegatedRecipientDetails.DialCode, delegatedRecipientDetails.Mobile);
                        mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", emailMobileNumberDetails);


                        mailTemplatepassword = mailTemplatepassword.Replace("#RecipientEmailId", delegatedPersonEmail);
                        mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode));
                        mailTemplatepassword = mailTemplatepassword.Replace("#PasswordToOpenDoc", System.Web.HttpUtility.HtmlEncode(password));
                        //mailTemplatepassword = mailTemplatepassword.Replace("#ImageURL", imageLogoURl);
                        mailTemplatepassword = mailTemplatepassword.Replace("#clientLogo", "");
                        mailTemplatepassword = mailTemplatepassword.Replace("#ExpireDays", ExpireDays);
                        mailTemplatepassword = mailTemplatepassword.Replace("#DoNotShareMail", DoNotShareMail);
                        mailTemplatepassword = mailTemplatepassword.Replace("#AlternateSigningOption", AlternateSigningOption);
                        mailTemplatepassword = mailTemplatepassword.Replace("#SignFromRSignWebSite", SignFromRSignWebSite);
                        mailTemplatepassword = mailTemplatepassword.Replace("#QuestionsAboutDocument", QuestionsAboutDocument);
                        mailTemplatepassword = mailTemplatepassword.Replace("#QuestionsAboutDocText", QuestionsAboutDocumentText);

                        mailTemplatepassword = EmailBannerSettings(mailTemplatepassword, allSettingsDetails, Constants.String.MailTemplateName.PasswordSign);
                        mailTemplatepassword = _genericRepository.AppendFooterText(mailTemplatepassword, delegatedPersonEmail, Constants.String.MailTemplateName.PasswordSign, cultureInfo, "FinalContractFooter");

                        if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            //To Add data in Emailqueue and EmailqueueRecipients for Delegate Electronic Signature Sender Notification 
                            EmailQueueData emailQueueData = new EmailQueueData();
                            EmailSendInfo emailSendData = new EmailSendInfo();
                            emailQueueData.envelope = envelope;
                            emailQueueData.MailMessageBody = mailTemplatepassword;
                            emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                            emailQueueData.EmailType = Constants.EmailTypes.ESPO;
                            emailQueueData.EmailSubject = envelope.Subject;
                            emailSendData.RecipientName = null;
                            emailSendData.RecipientEmail = delegatedPersonEmail;
                            emailQueueData.emailSendInfo = emailSendData;
                            EmailQueueFunction(emailQueueData);
                        }
                        else
                        {
                            var Chilkat = new ChilkatHelper(_appConfiguration);
                            emailLogs = Chilkat.SendMailUsingChilKet(new string[] { delegatedPersonEmail }, null,
                                             null, null,
                                             null, null,
                                             envelopeSenderEmail, envelopeSenderName, subject + ": " + envelope.Subject, mailTemplatepassword, null, null, envelope.EDisplayCode, Constants.String.EmailOperation.PasswordToSign, SignReqReplyToAddressValue);
                        }
                    }

                    if (isPwdMobileSend)
                    {
                        mailTemplatepassword = string.Empty;
                        mailTemplatepassword = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.PasswordSign, cultureInfo, EmailDesclaimer, 3, "mobile");

                        mailTemplatepassword = mailTemplatepassword.Replace("#SenderName", envelopeSenderName);
                        mailTemplatepassword = mailTemplatepassword.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode));
                        mailTemplatepassword = mailTemplatepassword.Replace("#Password", System.Web.HttpUtility.HtmlEncode(password));

                        if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                        {
                            string emailSubject = envelope.Subject;
                            SendSMSThroughEmailService(envelope, mailTemplatepassword, SignReqReplyToAddressValue, Constants.EmailTypes.ESPO, delegatedRecipientDetails, emailSubject);
                        }
                        else
                        {
                            string signerMobileNumber = delegatedRecipientDetails.DialCode + delegatedRecipientDetails.Mobile;
                            SendMobileSMS(envelope, mailTemplatepassword, signerMobileNumber);
                        }
                    }
                }
                // Create Full url path based on information
                //if (HttpContext.Request.Url == null) return;
                //var strURL = HttpContext.Request.Url.Scheme + "://" + HttpContext.Request.Url.Authority + "/SignDocument/Index?";
                var strURL = "";
                var senderDetails = envelope.Recipients.FirstOrDefault(r => r.RecipientTypeID == Constants.RecipientType.Sender);
                if (Convert.ToBoolean(envelope.IsSignerIdentitiy))
                {
                    if (IsGenerateNewSigningUrl(senderDetails.EmailAddress))
                        strURL = Convert.ToString(_appConfiguration["NewSigningURL"]) + "authenticate-signer?";
                    else
                        strURL = Path.Combine(Convert.ToString(_appConfiguration["SigningURL"]), "SignDocument/AuthenticateSigner?");
                }
                else
                {
                    if (IsGenerateNewSigningUrl(senderDetails.EmailAddress))
                        strURL = Convert.ToString(_appConfiguration["NewSigningURL"]) + "signer-landing?";
                    else
                        strURL = Path.Combine(Convert.ToString(_appConfiguration["SigningURL"]), "SignDocument/Index?");
                }

                // encrypt querystring
                string strURLWithData = strURL;// +HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}", envelope.ID, delegatedRecipientId), AppConfig.Instance.Settings.AppKey));
                if (envelope.TemplateKey != null)
                    strURLWithData = strURLWithData + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}&TemplateKey={2}&EmailId={3}", envelope.ID, delegatedRecipientId, envelope.TemplateKey, HttpUtility.UrlEncode(delegatedPersonEmail)), Convert.ToString(_appConfiguration["AppKey"])));
                else
                    strURLWithData = strURLWithData + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}&EmailId={2}", envelope.ID, delegatedRecipientId, HttpUtility.UrlEncode(delegatedPersonEmail)), Convert.ToString(_appConfiguration["AppKey"])));

                string signingShortURL = string.Empty;
                if (isMobileSend)
                {
                    string md5ShortUriPasscode = _modelHelper.CalculateMD5HashForShortURL(strURLWithData).ToLower();
                    signingShortURL = Convert.ToString(_appConfiguration["SigningURL"]) + "Msg/Rs/" + md5ShortUriPasscode;
                    SaveShortUrlForSMS(envelope, strURLWithData, signingShortURL, md5ShortUriPasscode, false);
                }

                if (isEmailSend)
                {
                    var strURLForSecurityCode = string.Empty;
                    if (IsGenerateNewSigningUrl(senderDetails.EmailAddress))
                        strURLForSecurityCode = Convert.ToString(_appConfiguration["NewSigningURL"]) + "/security-code";
                    else
                        strURLForSecurityCode = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SignDocuments"; //URLTOGenerateCode

                    // var strURLForSecurityCode = Convert.ToString(_appConfiguration["SigningURL"]) + "/SignDocument/SignDocuments"; //URLTOGenerateCode

                    string mailTemplate = string.Empty;
                    List<Recipients> recipients = envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer).ToList();
                    mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.DelegatedTo, cultureInfo, EmailDesclaimer, DisclaimerLocationId);
                    //mailTemplate = mailTemplate.Replace("#ImageURL", imageLogoURl);
                    mailTemplate = mailTemplate.Replace("#URL", strURLWithData);
                    mailTemplate = mailTemplate.Replace("#RecipientName", delegatedPersonName);
                    mailTemplate = mailTemplate.Replace("#SenderName", senderDetails.Name);
                    mailTemplate = mailTemplate.Replace("#SenderEmailId", senderDetails.EmailAddress);
                    mailTemplate = mailTemplate.Replace("#OriginalSignerName", recipientDetails.Name);

                    //if (!string.IsNullOrEmpty(recipientDetails.EmailAddress) && !string.IsNullOrEmpty(recipientDetails.Mobile) && recipientDetails.DeliveryMode == 2)
                    //    mailTemplate = mailTemplate.Replace("#OriginalSignerEmailId", recipientDetails.EmailAddress + ", " + recipientDetails.DialCode + recipientDetails.Mobile);
                    //else if (!string.IsNullOrEmpty(recipientDetails.EmailAddress) && recipientDetails.DeliveryMode == 1)
                    //    mailTemplate = mailTemplate.Replace("#OriginalSignerEmailId", recipientDetails.EmailAddress);
                    //else if (!string.IsNullOrEmpty(recipientDetails.Mobile) && recipientDetails.DeliveryMode == 3)
                    //    mailTemplate = mailTemplate.Replace("#OriginalSignerEmailId", recipientDetails.DialCode + recipientDetails.Mobile);
                    //else if (!string.IsNullOrEmpty(recipientDetails.EmailAddress))
                    //    mailTemplate = mailTemplate.Replace("#OriginalSignerEmailId", recipientDetails.EmailAddress);

                    string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(recipientDetails.DeliveryMode, recipientDetails.EmailAddress, recipientDetails.DialCode, recipientDetails.Mobile);
                    mailTemplate = mailTemplate.Replace("#OriginalSignerEmailId", emailMobileNumberDetails);
                    string delegatedPersonEmailMobileDetails = _asposeHelper.AppendSignerEmailMobileDetails(delegatedRecipientDetails.DeliveryMode, delegatedPersonEmail, delegatedRecipientDetails.DialCode, delegatedRecipientDetails.Mobile);
                    mailTemplate = mailTemplate.Replace("#DelegatedSignerEmailId", delegatedPersonEmailMobileDetails);

                    mailTemplate = mailTemplate.Replace("#DelegatedSignerName", delegatedPersonName);
                    //if (isMobileSend)
                    //    mailTemplate = mailTemplate.Replace("#DelegatedSignerEmailId", (delegatedPersonEmail + ", " + delegatedRecipientDetails.DialCode + delegatedRecipientDetails.Mobile));
                    //else
                    //    mailTemplate = mailTemplate.Replace("#DelegatedSignerEmailId", delegatedPersonEmail);
                    mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode));
                    mailTemplate = mailTemplate.Replace("#GenerateCodeURL", strURLForSecurityCode);
                    mailTemplate = mailTemplate.Replace("#EnvelopeSecurityCode", recipientCode);
                    mailTemplate = mailTemplate.Replace("#ExpireDays", ExpireDays);
                    mailTemplate = mailTemplate.Replace("#DoNotShareMail", DoNotShareMail);
                    mailTemplate = mailTemplate.Replace("#AlternateSigningOption", AlternateSigningOption);
                    mailTemplate = mailTemplate.Replace("#SignFromRSignWebSite", SignFromRSignWebSite);
                    mailTemplate = mailTemplate.Replace("#QuestionsAboutDocument", QuestionsAboutDocument);
                    mailTemplate = mailTemplate.Replace("#QuestionsAboutDocText", QuestionsAboutDocumentText);

                    string signerComments = string.Empty;
                    var allRecipients = _recipientRepository.GetAllRecipients(envelope.ID);
                    var recipientCommentsList = allRecipients.Where(t => t.Comments != "").Select(t => t.Comments).ToList();
                    foreach (var recipientList in recipientCommentsList)
                    {
                        if (recipientList != null)
                        {
                            signerComments += "<tr><td><span style = 'font-family: calibri,sans-serif ;font-size:11pt;color: #000;font-weight: bold'> The reason for changing the signer </span>"
                                        + "</td> </tr> <tr> <td> <span style = 'font-family: calibri,sans-serif ;font-size:11pt;color: #000;'>" + recipientList + "</span></td> </tr> ";
                        }
                    }

                    mailTemplate = mailTemplate.Replace("id=\"tblSignerComments\">", ">" + signerComments);

                    bool isMultiTemplate = envelope.Recipients.Where(s => s.TemplateID != null && s.RecipientTypeID == Constants.RecipientType.Signer).Select(s => s.TemplateID).Distinct().Count() > 1;
                    if (recipientDetails.TemplateID != null && isMultiTemplate)
                    {
                        mailTemplate = mailTemplate.Replace("#DocumentLabel", "Document:");
                        mailTemplate = mailTemplate.Replace("#DocumentName", string.Join(", ", _genericRepository.GetTemplatDocumentNames(recipientDetails.TemplateID.Value).ToArray()));
                        //mailTemlate = mailTemlate.Replace("#DocumentName", string.Join(", ", envelope.Documents.Select(e => e.DocumentName).ToArray()));
                    }
                    else
                    {
                        mailTemplate = mailTemplate.Replace("#DocumentLabel", string.Empty);
                        mailTemplate = mailTemplate.Replace("#DocumentName", string.Empty);
                    }
                    //mailTemplate = mailTemplate.Replace("#DocumentName", string.Join(", ", envelope.Documents.Select(e => e.DocumentName).ToArray()));

                    mailTemplate = mailTemplate.Replace("#EmailBodyText", envelope.Message);
                    mailTemplate = mailTemplate.Replace("#clientLogo", string.Empty);

                    mailTemplate = EmailBannerSettings(mailTemplate, allSettingsDetails, Constants.String.MailTemplateName.DelegatedTo);
                    mailTemplate = _genericRepository.AppendFooterText(mailTemplate, delegatedPersonEmail, Constants.String.MailTemplateName.DelegatedTo, cultureInfo, "SigningFooter");

                    //Append 'To' list in mailTemplate
                    mailTemplate = AppendAllSignerRecipient(recipients, mailTemplate, envelope.EnableMessageToMobile);
                    //End of append 'To' list
                    if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                    {
                        //To Add data in Emailqueue and EmailqueueRecipients for Delegate Electronic Signature  Notification 
                        EmailQueueData emailQueueData = new EmailQueueData();
                        EmailSendInfo emailSendData = new EmailSendInfo();
                        emailQueueData.envelope = envelope;
                        emailQueueData.MailMessageBody = mailTemplate;
                        emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                        emailQueueData.EmailType = Constants.EmailTypes.DGESR;
                        emailQueueData.EmailSubject = envelope.Subject;
                        emailSendData.RecipientName = null;
                        emailSendData.RecipientEmail = delegatedPersonEmail;
                        emailQueueData.emailSendInfo = emailSendData;
                        EmailQueueFunction(emailQueueData, true);
                    }
                    else
                    {
                        var Chilkat = new ChilkatHelper(_appConfiguration);
                        emailLogs = Chilkat.SendMailUsingChilKet(new string[] { delegatedPersonEmail }, null,
                                         null, null,
                                         null, null,
                                         envelopeSenderEmail, envelopeSenderName, subject + ": " + envelope.Subject, mailTemplate, null, null, envelope.EDisplayCode, Constants.String.EmailOperation.Delegate, SignReqReplyToAddressValue, msgId);

                        _genericRepository.SaveEmailLogsRecord(emailLogs, out EmailSentType, out RetryCount);
                        //Save email destination record
                        _genericRepository.SaveDestinationRecord(new Destination() { MessageId = msgId, EnvelopeCode = envelope.EDisplayCode, RecipientEmail = delegatedPersonEmail, IsSent = true, IsProcessed = false, EmailSentType = EmailSentType, RetryCount = RetryCount });
                    }
                }

                if (isMobileSend)
                {
                    string mailTemplate = string.Empty;
                    mailTemplate = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.DelegatedTo, cultureInfo, EmailDesclaimer, DisclaimerLocationId, "mobile");
                    mailTemplate = mailTemplate.Replace("#OriginalSignerName", recipientDetails.Name);
                    mailTemplate = mailTemplate.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode));
                    mailTemplate = mailTemplate.Replace("#SigningShortURL", signingShortURL);

                    if (_appConfiguration["SendEmailFromService"] != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                    {
                        string emailSubject = envelope.Subject;
                        SendSMSThroughEmailService(envelope, mailTemplate, SignReqReplyToAddressValue, Constants.EmailTypes.DGESR, delegatedRecipientDetails, emailSubject);
                    }
                    else
                    {
                        string signerMobileNumber = delegatedRecipientDetails.DialCode + delegatedRecipientDetails.Mobile;
                        SendMobileSMS(envelope, mailTemplate, signerMobileNumber);
                    }
                }
                _recipientRepository.ModifyLastRecipientEntry(recipientDetails.ID, Constants.StatusCode.Signer.Delegated, ipAddress);

                loggerModelNew.Message = "Process completed for Delegated To Mail";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - DelegateToMail method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
        }
        public void DelegatedSenderMail(string delegatedPearsonName, string delegatedPersonEmail, Envelope envelope, Recipients recipientDetail, Guid delegatedRecipientId, Recipients senderDetails, string senderEmailAddress, string ipAddress, string contextVal, string authKey, Recipients delegatedRecipientDetails)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "DelegatedSenderMail", "Process started for Delegated Sender Mail", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                var cultureInfo = envelope.CultureInfo;
                var currentCultureInfo = System.Threading.Thread.CurrentThread.CurrentUICulture.Name.ToLowerInvariant();
                int isSenderCopyAddress = 0;
                Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(cultureInfo);
                Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;
                int SignReqReplyToAddressValue = 1;
                string subject = GetLanguageBasedApiMessge(envelope.UserID, "Subject_DocumentDelegated");
                string imageLogoURl = System.IO.Path.Combine(Convert.ToString(_appConfiguration["CommonFilesPath"]), Convert.ToString(_appConfiguration["Images"]));
                imageLogoURl = System.IO.Path.Combine(imageLogoURl, "RMail-100.png");

                var settingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
                //if (settingsDetails != null)
                //    SignReqReplyToAddressValue = Convert.ToInt32(settingsDetails.OptionValue);

                var envelopeSettingObject = _eSignHelper.GetEnvelopeSettingsDetail(envelope.ID);
                if (envelopeSettingObject != null)
                    SignReqReplyToAddressValue = Convert.ToInt32(envelopeSettingObject.SignReqReplyAdrs);

                //if (HttpContext.Request.Url == null) return;
                //var strURL = HttpContext.Request.Url.Scheme + "://" + HttpContext.Request.Url.Authority + "/SignDocument/Index?";
                var strURL = Path.Combine(Convert.ToString(_appConfiguration["SigningURL"]), "SignDocument/Index?");

                //* Added by RLabs-RSign DEV Team
                AdminGeneralAndSystemSettings allSettingsDetails = GetAllSettingsDetails(envelope.UserID, senderDetails.EmailAddress);
                if (allSettingsDetails.ShowRSignLogo != true)
                {
                    imageLogoURl = "";
                }
                //*//
                List<string> senderEmailList = new List<string>();
                // List<string> senderEmailNamesList = new List<string>();
                senderEmailList = new List<string>(new string[] { senderEmailAddress });
                //senderEmailNamesList = new List<string>(new string[] { senderDetails.Name });

                if (envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Sender && !string.IsNullOrEmpty(r.CopyEmailAddress)).Count() > 0)
                {
                    if (!string.IsNullOrEmpty(senderDetails.CopyEmailAddress))
                        senderEmailList.AddRange(senderDetails.CopyEmailAddress.Split(','));
                }
                string strURLWithData = string.Empty, RecipientfirstName = string.Empty, mailTemplateSender = string.Empty, senderName = string.Empty;
                UserProfile usersInfo = new UserProfile();
                foreach (string senderEmail in senderEmailList)
                {
                    // encrypt querystring
                    if (isSenderCopyAddress == 0)
                    {
                        RecipientfirstName = senderDetails.Name.Split(' ').FirstOrDefault();
                        senderName = senderDetails.Name;
                    }
                    else
                    {
                        usersInfo = !string.IsNullOrEmpty(senderEmail) ? _userRepository.GetUserProfileByEmailID(senderEmail) : null;
                        senderName = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : senderEmail.Split('@')[0];
                        if (usersInfo != null)
                        {
                            RecipientfirstName = usersInfo.FirstName;
                        }
                        else
                        {
                            RecipientfirstName = senderEmail.Split('@')[0];
                        }

                    }
                    isSenderCopyAddress++;
                    //bool isEmailSend = false;
                    //bool isMobileSend = false;
                    //if (delegatedRecipientDetails != null)
                    //{
                    //    if ((delegatedRecipientDetails.DeliveryMode == 1 || delegatedRecipientDetails.DeliveryMode == 2) && !string.IsNullOrEmpty(delegatedRecipientDetails.EmailAddress))
                    //    {
                    //        isEmailSend = true;
                    //    }

                    //    if ((delegatedRecipientDetails.DeliveryMode == 2 || delegatedRecipientDetails.DeliveryMode == 3) && !string.IsNullOrEmpty(delegatedRecipientDetails.Mobile))
                    //    {
                    //        isMobileSend = true;
                    //    }
                    //}

                    strURLWithData = strURL + HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientId={1}", envelope.ID, delegatedRecipientId), Convert.ToString(_appConfiguration["AppKey"])));
                    mailTemplateSender = string.Empty;
                    mailTemplateSender = _genericRepository.GetNewMailTemplate(Constants.String.MailTemplateName.DelegateSender, cultureInfo, AppendEmailDisclaimer(envelope.UserID));

                    mailTemplateSender = mailTemplateSender.Replace("#RecipientName", RecipientfirstName);
                    //mailTemplateSender = mailTemplateSender.Replace("#ImageURL", imageLogoURl);
                    mailTemplateSender = mailTemplateSender.Replace("#SenderName", senderName);
                    mailTemplateSender = mailTemplateSender.Replace("#SenderEmailId", senderEmail);
                    mailTemplateSender = mailTemplateSender.Replace("#OriginalSignerName", recipientDetail.Name);

                    //if (!string.IsNullOrEmpty(recipientDetail.EmailAddress) && !string.IsNullOrEmpty(recipientDetail.Mobile))
                    //    mailTemplateSender = mailTemplateSender.Replace("#OriginalSignerEmailId", recipientDetail.EmailAddress + ", " + recipientDetail.DialCode + recipientDetail.Mobile);
                    //else if (!string.IsNullOrEmpty(recipientDetail.EmailAddress))
                    //    mailTemplateSender = mailTemplateSender.Replace("#OriginalSignerEmailId", recipientDetail.EmailAddress);
                    //else if (!string.IsNullOrEmpty(recipientDetail.Mobile))
                    //    mailTemplateSender = mailTemplateSender.Replace("#OriginalSignerEmailId", recipientDetail.DialCode + recipientDetail.Mobile);

                    string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(recipientDetail.DeliveryMode, recipientDetail.EmailAddress, recipientDetail.DialCode, recipientDetail.Mobile);
                    mailTemplateSender = mailTemplateSender.Replace("#OriginalSignerEmailId", emailMobileNumberDetails);
                    string delegatedEmailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(delegatedRecipientDetails.DeliveryMode, delegatedPersonEmail, delegatedRecipientDetails.DialCode, delegatedRecipientDetails.Mobile);
                    mailTemplateSender = mailTemplateSender.Replace("#DelegatedSignerEmailId", delegatedEmailMobileNumberDetails);

                    mailTemplateSender = mailTemplateSender.Replace("#DelegatedSignerName", delegatedPearsonName);

                    //if (isMobileSend)
                    //    mailTemplateSender = mailTemplateSender.Replace("#DelegatedSignerEmailId", (delegatedPersonEmail + ", " + delegatedRecipientDetails.DialCode + delegatedRecipientDetails.Mobile));
                    //else
                    //    mailTemplateSender = mailTemplateSender.Replace("#DelegatedSignerEmailId", delegatedPersonEmail);

                    mailTemplateSender = mailTemplateSender.Replace("#EnvelopeDisplayCode", Convert.ToString(envelope.EDisplayCode));
                    mailTemplateSender = mailTemplateSender.Replace("#EmailBodyText", envelope.Message);
                    mailTemplateSender = mailTemplateSender.Replace("#clientLogo", string.Empty);

                    string signerComments = string.Empty;
                    var allRecipients = _recipientRepository.GetAllRecipients(envelope.ID);
                    var recipientCommentsList = allRecipients.Where(t => t.Comments != "").Select(t => t.Comments).ToList();
                    foreach (var recipientList in recipientCommentsList)
                    {
                        if (recipientList != null)
                        {
                            signerComments += "<tr><td><span style = 'font-family: calibri,sans-serif ;font-size:11pt;color: #000;font-weight: bold'> The reason for changing the signer </span>"
                                        + "</td> </tr> <tr> <td> <span style = 'font-family: calibri,sans-serif ;font-size:11pt;color: #000;'>" + recipientList + "</span></td> </tr> ";
                        }
                    }

                    mailTemplateSender = mailTemplateSender.Replace("id=\"tblSignerComments\">", ">" + signerComments);
                    mailTemplateSender = EmailBannerSettings(mailTemplateSender, allSettingsDetails, Constants.String.MailTemplateName.DelegateSender);
                    mailTemplateSender = _genericRepository.AppendFooterText(mailTemplateSender, senderEmail, Constants.String.MailTemplateName.DelegateSender, cultureInfo, "FinalContractFooter");

                    Thread.CurrentThread.CurrentCulture = new System.Globalization.CultureInfo(currentCultureInfo);
                    Thread.CurrentThread.CurrentUICulture = Thread.CurrentThread.CurrentCulture;

                    if (Convert.ToString(_appConfiguration["SendEmailFromService"]) != null && Convert.ToString(_appConfiguration["SendEmailFromService"]).ToUpper() == "TRUE")
                    {
                        //To Add data in Emailqueue and EmailqueueRecipients for Delegate Electronic Signature Sender Notification 
                        EmailQueueData emailQueueData = new EmailQueueData();
                        EmailSendInfo emailSendData = new EmailSendInfo();
                        emailQueueData.envelope = envelope;
                        emailQueueData.MailMessageBody = mailTemplateSender;
                        emailQueueData.SignReqReplyToAddressValue = SignReqReplyToAddressValue;
                        emailQueueData.EmailType = Constants.EmailTypes.DGESR;
                        emailQueueData.EmailSubject = subject;
                        emailSendData.RecipientName = null;
                        emailSendData.RecipientEmail = senderEmail;
                        emailQueueData.emailSendInfo = emailSendData;
                        EmailQueueFunction(emailQueueData);
                    }
                    else
                    {
                        var Chilkat = new ChilkatHelper(_appConfiguration);
                        Chilkat.SendMailUsingChilKet(new string[] { senderEmail }, null,
                                        null, null,
                                        null, null,
                                        senderEmail.ToString(), senderName, subject + ": " + envelope.Subject, mailTemplateSender, null, null, envelope.EDisplayCode, Constants.String.EmailOperation.Delegate, SignReqReplyToAddressValue);
                    }
                }
                loggerModelNew.Message = "Process completed for Delegated Sender Mail";
                rsignlog.RSignLogInfo(loggerModelNew);

            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - DelegatedSenderMail method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
        }
        public static int GetExpiryDays(int ExpiresInValue, string ExpiresInOptionValue, DateTime CreatedDateTime, bool isUpdateAndResend)
        {
            switch (ExpiresInOptionValue.ToLower())
            {
                case "44e03b8a-2e73-473c-b453-b8643d09910b":
                    ExpiresInValue = 7;
                    break;
                case "c0f07aae-47dc-4530-ae38-0b5a0f7dacc8":
                    ExpiresInValue = 10;
                    break;
                case "5a6ad6bf-564b-4306-93e7-1563da6db649":
                    ExpiresInValue = 14;
                    break;
                case "ee01fd0a-b72e-4f62-b434-7081db5bb1db":
                    ExpiresInValue = 30;
                    break;
                case "8dfda0d8-5fdf-41b8-8455-6a63791e4130":
                    ExpiresInValue = 90;
                    break;
                case "25b259e0-5c43-4724-b215-406aad6000c1":
                    ExpiresInValue = 1;
                    break;
                case "2bd241a0-7196-45e7-a980-f887e823fc63":
                    ExpiresInValue = 2;
                    break;
                case "9c7a85d8-2bc1-487d-93f6-3356d670c867":
                    ExpiresInValue = 3;
                    break;
                case "a6b7b576-46bf-4cfd-95e1-030179fa89ad":
                    ExpiresInValue = 4;
                    break;
                case "b1451de4-cc89-46ce-8098-41e2c9d3618f":
                    ExpiresInValue = 5;
                    break;
                case "cabc31e9-fcf1-45bb-b2f3-ab0bd0df46e1":
                    ExpiresInValue = 6;
                    break;
                case "67cdb85f-8cd3-4d92-ab9a-8bc7dfea28a7":
                    ExpiresInValue = 60;
                    break;
            }
            if (!isUpdateAndResend)
                ExpiresInValue = ExpiresInValue - (DateTime.Now - CreatedDateTime).Days;
            else
                ExpiresInValue = ExpiresInValue;
            return ExpiresInValue;
        }
