        public string AppendAllSignerRecipient(List<Recipients> recipients, string mailTemlate, bool? enableMessageToMobile = false)
        {
            StringBuilder sbSigner = new StringBuilder();
            //Append 'To' list in mailTemplate
            var htmlCodeSigner = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#ToName(<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#ToEmailId'>#ToEmailId</a>)</font>";
            List<string> signersEmailList = new List<string>();
            int isCopyAddress = 0;
            UserProfile usersInfo = new UserProfile();
            string SigneruserName = string.Empty;
            foreach (var signerRecipient in recipients)
            {
                isCopyAddress = 0;
                signersEmailList.Clear();
                signersEmailList.Add(signerRecipient.EmailAddress);
                if (!string.IsNullOrEmpty(signerRecipient.CopyEmailAddress))
                {
                    signersEmailList.AddRange(signerRecipient.CopyEmailAddress.Split(','));
                }
                foreach (string signerEmail in signersEmailList)
                {
                    if (isCopyAddress > 0)
                    {
                        usersInfo = !string.IsNullOrEmpty(signerEmail) ? _userRepository.GetUserProfileByEmailID(signerEmail) : null;
                        SigneruserName = usersInfo != null ? usersInfo.FirstName + " " + usersInfo.LastName : signerEmail.Split('@')[0];
                    }

                    var tempHtmlCode = htmlCodeSigner.Replace("'", "\"");
                    tempHtmlCode = tempHtmlCode.Replace("#ToName", isCopyAddress == 0 ? signerRecipient.Name : SigneruserName);
                    if (Convert.ToBoolean(enableMessageToMobile))
                    {
                        //if (!string.IsNullOrEmpty(signerEmail) && !string.IsNullOrEmpty(signerRecipient.Mobile) && signerRecipient.DeliveryMode == 2)
                        //{
                        //    string signerMobileNumber = signerRecipient.EmailAddress + ", " + signerRecipient.DialCode + signerRecipient.Mobile;
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerMobileNumber);
                        //}
                        //else if (!string.IsNullOrEmpty(signerEmail) && (signerRecipient.DeliveryMode == 1 || signerRecipient.DeliveryMode == null))
                        //{
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerEmail);
                        //}
                        //else if (!string.IsNullOrEmpty(signerRecipient.Mobile) && signerRecipient.DeliveryMode == 3)
                        //{
                        //    string signerMobileNumber = signerRecipient.DialCode + signerRecipient.Mobile;
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerMobileNumber);
                        //}
                        //else if (!string.IsNullOrEmpty(signerEmail))
                        //{
                        //    tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerEmail);
                        //}

                        string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signerRecipient.DeliveryMode, signerRecipient.EmailAddress, signerRecipient.DialCode, signerRecipient.Mobile);
                        tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", emailMobileNumberDetails);
                    }
                    else
                    {
                        tempHtmlCode = tempHtmlCode.Replace("#ToEmailId", signerEmail);
                    }
                    sbSigner.Append(tempHtmlCode + ", ");
                    isCopyAddress++;
                }
            }

            mailTemlate = mailTemlate.Replace("#ToList", sbSigner.ToString().Substring(0, sbSigner.ToString().LastIndexOf(",")));
            //End of append 'To' list

            return mailTemlate;
        }
        public void DeleteContractFileInCaseOfError(Guid envelopeID, string envelopeDirectoryUNCPath)
        {
            string tempEnvelopeDirectory = Path.Combine(envelopeDirectoryUNCPath, Convert.ToString(envelopeID));
            if (Directory.Exists(Path.Combine(tempEnvelopeDirectory, "Final")))
            {
                System.IO.DirectoryInfo diEnvelope = new DirectoryInfo(Path.Combine(tempEnvelopeDirectory, "Final"));
                foreach (FileInfo file in diEnvelope.GetFiles())
                {
                    GC.Collect();
                    GC.WaitForPendingFinalizers();
                    file.Delete();
                }
            }
            if (Directory.Exists(Path.Combine(tempEnvelopeDirectory)))
            {
                foreach (FileInfo file in new DirectoryInfo(tempEnvelopeDirectory).GetFiles("*.pdf"))
                {
                    GC.Collect();
                    GC.WaitForPendingFinalizers();
                    file.Delete();
                }
            }
            if (Directory.Exists(Path.Combine(tempEnvelopeDirectory, "FinalZipPDF")))
            {
                System.IO.DirectoryInfo diEnvelope = new DirectoryInfo(Path.Combine(tempEnvelopeDirectory, "FinalZipPDF"));
                foreach (FileInfo file in diEnvelope.GetFiles())
                {
                    GC.Collect();
                    GC.WaitForPendingFinalizers();
                    file.Delete();
                }
            }
        }
        public EnvelopeContent CreateXml(Envelope sessionEnvelope)
        {
            try
            {
                EnvelopeContent envelopeContent = new EnvelopeContent();
                Guid newEnvelopeContectID = Guid.NewGuid();
                var documents = sessionEnvelope.Documents;
                var templateIds = sessionEnvelope.Recipients.Where(r => r.TemplateID != null).Select(a => a.TemplateID.Value).Distinct().ToList();
                var templateCodes = string.Empty;
                var status = _lookupRepository.GetLookupMasterLanguage(Lookup.MasterLanguageKeyDetails, sessionEnvelope.CultureInfo, Lookup.EnvelopeStatus.ToString()).FirstOrDefault(s => s.Key == sessionEnvelope.StatusID).Value;

                if (templateIds != null && templateIds.Count > 0)
                {
                    var sbTemplateCodes = new List<string>();
                    foreach (var id in templateIds)
                    {
                        var template = _genericRepository.GetTemplateEntity(id);
                        if (template != null && template.TemplateCode != null)
                            sbTemplateCodes.Add(template.TemplateCode.Value.ToString());
                    }
                    templateCodes = string.Join(",", sbTemplateCodes);
                }

                var declineReasons = string.Empty;
                if (sessionEnvelope.StatusID == Constants.StatusCode.Envelope.Terminated)
                {
                    var subEnvelope = GetSubEnvelopeIdByEnvelopeCode(sessionEnvelope.EDisplayCode);
                    var envelope = subEnvelope != null ? _genericRepository.GetEnvelopeRecipients(subEnvelope.MasterEnvelopeID) : _genericRepository.GetEnvelopeRecipients(sessionEnvelope.ID);
                    if (envelope != null && envelope.Recipients != null && envelope.Recipients.Count() > 0)
                    {
                        foreach (var recipient in envelope.Recipients.Where(r => r.RecipientTypeID == Constants.RecipientType.Signer))
                        {
                            var signerStatus = recipient.SignerStatus != null && recipient.SignerStatus.Count() > 0 ? recipient.SignerStatus.OrderByDescending(a => a.CreatedDateTime).FirstOrDefault(s => s.RejectionRemarks != null) : null;
                            if (signerStatus != null)
                            {
                                var declineTemplateSetting = JsonConvert.DeserializeObject<List<DeclineTemplateResponses>>(signerStatus.RejectionRemarks);
                                if (declineTemplateSetting != null)
                                {
                                    if (declineTemplateSetting.Count > 0)
                                    {
                                        foreach (var item in declineTemplateSetting)
                                            declineReasons = declineReasons + item.ResponseText + ",";
                                        declineReasons = declineReasons.Remove(declineReasons.Length - 1);
                                    }
                                }
                            }
                        }
                    }
                }

                using (var dbContext = new RSignDbContext(_configuration))
                {
                    var xmlDocument = new XDocument(
                    new XDeclaration("1.0", "utf-8", "yes"),
                    new XElement("Envelope", new XAttribute("id", sessionEnvelope.ID), new XAttribute("EnvelopeCode", sessionEnvelope.EDisplayCode)
                , new XElement("EnvelopeStatus", status)
                , new XElement("DeclineReason", declineReasons)
                , new XElement("TemplateCode", templateCodes)
                , new XElement("ReferenceCode", sessionEnvelope.ReferenceCode ?? string.Empty)
                , new XElement("ReferenceEmail", sessionEnvelope.ReferenceEmail ?? string.Empty),
                 (from recpt in sessionEnvelope.Recipients.OrderBy(d => d.CreatedDateTime)
                  select new
                  {
                      recpt.ID,
                      recpt.Name,
                      recpt.EmailAddress,
                      recpt.DeliveryMode,
                      recpt.CountryCode,
                      recpt.DialCode,
                      recpt.Mobile,
                      Description = ModelHelper.GetRecipientTypeName(Convert.ToString(recpt.RecipientTypeID).ToUpper())//recpt.RecipientType.Description
                  }).ToList().Select(rec =>
           new XElement("Recipients", new XAttribute("ID", rec.ID), new XAttribute("Name", rec.Name),
          new XAttribute("EmailAddress", (!string.IsNullOrEmpty(rec.EmailAddress) && rec.EmailAddress != "null") ? rec.EmailAddress : ""),
                new XAttribute("Type", rec.Description),
               new XAttribute("DeliveryMode", (rec.DeliveryMode == null || rec.DeliveryMode == 0) ? "" : Convert.ToString(rec.DeliveryMode)),
           new XAttribute("CountryCode", (rec.DeliveryMode == Constants.DeliveryModes.EmailSlashMobile || rec.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile
                                    || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmail || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile
                                    || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashEmail
                                    || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashMobile || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashNone) ? !string.IsNullOrEmpty(rec.CountryCode) ? rec.CountryCode : "" : ""),
             new XAttribute("DialCode", ((rec.DeliveryMode == Constants.DeliveryModes.EmailSlashMobile || rec.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile
                                    || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmail || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile
                                    || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashEmail
                                    || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashMobile || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashNone) && !string.IsNullOrEmpty(rec.Mobile)) ? !string.IsNullOrEmpty(rec.DialCode) ? rec.DialCode : "" : ""),
      new XAttribute("Mobile", (rec.DeliveryMode == Constants.DeliveryModes.EmailSlashMobile || rec.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile
                                    || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmail || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile
                                    || rec.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashEmail
                                    || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashMobile || rec.DeliveryMode == Constants.DeliveryModes.MobileSlashNone) ? !string.IsNullOrEmpty(rec.Mobile) ? rec.Mobile : "" : ""),
      new XAttribute("IPAddress", string.Empty))),
                 new XElement("Documents",
                         (from dcs in documents.OrderBy(d => d.Order)
                          select new
                          {
                              dcs.ID,
                              dcs.DocumentName,
                              dcs.DocumentContents
                          }).ToList().Select(doc =>
                             new XElement("Documents", new XAttribute("ID", doc.ID), new XAttribute("Name", doc.DocumentName),
                             new XElement("Controls",
                                          (from dc in doc.DocumentContents.Where(x => x.Documents.ID == doc.ID)
                                           select new
                                           {
                                               ID = dc.ID,
                                               Label = dc.Label,
                                               ControlValue = ((dc.ControlID != Constants.Control.DropDown || string.IsNullOrEmpty(dc.ControlValue)) ? dc.ControlValue :
                                               (dbContext.SelectControlOptions.Where(d => d.ID == new Guid(dc.ControlValue)).Select(s => s.OptionText).FirstOrDefault())),
                                               ControlName = string.IsNullOrEmpty(dc.ControlName) ? GetControlName(dc.ControlID == Constants.Control.NewInitials ? Constants.Control.Initials : dc.ControlID) : dc.ControlName,
                                               ControlHtmlID = !string.IsNullOrEmpty(dc.IntControlId) ? dc.IntControlId : dc.ControlHtmlID,
                                               Required = dc.Required,
                                               Height = dc.Height,
                                               Width = dc.Width,
                                               DocumentPageNo = dc.DocumentPageNo,
                                               XCoordinate = dc.XCoordinate,
                                               YCoordinate = dc.YCoordinate,
                                               ZCoordinate = dc.ZCoordinate,
                                               //TopIndex = dc.TopIndex,
                                               //LeftIndex = dc.LeftIndex,
                                               Documents = dc.Documents,
                                               RecipientName = string.IsNullOrEmpty(dc.RecipientName) ? sessionEnvelope.Recipients.Where(r => r.ID == dc.RecipientID).Select(s => s.Name).FirstOrDefault() : dc.RecipientName,
                                               RecipientEmailAddress = string.IsNullOrEmpty(dc.RecipientEmailAddress) ? sessionEnvelope.Recipients.Where(r => r.ID == dc.RecipientID).Select(s => s.EmailAddress).FirstOrDefault() : dc.RecipientEmailAddress,
                                               RecipientMobile = string.IsNullOrEmpty(dc.RecipientEmailAddress) ? sessionEnvelope.Recipients.Where(r => r.ID == dc.RecipientID).Select(s => !string.IsNullOrEmpty(s.Mobile) ? (s.DialCode + s.Mobile) : "").FirstOrDefault() : dc.RecipientEmailAddress,
                                               TemplateControl = dc.MappedTemplateControlID == null || dc.MappedTemplateControlID == Guid.Empty ? string.Empty : GetTemplateContentRole(dc.MappedTemplateControlID, dbContext),
                                               OriginalControlValue = dc.OriginalControlValue
                                           }).ToList()
                                             .Select(
                                                 ctn =>
                                                       new XElement(
                                                         "Control",
                                                          new XAttribute("ID", ctn.ID),
                                                          new XAttribute("Name", ctn.ControlName ?? string.Empty),
                                                          new XAttribute("ControlHtmlID", ctn.ControlHtmlID ?? string.Empty),
                                                          new XAttribute("label", ctn.Label ?? string.Empty),
                                                          new XAttribute("text", ctn.ControlValue ?? string.Empty),
                                                          new XAttribute("OriginalValue", ctn.OriginalControlValue ?? string.Empty),
                                                          new XAttribute("required", ctn.Required),
                                                          new XAttribute("Height", ctn.Height.GetValueOrDefault()),
                                                          new XAttribute("Width", ctn.Width.GetValueOrDefault()),
                                                          new XAttribute("PageNo", ctn.DocumentPageNo.GetValueOrDefault()),
                                                          new XAttribute("XCoordinate", ctn.XCoordinate.GetValueOrDefault()),
                                                          new XAttribute("YCoordinate", ctn.YCoordinate.GetValueOrDefault()),
                                                          new XAttribute("ZCoordinate", ctn.ZCoordinate.GetValueOrDefault()),
                                                          new XAttribute("TemplateControl", ctn.TemplateControl ?? string.Empty),
                                                         //new XAttribute("Top", ctn.TopIndex),
                                                         //new XAttribute("Left", ctn.LeftIndex),
                                                         new XElement("Signer", new XAttribute("Name", ctn.RecipientName ?? string.Empty),
                                                         new XAttribute("EmailAddress", (!string.IsNullOrEmpty(ctn.RecipientEmailAddress) && ctn.RecipientEmailAddress != "null") ? ctn.RecipientEmailAddress : string.Empty),
                                                         new XAttribute("Mobile", !string.IsNullOrEmpty(ctn.RecipientMobile) ? ctn.RecipientMobile : string.Empty))))))))));

                    sessionEnvelope.EnvelopeContent.Add(new EnvelopeContent
                    {
                        ID = newEnvelopeContectID,
                        EnvelopeID = sessionEnvelope.ID,
                        ContentXML = xmlDocument.ToString()
                    });

                    //SessionHelper.Set(SessionKey.Envelope, sessionEnvelope);
                    envelopeContent = new EnvelopeContent
                    {
                        ID = newEnvelopeContectID,
                        EnvelopeID = sessionEnvelope.ID,
                        ContentXML = xmlDocument.ToString()
                    };
                    dbContext.SaveChanges();
                    return envelopeContent;
                }
            }
            catch (Exception ex)
            {
                //Elmah.ErrorSignal.FromCurrentContext().Raise(ex);
                throw;
            }
        }
