        public string GetTemplateContentRole(Guid? TemplateControlId, RSignDbContext dbContext)
        {
            string roleName = string.Empty;
            //using (var dbContext = new RSignDbContext(_configuration))
            //{
            try
            {
                var templateContent = dbContext.TemplateDocumentContents.FirstOrDefault(x => x.ID == TemplateControlId);
                if (templateContent == null)
                    return roleName;
                else
                {
                    roleName = (from e in dbContext.TemplateRoles where e.ID == templateContent.RecipientID select e.Name).FirstOrDefault();
                    roleName = roleName ?? string.Empty;
                    return templateContent.ControlHtmlID + "_" + roleName;
                }
            }
            catch (Exception ex)
            {
                return string.Empty;
            }
            //}
        }
        private Dictionary<List<byte[]>, List<string>> GetAttachmentByteArray(Envelope envelopeObject, string envelopeDirectoryPath, int intDtFormat = 0)
        {
            Dictionary<List<byte[]>, List<string>> myDictionary = new Dictionary<List<byte[]>, List<string>>();
            var attachements = new List<byte[]>();
            var attachedDocNames = new List<string>();
            var attachementsSigners = new List<byte[]>();
            var attachedDocNamesSigners = new List<string>();
            //var finalDocName = envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).First().DocumentName;
            //finalDocName = (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) ? "Contracts" : finalDocName.Substring(0, finalDocName.LastIndexOf('.'));

            var finalDocumentName = "";
            var finalDocName = envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).First().DocumentName;
            finalDocName = (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) ? "Contracts" : finalDocName.Substring(0, finalDocName.LastIndexOf('.'));

            if (envelopeObject.EnableMultipleNameCustomize == true && envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1)
            {
                finalDocumentName = UpdateFinalSignedDocumentNamingForMultipleDocuments(envelopeObject);
            }
            else
            {
                finalDocumentName = envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).First().DocumentName;
                finalDocumentName = (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) ? "Contracts" : finalDocumentName.Substring(0, finalDocumentName.LastIndexOf('.'));
            }

            string tempDirectoryPath = Path.GetDirectoryName(tempEnvelopeDir);

            var filereviewdirPath = envelopeDirectoryPath;
            string filereviewDocDirectory = filereviewdirPath + envelopeObject.ID;

            attachements.Add(System.IO.File.ReadAllBytes(finalPdfFilePath));
            //attachedDocNames.Add((envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) && envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? AppendDateTime(intDtFormat, finalDocName) + ".zip" : AppendDateTime(intDtFormat, finalDocName + ".pdf"));
            if (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() == 1)
            {
                attachedDocNames.Add(AppendDateTime(intDtFormat, finalDocumentName + ".pdf"));
            }
            else
            {
                attachedDocNames.Add(envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? finalDocumentName + ".zip" : finalDocumentName + ".pdf");
            }

            if (envelopeObject.IsWaterMark == true)
            {
                string finalPdfFilePathSigner = Path.GetDirectoryName(finalPdfFilePath);
                if (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1 && envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true)
                    finalPdfFilePathSigner = Path.Combine(finalPdfFilePathSigner, "ContractsSigner.zip");
                else
                    finalPdfFilePathSigner = Path.Combine(finalPdfFilePathSigner, "OutputSigner.Pdf");
                if (System.IO.File.Exists(finalPdfFilePathSigner))
                {
                    //attachementsSigners.Add(System.IO.File.ReadAllBytes(finalPdfFilePathSigner));
                    //attachedDocNamesSigners.Add((envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) && envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? AppendDateTime(intDtFormat, finalDocName) + ".zip" : AppendDateTime(intDtFormat, finalDocName + ".pdf"));

                    attachementsSigners.Add(System.IO.File.ReadAllBytes(finalPdfFilePathSigner));
                    //attachedDocNamesSigners.Add((envelopeObject.Documents.Where(d => d.ActionType == eSign.Core.Helpers.Constants.ActionTypes.Sign).Count() > 1) && envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? AppendDateTime(intDtFormat, finalDocumentName) + ".zip" : AppendDateTime(intDtFormat, finalDocumentName + ".pdf"));
                    if (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() == 1)
                    {
                        attachedDocNamesSigners.Add(AppendDateTime(intDtFormat, finalDocumentName + ".pdf"));
                    }
                    else if (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1 && envelopeObject.EnableMultipleNameCustomize == false)
                    {
                        attachedDocNamesSigners.Add(envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? AppendDateTime(intDtFormat, finalDocumentName) + ".zip" : AppendDateTime(intDtFormat, finalDocumentName + ".pdf"));
                        //attachedDocNamesSigners.Add((envelopeObject.Documents.Where(d => d.ActionType == eSign.Core.Helpers.Constants.ActionTypes.Sign).Count() > 1) && envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? finalDocumentName + ".zip" : finalDocumentName + ".pdf");

                    }
                    else if (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1 && envelopeObject.EnableMultipleNameCustomize == true)
                    {
                        attachedDocNamesSigners.Add(envelopeObject.IsSeparateMultipleDocumentsAfterSigningRequired == true ? finalDocumentName + ".zip" : finalDocumentName + ".pdf");
                    }
                }
            }
            if (envelopeObject.IsFinalCertificateReq == null || (envelopeObject.IsFinalCertificateReq != null && !envelopeObject.IsFinalCertificateReq.Value))
            {
                var certificatepath = Path.Combine(tempEnvelopeDir, "ENV" + (envelopeObject.EDisplayCode).ToString(CultureInfo.InvariantCulture) + "_SigningCertificate.pdf");
                attachements.Add(System.IO.File.ReadAllBytes(certificatepath));
                string finalCertificateName = "Certificate-" + envelopeObject.EDisplayCode;
                attachedDocNames.Add(AppendDateTime(intDtFormat, finalCertificateName) + ".pdf");
                if (envelopeObject.IsWaterMark == true)
                {
                    attachementsSigners.Add(System.IO.File.ReadAllBytes(certificatepath));
                    attachedDocNamesSigners.Add(AppendDateTime(intDtFormat, finalCertificateName) + ".pdf");
                }
            }
            if (envelopeObject.IsTransparencyDocReq && !string.IsNullOrEmpty(finalTransperancyPath))
            {
                attachements.Add(System.IO.File.ReadAllBytes(finalTransperancyPath));
                var transperancyDocName = ((envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).Count() > 1) ? "Contracts_transparency" : finalDocName + "_transparency");
                attachedDocNames.Add(AppendDateTime(intDtFormat, transperancyDocName + ".pdf"));
            }
            if (envelopeObject.IsSignerAttachFileReq > 0 && !string.IsNullOrEmpty(finalSignerAttachFilePath))
            {
                attachements.Add(File.ReadAllBytes(finalSignerAttachFilePath));
                attachedDocNames.Add(AppendDateTime(intDtFormat, Path.GetFileName(finalSignerAttachFilePath)));
                //******* SignerAttachment 
                attachementsSigners.Add(File.ReadAllBytes(finalSignerAttachFilePath));
                attachedDocNamesSigners.Add(AppendDateTime(intDtFormat, Path.GetFileName(finalSignerAttachFilePath)));
            }
            if (envelopeObject.IsAttachXML == true && !string.IsNullOrEmpty(xmlFilePath))
            {
                attachements.Add(File.ReadAllBytes(xmlFilePath));
                attachedDocNames.Add(AppendDateTime(intDtFormat, "Envelope.xml"));
            }

            if (envelopeObject.IsEnableFileReview == true && envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).Count() > 0)
            {
                var fileReviewDocName = envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).FirstOrDefault().DocumentName;
                var fileReviewDocFullName = envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).FirstOrDefault().DocumentName;
                fileReviewDocName = (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).Count() > 1) ? Regex.Replace(envelopeObject.Subject, "[\\\\/:*?\"<>|]", "") : fileReviewDocName.Substring(0, fileReviewDocName.LastIndexOf('.'));
                fileReviewDocName = fileReviewDocName.Length > 150 ? fileReviewDocName.Substring(0, 150) : fileReviewDocName;
                if (envelopeObject.Documents.Where(d => d.ActionType == Constants.ActionTypes.Review).Count() > 1)
                    fileDocReviewPath = Path.Combine(filereviewDocDirectory, fileReviewDocName + ".zip");
                else
                    fileDocReviewPath = Path.Combine(filereviewDocDirectory + "\\" + Convert.ToString(_appConfiguration["UploadedDocuments"]), fileReviewDocFullName);

                attachements.Add(File.ReadAllBytes(fileDocReviewPath));
                attachedDocNames.Add(AppendDateTime(intDtFormat, fileDocReviewPath));
            }

            myDictionary.Add(attachements, attachedDocNames);
            arrayDocumentsSigners.Add(attachementsSigners, attachedDocNamesSigners);

            return myDictionary;
        }
        public EnvelopeInfo GetSignerLandingStaticTemplateInfo(Guid templateID, Template envelope)
        {
            string currentMethod = "GetSignerLandingStaticTemplateInfo";
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "GetSignerLandingStaticTemplateInfo", "Process started for Get Signer Landing Static Template Info", templateID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                EnvelopeInfo controlsInfo = new EnvelopeInfo();
                // Put Document images information in session variable
                string templateFolderNasPath = _modelHelper.GetTemplateDirectory(templateID, string.Empty);
                string imagesPath = _eSignHelper.GetImagesFolderPath(templateID, templateFolderNasPath);
                Dictionary<Guid, string> envelopeDocumentsByOrder = new Dictionary<Guid, string>();
                foreach (var doc in envelope.TemplateDocuments.OrderBy(o => o.Order).ThenBy(o => o.DocumentName))
                    envelopeDocumentsByOrder.Add(doc.ID, doc.DocumentName);
                //List<string> documentImageList;
                List<EnvelopeImageInformation> documentImageData = new List<EnvelopeImageInformation>();
                foreach (var doc in envelopeDocumentsByOrder)
                {
                    DirectoryInfo dirInfo = new DirectoryInfo(imagesPath);
                    var files = dirInfo.GetFiles(Path.GetFileNameWithoutExtension(doc.Value) + "_*.png")
                        .Where(item => Path.GetFileNameWithoutExtension(doc.Value) + "_" + Regex.Match(Path.GetFileNameWithoutExtension(item.ToString()), @"\d+$").Value == Path.GetFileNameWithoutExtension(item.ToString()))
                        .OrderBy(o => o.Name).Select(s => s.Name).ToList();
                    if (files.Count == 0)
                    {
                        files = dirInfo.GetFiles(Path.GetFileNameWithoutExtension(doc.Value) + "_*.jpg")
                            .Where(item => Path.GetFileNameWithoutExtension(doc.Value) + "_" + Regex.Match(Path.GetFileNameWithoutExtension(item.ToString()), @"\d+$").Value == Path.GetFileNameWithoutExtension(item.ToString()))
                            .OrderBy(o => o.Name).Select(s => s.Name).ToList();
                    }
                    documentImageData.AddRange(
                        files.Select(file =>
                        new EnvelopeImageInformation
                        {
                            Id = int.Parse(file.Substring(file.LastIndexOf('_') + 1, file.LastIndexOf('.') - 1 - file.LastIndexOf('_'))), //// Image real id
                            Document = GetDocumentInfo(file.Substring(0, file.LastIndexOf('_')), envelopeDocumentsByOrder),
                            Dimension = GetDimensions(Path.Combine(imagesPath, file)), ///changes done for unit test                              
                            ImagePath = Path.Combine(imagesPath, file).Replace(@"\", "/"),
                        }).OrderBy(order => order.Id).ToList());
                }
                if (documentImageData.Count > 0)
                {
                    var docName = documentImageData[0].Document.Name;
                    int docPageNo = 1;
                    int pageNo = 1;
                    foreach (var docInfo in documentImageData)
                    {
                        if (docInfo.Document.Name == docName)
                        {
                            docInfo.DocPageNo = docPageNo;
                            docInfo.PageNo = pageNo++;
                            docPageNo++;
                        }
                        else
                        {
                            docName = docInfo.Document.Name;
                            docPageNo = 1;
                            docInfo.DocPageNo = docPageNo;
                            docInfo.PageNo = pageNo++;
                            docPageNo++;
                        }
                    }
                }
                //lookupRepository = ServiceLocator.Current.Container.Resolve<ILookupRepository>();
                //genericRepository = ServiceLocator.Current.Container.Resolve<IGenericRepository>();

                var fonts = _lookupRepository.GetLookup(Lookup.Fonts).OrderBy(fn => fn.Value);
                Dictionary<string, string> resultFonts = fonts.ToDictionary(x => x.Key, x => x.Value);

                IEnumerable<int> fontSizes = _eSignHelper.GetFontSize().Select(x => x).ToList();

                controlsInfo = new EnvelopeInfo
                {
                    RecipientTypeId = Constants.RecipientType.Signer,
                    //SignersList = resultRecipients,
                    FontsList = resultFonts,
                    FontSizes = fontSizes,
                    EnvelopeImageCollection = documentImageData
                };
                //SessionHelper.Set(SessionKey.DocumentImages, documentImageData);              
                loggerModelNew.Message = "Process completed for Get Signer Landing Static Template Info and Successfully retrieve Envelope details for static template.";
                rsignlog.RSignLogInfo(loggerModelNew);
                return controlsInfo;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }

        }
