        public FileStream DownloadPDFOnSignDocument(Envelope envelope, string temporaryLocation, Guid recipientId)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "DownloadPDFOnSignDocument", "Process started for Download PDF On Sign Document", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                string envelopeId = Convert.ToString(envelope.ID);
                string previewDirectory = Path.Combine(temporaryLocation, Convert.ToString(envelopeId) + "\\Preview");
                // Check whether Preview diectory exists if not create new 
                if (!Directory.Exists(previewDirectory))
                {
                    Directory.CreateDirectory(previewDirectory);
                }
                // Directory path where all temp pdf files are generated 
                var allfiles = Directory.GetFiles(temporaryLocation + envelopeId + "\\Converted", "*.pdf");
                List<string> allFilesPaths = new List<string>();
                foreach (var envDoc in envelope.Documents.Where(d => d.ActionType == Constants.ActionTypes.Sign).OrderBy(doc => doc.Order).ToList())
                {
                    foreach (var fle in allfiles)
                    {
                        if (Path.GetFileNameWithoutExtension(fle) == Path.GetFileNameWithoutExtension(envDoc.DocumentName))
                        {
                            allFilesPaths.Add(fle);
                            break;
                        }
                    }
                }
                // Final path of single merged file after complete merging
                var mergePdfFilePath = _asposeHelper.MergepdfFiles(allFilesPaths, Path.Combine(previewDirectory, "previewDocument.pdf")) ?? allFilesPaths[0];

                // Final path where rendered pdf file will be saved
                var savePdfFinalPath = Path.Combine(previewDirectory, "previewDocument.pdf");
                List<DocumentControls> controls = new List<DocumentControls>();
                controls = GetDocumentControls(envelope, recipientId);

                var pageNumbers = controls.GroupBy(x => new { x.PageNo }).Select(x => x.Key.PageNo).ToList();
                string finalPdfPath = _asposeHelper.AddTextInPdf(mergePdfFilePath, savePdfFinalPath, controls, pageNumbers, Path.Combine(temporaryLocation, Convert.ToString(envelope.ID), "Images"), string.Empty, string.Empty, null, envelope.DateFormatID, Constants.HeaderFooterSettings.None, envelope.ElectronicSignIndicationOptionID != null ? envelope.ElectronicSignIndicationOptionID.Value : Constants.ElectronicSignIndicationOption.Disable, false);
                using (FileStream fs = new FileStream(finalPdfPath, FileMode.Open, FileAccess.ReadWrite))
                {
                    return fs;
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw;
            }
        }
        public bool SaveControlsDetailForFinishLater(Envelope envelope, List<DocumentContents> userControls, Recipients recipient, bool isBack)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SaveControlsDetailForFinishLater", "Process started for Save Controls Detail For Finish Later", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    var envelopeContentData = dbContext.EnvelopeContent.Where(t => t.EnvelopeID == envelope.ID).FirstOrDefault();
                    XDocument doc = null;
                    if (envelopeContentData != null)
                        doc = XDocument.Parse(envelopeContentData.ContentXML);
                    var documentContents = new List<DocumentContents>();
                    string userTimezone = string.Empty;
                    var settingUserTimezone = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.TimeZone);
                    if (settingUserTimezone != null)
                    {
                        userTimezone = settingUserTimezone.OptionValue.ToString();
                    }
                    string dateTimeStampControlValue = string.Empty;
                    if (envelope.DateFormatID != null)
                    {
                        dateTimeStampControlValue = GetDateTimeStampControlValue(envelope.DateFormatID, string.IsNullOrEmpty(userTimezone) ? "UTC" : userTimezone);
                    }
                    List<Guid> SameRecipientIds = envelope.Recipients.Where(a => a.EmailAddress == recipient.EmailAddress && a.ID != recipient.ID && a.IsSameRecipient == true).Select(a => a.ID).ToList();
                    //We require controls for current recipient.
                    foreach (Documents document in envelope.Documents)
                        documentContents.AddRange(document.DocumentContents.Where(d => d.RecipientID == recipient.ID || (SameRecipientIds.Count > 0 && d.RecipientID != null && d.RecipientID != Guid.Empty && SameRecipientIds.Contains(d.RecipientID.Value)) || d.RecipientID == null));
                    if (documentContents.Count == 0) //save only signature control value if no other control assign to signer                    
                        SaveSignature(userControls, documentContents, recipient.ID, recipient, string.Empty, envelope.ElectronicSignIndicationOptionID != null ? envelope.ElectronicSignIndicationOptionID.Value : 1);
                    else //save control to database
                        SaveControl(userControls, recipient.ID, recipient, doc, documentContents, false, string.Empty, envelope.ElectronicSignIndicationOptionID != null ? envelope.ElectronicSignIndicationOptionID.Value : 1, dateTimeStampControlValue);

                    if (!isBack)
                        _recipientRepository.ModifyLastRecipientEntry(recipient.ID, Constants.StatusCode.Signer.Finish_Later_Selected, envelope.IpAddress);
                }
                return true;
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - SaveControlsDetailForFinishLater method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                throw ex;
            }
        }
