        public Dictionary<string, string> ReplaceMailTemplateValue(Dictionary<string, string> mailTemplateForRecepientLogIn, string keyword, string keyvalue)
        {
            Dictionary<string, string> mailTemplateForRecepientLogInLatest = new Dictionary<string, string>();
            foreach (KeyValuePair<string, string> temp in mailTemplateForRecepientLogIn)
            {
                mailTemplateForRecepientLogInLatest[temp.Key] = temp.Value.Replace(keyword, keyvalue);
            }
            return mailTemplateForRecepientLogInLatest;
        }
        private string MailTemplateReplaceLabelContent(string mailTemplateSender, double fileSize, string languageCode, MailTemplateLabelSettings mailTemplateLabelSettings, Boolean isStatic = false)
        {
            List<LookupItem> mailTemplateKeys = new List<LookupItem>();
            mailTemplateKeys = GetMailTemplateKeysFromDB(languageCode);
            string HeaderName = string.Empty, docSizeKey = string.Empty, FinalContractContent = string.Empty, TransparencyContent = string.Empty, EnvelopeXMLContent = string.Empty, SignerAttachmentContent = string.Empty;

            if (fileSize > 20)
            {
                if (mailTemplateKeys != null && mailTemplateKeys.Count > 0)
                {
                    docSizeKey = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.DocumentSizeMsg).Select(a => a.Value).SingleOrDefault();
                    if (isStatic == false)
                    {
                        FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractContent).Select(a => a.Value).SingleOrDefault();
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.HeaderTemplate).Select(a => a.Value).SingleOrDefault();
                    }
                    else
                    {
                        FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractStaticDocContent).Select(a => a.Value).SingleOrDefault();
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.StaticHeaderTemplate).Select(a => a.Value).SingleOrDefault();
                    }
                    TransparencyContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.TransparencyContentNew).Select(a => a.Value).SingleOrDefault();
                    EnvelopeXMLContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.EnvelopeXMLContentNew).Select(a => a.Value).SingleOrDefault();
                    SignerAttachmentContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.SignerAttachmentContentNew).Select(a => a.Value).SingleOrDefault();
                }
                mailTemplateSender = mailTemplateSender.Replace("#HeaderName", HeaderName);
                mailTemplateSender = mailTemplateSender.Replace("#DocSizeMsg", docSizeKey);

                mailTemplateSender = mailTemplateSender.Replace("#LabelContentFC", FinalContractContent);
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentT", TransparencyContent);
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentXML", EnvelopeXMLContent);
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentSA", SignerAttachmentContent);
            }
            else
            {
                if (mailTemplateKeys != null && mailTemplateKeys.Count > 0)
                {
                    docSizeKey = string.Empty;
                    if (isStatic == false)
                    {
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.HeaderTemplate).Select(a => a.Value).SingleOrDefault();
                        FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractContentNew).Select(a => a.Value).SingleOrDefault();
                    }
                    else
                    {
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.StaticHeaderTemplate).Select(a => a.Value).SingleOrDefault();
                        FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractStaticDocContentNew).Select(a => a.Value).SingleOrDefault();
                    }
                    TransparencyContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.TransparencyContent).Select(a => a.Value).SingleOrDefault();
                    EnvelopeXMLContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.EnvelopeXMLContent).Select(a => a.Value).SingleOrDefault();
                    SignerAttachmentContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.SignerAttachmentContent).Select(a => a.Value).SingleOrDefault();
                }
                mailTemplateSender = mailTemplateSender.Replace("#HeaderName", HeaderName);
                mailTemplateSender = mailTemplateSender.Replace("#DocSizeMsg", docSizeKey);
                if (mailTemplateLabelSettings != null && (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                      || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                      || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn))
                {
                    FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractContent).Select(a => a.Value).SingleOrDefault();
                }
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentFC", FinalContractContent);
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentT", TransparencyContent);
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentXML", EnvelopeXMLContent);
                mailTemplateSender = mailTemplateSender.Replace("#LabelContentSA", SignerAttachmentContent);
            }

            mailTemplateLabelSettings.RecipientTypeId = mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.CC ? Constants.RecipientType.Signer : mailTemplateLabelSettings.RecipientTypeId;
            if (mailTemplateLabelSettings != null)
            {
                if (mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.Sender)
                {
                    if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        mailTemplateSender = mailTemplateSender.Replace("#URL", mailTemplateLabelSettings.RetrievalLink);
                    else
                    {
                        //mailTemplateSender = mailTemplateSender.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);

                        string strURLWithDataSigner = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
                        //strURLWithDataSigner += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}", mailTemplateLabelSettings.EnvelopeId.ToString(), mailTemplateLabelSettings.RecipientTypeId.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                        //13-12-2023
                        strURLWithDataSigner += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2},&CultureInfo={3}", mailTemplateLabelSettings.EnvelopeId.ToString(), mailTemplateLabelSettings.RecipientTypeId.ToString(), Convert.ToBoolean(mailTemplateLabelSettings.EnableMessageToMobile) ? "1" : "0", languageCode), Convert.ToString(_appConfiguration["AppKey"])));
                        //mailTemplateLabelSettings.UrlGetPdf = strURLWithDataSigner;
                        mailTemplateSender = mailTemplateSender.Replace("#URL", strURLWithDataSigner);
                    }
                }
                else if (mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.Signer)
                {
                    if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderSigner)
                        mailTemplateSender = mailTemplateSender.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);
                    else if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderOnly)
                        mailTemplateSender = mailTemplateSender.Replace("#URL", mailTemplateLabelSettings.RetrievalLink);
                }
                else
                    mailTemplateSender = mailTemplateSender.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);
            }
            else
                mailTemplateSender = mailTemplateSender.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);

            return mailTemplateSender;
        }
