        private string RecMailTemplateReplaceLabelContent(string mailTemplate, double fileSize, string languageCode, MailTemplateLabelSettings mailTemplateLabelSettings, Boolean isStatic = false)
        {
            List<LookupItem> mailTemplateKeys = new List<LookupItem>();
            mailTemplateKeys = GetMailTemplateKeysFromDB(languageCode);
            string HeaderName = string.Empty, docSizeKey = string.Empty, FinalContractContentN = string.Empty, FinalContractContent = string.Empty, SignerAttachmentContent = string.Empty;
            if (mailTemplateKeys != null && mailTemplateKeys.Count > 0)
            {
                docSizeKey = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.DocumentSizeMsg).Select(a => a.Value).SingleOrDefault();
                if (isStatic == false)
                {
                    if (mailTemplateLabelSettings.RecipientTypeIdCC == Constants.RecipientType.CC)
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.HeaderTemplateCC).Select(a => a.Value).SingleOrDefault();
                    else
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.HeaderTemplate).Select(a => a.Value).SingleOrDefault();
                    FinalContractContentN = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractContentNew).Select(a => a.Value).SingleOrDefault();
                    FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractContent).Select(a => a.Value).SingleOrDefault();
                }
                else
                {
                    if (mailTemplateLabelSettings.RecipientTypeIdCC == Constants.RecipientType.CC)
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.HeaderTemplateCC).Select(a => a.Value).SingleOrDefault();
                    else
                        HeaderName = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.StaticHeaderTemplate).Select(a => a.Value).SingleOrDefault();
                    FinalContractContentN = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractStaticDocContentNew).Select(a => a.Value).SingleOrDefault();
                    FinalContractContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.FinalContractStaticDocContent).Select(a => a.Value).SingleOrDefault();

                }
                SignerAttachmentContent = mailTemplateKeys.Where(a => a.Key == Constants.String.MailTemplateName.SignerAttachmentContentNew).Select(a => a.Value).SingleOrDefault();
            }
            mailTemplate = mailTemplate.Replace("#HeaderName", HeaderName);
            mailTemplate = mailTemplate.Replace("#LabelContentSA", SignerAttachmentContent);
            if ((fileSize > 20) || (mailTemplateLabelSettings != null && (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)))
            {
                mailTemplate = mailTemplate.Replace("#DocSizeMsg", fileSize < 20 ? "" : docSizeKey);
                mailTemplate = mailTemplate.Replace("#LabelContentFC", FinalContractContent);
            }
            else
            {
                mailTemplate = mailTemplate.Replace("#DocSizeMsg", "");
                mailTemplate = mailTemplate.Replace("#LabelContentFC", FinalContractContentN);
            }

            mailTemplateLabelSettings.RecipientTypeId = mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.CC ? Constants.RecipientType.Signer : mailTemplateLabelSettings.RecipientTypeId;
            if (mailTemplateLabelSettings != null)
            {
                if (mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.Sender)
                {
                    if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        mailTemplate = mailTemplate.Replace("#URL", mailTemplateLabelSettings.RetrievalLink);
                    else
                        mailTemplate = mailTemplate.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);
                }
                else if (mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.Signer)
                {
                    if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderSigner)
                    {
                        //modified by TParker
                        //if (mailTemplateLabelSettings.IsWatermark == true)
                        //{
                        string strURLWithDataSigner = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
                        //strURLWithDataSigner += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2}", mailTemplateLabelSettings.EnvelopeId.ToString(), mailTemplateLabelSettings.RecipientTypeId.ToString(), mailTemplateLabelSettings.EnableMessageToMobile), Convert.ToString(_appConfiguration["AppKey"])));
                        // 13-12-2023
                        strURLWithDataSigner += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2}&CultureInfo={3}", mailTemplateLabelSettings.EnvelopeId.ToString(), mailTemplateLabelSettings.RecipientTypeId.ToString(), mailTemplateLabelSettings.EnableMessageToMobile, languageCode), Convert.ToString(_appConfiguration["AppKey"])));
                        mailTemplate = mailTemplate.Replace("#URL", strURLWithDataSigner);

                        //}
                        //else
                        //  mailTemplate = mailTemplate.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);
                    }
                    else if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderOnly)
                    {
                        if (mailTemplateLabelSettings.IsWatermark == true)
                        {
                            string strRetrievalLink = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/ViewDocument?");
                            strRetrievalLink += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&currentStatus={1}&RecipientTypeId={2}", mailTemplateLabelSettings.EnvelopeId.ToString(), "0", mailTemplateLabelSettings.RecipientTypeId.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                            mailTemplate = mailTemplate.Replace("#URL", strRetrievalLink);
                        }
                        else
                            mailTemplate = mailTemplate.Replace("#URL", mailTemplateLabelSettings.RetrievalLink);
                    }
                }
                else
                    mailTemplate = mailTemplate.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);
            }
            else
                mailTemplate = mailTemplate.Replace("#URL", mailTemplateLabelSettings.UrlGetPdf);

            return mailTemplate;
        }
        private Dictionary<string, string> RecMailTemplateReplaceLabelContentNew(Dictionary<string, string> mailTemplateList, double fileSize, string languageCode, MailTemplateLabelSettings mailTemplateLabelSettings, Boolean isStatic = false)
