        private string RecMobileTemplateReplaceLabelContent(string mailTemplate, double fileSize, string languageCode, MailTemplateLabelSettings mailTemplateLabelSettings, Envelope envelopeObject, Boolean isStatic = false)
        {
            string urlToMakeShort = "";

            mailTemplateLabelSettings.RecipientTypeId = mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.CC ? Constants.RecipientType.Signer : mailTemplateLabelSettings.RecipientTypeId;
            if (mailTemplateLabelSettings != null)
            {
                if (mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.Sender)
                {
                    if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                         || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandNoemailtoRecipient
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderRetrievallinkandRecipientSignIn)
                        urlToMakeShort = mailTemplateLabelSettings.RetrievalLink;
                    else
                        urlToMakeShort = mailTemplateLabelSettings.UrlGetPdf;
                }
                else if (mailTemplateLabelSettings.RecipientTypeId == Constants.RecipientType.Signer)
                {
                    if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderSigner)
                    {
                        string strURLWithDataSigner = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/GetPDF?");
                        //strURLWithDataSigner += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2}", mailTemplateLabelSettings.EnvelopeId.ToString(), mailTemplateLabelSettings.RecipientTypeId.ToString(), mailTemplateLabelSettings.EnableMessageToMobile), Convert.ToString(_appConfiguration["AppKey"])));
                        strURLWithDataSigner += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&RecipientTypeId={1}&EnableMessageToMobile={2},&CultureInfo={3}", mailTemplateLabelSettings.EnvelopeId.ToString(), mailTemplateLabelSettings.RecipientTypeId.ToString(), Convert.ToBoolean(mailTemplateLabelSettings.EnableMessageToMobile) ? "1" : "0", languageCode), Convert.ToString(_appConfiguration["AppKey"])));
                        urlToMakeShort = strURLWithDataSigner;
                    }
                    else if (mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.RetrievalLink
                        || mailTemplateLabelSettings.AttachedPdfOption == Constants.AttachSignedPDF.SenderOnly)
                    {
                        if (mailTemplateLabelSettings.IsWatermark == true)
                        {
                            string strRetrievalLink = Path.Combine(Convert.ToString(_appConfiguration["DownloadAppUrl"]), "SignDocument/ViewDocument?");
                            strRetrievalLink += HttpUtility.UrlEncode(EncryptDecryptQueryString.Encrypt(string.Format("EnvelopeId={0}&currentStatus={1}&RecipientTypeId={2}", mailTemplateLabelSettings.EnvelopeId.ToString(), "0", mailTemplateLabelSettings.RecipientTypeId.ToString()), Convert.ToString(_appConfiguration["AppKey"])));
                            urlToMakeShort = strRetrievalLink;
                        }
                        else
                            urlToMakeShort = mailTemplateLabelSettings.RetrievalLink;
                    }
                }
                else
                    urlToMakeShort = mailTemplateLabelSettings.UrlGetPdf;
            }
            else
                urlToMakeShort = mailTemplateLabelSettings.UrlGetPdf;

            string md5ShortUriPasscode = _modelHelper.CalculateMD5HashForShortURL(urlToMakeShort).ToLower();
            string signingShortURL = Convert.ToString(_appConfiguration["SigningURL"]) + "Msg/Rs/" + md5ShortUriPasscode;
            SaveShortUrlForSMS(envelopeObject, urlToMakeShort, signingShortURL, md5ShortUriPasscode, false);
            mailTemplate = mailTemplate.Replace("#SigningShortURL", signingShortURL);
            return mailTemplate;
        }

