        public Guid GetEnvelopeStatus(Guid newEnvelopeID)
        {
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    return dbContext.Envelope.Where(e => e.ID == newEnvelopeID).FirstOrDefault().StatusID;
                }
            }
            catch (Exception)
            {
                return Guid.Empty;
            }
        }
        public List<SelectListItem> DropdownFiller(IEnumerable<LookupItem> lookUpitems)
        {
            try
            {
                List<SelectListItem> items = new List<SelectListItem>();
                foreach (var itm in lookUpitems)
                {
                    items.Add(new SelectListItem { Text = itm.Value, Value = itm.Key, Selected = false });
                }
                return items;
            }
            catch (Exception ex)
            {
                throw;
            }
        }
        public string AppendDateTime(int dtFormatId, string fileName, string ModifiedDatetime)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "AppendDateTime", "AppendDateTime for file process started:" + fileName.ToString(), "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            if (dtFormatId <= 1)
                return fileName;
            string extension = Path.GetExtension(fileName);
            fileName = Path.GetFileNameWithoutExtension(fileName);
            DateTime dateTime = new DateTime();
            string ModifiedDatetimeString = ModifiedDatetime;
            bool isDate = DateTime.TryParseExact(ModifiedDatetime, "MM/dd/yyyy", CultureInfo.InvariantCulture, DateTimeStyles.None, out dateTime);
            if (isDate == false)
                ModifiedDatetimeString = DateTime.Now.ToString("MM/dd/yyyy hh:mm:ss tt").Trim();
            try
            {
                switch (Convert.ToInt32(dtFormatId))
                {
                    case 2:
                        fileName = string.Format("{0}-{1}", fileName, DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("yyyy-MM-dd-HH-mm-ss"));
                        break;
                    case 3:
                        fileName = string.Format("{0}-{1}", fileName, DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"));
                        break;
                    case 4:
                        fileName = string.Format("{0}-{1}", fileName, DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("dd-MM-yyyy-HH-mm-ss"));
                        break;
                    case 5:
                        fileName = string.Format("{0}-{1}", DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("yyyy-MM-dd-HH-mm-ss"), fileName);
                        break;
                    case 6:
                        fileName = string.Format("{0}-{1}", DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"), fileName);
                        break;
                    case 7:
                        fileName = string.Format("{0}-{1}", DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("dd-MM-yyyy-HH-mm-ss"), fileName);
                        break;
                    case 8:
                        fileName = string.Format("{0}_{1}", fileName, DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("yyyy_MM_dd_HH_mm_ss"));
                        break;
                    case 9:
                        fileName = string.Format("{0}_{1}", fileName, DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("MM_dd_yyyy_HH_mm_ss"));
                        break;
                    case 10:
                        fileName = string.Format("{0}_{1}", fileName, DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("dd_MM_yyyy_HH_mm_ss"));
                        break;
                    case 11:
                        fileName = string.Format("{0}_{1}", DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("yyyy_MM_dd_HH_mm_ss"), fileName);
                        break;
                    case 12:
                        fileName = string.Format("{0}_{1}", DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"), fileName);
                        break;
                    case 13:
                        fileName = string.Format("{0}_{1}", DateTime.Parse(ModifiedDatetimeString.ToString(), CultureInfo.InvariantCulture).ToString("dd_MM_yyyy_HH_mm_ss"), fileName);
                        break;
                    case 14:
                        fileName = string.Format("{0}_{1}", fileName, DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MMM-yyyy-HH-mm-ss"));
                        break;
                    case 15:
                        fileName = string.Format("{0}_{1}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MMM-yyyy-HH-mm-ss"), fileName);
                        break;
                    default:
                        return fileName;
                }
                //TODO: Check extension contains "." or not?
                if (!string.IsNullOrEmpty(extension))
                    return fileName + extension;
                return fileName;
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }
