        public void SendEmailsFromChilKet(EmailQueueProcessor.EmailQueueData emailQueueData, int emailRunningProcessCount = 0, int EmailQueueID = 0, EmailQueueProcessor.EmailQueueAttachmentData emailQueueAttachmentData = null)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SendEmailsFromChilKet", "Process started for Send Emails From ChilKet", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            try
            {
                var Chilkat = new ChilkatHelper(_appConfiguration);
                if (emailRunningProcessCount == 2)
                {
                    if (EmailQueueID != 0)
                    {
                        using (var dbContext = new RSignDbContext(_configuration))
                        {
                            var emailQueuereceipientsToDelete = dbContext.EmailQueueRecipients.FirstOrDefault(r => r.EmailQueueId == EmailQueueID);
                            if (emailQueuereceipientsToDelete != null)
                                dbContext.EmailQueueRecipients.Remove(emailQueuereceipientsToDelete);
                        }
                    }
                    if (emailQueueAttachmentData == null)
                    {
                        Chilkat.SendMailUsingChilKet(new string[] { emailQueueData.emailSendInfo != null ? emailQueueData.emailSendInfo.RecipientEmail : emailQueueData.SanboxSigner.RecipientEmail }, new string[] { emailQueueData.emailSendInfo != null ? emailQueueData.emailSendInfo.RecipientName : emailQueueData.SanboxSigner.RecipientName },
                                           null, null,
                                           null, null,
                                           emailQueueData.SenderEmailAddress.ToString(), emailQueueData.SenderName.ToString(), emailQueueData.EmailSubject, emailQueueData.MailMessageBody, null, null, emailQueueData.envelope.EDisplayCode, Constants.String.EmailOperation.SeviceEmailFail, 1);

                    }
                    else
                    {
                        Chilkat.SendMailUsingChilKet(new string[] { emailQueueData.emailSendInfo != null ? emailQueueData.emailSendInfo.RecipientEmail : emailQueueData.SanboxSigner.RecipientEmail }, new string[] { emailQueueData.emailSendInfo != null ? emailQueueData.emailSendInfo.RecipientName : emailQueueData.SanboxSigner.RecipientName },
                                           null, null,
                                           null, null,
                                           emailQueueData.SenderEmailAddress.ToString(), emailQueueData.SenderName.ToString(), emailQueueData.EmailSubject, emailQueueData.MailMessageBody, emailQueueAttachmentData.AttachmentData, emailQueueAttachmentData.AttachmentNamesInfo, emailQueueData.envelope.EDisplayCode, Constants.String.EmailOperation.SeviceEmailFail, 1);

                    }

                }
                else if (emailRunningProcessCount == 3)
                {
                    if (EmailQueueID != 0)
                    {
                        using (var dbContext = new RSignDbContext(_configuration))
                        {
                            var emailQueuereceipientsToDelete = dbContext.EmailQueueRecipients.FirstOrDefault(r => r.ID == EmailQueueID);
                            if (emailQueuereceipientsToDelete != null)
                                dbContext.EmailQueueRecipients.Remove(emailQueuereceipientsToDelete);

                            var emailAttachments = dbContext.EmailQueueAttachment.Where(r => r.EmailQueueId == EmailQueueID).ToList();
                            if (emailAttachments != null && emailAttachments.Count > 0)
                            {
                                foreach (EmailQueueAttachment attachment in emailAttachments)
                                {
                                    var EmailQueueAttachmentToDelete = dbContext.EmailQueueAttachment.FirstOrDefault(r => r.AttachmentId == attachment.AttachmentId);
                                    if (emailQueuereceipientsToDelete != null)
                                        dbContext.EmailQueueAttachment.Remove(EmailQueueAttachmentToDelete);
                                }
                            }
                        }
                    }

                    Chilkat.SendMailUsingChilKet(new string[] { emailQueueData.emailSendInfo != null ? emailQueueData.emailSendInfo.RecipientEmail : emailQueueData.SanboxSigner.RecipientEmail }, new string[] { emailQueueData.emailSendInfo != null ? emailQueueData.emailSendInfo.RecipientName : emailQueueData.SanboxSigner.RecipientName },
                                            null, null,
                                            null, null,
                                            emailQueueData.SenderEmailAddress.ToString(), emailQueueData.SenderName.ToString(), emailQueueData.EmailSubject, emailQueueData.MailMessageBody, emailQueueAttachmentData.AttachmentData, emailQueueAttachmentData.AttachmentNamesInfo, emailQueueData.envelope.EDisplayCode, Constants.String.EmailOperation.SeviceEmailFail, 1);

                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain- SendEmailsFromChilKet method and:" + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
                SendEmailsFromChilKet(emailQueueData, emailRunningProcessCount, EmailQueueID, emailQueueAttachmentData);
            }
        }
