        public void SaveSignature(IEnumerable<DocumentContents> documentContentDetail, List<DocumentContents> contents, Guid recipientId, Recipients recipientDetail, string certificateSignature = "", int electronicStampRequired = 1)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SaveSignature", "Process is started for Save Signature", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    bool signadded = false;
                    if (documentContentDetail != null)
                    {
                        if (documentContentDetail.Any(dc => dc.ControlName == Constants.String.SignatureControlName && dc.ID == Guid.Empty && !string.IsNullOrEmpty(dc.ControlValue)
                        && (dc.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || dc.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || dc.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())))
                        {
                            var documentContent = documentContentDetail.FirstOrDefault(dc => dc.ControlName == Constants.String.SignatureControlName && dc.ID == Guid.Empty);
                            string signValue = documentContent.ControlValue;
                            signValue = signValue.Replace("data:image/png;base64,", string.Empty);
                            if (IsBase64(signValue))
                            {
                                byte[] signByte = Convert.FromBase64String(signValue);
                                // signature stored in new table 
                                var signerSignature = new SignerSignature
                                {
                                    ID = Guid.NewGuid(),
                                    RecipientID = recipientId,
                                    Signature = signByte,
                                    SignatureTypeId = Guid.Parse(documentContent.ControlHtmlID)
                                };
                                _recipientRepository.Save(signerSignature);
                                UserProfile userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);
                                if (userProfile != null)
                                {
                                    if (signerSignature.Signature != null && electronicStampRequired <= 1)
                                    {
                                        userProfile.SignatureImage = signerSignature.Signature;
                                        userProfile.SignatureTypeID = signerSignature.SignatureTypeId;
                                        if (Guid.Parse(userProfile.SignatureTypeID.ToString().ToLower()) == Guid.Parse(Constants.SignatureType.Auto.ToString().ToLower()))
                                        {
                                            userProfile.SignatureText = documentContent.SignatureString;
                                            userProfile.FontClass = documentContent.SignatureFont;
                                        }
                                        else
                                        {
                                            userProfile.SignatureText = null;
                                            userProfile.FontClass = null;
                                        }
                                        _userRepository.Save(userProfile);
                                    }
                                }
                            }
                        }
                        else
                        {
                            foreach (var documentContent in documentContentDetail.Where(dc => dc.ControlName == Constants.String.SignatureControlName && dc.ID != Guid.Empty && !string.IsNullOrEmpty(dc.ControlValue)))
                            {
                                var content = contents.Where(dc => dc.ID == documentContent.ID && dc.RecipientID != null && dc.RecipientID != Guid.Empty && dc.ControlID == Constants.Control.Signature);
                                if (documentContent.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || documentContent.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || documentContent.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())
                                    if (documentContent.ControlValue.StartsWith("data:image/png;base64") && content != null && !signadded)
                                    {
                                        signadded = true;
                                        string signValue = documentContent.ControlValue;
                                        signValue = signValue.Replace("data:image/png;base64,", string.Empty);
                                        byte[] signByte = Convert.FromBase64String(signValue);
                                        // signature stored in new table 
                                        var signerSignature = new SignerSignature
                                        {
                                            ID = Guid.NewGuid(),
                                            RecipientID = recipientId,
                                            Signature = signByte,
                                            SignatureTypeId = Guid.Parse(documentContent.ControlHtmlID)
                                        };
                                        _recipientRepository.Save(signerSignature);
                                        UserProfile userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);
                                        if (userProfile != null)
                                        {
                                            //documentContent.Required
                                            if (signerSignature.Signature != null && electronicStampRequired <= 1)
                                            {
                                                userProfile.SignatureImage = signerSignature.Signature;
                                                userProfile.SignatureTypeID = signerSignature.SignatureTypeId;
                                                if (Guid.Parse(userProfile.SignatureTypeID.ToString().ToLower()) == Guid.Parse(Constants.SignatureType.Auto.ToString().ToLower()))
                                                {
                                                    userProfile.SignatureText = documentContent.SignatureString;
                                                    userProfile.FontClass = documentContent.SignatureFont;
                                                }
                                                else
                                                {
                                                    userProfile.SignatureText = null;
                                                    userProfile.FontClass = null;
                                                }
                                                _userRepository.Save(userProfile);
                                            }
                                        }
                                    }
                            }
                        }
                    }
                }
                loggerModelNew.Message = "Process completed for Save Signature";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - SaveSignature method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
        }
        public bool IsBase64(string base64String)
        {
            if (string.IsNullOrEmpty(base64String) || base64String.Length % 4 != 0
               || base64String.Contains(" ") || base64String.Contains("\t") || base64String.Contains("\r") || base64String.Contains("\n"))
                return false;
            try
            {
                Convert.FromBase64String(base64String);
                return true;
            }
            catch (Exception exception)
            {
                // Handle the exception
            }
            return false;
        }
        public void SaveControl(List<DocumentContents> documentContentDetail, Guid recipientId, Recipients recipientDetail, XDocument doc, List<DocumentContents> documentContents, bool isSignProcess, string certificateSignature = "", int electronicStampRequired = 1, string timeStampControlValue = "")
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "SaveControl", "Process is started for Save Control", "", "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            try
            {
                using (var dbContext = new RSignDbContext(_configuration))
                {
                    if (isSignProcess)
                    {
                        SaveSignature(documentContentDetail, documentContents, recipientId, recipientDetail, certificateSignature, electronicStampRequired);
                    }
                    foreach (var documentContent in documentContents.Where(r => r.IsControlDeleted == false))
                    {
                        if (documentContentDetail != null)
                        {
                            var documentContentWithValue = documentContentDetail.FirstOrDefault(d => d.ID == documentContent.ID);
                            if (documentContentWithValue != null)
                            {
                                documentContentWithValue.OriginalControlValue = string.IsNullOrEmpty(documentContent.OriginalControlValue) ? documentContent.ControlValue : documentContent.OriginalControlValue;
                                documentContentWithValue.LastModifiedBy = recipientDetail.EmailAddress;
                            }
                            if (documentContentWithValue != null)
                            {
                                if (documentContentWithValue.ControlHtmlID == Constants.SignatureType.Auto.ToString().ToUpper() || documentContentWithValue.ControlHtmlID == Constants.SignatureType.Hand.ToString().ToUpper() || documentContentWithValue.ControlHtmlID == Constants.SignatureType.UploadSignature.ToString().ToUpper())
                                {
                                    if (documentContentWithValue.ControlValue != null && !documentContentWithValue.ControlValue.StartsWith("/Content/NewTheme/img/signature"))
                                    {
                                        string signValue = documentContentWithValue.ControlValue;
                                        signValue = signValue.Replace("data:image/png;base64,", string.Empty);
                                        byte[] signByte = Convert.FromBase64String(signValue);
                                        documentContentWithValue.SignatureControlValue = signByte;
                                        documentContentWithValue.ControlValue = "Signed";
                                    }
                                }
                                else
                                {
                                    Guid controlId = documentContent.ControlID;
                                    UserProfile userProfile = _userRepository.GetUserProfileByEmailID(recipientDetail.EmailAddress);
                                    if (controlId == Constants.Control.Company && isSignProcess)
                                    {
                                        if (userProfile != null)
                                        {
                                            userProfile.Company = documentContentWithValue.ControlValue;
                                            _userRepository.Save(userProfile);
                                        }
                                        else
                                        {
                                            NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            if (nonRpostuser != null)
                                            {
                                                nonRpostuser.Company = documentContentWithValue.ControlValue;
                                                _userRepository.Save(nonRpostuser);
                                            }
                                        }
                                    }
                                    else if (controlId == Constants.Control.Title && isSignProcess)
                                    {
                                        if (userProfile != null)
                                        {
                                            userProfile.Title = documentContentWithValue.ControlValue;
                                            _userRepository.Save(userProfile);
                                        }
                                        else
                                        {
                                            NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            if (nonRpostuser != null)
                                            {
                                                nonRpostuser.Title = documentContentWithValue.ControlValue;
                                                _userRepository.Save(nonRpostuser);
                                            }
                                        }
                                    }
                                    else if (controlId == Constants.Control.Initials && isSignProcess)
                                    {
                                        if (userProfile != null)
                                        {
                                            userProfile.Initials = documentContentWithValue.ControlValue;
                                            if (!IsUnitTestApp)
                                                _userRepository.Save(userProfile);
                                        }
                                        else
                                        {
                                            NonRpostUser nonRpostuser = _userRepository.GetNonRpostUser(recipientDetail.EmailAddress);
                                            if (nonRpostuser != null)
                                            {
                                                nonRpostuser.Initials = documentContentWithValue.ControlValue;
                                                _userRepository.Save(nonRpostuser);
                                            }
                                        }
                                    }
                                }
                                if (doc != null)
                                {
                                    var controlElement = doc.Element("Envelope").Elements("Documents")
                                                        .Elements("Documents").FirstOrDefault(m => m.Attribute("ID").Value == documentContent.DocumentID.ToString())
                                             .Elements("Controls").Elements("Control").Where(s => s.Attribute("ID").Value == documentContentWithValue.ID.ToString());
                                    if (documentContentWithValue.ControlValue != null)
                                    {
                                        if (documentContentWithValue.ControlName == "DateTimeStamp" && !string.IsNullOrEmpty(timeStampControlValue))
                                        {
                                            documentContentWithValue.ControlValue = timeStampControlValue;
                                        }
                                        if (controlElement.FirstOrDefault() != null && controlElement.FirstOrDefault().Attribute("text") != null)
                                            controlElement.FirstOrDefault().Attribute("text").Value = (documentContent.ControlID == Constants.Control.DropDown) ? !string.IsNullOrEmpty(documentContentWithValue.ControlValue) ? documentContent.SelectControlOptions.Where(d => d.ID == Guid.Parse(documentContentWithValue.ControlValue)).Select(d => d.OptionText).FirstOrDefault() : documentContentWithValue.ControlValue : documentContentWithValue.ControlValue;// documentContentWithValue.ControlValue;
                                    }
                                }

                                if (!IsUnitTestApp)
                                    _documentContentsRepository.Save(documentContentWithValue);
                                if (!IsUnitTestApp)
                                    dbContext.SaveChanges();
                            }
                            else //if dependency control is not checked the don't show dependecy controls in final signed document
                            {
                                //if it is dependent control then only set ControlValue = null;
                                //Dependent controls we found based on "data-parent-id"  from documentContents -- These are coming from DB
                                string dataControlHtmlData = (documentContent.ControlHtmlData);
                                int topIndex = dataControlHtmlData.IndexOf("data-parent-id");
                                string parentValue = string.Empty;
                                if (topIndex > 0 && documentContent.IsReadOnly != true)
                                {
                                    documentContent.ControlValue = null;
                                    if (!IsUnitTestApp)
                                        _documentContentsRepository.Save(documentContent);
                                    if (!IsUnitTestApp)
                                        dbContext.SaveChanges();
                                }
                            }
                        }
                    }
                }
                loggerModelNew.Message = "Process completed for Save Control";
                rsignlog.RSignLogInfo(loggerModelNew);
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Error occurred in EnvelopeHelperMain - SaveControl method and " + ex.Message;
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
        }
        public string TakeUniqueDisplayCodeForRecipient()
        {
            //string uniqueId = string.Empty;
            //return uniqueId = "SEC" + GetRandomNumber(8) + "-" + GetRandomNumber(4) + "-" + GetRandomUpperCaseLetters(4) + "-" + GetRandomNumber(4) + "-" + GetRandomUpperCaseLetters(4);
            int length = 16;
            string allowedChars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789";

            if (string.IsNullOrEmpty(allowedChars)) throw new ArgumentException("allowedChars may not be empty.");

            const int byteSize = 0x100;
            var allowedCharSet = new HashSet<char>(allowedChars).ToArray();
            if (byteSize < allowedCharSet.Length) throw new ArgumentException(String.Format("allowedChars may contain no more than {0} characters.", byteSize));

            // Guid.NewGuid and System.Random are not particularly random. By using a
            // cryptographically-secure random number generator, the caller is always
            // protected, regardless of use.
            using (var rng = System.Security.Cryptography.RandomNumberGenerator.Create())
            {
                var result = new StringBuilder();
                var buf = new byte[128];
                while (result.Length < length)
                {
                    rng.GetBytes(buf);
                    for (var i = 0; i < buf.Length && result.Length < length; ++i)
                    {
                        // Divide the byte into allowedCharSet-sized groups. If the
                        // random value falls into the last group and the last group is
                        // too small to choose from the entire allowedCharSet, ignore
                        // the value in order to avoid biasing the result.
                        var outOfRangeStart = byteSize - (byteSize % allowedCharSet.Length);
                        if (outOfRangeStart <= buf[i]) continue;
                        result.Append(allowedCharSet[buf[i] % allowedCharSet.Length]);
                    }
                }
                if (IsRecipientCodeExist(result.ToString()))
                {
                    return TakeUniqueDisplayCodeForRecipient();
                }
                else
                {
                    return result.ToString();
                }
            }
        }
        public bool IsRecipientCodeExist(string recipientCode)
        {
            using (var dbContext = new RSignDbContext(_configuration))
            {
                return dbContext.Recipients.Where(rc => rc.RecipientCode == recipientCode).Count() > 0;
            }
        }
        public string EncryptQueryString(string strQueryString)
        {
            return EncryptDecryptQueryString.Encrypt(strQueryString, Convert.ToString(_appConfiguration["QueryStringKey"]));
        }
        public static string TakeUniqueDisplayCode()
        {
            string uniqueId = string.Empty;
            return uniqueId = GetRandomNumber(8) + "-" + GetRandomNumber(4) + "-" + GetRandomUpperCaseLetters(4) + "-" + GetRandomNumber(4) + "-" + GetRandomUpperCaseLetters(4);
        }
        public static string GetRandomNumber(int CodeLength)
        {
            string chars = Guid.NewGuid().ToString(); //"ABCDEFGHIJKLMNOPQRSTUVWXYZABCDEFGHIJKLMNOPQRSTUVWXYZ";
            chars = Regex.Replace(chars, @"[^\d]", string.Empty);
            chars = (string.IsNullOrEmpty(chars) || chars.Length < CodeLength) ? GetRandomNumber(CodeLength) : chars.Substring(0, CodeLength);
            return chars;
        }
        public static string GetRandomUpperCaseLetters(int length)
        {
            string chars = Guid.NewGuid().ToString(); //"ABCDEFGHIJKLMNOPQRSTUVWXYZABCDEFGHIJKLMNOPQRSTUVWXYZ";
            chars = Regex.Replace(chars, @"[\d-]", string.Empty);
            chars = (string.IsNullOrEmpty(chars) || chars.Length < length) ? GetRandomUpperCaseLetters(length) : chars.Substring(0, length).ToUpper();
            return chars;
        }
