        public bool CheckAndCompleteGroupEnvelope(Envelope envelope, Guid recipientId)
        {
            loggerModelNew = new LoggerModelNew("", "EnvelopeHelperMain", "CheckAndCompleteGroupEnvelope", "Process started for Check And Complete Group Envelope", envelope.ID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);

            if (IsEnvelopeComplete(envelope.Recipients.ToList(), recipientId))
            {
                UpdateEnvelopeStatus(envelope, Constants.StatusCode.Envelope.Completed);

                //--- Update envelopeContent table
                var envelopeContentData = GetEnvelopeContent(envelope.ID);
                XDocument doc = XDocument.Parse(envelopeContentData.ContentXML);
                if (doc != null)
                {
                    var envelopeStatusElement = doc.Element("Envelope").Elements("EnvelopeStatus").FirstOrDefault();
                    if (envelopeStatusElement != null)
                        envelopeStatusElement.Value = "Completed";
                    envelopeContentData.ContentXML = doc.ToString();
                    SaveEnvelopeContentData(envelopeContentData);
                }

                loggerModelNew.Message = "Envelope Completed for envelope id = " + envelope.ID;
                rsignlog.RSignLogInfo(loggerModelNew);

                //Update- To get envelope completed notification event.
                var senderDetails = _recipientRepository.GetSenderDetails(envelope.ID);
                _genericRepository.UpdateEnvelopeCommonWebhookTransaction(envelope, Constants.WebhookEventNames.EnvelopeCompleted, senderDetails.EmailAddress);

                if (envelope.Recipients.Where(r => r.CCSignerType == Constants.CCRecipientType.NotificationsOnly && r.RecipientTypeID == Constants.RecipientType.CC).Count() > 0)
                {
                    int SignReqReplyToAddressValue = 1;
                    var replyTosettingsDetails = _settingsRepository.GetEntityForByKeyConfig(envelope.UserID, Constants.SettingsKeyConfig.SignatureRequestReplyAddress);
                    if (replyTosettingsDetails != null)
                        SignReqReplyToAddressValue = Convert.ToInt32(replyTosettingsDetails.OptionValue);
                }

                if (!Convert.ToBoolean(_appConfiguration["IsSignedDocumentService"]))
                {
                    return GenerateRSignDocuments(envelope.ID);
                }
                else
                {
                    var envelopeContractStatus = new EnvelopeContractStatus
                    {
                        Id = envelope.ID,
                        Status = 1,
                        ServerName = System.Environment.MachineName,
                        CreatedDateTime = DateTime.Now
                    };
                    using (var dbContext = new RSignDbContext(_configuration))
                    {
                        dbContext.EnvelopeContractStatus.Add(envelopeContractStatus);
                        dbContext.SaveChanges();
                    }
                }
            }
            loggerModelNew.Message = "Process completed for Check And Complete Group Envelope";
            rsignlog.RSignLogInfo(loggerModelNew);
            return true;
        }
