        public List<SettingsDetailsAdditionalValues> GetSettingDetailByUserId(Guid UserID)
        {
            loggerModelNew = new LoggerModelNew("", "GetSettingDetailByUserId", "GetSettingDetailByUserId", "Get SettingDetails By UserId", UserID.ToString(), "", "", "", "API");
            rsignlog.RSignLogInfo(loggerModelNew);
            List<SettingsDetailsAdditionalValues> settingsDetails = new List<SettingsDetailsAdditionalValues>();
            try
            {
                SqlConnection connection = new SqlConnection(Convert.ToString(_configuration.Value.ConnectionStrings.RSignContext));
                DataSet dataset = new DataSet();
                SqlDataAdapter adapter = new SqlDataAdapter();
                adapter.SelectCommand = new SqlCommand("usp_GetSettingDetailByUserId", connection);
                adapter.SelectCommand.CommandType = CommandType.StoredProcedure;
                adapter.SelectCommand.Parameters.AddWithValue("@UserId", UserID);
                adapter.Fill(dataset);

                if (dataset != null && dataset.Tables.Count > 0)
                {
                    settingsDetails = JsonConvert.DeserializeObject<List<SettingsDetailsAdditionalValues>>(JsonConvert.SerializeObject(dataset.Tables[0]));
                }
            }
            catch (Exception ex)
            {
                loggerModelNew.Message = "Retriving settingDetails failed.";
                rsignlog.RSignLogError(loggerModelNew, ex);
            }
            return settingsDetails;
        }
        public SettingsDetailsAdditionalValues GetSettingsDetailsByKeyConfig(Guid keyConfig, List<SettingsDetailsAdditionalValues> settingAdditionalDetails)
        {
            try
            {
                return settingAdditionalDetails.FirstOrDefault(f => f.KeyConfig == keyConfig);
            }
            catch (Exception ex)
            {
                return null;
                //throw ex;
            }
        }
        public void GetMobileDeiliveryModeOptions(Recipients signer, ref bool isEmailSend, ref bool isMobileSend)
        {
            //EmailSlashEmail = 1;
            //EmailSlashMobile = 2;
            //EmailSlashEmailAndMobile = 3;
            //MobileSlashMobile = 4;
            //MobileSlashEmail = 5;
            //MobileSlashNone = 6;
            //MobileSlashEmailAndMobile = 7;
            //EmailAndMobileSlashMobile = 8;
            //EmailAndMobileSlashEmail = 9;
            //EmailAndMobileSlashEmailAndMobile = 10;
            //EmailSlashNone = 11;
            //EmailAndMobileSlashNone = 12;
            if ((signer.DeliveryMode == Constants.DeliveryModes.EmailSlashEmail || signer.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile ||
                signer.DeliveryMode == Constants.DeliveryModes.MobileSlashEmail || signer.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile ||
                signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmail || signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile)
                && !string.IsNullOrEmpty(signer.EmailAddress))
            {
                isEmailSend = true;
            }

            if ((signer.DeliveryMode == Constants.DeliveryModes.EmailSlashMobile || signer.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile ||
                signer.DeliveryMode == Constants.DeliveryModes.MobileSlashMobile || signer.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile ||
                signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile || signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile)
                && !string.IsNullOrEmpty(signer.Mobile))
            {
                isMobileSend = true;
            }

            if (!isEmailSend && !isMobileSend)
            {
                if (signer.DeliveryMode != null && !string.IsNullOrEmpty(signer.EmailAddress) && signer.DeliveryMode == Constants.DeliveryModes.EmailSlashNone) { isEmailSend = true; }
                else if (signer.DeliveryMode != null && !string.IsNullOrEmpty(signer.Mobile) && signer.DeliveryMode == Constants.DeliveryModes.MobileSlashNone) { isMobileSend = true; }
                else if (signer.DeliveryMode != null && !string.IsNullOrEmpty(signer.EmailAddress) && !string.IsNullOrEmpty(signer.Mobile) && signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone) { isMobileSend = true; isEmailSend = true; }
            }
        }
        public void GetEmailDeiliveryModeOptions(Recipients signer, ref bool isEmailSend, ref bool isMobileSend)
        {
            if ((signer.DeliveryMode == Constants.DeliveryModes.EmailSlashEmail || signer.DeliveryMode == Constants.DeliveryModes.EmailSlashMobile ||
                   signer.DeliveryMode == Constants.DeliveryModes.EmailSlashEmailAndMobile ||
                   signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile || signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmail ||
                   signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile || signer.DeliveryMode == Constants.DeliveryModes.EmailSlashNone
                   || signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone) && !string.IsNullOrEmpty(signer.EmailAddress))
            {
                isEmailSend = true;
            }

            if ((signer.DeliveryMode == Constants.DeliveryModes.MobileSlashMobile || signer.DeliveryMode == Constants.DeliveryModes.MobileSlashEmail ||
                signer.DeliveryMode == Constants.DeliveryModes.MobileSlashNone || signer.DeliveryMode == Constants.DeliveryModes.MobileSlashEmailAndMobile ||
                signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashMobile || signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashEmailAndMobile ||
                signer.DeliveryMode == Constants.DeliveryModes.EmailAndMobileSlashNone) && !string.IsNullOrEmpty(signer.Mobile))
            {
                isMobileSend = true;
            }

            if (!isEmailSend && !isMobileSend)
            {
                if (signer.DeliveryMode != null && !string.IsNullOrEmpty(signer.EmailAddress)) { isEmailSend = true; }
                else if (signer.DeliveryMode != null && !string.IsNullOrEmpty(signer.Mobile)) { isMobileSend = true; }
            }
        }

        public bool GetIsPasswordMailToSigner(bool? enableMessageToMobile, Envelope envelope)
        {
            if (Convert.ToBoolean(enableMessageToMobile))
            {
                if (envelope.AccessAuthType != Constants.ConfigurationalProperties.PasswordType.Select) return true;
                else return false;
            }
            else
            {
                return Convert.ToBoolean(envelope.IsPasswordMailToSigner);
            }
        }
        public string AppendSignerDeliveryModeDetails(Recipients signerRecipient, string mailTemlate, string replaceTag, int isCopyAddress = 0)
        {
            signerRecipient.EmailAddress = isCopyAddress == 0 ? signerRecipient.EmailAddress : signerRecipient.CopyEmailAddress;

            string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(signerRecipient.DeliveryMode, signerRecipient.EmailAddress, signerRecipient.DialCode, signerRecipient.Mobile);
            mailTemlate = mailTemlate.Replace(replaceTag, emailMobileNumberDetails);

            return mailTemlate;
        }
        public string AppendCCUserEmailsList(List<Recipients> recipients, bool? enableMessageToMobile = false)
        {
            var htmlCodeCC = "<font face='calibri,sans-serif'font-size:11pt;color='#333333'>#CCName (<a style='color: blue; text-decoration: underline; text-underline: single' href='mailto:#CCEmailId'>#CCEmailId</a>)</font>";
            StringBuilder sbCC = new StringBuilder();
            if (recipients.Count > 0)
            {
                foreach (var ccRecipient in recipients)
                {
                    var tempHtmlCode = htmlCodeCC.Replace("'", "\"");
                    tempHtmlCode = tempHtmlCode.Replace("#CCName", ccRecipient.Name);

                    if (Convert.ToBoolean(enableMessageToMobile))
                    {
                        string emailMobileNumberDetails = _asposeHelper.AppendSignerEmailMobileDetails(ccRecipient.DeliveryMode, ccRecipient.EmailAddress, ccRecipient.DialCode, ccRecipient.Mobile);
                        tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", emailMobileNumberDetails);
                    }
                    else
                    {
                        tempHtmlCode = tempHtmlCode.Replace("#CCEmailId", ccRecipient.EmailAddress);
                    }

                    sbCC.Append(tempHtmlCode + ", ");
                }
            }

            return sbCC.ToString();
        }

        #region FinalSignedDocumentNamingForMultipleDocuments
        public string UpdateFinalSignedDocumentNamingForMultipleDocuments(Envelope envelopeObject)
        {
            var finalDocumentName = GenerateFinalSignedDocumentNamingForMultipleDocuments(envelopeObject);
            return finalDocumentName;
        }
        public string UpdateFinalSignedDocumentNamingForMultipleDocuments(Envelope envelopeObject, Guid companyId)
        {
            int renameFileTo = 1;
            int addPrefixToFileNameMode = 1;
            int dateTimeStampForMultipleDocSettingsForPrefix = 0;
            int dateTimeStampForMultipleDocSettingsForSufix = 0;
            int addSuffixFileToMode = 1;
            string prefixCustomName = "";
            string suffixCustomName = "";
            using (var dbContext = new RSignDbContext(_configuration))
            {
                var settingRenameFileTo = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.RenameFileToMode);
                if (settingRenameFileTo != null)
                    renameFileTo = Convert.ToInt32(settingRenameFileTo.OptionValue);

                var settingAddPrefixToFileNameMode = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.AddPrefixToFileNameMode);
                if (settingAddPrefixToFileNameMode != null)
                    addPrefixToFileNameMode = Convert.ToInt32(settingAddPrefixToFileNameMode.OptionValue);

                var settingDateTimeStampForMultipleDocSettingsForPrefix = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.DateTimeStampForMultipleDocSettingsForPrefix);
                if (settingDateTimeStampForMultipleDocSettingsForPrefix != null)
                    dateTimeStampForMultipleDocSettingsForPrefix = Convert.ToInt32(settingDateTimeStampForMultipleDocSettingsForPrefix.OptionValue);

                var settingPrefixCustomName = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.PrefixCustomName);
                if (settingPrefixCustomName != null)
                    prefixCustomName = Convert.ToString(settingPrefixCustomName.OptionValue);

                var settingAddSuffixFileToMode = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.AddSuffixFileToMode);
                if (settingAddSuffixFileToMode != null)
                    addSuffixFileToMode = Convert.ToInt32(settingAddSuffixFileToMode.OptionValue);

                var settingDateTimeStampForMultipleDocSettingsForSufix = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.DateTimeStampForMultipleDocSettingsForSufix);
                if (settingDateTimeStampForMultipleDocSettingsForSufix != null)
                    dateTimeStampForMultipleDocSettingsForSufix = Convert.ToInt32(settingDateTimeStampForMultipleDocSettingsForSufix.OptionValue);

                var settingSufixCustomName = _settingsRepository.GetEntityForByKeyConfig(companyId, Constants.SettingsKeyConfig.SuffixCustomName);
                if (settingSufixCustomName != null)
                    suffixCustomName = Convert.ToString(settingSufixCustomName.OptionValue);
            }

            envelopeObject.RenameFileTo = renameFileTo;
            envelopeObject.AddPrefixToFileNameMode = addPrefixToFileNameMode;
            envelopeObject.PrefixCustomName = prefixCustomName;
            envelopeObject.DateTimeStampForMultipleDocSettingsForPrefix = dateTimeStampForMultipleDocSettingsForPrefix;
            envelopeObject.AddSuffixFileToMode = addSuffixFileToMode;
            envelopeObject.SuffixCustomName = suffixCustomName;
            envelopeObject.DateTimeStampForMultipleDocSettingsForSufix = dateTimeStampForMultipleDocSettingsForSufix;

            var finalDocumentName = GenerateFinalSignedDocumentNamingForMultipleDocuments(envelopeObject);
            return finalDocumentName;
        }
        public string GenerateFinalSignedDocumentNamingForMultipleDocuments(Envelope envelopeObject)
        {
            var finalDocumentName = "";
            string firstFileName = "";
            string lastFileName = "";
            using (var dbContext = new RSignDbContext(_configuration))
            {
                var getFilNameMode = dbContext.Documents.Where(a => a.EnvelopeID == envelopeObject.ID).OrderBy(x => x.Order).ToList();
                firstFileName = getFilNameMode.First().DocumentName;
                lastFileName = getFilNameMode.Last().DocumentName;
            }
            var getPrfixSettings = GetPrefixSettings(envelopeObject);
            var getSufixSettings = GetSufixSettings(envelopeObject);

            if (envelopeObject.RenameFileTo == Constants.RenameContractsFileTo.FirstUploadedDocumentName)
            {
                //firstFileName = Path.GetFileNameWithoutExtension(firstFileName);
                if (getPrfixSettings == "" && getSufixSettings == "")
                {
                    //finalDocumentName = firstFileName + '_' + getSufixSettings;
                    finalDocumentName = firstFileName;
                }
                else if (getPrfixSettings == "")
                {
                    finalDocumentName = firstFileName + '_' + getSufixSettings;
                }
                else if (getSufixSettings == "")
                {
                    finalDocumentName = getPrfixSettings + '_' + firstFileName;
                }
                else
                {
                    finalDocumentName = getPrfixSettings + '_' + firstFileName + '_' + getSufixSettings;

                }
            }
            else
            {
                lastFileName = Path.GetFileNameWithoutExtension(lastFileName);
                if (getPrfixSettings == "" && getSufixSettings == "")
                {
                    //finalDocumentName = firstFileName + '_' + getSufixSettings;
                    finalDocumentName = lastFileName;
                }
                else if (getPrfixSettings == "")
                {
                    finalDocumentName = lastFileName + '_' + getSufixSettings;
                }
                else if (getSufixSettings == "")
                {
                    finalDocumentName = getPrfixSettings + '_' + lastFileName;
                }
                else
                {
                    finalDocumentName = getPrfixSettings + '_' + lastFileName + '_' + getSufixSettings;

                }
            }
            return finalDocumentName;
        }
        public string GetPrefixSettings(Envelope envelopeObject)
        {
            var getPrefixDocName = "";
            if (envelopeObject.AddPrefixToFileNameMode <= 1)
                return getPrefixDocName;
            try
            {
                switch (Convert.ToInt32(envelopeObject.AddPrefixToFileNameMode))
                {
                    case 1:
                        getPrefixDocName = String.Format("{0}", getPrefixDocName);
                        break;
                    case 2:
                        getPrefixDocName = String.Format("{0}", "ENV" + envelopeObject.EDisplayCode);
                        break;
                    case 3:
                        getPrefixDocName = String.Format("{0}", envelopeObject.PrefixCustomName);
                        break;
                    case 4:
                        getPrefixDocName = String.Format("{0}", "Contracts");
                        break;
                    case 5:
                        getPrefixDocName = String.Format("{0}", AppendDateTimeForPrefixandSufix(envelopeObject.DateTimeStampForMultipleDocSettingsForPrefix));
                        break;
                    default:
                        return getPrefixDocName;
                }
                return getPrefixDocName;
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }
        public string GetSufixSettings(Envelope envelopeObject)
        {
            var getSufixDocName = "";
            if (envelopeObject.AddSuffixFileToMode <= 1)
                return getSufixDocName;
            try
            {
                switch (Convert.ToInt32(envelopeObject.AddSuffixFileToMode))
                {
                    case 1:
                        getSufixDocName = String.Format("{0}", getSufixDocName);
                        break;
                    case 2:
                        getSufixDocName = String.Format("{0}", "ENV" + envelopeObject.EDisplayCode);
                        break;
                    case 3:
                        getSufixDocName = String.Format("{0}", envelopeObject.SuffixCustomName);
                        break;
                    case 4:
                        getSufixDocName = String.Format("{0}", "Contracts");
                        break;
                    case 5:
                        getSufixDocName = String.Format("{0}", AppendDateTimeForPrefixandSufix(envelopeObject.DateTimeStampForMultipleDocSettingsForSufix));
                        break;
                    default:
                        return getSufixDocName;
                }
                return getSufixDocName;
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }
        private static string AppendDateTimeForPrefixandSufix(int dtFormatId)
        {
            string datetimeformat = "";
            if (dtFormatId <= 1)
                return "";
            try
            {
                switch (Convert.ToInt32(dtFormatId))
                {
                    case 2:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("yyyy-MM-dd-HH-mm-ss"));
                        break;
                    case 3:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("MM-dd-yyyy-HH-mm-ss"));
                        break;
                    case 4:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MM-yyyy-HH-mm-ss"));
                        break;
                    case 5:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd-MMM-yyyy-HH-mm-ss"));
                        break;
                    case 6:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("yyyy_MM_dd_HH_mm_ss"));
                        break;
                    case 7:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("MM_dd_yyyy_HH_mm_ss"));
                        break;
                    case 8:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd_MM_yyyy_HH_mm_ss"));
                        break;
                    case 9:
                        datetimeformat = String.Format("{0}", DateTime.Parse(DateTime.Now.ToString(), CultureInfo.InvariantCulture).ToString("dd_MMM_yyyy_HH_mm_ss"));
                        break;
                    default:
                        return datetimeformat;
                }
                return datetimeformat;
            }
            catch (Exception ex)
            {
                throw ex;
            }
        }
        #endregion FinalSignedDocumentNamingForMultipleDocuments

    }
